INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3, 1, 'match_pairs', 1, '{"pairs_left": ["א", "ב", "ג", "ד", "ה"], "pairs_right": ["Алеф", "Бет", "Гимель", "Далет", "Хей"]}', '{"matches": {"א": "Алеф", "ב": "Бет", "ג": "Гимель", "ד": "Далет", "ה": "Хей"}}', '{"text": "Первые 5 букв ивритского алфавита"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (6, 7, 'fill_blank', 1, '{"context": "Добавьте определённый артикль", "sentence_ru": "___ספר (книга, определённая)", "blank_position": 0}', '{"accept": ["ה", "הַ", "הא"], "correct": "הַ"}', '{"text": "Определённый артикль הַ ставится перед существительным слитно"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (10, 9, 'match_pairs', 2, '{"pairs_left": ["я", "ты (м.)", "он", "она", "мы"], "pairs_right": ["אני", "אתה", "הוא", "היא", "אנחנו"]}', '{"matches": {"я": "אני", "мы": "אנחנו", "он": "הוא", "она": "היא", "ты (м.)": "אתה"}}', '{"text": "Основные личные местоимения иврита"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (11, 11, 'fill_blank', 2, '{"hint": "קורא/קוראת", "sentence_ru": "אני _____ ספר (Я читаю книгу)", "blank_position": 1}', '{"accept": ["קורא", "קוראת"], "correct": "קורא"}', '{"text": "В настоящем времени глагол согласуется по роду и числу, но не по лицу"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (13, 12, 'match_pairs', 2, '{"pairs_left": ["Пааль", "Нифъаль", "Пиэль", "Хифъиль", "Хитпаэль"], "pairs_right": ["простое действие", "пассив/возвратное", "интенсив", "каузатив", "взаимное"]}', '{"matches": {"Пааль": "простое действие", "Пиэль": "интенсив", "Нифъаль": "пассив/возвратное", "Хифъиль": "каузатив", "Хитпаэль": "взаимное"}}', '{"text": "Каждый биньян несёт определённое значение"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (14, 11, 'word_order', 2, '{"translation": "Мальчик читает книгу", "words_shuffled": ["ספר", "קורא", "הילד"], "correct_sentence": "הילד קורא ספר"}', '{"correct_order": ["הילד", "קורא", "ספר"]}', '{"text": "Порядок слов в иврите: подлежащее — сказуемое — дополнение"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (15, 18, 'dictation', 1, '{"hint": "Приветствие", "word_he": "שָׁלוֹם", "word_translit": "шалом"}', '{"accept": ["שלום", "שָׁלוֹם"], "correct": "שלום"}', '{"text": "שָׁלוֹם (шалом) — привет, мир"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (16, 18, 'dictation', 1, '{"hint": "Благодарность", "word_he": "תּוֹדָה", "word_translit": "тодА"}', '{"accept": ["תודה", "תּוֹדָה"], "correct": "תודה"}', '{"text": "תּוֹדָה (тодА) — спасибо"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (17, 18, 'dictation', 1, '{"hint": "Извинение", "word_he": "סְלִיחָה", "word_translit": "слихА"}', '{"accept": ["סליחה", "סְלִיחָה"], "correct": "סליחה"}', '{"text": "סְלִיחָה (слихА) — извините"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (18, 18, 'dictation', 1, '{"hint": "Вежливость", "word_he": "בְּבַקָּשָׁה", "word_translit": "бевакашА"}', '{"accept": ["בבקשה", "בְּבַקָּשָׁה"], "correct": "בבקשה"}', '{"text": "בְּבַקָּשָׁה (бевакашА) — пожалуйста"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (19, 18, 'dictation', 1, '{"hint": "Согласие", "word_he": "כֵּן", "word_translit": "кен"}', '{"accept": ["כן", "כֵּן"], "correct": "כן"}', '{"text": "כֵּן (кен) — да"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (20, 18, 'dictation', 1, '{"hint": "Отрицание", "word_he": "לֹא", "word_translit": "ло"}', '{"accept": ["לא", "לֹא"], "correct": "לא"}', '{"text": "לֹא (ло) — нет"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (21, 19, 'minimal_pairs', 1, '{"pair_a": {"he": "בַּת", "meaning": "дочь", "translit": "бат"}, "pair_b": {"he": "בֵּית", "meaning": "дом", "translit": "бейт"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "בַּת (бат) — дочь, בֵּית (бейт) — дом. Различие в гласной."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (22, 19, 'minimal_pairs', 1, '{"pair_a": {"he": "כֶּלֶב", "meaning": "собака", "translit": "кЕлев"}, "pair_b": {"he": "חָלָב", "meaning": "молоко", "translit": "халАв"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "כ (каф) — обычное ''к''; ח (хет) — гортанное ''х''"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (23, 19, 'minimal_pairs', 1, '{"pair_a": {"he": "סֵפֶר", "meaning": "книга", "translit": "сЕфер"}, "pair_b": {"he": "שָׂפָה", "meaning": "язык/губа", "translit": "сафА"}, "question": "Какое слово вы слышите?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "ס (самех) = ''с''; שׂ (син) = тоже ''с''. В современном иврите звучат одинаково!"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (24, 19, 'minimal_pairs', 1, '{"pair_a": {"he": "דָּג", "meaning": "рыба", "translit": "даг"}, "pair_b": {"he": "דַּק", "meaning": "тонкий", "translit": "дак"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "ג (гимель) — звонкий ''г''; ק (куф) — глухой ''к''"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (25, 20, 'listening_comprehension', 2, '{"text_he": "שלום! אני דני. אני לומד עברית בּאולפּן. המורה שלנו שמה רות.", "questions": [{"correct": "Дэни", "options": ["Рут", "Дэни", "Давид"], "question": "Как зовут говорящего?"}, {"correct": "в ульпане", "options": ["в школе", "в ульпане", "дома"], "question": "Где он учит иврит?"}, {"correct": "Рут", "options": ["Дэни", "Сара", "Рут"], "question": "Как зовут учительницу?"}], "text_translit": "шалОм! анИ дАни. анИ ломЕд иврИт беульпАн. hа-морА шелАну шмА рут."}', '{"correct_answers": ["Дэни", "в ульпане", "Рут"]}', '{"text": "Простой текст о студенте в ульпане"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (26, 21, 'dictation', 2, '{"hint": "Я учу иврит", "word_he": "אני לומד עברית", "word_translit": "анИ ломЕд иврИт"}', '{"accept": ["אני לומד עברית", "אֲנִי לוֹמֵד עִבְרִית"], "correct": "אני לומד עברית"}', '{"text": "אֲנִי לוֹמֵד עִבְרִית — Я учу иврит"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (284, 35, 'fill_blank', 3, '{"hint": "перед которой (союз)", "sentence": "הבעיה _ אנחנו עומדים בפניה היא מורכבת"}', '{"correct": "ש", "alternatives": []}', '{"text": "ש (ше) + предложное управление: עומדים בפניה — стоим перед ней"}', 10);
