INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (45, 27, 'fill_blank', 3, '{"context": "Вставьте условный союз", "sentence_ru": "___ תלמד, תצליח (Если будешь учиться, преуспеешь)", "blank_position": 0}', '{"accept": ["אם"], "correct": "אם"}', '{"text": "אם + будущее время = реальное условие"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (46, 27, 'word_order', 3, '{"translation": "Если бы я знал, я бы пришёл", "words_shuffled": ["בא", "הייתי", "ידעתי", "אילו"], "correct_sentence": "אילו ידעתי הייתי בא"}', '{"correct_order": ["אילו", "ידעתי", "הייתי", "בא"]}', '{"text": "אילו + прошедшее = нереальное условие"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (47, 28, 'match_pairs', 3, '{"pairs_left": ["פיעל → פועל", "הפעיל → הופעל", "פעל → נפעל"], "pairs_right": ["סיפר → סופר", "הזמין → הוזמן", "שבר → נשבר"]}', '{"matches": {"פעל → נפעל": "שבר → נשבר", "פיעל → פועל": "סיפר → סופר", "הפעיל → הופעל": "הזמין → הוזמן"}}', '{"text": "Каждый активный биньян имеет пассивную пару"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (49, 29, 'fill_blank', 3, '{"context": "Вставьте относительную частицу", "sentence_ru": "הספר ___ קראתי היה מעניין (Книга, которую я прочитал, была интересной)", "blank_position": 1}', '{"accept": ["ש", "שקראתי"], "correct": "ש"}', '{"text": "ש- вводит относительное придаточное"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (409, 3, 'translate_ru_he', 1, '{"hint": "Содержит буквы Мем, Ламед, Каф", "sentence_ru": "Царь"}', '{"accept": ["מֶלֶךְ"], "correct": "מלך"}', '{"text": "מלך (мЕлех) — царь. Конечная Каф пишется как ך."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (51, 30, 'match_pairs', 3, '{"pairs_left": ["должен", "может", "хочет", "обязан"], "pairs_right": ["צריך", "יכול", "רוצה", "חייב"]}', '{"matches": {"может": "יכול", "хочет": "רוצה", "должен": "צריך", "обязан": "חייב"}}', '{"text": "Основные модальные выражения иврита"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (52, 30, 'word_order', 3, '{"translation": "Я должен учить иврит", "words_shuffled": ["ללמוד", "צריך", "אני", "עברית"], "correct_sentence": "אני צריך ללמוד עברית"}', '{"correct_order": ["אני", "צריך", "ללמוד", "עברית"]}', '{"text": "Порядок: подлежащее + модальное слово + инфинитив"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (53, 33, 'dictation', 3, '{"hint": "Условное предложение", "word_he": "אם יהיה חם, נלך לים", "word_translit": "им йиhйЕ хам, нелЕх ла-йам"}', '{"accept": ["אם יהיה חם נלך לים", "אם יהיה חם, נלך לים"], "correct": "אם יהיה חם נלך לים"}', '{"text": "Условное предложение: если будет жарко, пойдём к морю"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (54, 33, 'dictation', 3, '{"hint": "Относительное придаточное", "word_he": "הספר שקראתי היה מעניין", "word_translit": "hа-сЕфер ше-карАти hайА меанйЕн"}', '{"accept": ["הספר שקראתי היה מעניין"], "correct": "הספר שקראתי היה מעניין"}', '{"text": "Книга, которую я прочитал, была интересной"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (55, 34, 'translate_ru_he', 3, '{"hint": "אני + צריך + ללמוד + עברית + כל יום", "prompt_ru": "Я должен учить иврит каждый день", "target_he": "אני צריך ללמוד עברית כל יום"}', '{"accept": ["אני צריך ללמוד עברית כל יום"], "correct": "אני צריך ללמוד עברית כל יום"}', '{"text": "צריך + инфинитив = должен"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (56, 34, 'translate_ru_he', 3, '{"hint": "אם + יהיה + זמן + אבוא", "prompt_ru": "Если будет время, я приду", "target_he": "אם יהיה זמן, אבוא"}', '{"accept": ["אם יהיה זמן אבוא", "אם יהיה זמן, אבוא"], "correct": "אם יהיה זמן אבוא"}', '{"text": "אם + будущее = реальное условие"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (58, 35, 'fill_blank', 4, '{"context": "Вставьте следственный союз", "sentence_ru": "הוא למד הרבה, ___ הצליח (Он много учился, поэтому преуспел)", "blank_position": 3}', '{"accept": ["לכן", "על כן"], "correct": "לכן"}', '{"text": "לכן/על כן = поэтому / следовательно"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (59, 36, 'match_pairs', 4, '{"pairs_left": ["כתב (писать)", "דיבר (говорить)", "הזמין (пригласить)", "התלבש (одеться)"], "pairs_right": ["כתיבה", "דיבור", "הזמנה", "התלבשות"]}', '{"matches": {"כתב (писать)": "כתיבה", "דיבר (говорить)": "דיבור", "התלבש (одеться)": "התלבשות", "הזמין (пригласить)": "הזמנה"}}', '{"text": "Отглагольные существительные образуются по шаблону биньяна"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (61, 37, 'match_pairs', 4, '{"pairs_left": ["זכר (помнил)", "הזכיר (напомнил)", "נזכר (вспомнил)", "הוזכר (был упомянут)"], "pairs_right": ["Пааль", "Хифъиль", "Нифъаль", "Хуфъаль"]}', '{"matches": {"זכר (помнил)": "Пааль", "נזכר (вспомнил)": "Нифъаль", "הזכיר (напомнил)": "Хифъиль", "הוזכר (был упомянут)": "Хуфъаль"}}', '{"text": "Один корень ז.כ.ר в разных биньянах"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (62, 40, 'dictation', 4, '{"hint": "Возможно, ситуация изменится скоро", "word_he": "ייתכן שהמצב ישתנה בקרוב", "word_translit": "йитахЕн ше-hа-мацАв йиштанЕ бекарОв"}', '{"accept": ["ייתכן שהמצב ישתנה בקרוב"], "correct": "ייתכן שהמצב ישתנה בקרוב"}', '{"text": "ייתכן ש- = возможно, что"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (64, 41, 'word_order', 5, '{"translation": "Пришла весна (инверсия)", "words_shuffled": ["האביב", "בא"], "correct_sentence": "בא האביב"}', '{"correct_order": ["בא", "האביב"]}', '{"text": "В высоком стиле сказуемое стоит перед подлежащим"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (65, 42, 'match_pairs', 5, '{"pairs_left": ["שבר את הראש", "הרים ידיים", "שם לב", "יצא מהכלים"], "pairs_right": ["долго думал", "сдался", "обратил внимание", "вышел из себя"]}', '{"matches": {"שם לב": "обратил внимание", "הרים ידיים": "сдался", "יצא מהכלים": "вышел из себя", "שבר את הראש": "долго думал"}}', '{"text": "Идиомы с частями тела"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (67, 46, 'match_pairs', 6, '{"pairs_left": ["חוזה", "עורך דין", "תקציב", "רווח"], "pairs_right": ["договор", "адвокат", "бюджет", "прибыль"]}', '{"matches": {"חוזה": "договор", "רווח": "прибыль", "תקציב": "бюджет", "עורך דין": "адвокат"}}', '{"text": "Базовая юридическая и деловая лексика"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (68, 46, 'fill_blank', 6, '{"context": "Завершение делового письма", "sentence_ru": "_____ רב, (С уважением — завершение письма)", "blank_position": 0}', '{"accept": ["בכבוד", "בכבוד רב"], "correct": "בכבוד"}', '{"text": "בכבוד רב — стандартное завершение делового письма"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (69, 49, 'fill_blank', 3, '{"context": "Реальное условие — какой союз нужен?", "sentence_ru": "___ יהיה לי זמן, אבוא לבקר אותך (Если у меня будет время, приду навестить тебя)", "blank_position": 0}', '{"accept": ["אם"], "correct": "אם"}', '{"text": "אם (им) + будущее время → реальное условие. Не путайте с אילו — это для нереальных условий!"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (70, 49, 'word_order', 3, '{"translation": "Если бы я был богат, я бы купил квартиру", "words_shuffled": ["דירה", "קונה", "הייתי", "עשיר", "הייתי", "אילו"], "correct_sentence": "אילו הייתי עשיר הייתי קונה דירה"}', '{"correct_order": ["אילו", "הייתי", "עשיר", "הייתי", "קונה", "דירה"]}', '{"text": "אילו + прошедшее время → нереальное условие (контрфактуал). Обратите внимание: הייתי появляется дважды — «был бы» и «купил бы»."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (72, 50, 'fill_blank', 3, '{"context": "Придаточное времени — нужен союз «когда»", "sentence_ru": "___ הגעתי הביתה, אכלתי ארוחת ערב (Когда я пришёл домой, поужинал)", "blank_position": 0}', '{"accept": ["כש", "כשהגעתי"], "correct": "כש"}', '{"text": "כש- (кше-) = когда. Приклеивается к следующему слову: כשהגעתי = когда-я-пришёл. Это одно из самых частых слов в иврите!"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (73, 51, 'translate_ru_he', 3, '{"hint": "אני + צריך + ללמוד + עברית + כי + אני + גר + בישראל", "prompt_ru": "Я должен учить иврит, потому что живу в Израиле", "target_he": "אני צריך ללמוד עברית כי אני גר בישראל"}', '{"accept": ["אני צריך ללמוד עברית כי אני גר בישראל", "אני צריך ללמוד עברית, כי אני גר בישראל"], "correct": "אני צריך ללמוד עברית כי אני גר בישראל"}', '{"text": "Модальный глагол צריך + инфинитив ללמוד + придаточное причины כי. Три конструкции из Гимель в одном предложении!"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (74, 51, 'match_pairs', 3, '{"pairs_left": ["כי", "כש-", "כדי ש-", "למרות ש-", "אם"], "pairs_right": ["потому что", "когда", "чтобы", "несмотря на", "если"]}', '{"matches": {"אם": "если", "כי": "потому что", "כש-": "когда", "כדי ש-": "чтобы", "למרות ש-": "несмотря на"}}', '{"text": "Пять главных союзов иврита. Запомните их — они встретятся в каждом тексте и в каждом разговоре."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (76, 52, 'fill_blank', 3, '{"context": "Что врач даёт, чтобы вы купили лекарства в аптеке?", "sentence_ru": "הרופא נתן לי ___ לתרופות (Врач дал мне ___ на лекарства)", "blank_position": 3}', '{"accept": ["מרשם"], "correct": "מרשם"}', '{"text": "מרשם (миршАм) = рецепт. Корень: ר.ש.מ (писать, записывать). Однокоренные: רשימה (список), רישום (регистрация)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (77, 53, 'match_pairs', 3, '{"pairs_left": ["ראש השנה", "יום כיפור", "פסח", "חנוכה", "פורים"], "pairs_right": ["תפוחים בדבש", "צום ותפילה", "מצות וליל הסדר", "נרות וסופגניות", "תחפושות ומשלוח מנות"]}', '{"matches": {"פסח": "מצות וליל הסדר", "חנוכה": "נרות וסופגניות", "פורים": "תחפושות ומשלוח מנות", "ראש השנה": "תפוחים בדבש", "יום כיפור": "צום ותפילה"}}', '{"text": "Каждый праздник — свои символы и обычаи. В Рош ха-Шана — яблоки в мёду на сладкий год, в Пурим — карнавальные костюмы и подарки друзьям."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (79, 54, 'dictation', 3, '{"hint": "Предложение о визите к врачу (8 слов)", "word_he": "כשאני חולה, אני הולך לרופא המשפחה בקופת החולים", "word_translit": "кше-анИ холЕ, анИ холЕх ле-рофЕ hа-мишпахА бе-купАт hа-холИм"}', '{"accept": ["כשאני חולה אני הולך לרופא המשפחה בקופת החולים", "כשאני חולה, אני הולך לרופא המשפחה בקופת החולים"], "correct": "כשאני חולה אני הולך לרופא המשפחה בקופת החולים"}', '{"text": "כש- + я болен → иду к семейному врачу в купат-холим. Обратите внимание на смихут: רופא המשפחה, קופת החולים."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (80, 54, 'dictation', 3, '{"hint": "Что делают в Рош ха-Шана (7 слов)", "word_he": "בראש השנה אנחנו אוכלים תפוחים בדבש ומאחלים שנה טובה", "word_translit": "бе-рош hа-шанА анАхну охлИм тапухИм бе-двАш у-меахалИм шанА товА"}', '{"accept": ["בראש השנה אנחנו אוכלים תפוחים בדבש ומאחלים שנה טובה"], "correct": "בראש השנה אנחנו אוכלים תפוחים בדבש ומאחלים שנה טובה"}', '{"text": "Традиция Рош ха-Шана: едим яблоки в мёду (תפוחים בדבש) и желаем доброго года (שנה טובה). Глагол מאחלים — от корня א.ח.ל, «желать»."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (81, 55, 'match_pairs', 4, '{"pairs_left": ["למד", "לימד", "נלמד", "התלמד"], "pairs_right": ["учился (сам)", "обучал (других)", "был выучен", "обучался / стажировался"]}', '{"matches": {"למד": "учился (сам)", "לימד": "обучал (других)", "נלמד": "был выучен", "התלמד": "обучался / стажировался"}}', '{"text": "Корень ל.מ.ד через биньяны: Пааль (сам учил) → Пиэль (учил других) → Нифъаль (пассив) → Хитпаэль (возвратное/стажировка). Один корень — четыре разных значения!"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (83, 55, 'fill_blank', 4, '{"context": "Какой биньян: учить ДРУГИХ?", "sentence_ru": "המנהל ___ את העובדים החדשים (Менеджер обучил новых сотрудников)", "blank_position": 1}', '{"accept": ["הדריך", "לימד"], "correct": "הדריך"}', '{"text": "Когда речь о том, что один человек обучает других — используем каузативные биньяны: לימד (Пиэль) или הדריך (Хифъиль). Не путайте с למד (Пааль) — это «учился сам»."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (84, 56, 'match_pairs', 4, '{"pairs_left": ["שלי", "שלך", "שלו", "שלה", "שלנו"], "pairs_right": ["мой", "твой", "его", "её", "наш"]}', '{"matches": {"שלה": "её", "שלו": "его", "שלי": "мой", "שלך": "твой", "שלנו": "наш"}}', '{"text": "של + местоимённый суффикс = притяжательное. Это самый частый предлог с суффиксами. Запомните ряд целиком!"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (85, 56, 'fill_blank', 4, '{"context": "Предлог ל- (к, для) с суффиксом 3-го лица м.р.", "sentence_ru": "הספר הזה שייך ___. תחזיר ___ אותו (Эта книга принадлежит ему. Верни ему её)", "blank_position": 2}', '{"accept": ["לו"], "correct": "לו"}', '{"text": "ל- + הוא = לו (ему). Полная парадигма: לי, לך, לו, לה, לנו, לכם, להם. Предлог ל- с суффиксами встречается в каждом втором предложении!"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (87, 57, 'match_pairs', 4, '{"pairs_left": ["כתב (писал)", "דיבר (говорил)", "הזמין (пригласил)", "התלבש (оделся)"], "pairs_right": ["כתיבה (письмо/писание)", "דיבור (речь)", "הזמנה (приглашение)", "התלבשות (одевание)"]}', '{"matches": {"כתב (писал)": "כתיבה (письмо/писание)", "דיבר (говорил)": "דיבור (речь)", "התלבש (оделся)": "התלבשות (одевание)", "הזמין (пригласил)": "הזמנה (приглашение)"}}', '{"text": "Каждый биньян имеет свой шаблон номинализации:\nПааль → כְּתִיבָה (ктивА)\nПиэль → דִּיבּוּר (дибУр)\nХифъиль → הַזְמָנָה (hазманА)\nХитпаэль → הִתְלַבְּשׁוּת (hитлабшУт)"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (88, 57, 'fill_blank', 4, '{"context": "Отглагольное существительное от כתב", "sentence_ru": "ה___ של הספר לקחה שנתיים (Написание книги заняло два года)", "blank_position": 0}', '{"accept": ["כתיבה"], "correct": "כתיבה"}', '{"text": "כתיבה (ктивА) — отглагольное существительное от כתב (писал). Шаблон Пааля: ктилА (כְּתִילָה). Другие примеры: קריאה (чтение), שמיעה (слушание), ישיבה (сидение/заседание)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (90, 58, 'fill_blank', 4, '{"context": "Что читают утром для новостей?", "sentence_ru": "אני קורא ___ כל בוקר כדי לדעת מה קורה בארץ (Я читаю ___ каждое утро, чтобы знать, что происходит)", "blank_position": 1}', '{"accept": ["עיתון", "חדשות"], "correct": "עיתון"}', '{"text": "עיתון (итОн) = газета. От корня ע.ת.ן (ивритская версия) или ע.ת — время. Однокоренные: עיתונאי (журналист), עיתונות (журналистика)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (92, 59, 'fill_blank', 4, '{"context": "Технология превращения солёной воды в пресную", "sentence_ru": "ישראל היא מובילה עולמית ב___ מי ים (Израиль — мировой лидер в ___ морской воды)", "blank_position": 3}', '{"accept": ["התפלת", "התפלה"], "correct": "התפלת"}', '{"text": "התפלה (hатпалА) = опреснение. От корня ת.פ.ל — пресный. התפלת מי ים = опреснение морской воды. Смихут: התפלה → התפלת (+ мей ям)."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (93, 60, 'translate_ru_he', 4, '{"hint": "למרות ש- + ה... + אני + ממשיך + כי + אני + רוצה + לעבוד + בהייטק", "prompt_ru": "Несмотря на то что учёба трудная, я продолжаю, потому что хочу работать в хай-теке", "target_he": "למרות שהלימודים קשים, אני ממשיך כי אני רוצה לעבוד בהייטק"}', '{"accept": ["למרות שהלימודים קשים אני ממשיך כי אני רוצה לעבוד בהייטק", "למרות שהלימודים קשים, אני ממשיך כי אני רוצה לעבוד בהייטק", "למרות שהלימודים קשים, אני ממשיך, כי אני רוצה לעבוד בהייטק"], "correct": "למרות שהלימודים קשים אני ממשיך כי אני רוצה לעבוד בהייטק"}', '{"text": "Два придаточных в одном предложении:\nלמרות ש- (уступка) + כי (причина). Это уровень B2 — связная аргументация!"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (95, 60, 'dictation', 4, '{"hint": "Написание статьи было трудным, но результат отличный (9 слов)", "word_he": "הכתיבה של המאמר הייתה קשה, אבל התוצאה הייתה מצוינת", "word_translit": "hа-ктивА шель hа-маамАр hайтА кашА, авАль hа-тоцаА hайтА мецуйЕнет"}', '{"accept": ["הכתיבה של המאמר הייתה קשה אבל התוצאה הייתה מצוינת", "הכתיבה של המאמר הייתה קשה, אבל התוצאה הייתה מצוינת"], "correct": "הכתיבה של המאמר הייתה קשה אבל התוצאה הייתה מצוינת"}', '{"text": "Номинализация כתיבה в живом предложении. Обратите внимание: הייתה (была) — ж.р., потому что כתיבה и תוצאה — женского рода."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (986, 99, 'translate_ru_he', 3, '{"hints": ["חשוב", "לנו"], "text_ru": "Это важно для нас"}', '{"correct": "זה חשוב לנו", "alternatives": ["זה חשוב בשבילנו"]}', '{"text": "לנו (лАну) — нам / для нас."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (96, 61, 'match_pairs', 5, '{"pairs_left": ["שבר את הראש", "הרים ידיים", "שם לב", "עשה חיים", "ירד מהפסים"], "pairs_right": ["долго думал", "сдался", "обратил внимание", "наслаждался", "сбился с пути"]}', '{"matches": {"שם לב": "обратил внимание", "עשה חיים": "наслаждался", "הרים ידיים": "сдался", "ירד מהפסים": "сбился с пути", "שבר את הראש": "долго думал"}}', '{"text": "Идиомы невозможно перевести буквально. שבר את הראש = «сломал голову» = долго думал. Запоминайте как целые единицы!"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (98, 62, 'fill_blank', 5, '{"context": "Академическая связка «в дополнение к этому»", "sentence_ru": "___ לכך, המחקר מצביע על מגמה ברורה (В дополнение к этому, исследование указывает на чёткую тенденцию)", "blank_position": 0}', '{"accept": ["בנוסף", "נוסף"], "correct": "בנוסף"}', '{"text": "בנוסף לכך = в дополнение к этому. Другие связки:\nלפיכך = следовательно\nיתרה מזאת = более того\nלסיכום = в заключение"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (410, 3, 'dictation', 1, '{"audio_text": "סוס", "instruction": "Животное, три буквы"}', '{"accept": ["סוּס"], "correct": "סוס"}', '{"text": "סוס (сус) — лошадь. Самех-Вав-Самех."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (99, 62, 'match_pairs', 5, '{"pairs_left": ["לפיכך", "יתרה מזאת", "לעומת זאת", "לסיכום"], "pairs_right": ["следовательно", "более того", "в то время как", "в заключение"]}', '{"matches": {"לפיכך": "следовательно", "לסיכום": "в заключение", "יתרה מזאת": "более того", "לעומת זאת": "в то время как"}}', '{"text": "Академические связки — маркеры высокого стиля. Они превращают простой текст в аргументированный."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (100, 63, 'word_order', 5, '{"translation": "Пришла возможность (инверсия)", "words_shuffled": ["ההזדמנות", "באה"], "correct_sentence": "באה ההזדמנות"}', '{"correct_order": ["באה", "ההזדמנות"]}', '{"text": "В высоком стиле сказуемое часто стоит перед подлежащим: באה ההזדמנות вместо ההזדמנות באה. Это придаёт торжественность и литературность."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (102, 63, 'fill_blank', 5, '{"context": "Безличная конструкция «следует»", "sentence_ru": "___ לציין שהתוצאות חיוביות (Следует отметить, что результаты положительные)", "blank_position": 0}', '{"accept": ["יש", "ראוי", "יש לציין"], "correct": "יש"}', '{"text": "יש לציין = следует отметить. Модель יש + ל + инфинитив = «следует / необходимо» — безличная конструкция высокого стиля."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (103, 64, 'match_pairs', 5, '{"pairs_left": ["בעור שיניים", "מלח הארץ", "אבן פינה", "נשא בעול"], "pairs_right": ["еле-еле (кожей зубов)", "соль земли", "краеугольный камень", "нёс бремя"]}', '{"matches": {"אבן פינה": "краеугольный камень", "מלח הארץ": "соль земли", "נשא בעול": "нёс бремя", "בעור שיניים": "еле-еле (кожей зубов)"}}', '{"text": "Десятки выражений из Танаха живут в повседневном иврите. בעור שיניים (Иов 19:20) = едва, чудом. Израильтяне используют их, часто не зная источник!"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (105, 65, 'fill_blank', 5, '{"context": "Инфинитив с предлогом ב- и суффиксом 3 л. мн.ч.", "sentence_ru": "___ הגיעו לארץ, הם הרגישו בבית (По прибытии в страну, они почувствовали себя дома)", "blank_position": 0}', '{"accept": ["בהגיעם"], "correct": "בהגיעם"}', '{"text": "ב + הגיע + ם (суффикс «они») = בהגיעם = по их прибытии. Высокий стиль. В разговорной речи скажут: כשהם הגיעו."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (106, 65, 'translate_ru_he', 5, '{"hint": "לדעתי + ה... + הזה + חשוב + מאוד", "prompt_ru": "По моему мнению, эта книга очень важна", "target_he": "לדעתי, הספר הזה חשוב מאוד"}', '{"accept": ["לדעתי הספר הזה חשוב מאוד", "לדעתי, הספר הזה חשוב מאוד"], "correct": "לדעתי הספר הזה חשוב מאוד"}', '{"text": "לדעתי = по моему мнению (буквально: «к моему знанию»). Инфинитив דעת + суффикс י. Очень частое выражение!"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (107, 66, 'match_pairs', 5, '{"pairs_left": ["נראה", "נשמע", "נרדם", "הסתדר", "התעניין"], "pairs_right": ["выглядит", "звучит", "заснул", "устроился", "интересовался"]}', '{"matches": {"נראה": "выглядит", "נרדם": "заснул", "נשמע": "звучит", "הסתדר": "устроился", "התעניין": "интересовался"}}', '{"text": "Стативный Нифъаль: נראה = выглядит, נשמע = звучит. Хитпаэль с метатезой: הסתדר (от סדר), הצטלם (от צלם)."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (109, 67, 'dictation', 5, '{"hint": "Академическое предложение: исследование указывает на изменение (8 слов)", "word_he": "בנוסף לכך, המחקר מצביע על שינוי משמעותי בגישת הציבור", "word_translit": "бе-носАф ле-хАх, hа-мехкАр мацбИа аль шинУй машмаутИ бе-гишАт hа-цибУр"}', '{"accept": ["בנוסף לכך המחקר מצביע על שינוי משמעותי בגישת הציבור", "בנוסף לכך, המחקר מצביע על שינוי משמעותי בגישת הציבור"], "correct": "בנוסף לכך המחקר מצביע על שינוי משמעותי בגישת הציבור"}', '{"text": "Академический стиль: בנוסף לכך (в дополнение), מצביע על (указывает на), שינוי משמעותי (значительное изменение), גישת הציבור (подход общества)."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (110, 67, 'dictation', 5, '{"hint": "Библейское выражение с вводным словом (5 слов)", "word_he": "לדעתי, אין חדש תחת השמש", "word_translit": "ле-даатИ, эйн хадАш тАхат hа-шЕмеш"}', '{"accept": ["לדעתי אין חדש תחת השמש", "לדעתי, אין חדש תחת השמש"], "correct": "לדעתי אין חדש תחת השמש"}', '{"text": "לדעתי + библейская цитата из Экклезиаста. Два уровня языка в одном предложении — типично для образованного иврита."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (111, 68, 'translate_ru_he', 5, '{"hint": "לדעתי + נראה + עייף + כי + שבר את הראש + על + בעיה", "prompt_ru": "По моему мнению, он выглядит усталым, потому что долго думал над проблемой", "target_he": "לדעתי, הוא נראה עייף כי שבר את הראש על הבעיה"}', '{"accept": ["לדעתי הוא נראה עייף כי שבר את הראש על הבעיה", "לדעתי, הוא נראה עייף כי שבר את הראש על הבעיה"], "correct": "לדעתי הוא נראה עייף כי שבר את הראש על הבעיה"}', '{"text": "Всё C1 в одном предложении:\nלדעתי (инфинитивная конструкция) + נראה (стативный Нифъаль) + שבר את הראש (идиома) — три конструкции уровня Хей!"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (112, 68, 'word_order', 5, '{"translation": "Наконец пришла большая возможность", "words_shuffled": ["הגדולה", "ההזדמנות", "באה", "לבסוף"], "correct_sentence": "לבסוף באה ההזדמנות הגדולה"}', '{"correct_order": ["לבסוף", "באה", "ההזדמנות", "הגדולה"]}', '{"text": "Наречие + инверсия (сказуемое перед подлежащим) = высокий стиль. לבסוף באה — вместо «ההזדמנות באה לבסוף»."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (113, 69, 'match_pairs', 6, '{"pairs_left": ["דימוי", "מטאפורה", "הקבלה", "חזרה", "כינוי"], "pairs_right": ["сравнение / образ", "метафора", "параллелизм", "повтор / анафора", "эпитет / именование"]}', '{"matches": {"חזרה": "повтор / анафора", "דימוי": "сравнение / образ", "הקבלה": "параллелизм", "כינוי": "эпитет / именование", "מטאפורה": "метафора"}}', '{"text": "Поэтические приёмы иврита восходят к Танаху. Параллелизм (הקבלה) — главный приём библейской поэзии: «Небеса проповедуют славу Бога / и о делах рук Его вещает твердь» (Пс. 19:2). Две строки выражают одну мысль разными словами."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (115, 70, 'fill_blank', 6, '{"context": "Юридическая формула «настоящим» / «сим»", "sentence_ru": "הצדדים מסכימים ___ כי השוכר ישלם את דמי השכירות עד לתאריך הראשון בכל חודש (Стороны соглашаются ___, что арендатор будет платить арендную плату до первого числа каждого месяца)", "blank_position": 2}', '{"accept": ["בזאת", "בזה"], "correct": "בזאת"}', '{"text": "בזאת / בזה = настоящим, сим — стандартная юридическая формула. В договорах также встречаются: הואיל (ввиду того что), לפיכך (посему), מוסכם ומותנה (согласовано и обусловлено). Юридический иврит — один из самых формальных регистров."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1024, 102, 'fill_blank', 2, '{"hint": "ставку (должность)", "sentence": "אני מחפש _ מלאה."}', '{"correct": "משרה", "alternatives": ["מִשְׂרָה"]}', '{"text": "משרה מלאה (мисрА мелеА) — полная ставка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (116, 70, 'match_pairs', 6, '{"pairs_left": ["חוזה", "ייפוי כוח", "פסק דין", "תביעה", "עדות"], "pairs_right": ["договор / контракт", "доверенность", "судебное решение", "иск", "свидетельские показания"]}', '{"matches": {"חוזה": "договор / контракт", "עדות": "свидетельские показания", "תביעה": "иск", "פסק דין": "судебное решение", "ייפוי כוח": "доверенность"}}', '{"text": "Юридическая лексика иврита — смесь талмудического и современного. חוזה (контракт) — от корня ח.ז.ה (предвидеть → предусматривать условия). ייפוי כוח (доверенность) — буквально «наделение силой». Многие термины были созданы в эпоху Британского мандата."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (117, 71, 'word_order', 6, '{"translation": "Правительство одобрило всеобъемлющую реформу образования", "words_shuffled": ["הממשלה", "אישרה", "רפורמה", "מקיפה", "בחינוך"], "correct_sentence": "הממשלה אישרה רפורמה מקיפה בחינוך"}', '{"correct_order": ["הממשלה", "אישרה", "רפורמה", "מקיפה", "בחינוך"]}', '{"text": "Израильские заголовки строятся по формуле: подлежащее + глагол в прошедшем времени + объект. Прошедшее время в заголовках обозначает только что произошедшее событие — в русской прессе для этого используют настоящее."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (118, 71, 'fill_blank', 6, '{"context": "Журналистское слово «отчёт / доклад»", "sentence_ru": "לפי ___ שפורסם היום, רמת האבטלה ירדה (Согласно ___, опубликованному сегодня, уровень безработицы снизился)", "blank_position": 1}', '{"accept": ["דוח", "דו\"ח", "הדוח"], "correct": "דוח"}', '{"text": "דו\"ח (дох) = отчёт, доклад — ключевое слово журналистики. От него: דיווח (репортаж), דווח (было сообщено). Журналистские клише: לפי דוח (согласно отчёту), על פי הערכות (по оценкам), מסתמן כי (вырисовывается, что)."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (120, 72, 'match_pairs', 6, '{"pairs_left": ["לעוף על", "חבל על הזמן", "להיות על הפנים", "לדפוק חשבון", "סוף הדרך"], "pairs_right": ["обожать (сленг)", "потрясающе", "быть в ужасном состоянии", "призвать к ответу", "великолепно / предел"]}', '{"matches": {"לעוף על": "обожать (сленг)", "סוף הדרך": "великолепно / предел", "חבל על הזמן": "потрясающе", "לדפוק חשבון": "призвать к ответу", "להיות על הפנים": "быть в ужасном состоянии"}}', '{"text": "Израильский сленг полон неожиданных метафор:\n- לעוף על (буквально «летать на») = обожать\n- חבל על הזמן (буквально «жалко времени») = настолько круто, что жалко тратить время на описание\n- על הפנים (буквально «на лице») = ужасно\n- סוף הדרך (буквально «конец пути») = высший класс"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (122, 73, 'fill_blank', 6, '{"context": "Средневековое слово «толкование / комментарий», ныне повседневное", "sentence_ru": "הביקורת הספרותית היא ___ של הטקסט (Литературная критика — это ___ текста)", "blank_position": 3}', '{"accept": ["פירוש", "הפירוש"], "correct": "פירוש"}', '{"text": "פירוש (перуш) = толкование, комментарий. Слово из мира средневековых комментаторов вошло в повседневный иврит: «זה הפירוש?» = «вот в чём смысл?». Глагол: לפרש = толковать, объяснять. Раши — автор самого знаменитого פירוש к Торе."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (133, 2, 'fill_blank', 1, '{"hint": "Какой тип звука «х»?", "context": "Хет отличается от буквы Хей (ה) более глубоким произношением", "sentence_ru": "Буква ח (Хет) обозначает ___ гортанный звук «х»."}', '{"accept": ["гортанный", "глубокий гортанный"], "correct": "гортанный"}', '{"text": "Буква ח (Хет) произносится как глубокий гортанный «х», в отличие от ה (Хей), которая звучит как лёгкое придыхание."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (129, 76, 'match_pairs', 6, '{"pairs_left": ["אולם", "אבל", "בס", "לפיכך", "אז", "יאללה"], "pairs_right": ["однако (высокий)", "но (стандартный)", "но (сленг)", "поэтому (высокий)", "тогда / так (стандартный)", "давай / ну (сленг)"]}', '{"matches": {"אז": "тогда / так (стандартный)", "בס": "но (сленг)", "אבל": "но (стандартный)", "אולם": "однако (высокий)", "יאללה": "давай / ну (сленг)", "לפיכך": "поэтому (высокий)"}}', '{"text": "Регистр определяется выбором слов-связок:\n- Высокий: אולם, לפיכך, יתרה מזאת, אשר על כן\n- Стандартный: אבל, לכן, אז, בגלל ש-\n- Сленг: בס (от арабского بس), יאללה, סתם, כאילו\nУмение выбрать правильную связку — ключ к переключению регистра."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (123, 74, 'translate_ru_he', 6, '{"hint": "יש לציין כי + הסוגיה + מחייבת + עיון + מעמיק", "prompt_ru": "Следует отметить, что данный вопрос требует тщательного рассмотрения (высокий регистр)", "target_he": "יש לציין כי הסוגיה הנדונה מחייבת עיון מעמיק"}', '{"accept": ["יש לציין כי הסוגיה הנדונה מחייבת עיון מעמיק", "יש לציין כי הנושא הנדון מחייב עיון מעמיק", "ראוי לציין כי הסוגיה מחייבת עיון מעמיק"], "correct": "יש לציין כי הסוגיה הנדונה מחייבת עיון מעמיק"}', '{"text": "Маркеры высокого регистра в одном предложении:\n- יש לציין כי (следует отметить, что) — безличная конструкция\n- הסוגיה הנדונה (обсуждаемый вопрос) — причастие-определение\n- מחייבת עיון מעמיק (требует углублённого рассмотрения) — книжная лексика\nВ разговоре скажут: «שים לב שצריך לחשוב על זה טוב»"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (125, 75, 'dictation', 6, '{"hint": "Журналистское предложение: премьер-министр объявил о реформе (10 слов)", "word_he": "ראש הממשלה הודיע כי הרפורמה תיכנס לתוקף בתחילת השנה הבאה", "word_translit": "рОш hа-мемшалА hодИа ки hа-рефОрма тиканЕс ле-тОкеф бе-тхилАт hа-шанА hа-баА"}', '{"accept": ["ראש הממשלה הודיע כי הרפורמה תיכנס לתוקף בתחילת השנה הבאה", "ראש הממשלה הודיע כי הרפורמה תכנס לתוקף בתחילת השנה הבאה"], "correct": "ראש הממשלה הודיע כי הרפורמה תיכנס לתוקף בתחילת השנה הבאה"}', '{"text": "Журналистский стиль:\n- ראש הממשלה (премьер-министр) — смихут\n- הודיע כי (объявил, что) — כי вместо разговорного ש-\n- תיכנס לתוקף (вступит в силу) — юридический оборот\n- בתחילת השנה הבאה (в начале следующего года) — смихут + определение"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (126, 75, 'dictation', 6, '{"hint": "Юридическая формула: стороны договорились о порядке разрешения споров (10 слов)", "word_he": "מוסכם ומותנה בין הצדדים כי כל סכסוך ייושב בדרך של גישור", "word_translit": "мускАм у-мутнЕ бейн hа-цдадИм ки коль сихсУх йеушАв бе-дЕрех шель гишУр"}', '{"accept": ["מוסכם ומותנה בין הצדדים כי כל סכסוך ייושב בדרך של גישור", "מוסכם ומותנה בין הצדדים כי כל סכסוך יושב בדרך של גישור"], "correct": "מוסכם ומותנה בין הצדדים כי כל סכסוך ייושב בדרך של גישור"}', '{"text": "Юридическая формула:\n- מוסכם ומותנה (согласовано и обусловлено) — стандартная связка в договорах\n- בין הצדדים (между сторонами) — צדדים = стороны (юрид.)\n- סכסוך (спор / конфликт) — от арамейского корня\n- ייושב (будет разрешён) — пассив от י.ש.ב (в юрид. значении)\n- גישור (медиация) — от корня ג.ש.ר (мост → наведение мостов)"}', 35);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (127, 76, 'translate_ru_he', 6, '{"hint": "אף על פי ש... + סגנון + מזכיר + שירת ימי הביניים + תוכן + רלוונטי + גם היום", "prompt_ru": "Хотя его стиль напоминает средневековую поэзию, содержание актуально и сегодня", "target_he": "אף על פי שסגנונו מזכיר את שירת ימי הביניים, התוכן רלוונטי גם היום"}', '{"accept": ["אף על פי שסגנונו מזכיר את שירת ימי הביניים, התוכן רלוונטי גם היום", "אף על פי שהסגנון שלו מזכיר שירת ימי הביניים התוכן רלוונטי גם היום", "למרות שסגנונו מזכיר את שירת ימי הביניים התוכן רלוונטי גם היום"], "correct": "אף על פי שסגנונו מזכיר את שירת ימי הביניים, התוכן רלוונטי גם היום"}', '{"text": "Всё C2 в одном предложении:\n- אף על פי ש- (хотя) — уступительный союз высокого стиля\n- סגנונו (его стиль) — смихут с местоимённым суффиксом\n- שירת ימי הביניים (средневековая поэзия) — двойной смихут\n- רלוונטי (актуальный) — заимствование, прижившееся в стандартном иврите"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (128, 76, 'word_order', 6, '{"translation": "Время доказало, что нет ничего нового под солнцем", "words_shuffled": ["שאין", "הוכיח", "הזמן", "תחת", "חדש", "השמש"], "correct_sentence": "הזמן הוכיח שאין חדש תחת השמש"}', '{"correct_order": ["הזמן", "הוכיח", "שאין", "חדש", "תחת", "השמש"]}', '{"text": "Библейская цитата (Коhелет 1:9) в современном обрамлении. הזמן הוכיח (время доказало) — стандартный иврит. אין חדש תחת השמש — библейская формула. Такое смешение — норма для образованного иврита: древнее и современное сплетаются в одном предложении."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (132, 2, 'match_pairs', 1, '{"pairs_left": ["ו", "ז", "ח", "ט", "י"], "pairs_right": ["Йуд", "Тет", "Хет", "Зайин", "Вав"]}', '{"matches": {"ו": "Вав", "ז": "Зайин", "ח": "Хет", "ט": "Тет", "י": "Йуд"}}', '{"text": "ו — Вав (6), ז — Зайин (7), ח — Хет (8), ט — Тет (9), י — Йуд (10). Числовые значения букв идут последовательно."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (136, 3, 'match_pairs', 1, '{"pairs_left": ["כ", "ל", "מ", "נ", "ס"], "pairs_right": ["Самех", "Нун", "Мем", "Ламед", "Каф"]}', '{"matches": {"כ": "Каф", "ל": "Ламед", "מ": "Мем", "נ": "Нун", "ס": "Самех"}}', '{"text": "כ — Каф (20), ל — Ламед (30), מ — Мем (40), נ — Нун (50), ס — Самех (60). В скобках — числовые значения."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (137, 3, 'fill_blank', 1, '{"hint": "Согласный звук, как в слове «лампа»", "context": "Ламед — единственная буква ивритского алфавита, выступающая над строкой", "sentence_ru": "Буква ל (Ламед) обозначает звук ___."}', '{"accept": ["л", "Л"], "correct": "л"}', '{"text": "Буква ל (Ламед) обозначает звук «л». Её числовое значение — 30. Ламед — самая высокая буква в ивритском алфавите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (139, 3, 'word_order', 2, '{"translation": "Расставьте буквы Каф–Самех в алфавитном порядке", "words_shuffled": ["ס", "נ", "מ", "ל", "כ"], "correct_sentence": "כ ל מ נ ס"}', '{"correct_order": ["כ", "ל", "מ", "נ", "ס"]}', '{"text": "Алфавитный порядок: כ (Каф, 11-я), ל (Ламед, 12-я), מ (Мем, 13-я), נ (Нун, 14-я), ס (Самех, 15-я)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (141, 4, 'match_pairs', 1, '{"pairs_left": ["ע", "פ", "צ", "ק", "ר"], "pairs_right": ["Реш", "Куф", "Цади", "Пей", "Айин"]}', '{"matches": {"ע": "Айин", "פ": "Пей", "צ": "Цади", "ק": "Куф", "ר": "Реш"}}', '{"text": "ע — Айин (70), פ — Пей (80), צ — Цади (90), ק — Куф (100), ר — Реш (200). Шин (ש, 300) изучается отдельно."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (143, 4, 'fill_blank', 2, '{"hint": "Звук, как в русском слове «цапля»", "context": "Цади — одна из букв, имеющих конечную форму (софит)", "sentence_ru": "В слове צִפּוֹר (ципОр — «птица») буква צ обозначает звук ___."}', '{"accept": ["ц", "Ц", "tz", "ts"], "correct": "ц"}', '{"text": "Буква צ (Цади) обозначает звук «ц». В конце слова она принимает форму ץ (Цади-софит)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (146, 5, 'match_pairs', 1, '{"pairs_left": ["כ", "מ", "נ", "פ", "צ"], "pairs_right": ["ץ", "ף", "ן", "ם", "ך"]}', '{"matches": {"כ": "ך", "מ": "ם", "נ": "ן", "פ": "ף", "צ": "ץ"}}', '{"text": "Конечные формы (софиёт): כ→ך (Каф-софит), מ→ם (Мем-софит), נ→ן (Нун-софит), פ→ף (Пей-софит), צ→ץ (Цади-софит)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (147, 5, 'fill_blank', 1, '{"hint": "Такой же звук, как у буквы ט (Тет)", "context": "Тав — последняя буква ивритского алфавита", "sentence_ru": "Буква ת (Тав) обозначает звук ___."}', '{"accept": ["т", "Т", "t"], "correct": "т"}', '{"text": "Буква ת (Тав) обозначает звук «т». Она является последней (22-й) буквой алфавита. Её числовое значение — 400."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (149, 5, 'word_order', 2, '{"translation": "Расставьте конечные формы букв в алфавитном порядке (по основной букве)", "words_shuffled": ["ף", "ך", "ץ", "ם", "ן"], "correct_sentence": "ך ם ן ף ץ"}', '{"correct_order": ["ך", "ם", "ן", "ף", "ץ"]}', '{"text": "По порядку основных букв: ך (Каф, 11-я), ם (Мем, 13-я), ן (Нун, 14-я), ף (Пей, 17-я), ץ (Цади, 18-я)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (151, 10, 'fill_blank', 1, '{"hint": "Слитный предлог, означающий «в»", "context": "Нужен предлог «в» (внутри города)", "sentence_ru": "אֲנִי גָּר ___ תֵּל אָבִיב (Я живу ___ Тель-Авиве)"}', '{"accept": ["בְּ", "ב", "בּ", "בְ"], "correct": "בְּ"}', '{"text": "Предлог בְּ (бэ-) означает «в». Полная фраза: אֲנִי גָּר בְּתֵּל אָבִיב (ани гар бэ-Тель-Авив) — «Я живу в Тель-Авиве»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (152, 10, 'match_pairs', 2, '{"pairs_left": ["בְּ", "לְ", "מִ", "עַל", "עִם"], "pairs_right": ["с (совместно)", "на / над", "из / от", "для / к", "в / внутри"]}', '{"matches": {"לְ": "для / к", "מִ": "из / от", "בְּ": "в / внутри", "עִם": "с (совместно)", "עַל": "на / над"}}', '{"text": "Основные предлоги: בְּ (в), לְ (к/для), מִ (из/от), עַל (на/над), עִם (с). Первые три — слитные (пишутся вместе со словом)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (153, 10, 'word_order', 2, '{"translation": "Книга на столе", "words_shuffled": ["הַסֵּפֶר", "עַל", "הַשֻּׁלְחָן"], "correct_sentence": "הַסֵּפֶר עַל הַשֻּׁלְחָן"}', '{"correct_order": ["הַסֵּפֶר", "עַל", "הַשֻּׁלְחָן"]}', '{"text": "הַסֵּפֶר עַל הַשֻּׁלְחָן (ха-сЕфер аль ха-шульхАн) — «Книга на столе». Предлог עַל (аль) означает «на» / «над»."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (154, 10, 'fill_blank', 2, '{"hint": "Слитный предлог, означающий «из» или «от»", "context": "Нужен предлог, означающий «из»", "sentence_ru": "הוּא בָּא ___ הָעִיר (Он приехал ___ города)"}', '{"accept": ["מֵ", "מִ", "מ", "מֵהָ"], "correct": "מֵ"}', '{"text": "Предлог מִ (ми-) означает «из» / «от». Перед определённым артиклем הַ он сливается: מִן + הַ → מֵהָ. Полная фраза: הוּא בָּא מֵהָעִיר (ху ба мэ-ха-ир) — «Он приехал из города»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (156, 15, 'fill_blank', 1, '{"hint": "Слово «ученик» на иврите", "context": "Ученик представляется в ульпане", "sentence_ru": "שָׁלוֹם, אֲנִי ___ חָדָשׁ (Привет, я новый ___)"}', '{"accept": ["תַּלְמִיד", "תלמיד"], "correct": "תַּלְמִיד"}', '{"text": "תַּלְמִיד (талмИд) — ученик. Женская форма — תַּלְמִידָה (талмидА). В ульпане ученики называются תַּלְמִידֵי אוּלְפָּן."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (257, 29, 'translate_ru_he', 3, '{"hints": ["לדעת", "לעבוד"], "text_ru": "Я знаю, что он работает здесь"}', '{"correct": "אני יודע שהוא עובד פה", "alternatives": ["אני יודע שהוא עובד כאן"]}', '{"text": "ש связывает главное и придаточное предложения"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (157, 15, 'word_order', 2, '{"translation": "Я учу иврит в ульпане", "words_shuffled": ["בָּאוּלְפָּן", "עִבְרִית", "אֲנִי", "לוֹמֵד"], "correct_sentence": "אֲנִי לוֹמֵד עִבְרִית בָּאוּלְפָּן"}', '{"correct_order": ["אֲנִי", "לוֹמֵד", "עִבְרִית", "בָּאוּלְפָּן"]}', '{"text": "אֲנִי לוֹמֵד עִבְרִית בָּאוּלְפָּן (ани ломЕд иврИт ба-ульпАн) — «Я учу иврит в ульпане». Порядок: подлежащее — сказуемое — дополнение — обстоятельство."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (158, 15, 'match_pairs', 2, '{"pairs_left": ["מוֹרָה", "תַּלְמִיד", "כִּתָּה", "סֵפֶר", "שִׁעוּר"], "pairs_right": ["урок", "книга", "класс", "ученик", "учительница"]}', '{"matches": {"סֵפֶר": "книга", "מוֹרָה": "учительница", "כִּתָּה": "класс", "שִׁעוּר": "урок", "תַּלְמִיד": "ученик"}}', '{"text": "Слова, связанные с ульпаном: מוֹרָה (морА) — учительница, תַּלְמִיד (талмИд) — ученик, כִּתָּה (китА) — класс, סֵפֶר (сЕфер) — книга, שִׁעוּר (шиУр) — урок."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (161, 13, 'fill_blank', 2, '{"hint": "Прошедшее время, 3-е лицо ж.р. ед.ч.", "context": "Глагол «читать» — לִקְרוֹא, корень ק.ר.א", "sentence_ru": "הִיא ___ סֵפֶר (Она читала книгу)"}', '{"accept": ["קָרְאָה", "קראה"], "correct": "קָרְאָה"}', '{"text": "קָרְאָה (карА) — «она читала». В 3-м лице ж.р. ед.ч. прошедшего времени к основе добавляется окончание ָ-ה. Корень: ק.ר.א."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (162, 13, 'match_pairs', 2, '{"pairs_left": ["כָּתַבְתִּי", "כָּתַבְתָּ", "כָּתַב", "כָּתְבָה", "כָּתַבְנוּ"], "pairs_right": ["мы написали", "она написала", "он написал", "ты (м.) написал", "я написал(а)"]}', '{"matches": {"כָּתַב": "он написал", "כָּתְבָה": "она написала", "כָּתַבְנוּ": "мы написали", "כָּתַבְתָּ": "ты (м.) написал", "כָּתַבְתִּי": "я написал(а)"}}', '{"text": "Спряжение глагола כָּתַב (писать) в прошедшем времени: -תִּי (я), -תָּ (ты м.), -תְּ (ты ж.), без суффикса (он), ָ-ה (она), -נוּ (мы), -תֶּם (вы м.), -תֶּן (вы ж.), -וּ (они)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (163, 13, 'word_order', 2, '{"translation": "Вчера мы учили иврит", "words_shuffled": ["אֶתְמוֹל", "לָמַדְנוּ", "עִבְרִית", "אֲנַחְנוּ"], "correct_sentence": "אֶתְמוֹל אֲנַחְנוּ לָמַדְנוּ עִבְרִית"}', '{"correct_order": ["אֶתְמוֹל", "אֲנַחְנוּ", "לָמַדְנוּ", "עִבְרִית"]}', '{"text": "אֶתְמוֹל אֲנַחְנוּ לָמַדְנוּ עִבְרִית (этмОль анАхну ламАдну иврИт) — «Вчера мы учили иврит». Наречие времени часто стоит в начале предложения."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (166, 14, 'fill_blank', 2, '{"hint": "Будущее время, 1-е лицо ед.ч. — префикс אֶ-", "context": "Глагол «учить» — לִלְמוֹד, корень ל.מ.ד, биньян паАль", "sentence_ru": "אֲנִי ___ עִבְרִית מָחָר (Я буду учить иврит завтра)"}', '{"accept": ["אֶלְמַד", "אלמד"], "correct": "אֶלְמַד"}', '{"text": "אֶלְמַד (эльмАд) — «я буду учить». Форма 1-го лица ед.ч. будущего времени в биньяне паАль: префикс אֶ- + корень ל.מ.ד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (167, 14, 'match_pairs', 2, '{"pairs_left": ["אֶכְתּוֹב", "תִּכְתּוֹב", "יִכְתּוֹב", "נִכְתּוֹב", "יִכְתְּבוּ"], "pairs_right": ["они напишут", "мы напишем", "он напишет", "ты (м.) напишешь", "я напишу"]}', '{"matches": {"אֶכְתּוֹב": "я напишу", "יִכְתּוֹב": "он напишет", "נִכְתּוֹב": "мы напишем", "יִכְתְּבוּ": "они напишут", "תִּכְתּוֹב": "ты (м.) напишешь"}}', '{"text": "Спряжение глагола כָּתַב (писать) в будущем времени. Префиксы: אֶ- (я), תִּ- (ты м. / она), יִ- (он / они), נִ- (мы). Суффикс וּ- для мн.ч."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (191, 32, 'fill_blank', 2, '{"hint": "מ.מ.ח", "context": "Вставьте слово «эксперты»", "sentence_ru": "הפרופסורים שלנו _____ בתחומם (эксперты в своих областях)"}', '{"accept": ["מומחים", "מוּמְחִים"], "correct": "מומחים"}', '{"text": "מוּמְחִים (мумхИм) — эксперты, специалисты. Единственное число: מוּמְחֶה (мумхЕ)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (168, 14, 'word_order', 2, '{"translation": "Завтра мы поедем в Иерусалим", "words_shuffled": ["נִסַּע", "מָחָר", "לִירוּשָׁלַיִם", "אֲנַחְנוּ"], "correct_sentence": "מָחָר אֲנַחְנוּ נִסַּע לִירוּשָׁלַיִם"}', '{"correct_order": ["מָחָר", "אֲנַחְנוּ", "נִסַּע", "לִירוּשָׁלַיִם"]}', '{"text": "מָחָר אֲנַחְנוּ נִסַּע לִירוּשָׁלַיִם (махАр анАхну нисА ле-ерушалАим) — «Завтра мы поедем в Иерусалим». Глагол נִסַּע — будущее время от לִנְסוֹעַ (ехать), 1-е лицо мн.ч."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (171, 16, 'match_pairs', 2, '{"pairs_left": ["לֶחֶם", "חָלָב", "גְּבִינָה", "פֵּרוֹת", "יְרָקוֹת"], "pairs_right": ["овощи", "фрукты", "сыр", "молоко", "хлеб"]}', '{"matches": {"חָלָב": "молоко", "לֶחֶם": "хлеб", "פֵּרוֹת": "фрукты", "יְרָקוֹת": "овощи", "גְּבִינָה": "сыр"}}', '{"text": "Продукты: לֶחֶם (лЕхем) — хлеб, חָלָב (халАв) — молоко, גְּבִינָה (гвинА) — сыр, פֵּרוֹת (перОт) — фрукты, יְרָקוֹת (еракОт) — овощи."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (172, 16, 'fill_blank', 2, '{"hint": "Слово «литр» на иврите", "context": "Покупатель просит определённое количество в магазине", "sentence_ru": "אֲנִי רוֹצֶה ___ חָלָב, בְּבַקָּשָׁה (Я хочу ___ молока, пожалуйста)"}', '{"accept": ["לִיטֶר", "ליטר"], "correct": "לִיטֶר"}', '{"text": "לִיטֶר (лИтер) — «литр». Полная фраза: אֲנִי רוֹצֶה לִיטֶר חָלָב, בְּבַקָּשָׁה (ани роцЕ лИтер халАв, бевакашА) — «Я хочу литр молока, пожалуйста»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (173, 16, 'word_order', 2, '{"translation": "Дай мне хлеб, пожалуйста", "words_shuffled": ["בְּבַקָּשָׁה", "לֶחֶם", "לִי", "תֵּן"], "correct_sentence": "תֵּן לִי לֶחֶם בְּבַקָּשָׁה"}', '{"correct_order": ["תֵּן", "לִי", "לֶחֶם", "בְּבַקָּשָׁה"]}', '{"text": "תֵּן לִי לֶחֶם בְּבַקָּשָׁה (тэн ли лЕхем бевакашА) — «Дай мне хлеб, пожалуйста». תֵּן — повелительное наклонение от לָתֵת (давать), לִי — «мне»."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (175, 17, 'match_pairs', 2, '{"pairs_left": ["אָב", "אֵם", "אָח", "אָחוֹת", "סָבָא"], "pairs_right": ["дедушка", "сестра", "брат", "мама", "папа"]}', '{"matches": {"אֵם": "мама", "אָב": "папа", "אָח": "брат", "סָבָא": "дедушка", "אָחוֹת": "сестра"}}', '{"text": "Семья (מִשְׁפָּחָה): אָב (ав) — отец, אֵם (эм) — мать, אָח (ах) — брат, אָחוֹת (ахОт) — сестра, סָבָא (сАба) — дедушка. Также: סָבְתָא (сАвта) — бабушка."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (176, 17, 'fill_blank', 2, '{"hint": "Множественное число от אָח (брат)", "context": "Рассказ о членах семьи", "sentence_ru": "יֵשׁ לִי שְׁנֵי ___ וְאָחוֹת אַחַת (У меня два ___ и одна сестра)"}', '{"accept": ["אַחִים", "אחים"], "correct": "אַחִים"}', '{"text": "אַחִים (ахИм) — «братья», множественное число от אָח (ах — брат). Обратите внимание на неправильное образование множественного числа (не אָחִים)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (178, 17, 'word_order', 2, '{"translation": "Моя семья большая", "words_shuffled": ["גְּדוֹלָה", "הַמִּשְׁפָּחָה", "שֶׁלִּי"], "correct_sentence": "הַמִּשְׁפָּחָה שֶׁלִּי גְּדוֹלָה"}', '{"correct_order": ["הַמִּשְׁפָּחָה", "שֶׁלִּי", "גְּדוֹלָה"]}', '{"text": "הַמִּשְׁפָּחָה שֶׁלִּי גְּדוֹלָה (ха-мишпахА шелИ гдолА) — «Моя семья большая». Порядок: определённое существительное + притяжательное + прилагательное."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (180, 26, 'word_order', 2, '{"translation": "Привет, меня зовут Давид", "words_shuffled": ["שְׁמִי", "שָׁלוֹם", "דָּוִד"], "correct_sentence": "שָׁלוֹם שְׁמִי דָּוִד"}', '{"correct_order": ["שָׁלוֹם", "שְׁמִי", "דָּוִד"]}', '{"text": "שָׁלוֹם שְׁמִי דָּוִד (шалОм шмИ давИд) — «Привет, меня зовут Давид». שְׁמִי (шмИ) — «моё имя» (שֵׁם + суффикс י-)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (181, 26, 'fill_blank', 2, '{"hint": "Новый репатриант (м.р.)", "context": "Первые фразы в письме о себе. Нужно слово, подходящее для мужчины, репатриировавшегося в Израиль.", "sentence_ru": "אֲנִי ___ מֵרוּסְיָה (Я ___ из России)"}', '{"accept": ["עוֹלֶה חָדָשׁ", "עולה חדש", "עולה"], "correct": "עוֹלֶה חָדָשׁ"}', '{"text": "עוֹלֶה חָדָשׁ (олЕ хадАш) — «новый репатриант» (м.р.). Женская форма — עוֹלָה חֲדָשָׁה (олА хадашА). Слово עוֹלֶה буквально означает «поднимающийся» (алия — «восхождение» в Израиль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (183, 26, 'match_pairs', 2, '{"pairs_left": ["רִאשִׁית", "שְׁנִית", "לְבַסּוֹף", "אֲבָל", "לְכֵן"], "pairs_right": ["поэтому", "но", "в конце концов", "во-вторых", "во-первых"]}', '{"matches": {"אֲבָל": "но", "לְכֵן": "поэтому", "שְׁנִית": "во-вторых", "רִאשִׁית": "во-первых", "לְבַסּוֹף": "в конце концов"}}', '{"text": "Слова-связки для письма: רִאשִׁית (ришИт) — во-первых, שְׁנִית (шенИт) — во-вторых, לְבַסּוֹף (лэвасОф) — в конце концов, אֲבָל (авАль) — но, לְכֵן (лахЕн) — поэтому."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (184, 26, 'word_order', 3, '{"translation": "Я живу и работаю в Иерусалиме", "words_shuffled": ["בִּירוּשָׁלַיִם", "אֲנִי", "וְעוֹבֵד", "גָּר"], "correct_sentence": "אֲנִי גָּר וְעוֹבֵד בִּירוּשָׁלַיִם"}', '{"correct_order": ["אֲנִי", "גָּר", "וְעוֹבֵד", "בִּירוּשָׁלַיִם"]}', '{"text": "אֲנִי גָּר וְעוֹבֵד בִּירוּשָׁלַיִם (ани гар вэ-овЕд би-ерушалАим) — «Я живу и работаю в Иерусалиме». Союз וְ (вэ-) — «и», пишется слитно со следующим словом."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (186, 31, 'fill_blank', 2, '{"hint": "ט.י.ל", "context": "Вставьте подходящее слово: путешествие", "sentence_ru": "בקיץ האחרון נסעתי ל_____ בצפון הארץ (путешествие по северу страны)"}', '{"accept": ["טיול", "טִיוּל"], "correct": "טיול"}', '{"text": "טיול (тиУль) — путешествие, поездка. Корень ט.י.ל."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (187, 31, 'match_pairs', 2, '{"pairs_left": ["טבריה", "צפת", "רמת הגולן"], "pairs_right": ["עיר על שפת הכינרת", "עיר עתיקה על הר גבוה", "נופים מדהימים וכרמי יין"]}', '{"matches": {"צפת": "עיר עתיקה על הר גבוה", "טבריה": "עיר על שפת הכינרת", "רמת הגולן": "נופים מדהימים וכרמי יין"}}', '{"text": "Тверия — город на берегу Кинерета, Цфат — древний город на горе, Голанские высоты — пейзажи и виноградники."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (193, 32, 'match_pairs', 2, '{"pairs_left": ["הרצאות", "מעונות", "פרויקט קבוצתי", "עבודת צוות", "שותפה"], "pairs_right": ["лекции", "общежития", "групповой проект", "командная работа", "соседка"]}', '{"matches": {"שותפה": "соседка", "הרצאות": "лекции", "מעונות": "общежития", "עבודת צוות": "командная работа", "פרויקט קבוצתי": "групповой проект"}}', '{"text": "Ключевая лексика студенческой жизни: הרצאות (лекции), מעונות (общежития), פרויקט קבוצתי (групповой проект)."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (196, 38, 'fill_blank', 3, '{"hint": "ח.ד.ש", "context": "Вставьте слово «инновации»", "sentence_ru": "התרבות הישראלית מעודדת _____ וחוצפה (инновации и дерзость)"}', '{"accept": ["חדשנות", "חַדְשָׁנוּת"], "correct": "חדשנות"}', '{"text": "חַדְשָׁנוּת (хадшанУт) — инновации, новаторство. От корня ח.ד.ש (новый). Суффикс -וּת образует абстрактные существительные."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (197, 38, 'match_pairs', 3, '{"pairs_left": ["סטארט-אפ", "חדשנות", "מחקר ופיתוח", "נרכשות", "חוצפה"], "pairs_right": ["стартап", "инновации", "исследования и разработки", "приобретаются", "дерзость"]}', '{"matches": {"חוצפה": "дерзость", "חדשנות": "инновации", "נרכשות": "приобретаются", "סטארט-אפ": "стартап", "מחקר ופיתוח": "исследования и разработки"}}', '{"text": "Экономическая лексика B2: חדשנות (инновации), מחקר ופיתוח (R&D), נרכשות (приобретаются — биньян нифъаль)."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (201, 39, 'fill_blank', 3, '{"hint": "ע.ת.ר", "context": "Вставьте слово «петиции»", "sentence_ru": "בית המשפט העליון דן ב_____ נגד החלטות ממשלתיות (петиции против правительственных решений)"}', '{"accept": ["עתירות", "עֲתִירוֹת"], "correct": "עתירות"}', '{"text": "עֲתִירוֹת (атирОт) — петиции, обращения в суд. Единственное число: עֲתִירָה (атирА). Корень ע.ת.ר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (202, 39, 'match_pairs', 3, '{"pairs_left": ["בית המשפט העליון", "בתי המשפט המחוזיים", "בית משפט השלום", "שופט", "עתירה"], "pairs_right": ["Верховный суд", "окружные суды", "мировой суд", "судья", "петиция"]}', '{"matches": {"שופט": "судья", "עתירה": "петиция", "בית משפט השלום": "мировой суд", "בית המשפט העליון": "Верховный суд", "בתי המשפט המחוזיים": "окружные суды"}}', '{"text": "Три уровня судов: בית המשפט העליון (Верховный), מחוזיים (окружные), השלום (мировой). שופט — судья, עתירה — петиция."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (206, 43, 'fill_blank', 5, '{"hint": "ל + תאר", "context": "Глагол в инфинитиве, означающий «описать / изобразить»", "sentence_ru": "הסופר הצליח ___ את רגשות הדמויות בצורה מעמיקה ומורכבת"}', '{"accept": ["לתאר", "לְתָאֵר"], "correct": "לתאר"}', '{"text": "לתאר = описывать, изображать. Корень ת-א-ר, биньян Пиэль. В литературной критике часто говорят: «הסופר מתאר את המציאות» — писатель описывает реальность."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (207, 43, 'match_pairs', 5, '{"pairs_left": ["עלילה", "דמות", "עלילה משנית", "מספר", "רקע"], "pairs_right": ["сюжет", "персонаж", "побочная линия", "рассказчик", "фон / контекст"]}', '{"matches": {"רקע": "фон / контекст", "דמות": "персонаж", "מספר": "рассказчик", "עלילה": "сюжет", "עלילה משנית": "побочная линия"}}', '{"text": "Литературоведческая терминология на иврите: עלילה (алилА) = сюжет, דמות (дмУт) = персонаж, מספר (месапЕр) = рассказчик, רקע (рЕка) = фон. Эти термины необходимы для анализа любого литературного произведения."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (250, 27, 'fill_blank', 3, '{"hint": "выйдем (будущее, мн.ч.)", "sentence": "אם _ מוקדם, נספיק להגיע"}', '{"correct": "נצא", "alternatives": []}', '{"text": "נצא (нецЭ) — мы выйдем, будущее от לצאת"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (208, 43, 'word_order', 5, '{"translation": "Современная ивритская литература отражает сложность израильского общества", "words_shuffled": ["המודרנית", "הספרות", "משקפת", "העברית", "את", "של", "מורכבותה", "החברה", "הישראלית"], "correct_sentence": "הספרות העברית המודרנית משקפת את מורכבותה של החברה הישראלית"}', '{"correct_order": ["הספרות", "העברית", "המודרנית", "משקפת", "את", "מורכבותה", "של", "החברה", "הישראלית"]}', '{"text": "Сложная именная группа: הספרות העברית המודרנית — существительное + два согласованных прилагательных. מורכבותה של החברה — смихут с суффиксом: «её сложность» + של + «общество». Это типичная конструкция академического иврита."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (210, 44, 'fill_blank', 5, '{"hint": "на + основе / посредством", "context": "Предлог, означающий «посредством / благодаря»", "sentence_ru": "החיים בישראל מאופיינים ___ מגוון תרבותי עשיר ומורכב"}', '{"accept": ["על ידי", "ע\"י", "באמצעות"], "correct": "על ידי"}', '{"text": "על ידי (аль йедЕй) = посредством, благодаря, при помощи. В академическом письме также используют באמצעות (бе-эмцаУт). Обе формы подходят для эссе уровня C1."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (211, 44, 'word_order', 5, '{"translation": "Подводя итог, можно сказать, что жизнь в Израиле предлагает уникальный вызов", "words_shuffled": ["לסכם", "ניתן", "כי", "לומר", "בישראל", "החיים", "מציעים", "ייחודי", "אתגר"], "correct_sentence": "לסכם, ניתן לומר כי החיים בישראל מציעים אתגר ייחודי"}', '{"correct_order": ["לסכם", "ניתן", "לומר", "כי", "החיים", "בישראל", "מציעים", "אתגר", "ייחודי"]}', '{"text": "Структура заключительного абзаца эссе: לסכם (подводя итог) + ניתן לומר כי (можно сказать, что) — безличная конструкция высокого стиля. В эссе уровня C1 заключение обобщает аргументы и предлагает вывод."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (213, 44, 'match_pairs', 5, '{"pairs_left": ["טענה", "נימוק", "דוגמה", "מסקנה", "סתירה"], "pairs_right": ["тезис / утверждение", "аргумент / довод", "пример", "вывод", "противоречие"]}', '{"matches": {"טענה": "тезис / утверждение", "דוגמה": "пример", "מסקנה": "вывод", "נימוק": "аргумент / довод", "סתירה": "противоречие"}}', '{"text": "Ключевые слова академического эссе: טענה (таанА) = тезис, נימוק (нимУк) = аргумент, דוגמה (дугмА) = пример, מסקנה (маскенА) = вывод, סתירה (стирА) = противоречие. Без них невозможно написать грамотное эссе."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (214, 44, 'fill_blank', 5, '{"hint": "למרות + ש...", "context": "Уступительный союз «несмотря на то что»", "sentence_ru": "___ שהחיים בישראל מורכבים, הם מלאים בהזדמנויות צמיחה"}', '{"accept": ["למרות", "על אף", "חרף העובדה"], "correct": "למרות"}', '{"text": "למרות ש- (ламрОт ше-) = несмотря на то что. Высокий стиль: על אף ש- (аль аф ше-), חרף העובדה ש- (хараф hа-увдА ше-). Уступительные конструкции необходимы для построения контраргумента в эссе."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (216, 47, 'fill_blank', 6, '{"hint": "נ-ת-נ-ים", "context": "Существительное мн.ч. — «данные / сведения»", "sentence_ru": "על פי ___ שפורסמו אתמול, שיעור האבטלה ירד לרמה חסרת תקדים"}', '{"accept": ["נתונים", "הנתונים"], "correct": "נתונים"}', '{"text": "נתונים (нетунИм) = данные / сведения. על פי נתונים שפורסמו = согласно опубликованным данным. Типичная конструкция газетного стиля. שיעור האבטלה (шиУр hа-автлА) = уровень безработицы — ещё одно газетное клише."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (217, 47, 'match_pairs', 6, '{"pairs_left": ["כותרת", "כתב", "פרשנות", "מערכת", "פרסום"], "pairs_right": ["заголовок", "корреспондент", "комментарий / аналитика", "редакция", "публикация"]}', '{"matches": {"כתב": "корреспондент", "כותרת": "заголовок", "מערכת": "редакция", "פרסום": "публикация", "פרשנות": "комментарий / аналитика"}}', '{"text": "Лексика СМИ на иврите: כותרת (котЕрет) = заголовок, כתב (катАв) = корреспондент, פרשנות (паршанУт) = комментарий / аналитика, מערכת (маарЕхет) = редакция, פרסום (пирсУм) = публикация."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (219, 47, 'fill_blank', 6, '{"hint": "ממליץ", "context": "Глагол «рекомендует» в м.р. ед.ч., настоящее время", "sentence_ru": "הדו\"ח ___ כי יש צורך ברפורמה מקיפה במערכת החינוך"}', '{"accept": ["ממליץ", "מַמְלִיץ"], "correct": "ממליץ"}', '{"text": "ממליץ (мамлИц) = рекомендует. Корень מ-ל-צ, биньян Хифъиль. דו\"ח ממליץ = отчёт рекомендует — стандартная формулировка в прессе и официальных документах. רפורמה מקיפה (рефОрма макИфа) = всеобъемлющая реформа."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (221, 48, 'fill_blank', 6, '{"hint": "ש-א-פ, биньян Пааль", "context": "Глагол «стремится / ставит целью» в м.р. ед.ч.", "sentence_ru": "מחקר זה ___ לבחון את השפעת הרשתות החברתיות על השיח הציבורי"}', '{"accept": ["שואף", "שׁוֹאֵף", "מבקש"], "correct": "שואף"}', '{"text": "שואף (шоЭф) = стремится. מחקר זה שואף לבחון = данное исследование стремится изучить. Альтернативы: מבקש לבדוק (стремится проверить), מטרתו לנתח (его цель — проанализировать). Все формы типичны для введения академической работы."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (222, 48, 'match_pairs', 6, '{"pairs_left": ["השערה", "מתודולוגיה", "ממצאים", "ביבליוגרפיה", "ציטוט"], "pairs_right": ["гипотеза", "методология", "результаты / находки", "библиография", "цитата"]}', '{"matches": {"השערה": "гипотеза", "ציטוט": "цитата", "ממצאים": "результаты / находки", "מתודולוגיה": "методология", "ביבליוגרפיה": "библиография"}}', '{"text": "Академическая терминология: השערה (hашаарА) = гипотеза, מתודולוגיה (методолОгия) = методология, ממצאים (мимцаИм) = результаты / находки, ביבליוגרפיה (библиогрАфия) = библиография, ציטוט (цитУт) = цитата."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (223, 48, 'word_order', 6, '{"translation": "Из результатов следует, что между переменными существует значимая связь", "words_shuffled": ["מן", "עולה", "כי", "הממצאים", "קיים", "מובהק", "בין", "קשר", "המשתנים"], "correct_sentence": "מן הממצאים עולה כי קיים קשר מובהק בין המשתנים"}', '{"correct_order": ["מן", "הממצאים", "עולה", "כי", "קיים", "קשר", "מובהק", "בין", "המשתנים"]}', '{"text": "Формулировка результатов исследования: מן הממצאים עולה כי (из результатов следует, что) — инверсия (עולה перед подлежащим). קשר מובהק (кЕшер мувhАк) = значимая / статистически достоверная связь. Это стандартный язык научных публикаций на иврите."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (224, 48, 'fill_blank', 6, '{"hint": "לציין", "context": "Инфинитив «отметить / упомянуть» в конструкции יש + ל-", "sentence_ru": "יש ___ את מגבלות המחקר, ובראשן גודל המדגם המצומצם"}', '{"accept": ["לציין", "לְצַיֵּן"], "correct": "לציין"}', '{"text": "יש לציין (йеш лецайЕн) = следует отметить — безличная конструкция академического стиля. מגבלות המחקר (магбалОт hа-мехкАр) = ограничения исследования — обязательный раздел в любой научной работе. מדגם (мидгАм) = выборка, מצומצם (мецумцАм) = ограниченный."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (227, 6, 'fill_blank', 1, '{"hint": "название", "sentence": "Огласовка «_» (три точки) обозначает звук «э»"}', '{"correct": "сеголь", "alternatives": ["сегол"]}', '{"text": "Сеголь (סֶ) — три точки треугольником под буквой, звук «э»"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (229, 7, 'fill_blank', 1, '{"hint": "определённый артикль + мальчик", "sentence": "_ ילד הולך לבית הספר"}', '{"correct": "הילד", "alternatives": []}', '{"text": "הילד (ха-йЕлед) — мальчик с определённым артиклем"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (230, 7, 'translate_ru_he', 1, '{"hints": ["ספר", "שולחן"], "text_ru": "Книга на столе"}', '{"correct": "הספר על השולחן", "alternatives": []}', '{"text": "Оба существительных с артиклем ה, так как речь о конкретных предметах"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (232, 8, 'fill_blank', 1, '{"hint": "мальчик", "sentence": "ילדים — это множественное число от _"}', '{"correct": "ילד", "alternatives": []}', '{"text": "ילד (йЕлед) → ילדים (еладИм): окончание ים- для мужского рода мн.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (314, 61, 'fill_blank', 4, '{"hint": "знает (идиома)", "sentence": "הוא תמיד יודע מה לעשות — הוא _ את השטח"}', '{"correct": "מכיר", "alternatives": []}', '{"text": "מכיר את השטח — ориентируется в ситуации"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (236, 9, 'fill_blank', 1, '{"hint": "она", "sentence": "_ לומדת עברית"}', '{"correct": "היא", "alternatives": []}', '{"text": "היא (hи) — она. Глагол לומדת в женском роде согласуется с местоимением"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (237, 9, 'translate_ru_he', 1, '{"hints": ["אנחנו", "בית ספר"], "text_ru": "Мы учимся в школе"}', '{"correct": "אנחנו לומדים בבית הספר", "alternatives": []}', '{"text": "אנחנו (анАхну) — мы, לומדים — учимся (м.р. или смешанная группа)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (238, 20, 'dictation', 1, '{"hint": "Приветствие", "audio_text": "שלום, מה שלומך?"}', '{"correct": "שלום, מה שלומך?"}', '{"text": "שלום מה שלומך — Привет, как дела?"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (239, 20, 'dictation', 1, '{"hint": "Где ты живёшь?", "audio_text": "אני גר בתל אביב"}', '{"correct": "אני גר בתל אביב"}', '{"text": "אני גר בתל אביב — Я живу в Тель-Авиве"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (244, 12, 'fill_blank', 2, '{"hint": "пассив пиэля", "sentence": "Биньян _ является пассивной формой Пиэля"}', '{"correct": "пуаль", "alternatives": ["Пуаль"]}', '{"text": "Пуаль (פועל) — пассивная пара биньяна Пиэль"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (247, 22, 'dictation', 2, '{"hint": "Животное", "audio_text": "סוס"}', '{"correct": "סוס"}', '{"text": "סוס (сус) — лошадь, с гласной «у»"}', 15);
