INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (249, 25, 'translate_ru_he', 2, '{"hints": ["לקרוא", "ספר"], "text_ru": "Она будет читать книгу"}', '{"correct": "היא תקרא ספר", "alternatives": ["היא תקרא את הספר"]}', '{"text": "תקרא — будущее время от לקרוא, 3-е лицо ж.р."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (251, 27, 'translate_ru_he', 3, '{"hints": ["גשם", "להישאר"], "text_ru": "Если будет дождь, я останусь дома"}', '{"correct": "אם ירד גשם, אישאר בבית", "alternatives": []}', '{"text": "ירד גשם — пойдёт дождь, אישאר — останусь, будущее от להישאר"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (253, 28, 'fill_blank', 3, '{"hint": "был написан (нифъаль)", "sentence": "הספר _ בשנת 1950"}', '{"correct": "נכתב", "alternatives": []}', '{"text": "נכתב (нихтАв) — пассив от לכתוב в прошедшем времени"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (254, 28, 'translate_ru_he', 3, '{"hints": ["בית", "לבנות"], "text_ru": "Дом был построен в прошлом году"}', '{"correct": "הבית נבנה בשנה שעברה", "alternatives": []}', '{"text": "נבנה (нивнА) — Нифъаль от לבנות, прошедшее 3 л. м.р."}', 15);
