INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (260, 30, 'translate_ru_he', 3, '{"hints": ["יכולה", "שפות"], "text_ru": "Она может говорить на трёх языках"}', '{"correct": "היא יכולה לדבר בשלוש שפות", "alternatives": []}', '{"text": "יכולה (ехолА) — может (ж.р.), модальный глагол + инфинитив"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (261, 33, 'dictation', 3, '{"hint": "Условное предложение", "audio_text": "אם הייתי יכול, הייתי נוסע לירושלים"}', '{"correct": "אם הייתי יכול, הייתי נוסע לירושלים"}', '{"text": "Нереальное условие: אם הייתי יכול — если бы я мог"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (262, 33, 'dictation', 3, '{"hint": "Совет", "audio_text": "צריך ללמוד כל יום כדי להצליח"}', '{"correct": "צריך ללמוד כל יום כדי להצליח"}', '{"text": "צריך ... כדי ... — нужно ... чтобы ..."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (263, 34, 'translate_ru_he', 3, '{"hints": ["לדעת", "לבוא"], "text_ru": "Если бы я знал, я бы пришёл"}', '{"correct": "אם הייתי יודע, הייתי בא", "alternatives": []}', '{"text": "אם הייתי + причастие — нереальное условие в прошлом"}', 15);
