INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (266, 49, 'fill_blank', 3, '{"hint": "выйдешь (м.р.)", "sentence": "אם _ בזמן, לא תאחר"}', '{"correct": "תצא", "alternatives": []}', '{"text": "תצא (тецЭ) — выйдешь, будущее 2 л. м.р. от לצאת"}', 10);
