INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (326, 65, 'fill_blank', 5, '{"hint": "прочитав (ב + инфинитив)", "sentence": "_ הספר, הוא הבין את הנושא"}', '{"correct": "בקראו את", "alternatives": ["בקוראו את"]}', '{"text": "בקראו — прочитав (ב + инфинитив абсолютный с суффиксом)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (327, 65, 'translate_ru_he', 5, '{"hints": ["לפני", "להיפרד"], "text_ru": "Перед тем как уйти, он попрощался со всеми"}', '{"correct": "לפני צאתו, הוא נפרד מכולם", "alternatives": []}', '{"text": "לפני + инфинитив-смихут: צאתו — его уход"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (329, 66, 'fill_blank', 5, '{"hint": "Хитпаэль от שוחח", "sentence": "הם _ (разговаривали между собой) בנושא קשה"}', '{"correct": "השתוחחו", "alternatives": ["התדברו"]}', '{"text": "השתוחחו — разговаривали (взаимное действие, Хитпаэль)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (331, 67, 'dictation', 5, '{"hint": "Начало лекции", "audio_text": "נושא ההרצאה היום הוא השפעת הגלובליזציה על התרבות המקומית"}', '{"correct": "נושא ההרצאה היום הוא השפעת הגלובליזציה על התרבות המקומית"}', '{"text": "נושא ההרצאה — тема лекции, גלובליזציה — глобализация"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1082, 106, 'fill_blank', 1, '{"hint": "рад", "sentence": "אני _ שבאת!"}', '{"correct": "שמח", "alternatives": ["שְׂמֵחַ"]}', '{"text": "שמח (самЭах) — рад (м.р.). Ж.р.: שמחה (смэхА)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (332, 67, 'dictation', 5, '{"hint": "Анализ данных", "audio_text": "כפי שניתן לראות מהנתונים, המגמה הולכת ומתחזקת"}', '{"correct": "כפי שניתן לראות מהנתונים, המגמה הולכת ומתחזקת"}', '{"text": "כפי שניתן לראות — как можно видеть, מגמה — тенденция"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (334, 68, 'translate_ru_he', 5, '{"hints": ["נסיבות", "החלטה"], "text_ru": "Учитывая все обстоятельства, решение было правильным"}', '{"correct": "בהתחשב בכל הנסיבות, ההחלטה הייתה נכונה", "alternatives": []}', '{"text": "בהתחשב ב — учитывая, нסיבות — обстоятельства"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (335, 68, 'fill_blank', 5, '{"hint": "ситуация (формальное)", "sentence": "_ אכן מורכבת יותר משנדמה"}', '{"correct": "המציאות", "alternatives": ["המצב"]}', '{"text": "המציאות (hа-мециУт) — реальность/действительность"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (339, 45, 'fill_blank', 5, '{"hint": "образы/метафоры", "sentence": "השירה של עמיחי מלאה ב_ מחיי היומיום"}', '{"correct": "דימויים", "alternatives": []}', '{"text": "דימויים (димуйИм) — сравнения/образы, мн.ч. от דימוי"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (340, 45, 'translate_ru_he', 5, '{"hints": ["שירי", "פשטות"], "text_ru": "Стихи Рахели отличаются простотой и глубиной"}', '{"correct": "שיריה של רחל מתאפיינים בפשטות ובעומק", "alternatives": []}', '{"text": "מתאפיינים ב — отличаются/характеризуются, עומק — глубина"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (342, 46, 'fill_blank', 5, '{"hint": "от להסכים", "sentence": "הצדדים _ (согласились) לתנאי החוזה"}', '{"correct": "הסכימו", "alternatives": []}', '{"text": "הסכימו (hискИму) — согласились, Хифъиль от הסכים"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (343, 46, 'translate_ru_he', 5, '{"hints": ["שוכר", "שכירות"], "text_ru": "Арендатор обязан оплачивать аренду в первый день каждого месяца"}', '{"correct": "השוכר מתחייב לשלם את דמי השכירות בראשון לכל חודש", "alternatives": []}', '{"text": "מתחייב — обязуется, דמי שכירות — арендная плата"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (345, 69, 'fill_blank', 5, '{"hint": "название стихотворения", "sentence": "_ הוא שיר של יהודה עמיחי על ירושלים"}', '{"correct": "ירושלים", "alternatives": ["אלוהים מרחם על ילדי הגן"]}', '{"text": "Иегуда Амихай — один из крупнейших израильских поэтов XX века"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (346, 69, 'translate_ru_he', 5, '{"hints": ["שירה", "מטפורות"], "text_ru": "Поэзия использует метафоры для выражения глубоких чувств"}', '{"correct": "השירה משתמשת במטפורות כדי לבטא רגשות עמוקים", "alternatives": []}', '{"text": "לבטא — выражать, רגשות עמוקים — глубокие чувства"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (347, 70, 'fill_blank', 5, '{"hint": "к (формальное)", "sentence": "בכפוף _ האמור לעיל, הצדדים מסכימים כדלקמן"}', '{"correct": "ל", "alternatives": ["אל"]}', '{"text": "בכפוף ל — при условии соблюдения, כדלקמן — как указано ниже"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (349, 70, 'translate_ru_he', 5, '{"hints": ["חוזה", "חתימה"], "text_ru": "Настоящий договор вступает в силу с момента подписания"}', '{"correct": "חוזה זה ייכנס לתוקף עם חתימתו", "alternatives": []}', '{"text": "ייכנס לתוקף — вступит в силу, עם חתימתו — с момента его подписания"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (351, 71, 'fill_blank', 5, '{"hint": "как выясняется (журн.)", "sentence": "_ עולה מדוח מבקר המדינה"}', '{"correct": "כפי שעולה", "alternatives": ["כפי ש"]}', '{"text": "כפי שעולה מ — как следует/выясняется из (журналистский оборот)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (490, 11, 'dictation', 1, '{"audio_text": "הם לומדים בבית הספר", "instruction": "Предложение с глаголом в мн.ч."}', '{"accept": ["הם לומדים בבית הספר"], "correct": "הם לומדים בבית הספר"}', '{"text": "הם לומדים בבית הספר — они учатся в школе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (352, 71, 'translate_ru_he', 5, '{"hints": ["דובר", "רפורמה"], "text_ru": "По словам представителя правительства, реформа будет завершена в следующем году"}', '{"correct": "לדברי דובר הממשלה, הרפורמה תושלם בשנה הבאה", "alternatives": []}', '{"text": "לדברי — по словам, תושלם — будет завершена (Пуаль)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (355, 72, 'fill_blank', 5, '{"hint": "потрясающе (сленг)", "sentence": "זה היה _ על הזמן!"}', '{"correct": "חבל", "alternatives": []}', '{"text": "חבל על הזמן — сленг: потрясающе (букв. жаль времени, т.е. не хватит времени описать)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (357, 73, 'fill_blank', 5, '{"hint": "комментарии", "sentence": "רש\"י כתב _ לתורה ולתלמוד"}', '{"correct": "פירוש", "alternatives": ["פירושים"]}', '{"text": "פירוש (пейрУш) — комментарий, Раши — крупнейший комментатор XI века"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (358, 73, 'translate_ru_he', 5, '{"hints": ["עברית", "השפעה"], "text_ru": "Средневековый иврит оказал влияние на формирование современного языка"}', '{"correct": "העברית של ימי הביניים השפיעה על עיצוב השפה המודרנית", "alternatives": []}', '{"text": "ימי הביניים — Средние века, עיצוב — формирование"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (361, 74, 'fill_blank', 5, '{"hint": "из-за (формально)", "sentence": "В формальном тексте вместо «בגלל» используют _"}', '{"correct": "עקב", "alternatives": ["מחמת", "בשל"]}', '{"text": "עקב, בשל, מחמת — формальные синонимы разговорного בגלל"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (362, 75, 'dictation', 5, '{"hint": "Юридическое заключение", "audio_text": "על פי פסיקת בית המשפט העליון, החוק אינו חוקתי"}', '{"correct": "על פי פסיקת בית המשפט העליון, החוק אינו חוקתי"}', '{"text": "פסיקה — постановление, חוקתי — конституционный, אינו — не является"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (363, 75, 'dictation', 5, '{"hint": "Академия языка", "audio_text": "בהתאם לתקנון האקדמיה ללשון העברית, יש להעדיף מונחים עבריים"}', '{"correct": "בהתאם לתקנון האקדמיה ללשון העברית, יש להעדיף מונחים עבריים"}', '{"text": "תקנון — устав, להעדיף — предпочитать, מונחים — термины"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (365, 76, 'translate_ru_he', 5, '{"hints": ["לעיל", "אורגניזם"], "text_ru": "Из всего вышесказанного следует, что язык — живой организм"}', '{"correct": "מכל האמור לעיל עולה כי השפה היא אורגניזם חי", "alternatives": []}', '{"text": "מכל האמור לעיל — из всего вышесказанного, עולה כי — следует что"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (366, 76, 'fill_blank', 5, '{"hint": "следует (формальное)", "sentence": "_ לציין כי הנושא טרם נחקר לעומקו"}', '{"correct": "ראוי", "alternatives": ["יש"]}', '{"text": "ראוי לציין — следует отметить, טרם נחקר — ещё не исследован"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (370, 11, 'fill_blank', 1, '{"hint": "пишет (ж.р., наст. время, Пааль)", "sentence": "הילדה _ (пишет) מכתב לסבתא"}', '{"correct": "כותבת", "alternatives": ["כותבת מכתב"]}', '{"text": "כותבת (котЕвет) — пишет (ж.р. ед.ч.), настоящее время Пааль от корня כ-ת-ב. Мишкаль настоящего времени Пааль для ж.р. ед.ч.: קוטֶלֶת."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (371, 11, 'translate_ru_he', 1, '{"hints": ["ללמוד", "עברית", "כל יום"], "text_ru": "Мы учим иврит каждый день"}', '{"correct": "אנחנו לומדים עברית כל יום", "alternatives": ["אנו לומדים עברית כל יום"]}', '{"text": "לומדים (ломдИм) — учим (мн.ч. м.р./смеш.), настоящее время Пааль от ל-מ-ד. В настоящем времени глагол согласуется с подлежащим в роде и числе."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (373, 20, 'dictation', 1, '{"hint": "Указание учителя в классе", "audio_text": "המורה אומרת: פתחו את הספרים בעמוד עשר"}', '{"correct": "המורה אומרת: פתחו את הספרים בעמוד עשר"}', '{"text": "המורה (ха-морА) — учительница, פתחו (питхУ) — откройте (повелит. мн.ч.), עמוד עשר (амУд Эсер) — страница десять. Типичная фраза в ульпане."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (374, 21, 'dictation', 2, '{"hint": "Учёба в школе", "audio_text": "אני לומד עברית בבית הספר כבר שנתיים"}', '{"correct": "אני לומד עברית בבית הספר כבר שנתיים"}', '{"text": "כבר שנתיים (квар шнатАйим) — уже два года. שנתיים — двойственное число от שנה (год). בבית הספר — в школе (букв. «в доме книги»)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (375, 21, 'dictation', 2, '{"hint": "Вечер дома", "audio_text": "בערב אנחנו אוהבים לשבת במרפסת ולשתות תה"}', '{"correct": "בערב אנחנו אוהבים לשבת במרפסת ולשתות תה"}', '{"text": "בערב (баЭрев) — вечером, מרפסת (мирпЕсет) — балкон/терраса. לשבת (лашЕвет) — сидеть, инфинитив Пааль. ולשתות — и пить (ва-лиштОт), союз ו + инфинитив."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (376, 33, 'dictation', 3, '{"hint": "Результаты экзамена", "audio_text": "למרות שהמבחן היה קשה, רוב התלמידים הצליחו לעבור אותו"}', '{"correct": "למרות שהמבחן היה קשה, רוב התלמידים הצליחו לעבור אותו"}', '{"text": "למרות ש (ламрОт ше) — несмотря на то что, уступительный союз. הצליחו לעבור (hицлИху лаавОр) — смогли сдать/пройти, Хифъиль от הצליח. רוב (ров) — большинство, управляет сопряжённой конструкцией."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (377, 55, 'fill_blank', 4, '{"hint": "объяснить (инфинитив, Хифъиль)", "sentence": "האם תוכלי _ (объяснить) לי את התרגיל?"}', '{"correct": "להסביר", "alternatives": []}', '{"text": "להסביר (леhасбИр) — объяснить, инфинитив Хифъиль от корня ס-ב-ר. Каузативное значение: הסביר — заставил понять (от סבר — считал, полагал). תוכלי (тухлИ) — ты сможешь (ж.р.), будущее от יכול."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (380, 56, 'fill_blank', 4, '{"hint": "ей (предлог ל + суффикс 3 л. ж.р. ед.ч.)", "sentence": "הספר הזה שייך _  (ей, дательный с ל)"}', '{"correct": "לה", "alternatives": ["לָהּ"]}', '{"text": "לה (ла) — ей, предлог ל с суффиксом 3 л. ж.р. ед.ч. Полная парадигма: לי, לך, לך, לו, לה, לנו, לכם, לכן, להם, להן."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (381, 60, 'translate_ru_he', 4, '{"hints": ["למרות", "קשיים", "רופאה"], "text_ru": "Несмотря на трудности, она продолжала учиться и в конце концов стала врачом"}', '{"correct": "למרות הקשיים, היא המשיכה ללמוד ובסוף הפכה לרופאה", "alternatives": ["למרות הקשיים היא המשיכה ללמוד ולבסוף הפכה לרופאה"]}', '{"text": "המשיכה (hимшИха) — продолжала, Хифъиль от משך. הפכה ל (hафхА ле) — стала (букв. превратилась в), Пааль от הפך. ובסוף / ולבסוף — и в конце концов."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (383, 40, 'dictation', 4, '{"hint": "Система образования", "audio_text": "מערכת החינוך בישראל עוברת שינויים רבים בשנים האחרונות, במיוחד בתחום הטכנולוגיה"}', '{"correct": "מערכת החינוך בישראל עוברת שינויים רבים בשנים האחרונות, במיוחד בתחום הטכנולוגיה"}', '{"text": "מערכת החינוך (маарЕхет ха-хинУх) — система образования. עוברת שינויים (оверет шинуйИм) — проходит/претерпевает изменения. בתחום הטכנולוגיה (ба-тхУм ха-технолОгия) — в области технологий."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (386, 1, 'fill_blank', 1, '{"context": "Гимель (ג) — третья буква алфавита, обозначает звук «г».", "sentence_ru": "Буква ___ (Гимель) обозначает звук «г».", "blank_position": 1}', '{"accept": ["Гимель", "гимель"], "correct": "ג"}', '{"text": "Гимель (ג) — третья буква алфавита, обозначает звук «г»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (389, 1, 'translate_ru_he', 1, '{"hint": "Слово начинается с буквы Шин", "sentence_ru": "Привет"}', '{"accept": ["שָׁלוֹם"], "correct": "שלום"}', '{"text": "שלום (шалОм) — приветствие. Содержит буквы из разных групп алфавита."}', 10);
