INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (785, 92, 'dictation', 1, '{"audio_text": "שמי אנה, אני בת עשרים וחמש", "instruction": "Представление женщины"}', '{"accept": ["שמי אנה אני בת עשרים וחמש"], "correct": "שמי אנה, אני בת עשרים וחמש"}', '{"text": "Меня зовут Анна, мне двадцать пять лет. בת — для женщин."}', 10);
