INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (789, 92, 'translate_ru_he', 2, '{"hint": "Слово «женат» — נשוי", "sentence_ru": "Я женат и у меня двое детей"}', '{"accept": ["אני נשוי ויש לי שתי ילדים"], "correct": "אני נשוי ויש לי שני ילדים"}', '{"text": "אני נשוי ויש לי שני ילדים — я женат и у меня двое детей."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (791, 92, 'dictation', 2, '{"audio_text": "אני גר בישראל שנתיים", "instruction": "Рассказ о жизни"}', '{"accept": ["אני גר בישראל שנתיים"], "correct": "אני גר בישראל שנתיים"}', '{"text": "Я живу в Израиле два года. שנתיים — двойственное число от שנה."}', 10);
