INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (814, 94, 'translate_ru_he', 1, '{"hint": "Вопрос «как» + «мир/покой»", "sentence_ru": "Как дела?"}', '{"accept": ["?מה נשמע", "?איך שלומך"], "correct": "?מה שלומך"}', '{"text": "מה שלומך? (ма шломхА?) — как дела? (обращение к мужчине)."}', 10);
