INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (817, 94, 'fill_blank', 2, '{"context": "Мужской род мн.ч.: -ים (им). Женский род мн.ч.: -ות (от).", "sentence_ru": "Множественное число мужского рода заканчивается на ___.", "blank_position": 1}', '{"accept": ["ים"], "correct": "-ים"}', '{"text": "Мужской род мн.ч.: -ים (им). Женский род мн.ч.: -ות (от)."}', 10);
