INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (829, 18, 'fill_blank', 1, '{"hint": "возвратный биньян", "sentence": "Биньян _ выражает взаимное или возвратное действие (напр. הִתְלַבֵּשׁ — одеваться)."}', '{"correct": "הִתְפַּעֵל", "alternatives": ["Хитпаэль", "התפעל"]}', '{"text": "Хитпаэль (הִתְפַּעֵל) — возвратный / взаимный: הִתְלַבֵּשׁ (оделся), הִתְרַחֵץ (помылся)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (830, 18, 'fill_blank', 1, '{"hint": "количество", "sentence": "В иврите _ биньянов."}', '{"correct": "7", "alternatives": ["שבעה", "семь"]}', '{"text": "В иврите 7 биньянов: Пааль, Нифъаль, Пиэль, Пуаль, Хифъиль, Хуфъаль, Хитпаэль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (832, 18, 'translate_ru_he', 2, '{"hints": ["ספר", "נכתב"], "text_ru": "Книга была написана на иврите"}', '{"correct": "הספר נכתב בעברית", "alternatives": ["הספר נכתב בשפה העברית"]}', '{"text": "נכתב (нихтАв) — был написан, Нифъаль от כ.ת.ב. Пассив от «писать»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (836, 19, 'fill_blank', 1, '{"hint": "читал (прошедшее, 1 л.)", "sentence": "אתמול אני _ ספר מעניין."}', '{"correct": "קראתי", "alternatives": ["קָרָאתִי"]}', '{"text": "קראתי (карАти) — я читал, прошедшее 1 л. ед.ч. от לקרוא."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (840, 19, 'translate_ru_he', 1, '{"hints": ["אתמול", "קולנוע"], "text_ru": "Вчера мы ходили в кино"}', '{"correct": "אתמול הלכנו לקולנוע", "alternatives": ["אתמול הלכנו לסרט"]}', '{"text": "הלכנו (hалАхну) — мы ходили, прошедшее 1 л. мн.ч. от ללכת."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (841, 19, 'translate_ru_he', 2, '{"hints": ["קנתה", "שמלה"], "text_ru": "Она купила новое платье"}', '{"correct": "היא קנתה שמלה חדשה", "alternatives": []}', '{"text": "קנתה (кантА) — она купила, прошедшее 3 л. ж.р. от לקנות."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (842, 19, 'dictation', 1, '{"hint": "Что я делал вчера", "audio_text": "אתמול הלכתי לשוק וקניתי פירות"}', '{"correct": "אתמול הלכתי לשוק וקניתי פירות"}', '{"text": "הלכתי (hалАхти) — я ходил, קניתי (канИти) — я купил. Оба в прошедшем."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (846, 20, 'fill_blank', 1, '{"hint": "буду учить (будущее, 1 л.)", "sentence": "מחר אני _ עברית בבוקר."}', '{"correct": "אלמד", "alternatives": ["אֶלְמַד"]}', '{"text": "אלמד (элмАд) — я буду учить. Приставка אֶ- + корень ל.מ.ד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (847, 20, 'fill_blank', 2, '{"hint": "поедут", "sentence": "השבוע הבא הם _ לחיפה."}', '{"correct": "יסעו", "alternatives": ["יִסְעוּ"]}', '{"text": "יסעו (йисъУ) — они поедут, будущее 3 л. мн.ч. от לנסוע."}', 10);
