INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (851, 20, 'translate_ru_he', 2, '{"hints": ["מתי", "לבוא"], "text_ru": "Когда ты приедешь?"}', '{"correct": "מתי תבוא?", "alternatives": ["מתי אתה תבוא?"]}', '{"text": "תבוא (тавО) — ты придёшь / приедешь, будущее 2 л. м.р. от לבוא."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (852, 20, 'dictation', 1, '{"hint": "Планы на будущее", "audio_text": "בשנה הבאה אני אלמד בירושלים"}', '{"correct": "בשנה הבאה אני אלמד בירושלים"}', '{"text": "בשנה הבאה — в следующем году, אלמד — буду учиться."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (856, 21, 'fill_blank', 1, '{"hint": "платить (инфинитив)", "sentence": "אני רוצה _ כרטיס אשראי."}', '{"correct": "לשלם", "alternatives": ["לשלם ב"]}', '{"text": "לשלם (лешалЕм) — платить. אני רוצה לשלם בכרטיס אשראי — хочу заплатить кредиткой."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (857, 21, 'fill_blank', 2, '{"hint": "размер", "sentence": "יש לכם _ יותר קטנה?"}', '{"correct": "מידה", "alternatives": []}', '{"text": "מידה (мидА) — размер. יש לכם מידה יותר קטנה? — У вас есть размер поменьше?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (860, 21, 'translate_ru_he', 1, '{"hints": ["לחם", "טרי"], "text_ru": "У вас есть свежий хлеб?"}', '{"correct": "יש לכם לחם טרי?", "alternatives": ["יש לכם לחם טרי"]}', '{"text": "יש לכם — у вас есть, טרי (тарИ) — свежий."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (861, 21, 'translate_ru_he', 2, '{"hints": ["עגבניות", "קילו"], "text_ru": "Я хочу два килограмма помидоров"}', '{"correct": "אני רוצה שני קילו עגבניות", "alternatives": ["אני רוצה שניים קילו עגבניות"]}', '{"text": "שני קילו (шнэй кИло) — два килограмма. Числительное согласуется с мужским родом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (862, 21, 'dictation', 1, '{"hint": "В пекарне", "audio_text": "כמה עולה הלחם? עשרה שקלים"}', '{"correct": "כמה עולה הלחם? עשרה שקלים"}', '{"text": "כמה עולה — сколько стоит, עשרה שקלים — десять шекелей."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (863, 21, 'dictation', 2, '{"hint": "Способ оплаты", "audio_text": "אפשר לשלם במזומן?"}', '{"correct": "אפשר לשלם במזומן?"}', '{"text": "במזומן (бимзумАн) — наличными. Альтернатива: בכרטיס אשראי — кредиткой."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (866, 22, 'fill_blank', 1, '{"hint": "братья", "sentence": "יש לי שני _ ואחות אחת."}', '{"correct": "אחים", "alternatives": ["אחים"]}', '{"text": "אחים (ахИм) — братья, мн.ч. от אח (ах — брат). Женская форма: אחיות (ахайОт)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (867, 22, 'fill_blank', 1, '{"hint": "папа", "sentence": "_ שלי עובד בבנק."}', '{"correct": "אבא", "alternatives": []}', '{"text": "אבא (Аба) — папа. אבא שלי עובד בבנק — Мой папа работает в банке."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (870, 22, 'translate_ru_he', 1, '{"hints": ["אח", "אחות"], "text_ru": "У меня два брата и одна сестра"}', '{"correct": "יש לי שני אחים ואחות אחת", "alternatives": ["יש לי שניים אחים ואחות אחת"]}', '{"text": "שני אחים — два брата (мужская форма числительного), אחות אחת — одна сестра."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (871, 22, 'translate_ru_he', 2, '{"hints": ["סבא", "ירושלים"], "text_ru": "Мой дедушка живёт в Иерусалиме"}', '{"correct": "סבא שלי גר בירושלים", "alternatives": []}', '{"text": "סבא שלי (сАба шелИ) — мой дедушка. גר (гар) — живёт (м.р.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (872, 22, 'dictation', 1, '{"hint": "Рассказ о семье", "audio_text": "יש לי משפחה גדולה: הורים, שלושה אחים ושתי אחיות"}', '{"correct": "יש לי משפחה גדולה: הורים, שלושה אחים ושתי אחיות"}', '{"text": "הורים (hорИм) — родители, שלושה אחים — три брата, שתי אחיות — две сестры."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (875, 23, 'dictation', 1, '{"hint": "Работа", "audio_text": "היא עובדת בבית חולים"}', '{"correct": "היא עובדת בבית חולים"}', '{"text": "עובדת (овЭдет) — работает (ж.р.). בית חולים (бэйт холИм) — больница."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (876, 23, 'dictation', 1, '{"hint": "Жильё", "audio_text": "אנחנו גרים בדירה קטנה"}', '{"correct": "אנחנו גרים בדירה קטנה"}', '{"text": "דירה קטנה (дирА ктанА) — маленькая квартира."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (878, 23, 'dictation', 2, '{"hint": "Планы", "audio_text": "מחר נסע לים המלח"}', '{"correct": "מחר נסע לים המלח"}', '{"text": "נסע (нисА) — мы поедем. ים המלח (ям hа-мЕлах) — Мёртвое море."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (880, 23, 'fill_blank', 1, '{"hint": "живу (м.р.)", "sentence": "אני _ בדירה בקומה השנייה."}', '{"correct": "גר", "alternatives": ["גָּר"]}', '{"text": "גר (гар) — живу (м.р. ед.ч. настоящее). Женская форма: גרה (гарА)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (881, 23, 'translate_ru_he', 1, '{"hints": ["משרד", "כל יום"], "text_ru": "Я работаю в офисе каждый день"}', '{"correct": "אני עובד במשרד כל יום", "alternatives": ["אני עובדת במשרד כל יום"]}', '{"text": "משרד (мисрАд) — офис. עובד/עובדת — работаю (м./ж.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (888, 24, 'fill_blank', 2, '{"hint": "какой гласный?", "sentence": "В слове בֵּית гласный звук — _."}', '{"correct": "э", "alternatives": ["цере", "е"]}', '{"text": "בֵּית (бэйт) — дом. Под бет стоит цере (ֵ), дающий звук «э»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (889, 24, 'dictation', 1, '{"hint": "Животное, живущее в воде", "audio_text": "דָּג"}', '{"correct": "דג"}', '{"text": "דג (даг) — рыба. Камац под далет даёт звук «а»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (890, 24, 'dictation', 2, '{"hint": "Вещь для чтения", "audio_text": "סֵפֶר"}', '{"correct": "ספר"}', '{"text": "ספר (сЕфер) — книга. Цере + сеголь: э-э."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (891, 24, 'translate_ru_he', 1, '{"hints": ["כלב", "חתול"], "text_ru": "У меня есть собака и кошка"}', '{"correct": "יש לי כלב וחתול", "alternatives": ["יש לי כלב וחתולה"]}', '{"text": "כלב (кЕлев) — собака, חתול (хатУль) — кот/кошка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (894, 25, 'translate_ru_he', 1, '{"hints": ["גר", "תל אביב"], "text_ru": "Я живу в Тель-Авиве"}', '{"correct": "אני גר בתל אביב", "alternatives": ["אני גרה בתל אביב"]}', '{"text": "גר/גרה (гар/гарА) — живу (м./ж.). Предлог ב перед названием города."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (895, 25, 'translate_ru_he', 1, '{"hints": ["לומדת", "אולפן"], "text_ru": "Она учит иврит в ульпане"}', '{"correct": "היא לומדת עברית באולפן", "alternatives": []}', '{"text": "לומדת (ломЕдет) — учит (ж.р.). באולפן (бэ-ульпАн) — в ульпане."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (896, 25, 'translate_ru_he', 2, '{"hints": ["נסע", "ירושלים"], "text_ru": "Мы поедем в Иерусалим завтра"}', '{"correct": "מחר נסע לירושלים", "alternatives": ["אנחנו נסע מחר לירושלים"]}', '{"text": "נסע (нисА) — мы поедем, будущее 1 л. мн.ч. от לנסוע."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (897, 25, 'translate_ru_he', 1, '{"hints": ["בית", "גדול"], "text_ru": "У него есть большой дом"}', '{"correct": "יש לו בית גדול", "alternatives": []}', '{"text": "יש לו (еш ло) — у него есть. Прилагательное גדול после существительного."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (898, 25, 'fill_blank', 1, '{"hint": "она", "sentence": "_ עובדת בבית חולים כבר חמש שנים."}', '{"correct": "היא", "alternatives": []}', '{"text": "היא (hи) — она. Глагол עובדת (овЭдет) согласован с женским родом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (899, 25, 'fill_blank', 2, '{"hint": "хотим", "sentence": "אנחנו _ ללכת לים בשבת."}', '{"correct": "רוצים", "alternatives": ["רוצות"]}', '{"text": "רוצים (роцИм) — хотим (мн.ч. м.р. или смешанная группа)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (902, 25, 'dictation', 1, '{"hint": "Рассказ о друге", "audio_text": "יש לי חבר טוב, הוא גר בחיפה"}', '{"correct": "יש לי חבר טוב, הוא גר בחיפה"}', '{"text": "חבר טוב (хавЭр тов) — хороший друг. בחיפה — в Хайфе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (903, 25, 'dictation', 2, '{"hint": "Почему мы учим иврит", "audio_text": "אנחנו לומדים עברית כי אנחנו גרים בישראל"}', '{"correct": "אנחנו לומדים עברית כי אנחנו גרים בישראל"}', '{"text": "כי (ки) — потому что. אנחנו גרים בישראל — мы живём в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (906, 26, 'fill_blank', 2, '{"hint": "потому что", "sentence": "אני אוהב את ישראל _ אני אוהב את האנשים."}', '{"correct": "כי", "alternatives": ["בגלל ש"]}', '{"text": "כי (ки) — потому что. Самый частый причинный союз в иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (907, 26, 'fill_blank', 1, '{"hint": "поэтому", "sentence": "הוא עובד קשה, _ הוא מצליח."}', '{"correct": "לכן", "alternatives": ["ולכן"]}', '{"text": "לכן (лахЭн) — поэтому. Логическое следствие предыдущего утверждения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (910, 26, 'translate_ru_he', 1, '{"hints": ["ישראל", "מוצא חן"], "text_ru": "Я живу в Израиле, потому что мне нравится здесь"}', '{"correct": "אני גר בישראל כי מוצא חן בעיניי כאן", "alternatives": ["אני גר בישראל כי אני אוהב את המקום הזה"]}', '{"text": "מוצא חן בעיניי — нравится (мне). כי — потому что."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (911, 26, 'translate_ru_he', 2, '{"hints": ["אתמול", "חם", "קר"], "text_ru": "Вчера было жарко, но сегодня холодно"}', '{"correct": "אתמול היה חם, אבל היום קר", "alternatives": []}', '{"text": "היה חם — было жарко. אבל — но. היום קר — сегодня холодно."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (912, 26, 'dictation', 1, '{"hint": "Тема сочинения", "audio_text": "אני רוצה לכתוב על המשפחה שלי"}', '{"correct": "אני רוצה לכתוב על המשפחה שלי"}', '{"text": "לכתוב (лихтОв) — писать. על המשפחה שלי — о моей семье."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (913, 26, 'dictation', 2, '{"hint": "Рассказ о выходных", "audio_text": "בסוף השבוע הלכתי לים עם חברים"}', '{"correct": "בסוף השבוע הלכתי לים עם חברים"}', '{"text": "בסוף השבוע (бесОф hа-шавУа) — в конце недели. עם חברים — с друзьями."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (917, 95, 'fill_blank', 1, '{"hint": "написал (1 л.)", "sentence": "אתמול אני _ מכתב לחבר שלי."}', '{"correct": "כתבתי", "alternatives": ["כָּתַבְתִּי"]}', '{"text": "כתבתי (катАвти) — я написал. Суффикс -תי для 1 л. ед.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (918, 95, 'fill_blank', 2, '{"hint": "открыли", "sentence": "הם _ את הדלת ונכנסו."}', '{"correct": "פתחו", "alternatives": ["פָּתְחוּ"]}', '{"text": "פתחו (патхУ) — они открыли. Суффикс -וּ для 3 л. мн.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (919, 95, 'fill_blank', 1, '{"hint": "присматривали", "sentence": "אנחנו _ על הילד כל היום."}', '{"correct": "שמרנו", "alternatives": ["שָׁמַרְנוּ"]}', '{"text": "שמרנו (шамАрну) — мы присматривали. Суффикс -נו для 1 л. мн.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (924, 95, 'translate_ru_he', 1, '{"hints": ["מכתב", "חברה"], "text_ru": "Я написал письмо подруге"}', '{"correct": "כתבתי מכתב לחברה שלי", "alternatives": ["כתבתי מכתב לחברה"]}', '{"text": "כתבתי — прошедшее 1 л. от לכתוב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (925, 95, 'translate_ru_he', 2, '{"hints": ["שמר", "ילד"], "text_ru": "Мы присматривали за ребёнком"}', '{"correct": "שמרנו על הילד", "alternatives": ["שמרנו על ילד"]}', '{"text": "שמרנו על — мы присматривали за. Предлог על с глаголом שמר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (926, 95, 'translate_ru_he', 3, '{"hints": ["דלת", "נכנסו"], "text_ru": "Они открыли дверь и вошли"}', '{"correct": "הם פתחו את הדלת ונכנסו", "alternatives": []}', '{"text": "פתחו (патхУ) — открыли. נכנסו (нихнесУ) — вошли (Нифъаль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (927, 95, 'dictation', 1, '{"hint": "Что я делал", "audio_text": "כתבתי מכתב לסבתא שלי"}', '{"correct": "כתבתי מכתב לסבתא שלי"}', '{"text": "כתבתי — я написал. לסבתא שלי — моей бабушке."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (928, 95, 'dictation', 2, '{"hint": "Учёба в ульпане", "audio_text": "הוא למד עברית באולפן שלוש שנים"}', '{"correct": "הוא למד עברית באולפן שלוש שנים"}', '{"text": "למד — учил. שלוש שנים — три года."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4114, 213, 'fill_blank', 1, '{"hint": "Прилагательное «красивая»", "sentence": "הילדה _____"}', '{"accept": ["יפה"], "correct": "יפה"}', '{"text": "יפה = красивая"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (932, 96, 'fill_blank', 1, '{"hint": "дал", "sentence": "אתמול הוא _ לי ספר."}', '{"correct": "נתן", "alternatives": ["נָתַן"]}', '{"text": "נתן (натАн) — он дал. Корень נ.ת.נ, группа פ\"נ."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (933, 96, 'fill_blank', 2, '{"hint": "построила", "sentence": "היא _ את הבית החדש בשנה שעברה."}', '{"correct": "בנתה", "alternatives": ["בָּנְתָה"]}', '{"text": "בנתה (бантА) — она построила. Корень ב.נ.ה, группа ל\"ה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (934, 96, 'fill_blank', 1, '{"hint": "приехали", "sentence": "אנחנו _ מירושלים אתמול בערב."}', '{"correct": "באנו", "alternatives": ["בָּאנוּ"]}', '{"text": "באנו (бАну) — мы пришли / приехали. Корень ב.ו.א, группа ע\"ו."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (939, 96, 'translate_ru_he', 1, '{"hints": ["נתן", "ספר"], "text_ru": "Он дал мне книгу"}', '{"correct": "הוא נתן לי ספר", "alternatives": ["הוא נתן לי את הספר"]}', '{"text": "נתן לי — дал мне. Предлог ל с суффиксом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (940, 96, 'translate_ru_he', 2, '{"hints": ["בא", "מאוחר"], "text_ru": "Я пришёл домой поздно"}', '{"correct": "באתי הביתה מאוחר", "alternatives": ["באתי לבית מאוחר"]}', '{"text": "באתי (бАти) — я пришёл. הביתה — домой (с направительным ה)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (941, 96, 'translate_ru_he', 3, '{"hints": ["ראתה", "שקיעה"], "text_ru": "Она увидела красивый закат"}', '{"correct": "היא ראתה שקיעה יפה", "alternatives": []}', '{"text": "ראתה (раатА) — она увидела. שקיעה (шкиА) — закат."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (942, 96, 'dictation', 1, '{"hint": "На рынке", "audio_text": "הלכתי לשוק וקניתי ירקות ופירות"}', '{"correct": "הלכתי לשוק וקניתי ירקות ופירות"}', '{"text": "ירקות (еракОт) — овощи, פירות (пейрОт) — фрукты."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (943, 96, 'dictation', 2, '{"hint": "Биография", "audio_text": "הוא בא לישראל לפני עשר שנים"}', '{"correct": "הוא בא לישראל לפני עשר שנים"}', '{"text": "בא (ба) — пришёл/приехал. לפני עשר שנים — десять лет назад."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (947, 97, 'fill_blank', 1, '{"hint": "буду учить", "sentence": "מחר אני _ עברית."}', '{"correct": "אלמד", "alternatives": ["אֶלְמַד"]}', '{"text": "אלמד (элмАд) — буду учить. Приставка א + корень ל.מ.ד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (948, 97, 'fill_blank', 2, '{"hint": "прочитают", "sentence": "בשבוע הבא הם _ את הספר."}', '{"correct": "יקראו", "alternatives": ["יִקְרְאוּ"]}', '{"text": "יקראו (йикреУ) — они прочитают. Приставка י + суффикс וּ."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (949, 97, 'fill_blank', 2, '{"hint": "вернёшься (ж.р.)", "sentence": "מתי את _ הביתה?"}', '{"correct": "תחזרי", "alternatives": ["תַּחְזְרִי"]}', '{"text": "תחזרי (тахзерИ) — ты вернёшься (ж.р.). Приставка ת + суффикс י."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (954, 97, 'translate_ru_he', 1, '{"hints": ["מחר", "מכתב"], "text_ru": "Завтра я напишу письмо"}', '{"correct": "מחר אכתוב מכתב", "alternatives": ["מחר אני אכתוב מכתב"]}', '{"text": "אכתוב — будущее 1 л. от לכתוב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (955, 97, 'translate_ru_he', 2, '{"hints": ["מתי", "ללמוד"], "text_ru": "Когда ты будешь учить иврит?"}', '{"correct": "מתי תלמד עברית?", "alternatives": ["מתי אתה תלמד עברית?"]}', '{"text": "תלמד — будущее 2 м.р. от ללמוד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (956, 97, 'translate_ru_he', 3, '{"hints": ["אילת", "קיץ"], "text_ru": "Мы поедем в Эйлат летом"}', '{"correct": "נסע לאילת בקיץ", "alternatives": ["אנחנו נסע לאילת בקיץ"]}', '{"text": "נסע (нисА) — мы поедем. בקיץ (бакАйиц) — летом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (957, 97, 'dictation', 1, '{"hint": "Планы на завтра", "audio_text": "מחר נלך לים ונשחה"}', '{"correct": "מחר נלך לים ונשחה"}', '{"text": "נלך (нелЭх) — мы пойдём. נשחה (нисхЭ) — мы будем плавать."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (958, 97, 'dictation', 2, '{"hint": "Планы на год", "audio_text": "בשנה הבאה אני אלמד באוניברסיטה"}', '{"correct": "בשנה הבאה אני אלמד באוניברסיטה"}', '{"text": "אוניברסיטה (университА) — университет."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (962, 98, 'fill_blank', 1, '{"hint": "пойду", "sentence": "מחר לא _ לעבודה, יש לי חופש."}', '{"correct": "אלך", "alternatives": ["אֵלֵךְ"]}', '{"text": "לא אלך — не пойду. Отрицание + будущее."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (963, 98, 'fill_blank', 2, '{"hint": "собираемся", "sentence": "אנחנו _ ללמוד עברית כל יום."}', '{"correct": "הולכים", "alternatives": ["הוֹלְכִים"]}', '{"text": "הולכים + инфинитив — собираемся. Разговорная конструкция будущего."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (964, 98, 'fill_blank', 3, '{"hint": "сможет", "sentence": "היא לא _ לבוא למסיבה."}', '{"correct": "תוכל", "alternatives": ["תּוּכַל"]}', '{"text": "לא תוכל — не сможет. Будущее от יכול (мочь), 3 л. ж.р."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (985, 99, 'translate_ru_he', 2, '{"hints": ["אמרתי", "מחר"], "text_ru": "Я сказал ей, что приду завтра"}', '{"correct": "אמרתי לה שאבוא מחר", "alternatives": []}', '{"text": "לה (лаh) — ей. ש + будущее = что + глагол."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (969, 98, 'translate_ru_he', 1, '{"hints": ["מסיבה", "לבוא"], "text_ru": "Она не придёт на вечеринку"}', '{"correct": "היא לא תבוא למסיבה", "alternatives": []}', '{"text": "לא תבוא — не придёт. Будущее 3 ж.р. от לבוא."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (970, 98, 'translate_ru_he', 2, '{"hints": ["שבת", "לנסוע"], "text_ru": "Мы не поедем в шаббат"}', '{"correct": "לא נסע בשבת", "alternatives": ["אנחנו לא נסע בשבת"]}', '{"text": "לא נסע — мы не поедем. בשבת — в шаббат."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (971, 98, 'translate_ru_he', 2, '{"hints": ["אוניברסיטה", "ללמוד"], "text_ru": "Я собираюсь учиться в университете"}', '{"correct": "אני הולך ללמוד באוניברסיטה", "alternatives": ["אני הולכת ללמוד באוניברסיטה"]}', '{"text": "הולך ללמוד — собираюсь учиться. Разговорная конструкция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (972, 98, 'dictation', 1, '{"hint": "Планы на выходные", "audio_text": "מה תעשה בסופשבוע? אלך לשוק ואקנה ירקות"}', '{"correct": "מה תעשה בסופשבוע? אלך לשוק ואקנה ירקות"}', '{"text": "תעשה — что будешь делать. אקנה — я куплю."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (973, 98, 'dictation', 2, '{"hint": "Изменение планов", "audio_text": "אנחנו לא נסע לאילת, נישאר בבית"}', '{"correct": "אנחנו לא נסע לאילת, נישאר בבית"}', '{"text": "נישאר (нишаЭр) — мы останемся. Будущее от להישאר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (977, 99, 'fill_blank', 1, '{"hint": "мой (של + я)", "sentence": "הספר _ נמצא על השולחן."}', '{"correct": "שלי", "alternatives": ["שֶׁלִּי"]}', '{"text": "שלי (шелИ) — мой/моя. הספר שלי — моя книга."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (978, 99, 'fill_blank', 2, '{"hint": "ему (ל + он)", "sentence": "אמרתי _ שאבוא מחר."}', '{"correct": "לו", "alternatives": ["לוֹ"]}', '{"text": "לו (ло) — ему. Предлог ל + суффикс 3 м.р."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (979, 99, 'fill_blank', 2, '{"hint": "в тебя (м.) (ב + ты)", "sentence": "אני מאמין _."}', '{"correct": "בך", "alternatives": ["בְּךָ"]}', '{"text": "בך (бехА) — в тебе (м.р.). Предлог ב + суффикс 2 м.р."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (987, 99, 'dictation', 1, '{"hint": "О друге", "audio_text": "יש לי חבר טוב, אני אוהב אותו"}', '{"correct": "יש לי חבר טוב, אני אוהב אותו"}', '{"text": "אותו (отО) — его. Маркер прямого дополнения + 3 м.р."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (988, 99, 'dictation', 2, '{"hint": "О книге", "audio_text": "הספר שלה מעניין מאוד, נתנה לי אותו"}', '{"correct": "הספר שלה מעניין מאוד, נתנה לי אותו"}', '{"text": "שלה — её. נתנה לי — она дала мне. אותו — его."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (992, 100, 'fill_blank', 1, '{"hint": "дом", "sentence": "_ חולים — это больница."}', '{"correct": "בית", "alternatives": ["בֵּית"]}', '{"text": "בית חולים (бэйт холИм) — больница. Букв. «дом больных»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (993, 100, 'fill_blank', 2, '{"hint": "сна", "sentence": "חדר _ — это спальня."}', '{"correct": "שנה", "alternatives": ["שֵׁנָה"]}', '{"text": "חדר שנה (хадАр шенА) — спальня. Букв. «комната сна»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (994, 100, 'fill_blank', 1, '{"hint": "кофе", "sentence": "כוס _ — чашка кофе."}', '{"correct": "קפה", "alternatives": ["קָפֶה"]}', '{"text": "כוס קפה (кос кафЭ) — чашка кофе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (999, 100, 'translate_ru_he', 1, '{"hints": ["בית חולים", "הלכתי"], "text_ru": "Я ходил в больницу"}', '{"correct": "הלכתי לבית החולים", "alternatives": ["הלכתי לבית חולים"]}', '{"text": "בית החולים — определённый смихут: конкретная больница."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1000, 100, 'translate_ru_he', 2, '{"hints": ["ספרי ילדים", "מדף"], "text_ru": "Детские книги стоят на полке"}', '{"correct": "ספרי ילדים עומדים על המדף", "alternatives": ["ספרי הילדים על המדף"]}', '{"text": "ספרי ילדים — смихут мн.ч.: окончание -ים → -י в нисмахе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1001, 100, 'translate_ru_he', 3, '{"hints": ["שנת לימודים", "ספטמבר"], "text_ru": "Учебный год начинается в сентябре"}', '{"correct": "שנת הלימודים מתחילה בספטמבר", "alternatives": []}', '{"text": "שנת לימודים — ж.р. смихут: שנה → שנת."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1002, 100, 'dictation', 1, '{"hint": "Школа", "audio_text": "הילדים לומדים בבית הספר כל יום"}', '{"correct": "הילדים לומדים בבית הספר כל יום"}', '{"text": "בבית הספר — в школе. Определённый смихут с предлогом ב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1003, 100, 'dictation', 2, '{"hint": "В кафе", "audio_text": "נכנסתי לבית קפה והזמנתי קפה הפוך"}', '{"correct": "נכנסתי לבית קפה והזמנתי קפה הפוך"}', '{"text": "בית קפה — кафе. קפה הפוך (кафЭ hафУх) — латте."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1007, 101, 'fill_blank', 1, '{"hint": "три (м.р.)", "sentence": "יש לי _ ילדים (три мальчика)."}', '{"correct": "שלושה", "alternatives": ["שְׁלוֹשָׁה"]}', '{"text": "שלושה (шлошА) — три (с муж. сущ.). С женским: שלוש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1008, 101, 'fill_blank', 2, '{"hint": "третья", "sentence": "הקומה _ — третий этаж."}', '{"correct": "השלישית", "alternatives": ["הַשְּׁלִישִׁית"]}', '{"text": "השלישית — третья (ж.р.). Порядковое от שלוש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1009, 101, 'fill_blank', 2, '{"hint": "пять", "sentence": "עשרים ו_ = 25."}', '{"correct": "חמש", "alternatives": ["חמישה"]}', '{"text": "עשרים וחמש / עשרים וחמישה — 25. Единицы после ו."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1014, 101, 'translate_ru_he', 1, '{"hints": ["ילדים", "שלושה"], "text_ru": "У меня трое детей"}', '{"correct": "יש לי שלושה ילדים", "alternatives": []}', '{"text": "שלושה ילדים — три ребёнка. Форма на ה с мужским родом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1015, 101, 'translate_ru_he', 2, '{"hints": ["עוגות", "חמש"], "text_ru": "Я купил пять пирожных"}', '{"correct": "קניתי חמש עוגות", "alternatives": []}', '{"text": "חמש עוגות — пять пирожных. Форма без ה с женским родом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1016, 101, 'translate_ru_he', 3, '{"hints": ["שיעור", "שני"], "text_ru": "Это мой второй урок иврита"}', '{"correct": "זה השיעור השני שלי בעברית", "alternatives": ["זה שיעור העברית השני שלי"]}', '{"text": "השני — второй. Порядковые числительные ведут себя как прилагательные."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1017, 101, 'dictation', 1, '{"hint": "О семье", "audio_text": "יש לי ארבעה אחים ושלוש אחיות"}', '{"correct": "יש לי ארבעה אחים ושלוש אחיות"}', '{"text": "ארבעה אחים — четыре брата (м.). שלוש אחיות — три сестры (ж.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1018, 101, 'dictation', 2, '{"hint": "О квартире", "audio_text": "הדירה בקומה החמישית, בלי מעלית"}', '{"correct": "הדירה בקומה החמישית, בלי מעלית"}', '{"text": "החמישית — пятая (ж.р.). מעלית (маалИт) — лифт."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1022, 102, 'fill_blank', 1, '{"hint": "программист", "sentence": "אני עובד כ_ בחברת הייטק."}', '{"correct": "מתכנת", "alternatives": ["מְתַכְנֵת"]}', '{"text": "מתכנת (мэтахнЭт) — программист. כ (кэ) — в качестве."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1023, 102, 'fill_blank', 2, '{"hint": "степень", "sentence": "סיימתי _ בכלכלה באוניברסיטה."}', '{"correct": "תואר", "alternatives": ["תֹּאַר"]}', '{"text": "תואר (тоАр) — степень. סיימתי תואר — я окончил степень."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1029, 102, 'translate_ru_he', 1, '{"hints": ["עבודה", "מתכנת"], "text_ru": "Я ищу работу программиста"}', '{"correct": "אני מחפש עבודה כמתכנת", "alternatives": ["אני מחפש עבודה של מתכנת"]}', '{"text": "מחפש עבודה — ищу работу. כ — в качестве."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1030, 102, 'translate_ru_he', 2, '{"hints": ["ספר", "עצמך"], "text_ru": "Расскажи о себе"}', '{"correct": "ספר לי על עצמך", "alternatives": ["ספר על עצמך"]}', '{"text": "ספר (сапЭр) — расскажи (повелительное). על עצמך — о себе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1031, 102, 'translate_ru_he', 3, '{"hints": ["עבד", "חברה"], "text_ru": "Я работал программистом в хайтек-компании"}', '{"correct": "עבדתי כמתכנת בחברת הייטק", "alternatives": []}', '{"text": "עבדתי — я работал. חברת הייטק — хайтек-компания (смихут)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1032, 102, 'dictation', 1, '{"hint": "На собеседовании", "audio_text": "אני מחפש משרה מלאה בתחום ההייטק"}', '{"correct": "אני מחפש משרה מלאה בתחום ההייטק"}', '{"text": "בתחום (бетхУм) — в области. הייטק — хайтек."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1033, 102, 'dictation', 2, '{"hint": "Опыт работы", "audio_text": "יש לי ניסיון של חמש שנים כמהנדס תוכנה"}', '{"correct": "יש לי ניסיון של חמש שנים כמהנדס תוכנה"}', '{"text": "מהנדס תוכנה — инженер-программист. Смихут."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1037, 103, 'fill_blank', 1, '{"hint": "болит", "sentence": "_ לי הגרון כבר יומיים."}', '{"correct": "כואב", "alternatives": ["כּוֹאֵב"]}', '{"text": "כואב לי הגרון — у меня болит горло. Конструкция: כואב + ל + часть тела."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1038, 103, 'fill_blank', 2, '{"hint": "очередь (приём)", "sentence": "אני צריך להזמין _ לרופא."}', '{"correct": "תור", "alternatives": ["תּוֹר"]}', '{"text": "להזמין תור (леhазмИн тор) — записаться на приём (букв. заказать очередь)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1039, 103, 'fill_blank', 2, '{"hint": "рецепт", "sentence": "הרופא כתב לי _."}', '{"correct": "מרשם", "alternatives": ["מִרְשָׁם"]}', '{"text": "מרשם (миршАм) — рецепт. כתב מרשם — выписал рецепт."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1044, 103, 'translate_ru_he', 1, '{"hints": ["ראש", "כואב"], "text_ru": "У меня болит голова"}', '{"correct": "כואב לי הראש", "alternatives": []}', '{"text": "Конструкция: כואב + לי + הראש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1045, 103, 'translate_ru_he', 2, '{"hints": ["תור", "רופא"], "text_ru": "Мне нужно записаться к врачу"}', '{"correct": "אני צריך להזמין תור לרופא", "alternatives": ["אני צריכה להזמין תור לרופא"]}', '{"text": "להזמין תור — записаться на приём."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1137, 109, 'dictation', 1, '{"hint": "Приглашение на шаббат", "audio_text": "שבת שלום! מה עושים הערב?"}', '{"correct": "שבת שלום! מה עושים הערב?"}', '{"text": "שבת שלום — шаббат шалом (приветствие)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1046, 103, 'translate_ru_he', 3, '{"hints": ["רופא", "תרופה"], "text_ru": "Врач выписал мне лекарство"}', '{"correct": "הרופא רשם לי תרופה", "alternatives": ["הרופא כתב לי מרשם לתרופה"]}', '{"text": "רשם (рашАм) — выписал (рецепт). תרופה (труфА) — лекарство."}', 10);
