INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1048, 103, 'dictation', 2, '{"hint": "Запись к врачу", "audio_text": "אני צריך להזמין תור לרופא משפחה"}', '{"correct": "אני צריך להזמין תור לרופא משפחה"}', '{"text": "רופא משפחה — семейный врач (смихут)."}', 10);
