INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1230, 27, 'fill_blank', 2, '{"hint": "союз «если» (реальное условие)", "sentence": "_____ ירד גשם, ניקח מטריה"}', '{"correct": "אם", "alternatives": []}', '{"text": "אם (им) + будущее время = реальное условие. אם ירד גשם — если пойдёт дождь."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1231, 27, 'translate_ru_he', 3, '{"hints": ["אילו", "ידעתי", "עברית", "ישראל"], "text_ru": "Если бы я знал иврит, я бы поехал в Израиль"}', '{"correct": "אילו ידעתי עברית, הייתי נוסע לישראל", "alternatives": ["לו ידעתי עברית, הייתי נוסע לישראל"]}', '{"text": "Нереальное условие: אילו/לו + прошедшее время, הייתי + причастие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1234, 27, 'fill_blank', 3, '{"hint": "вставьте «мы встали бы» (прош. время от קום)", "sentence": "אילו _____ מוקדם יותר, היינו מספיקים"}', '{"correct": "קמנו", "alternatives": []}', '{"text": "В условии III типа: אילו + прошедшее время. קמנו — мы встали (от קום)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1235, 27, 'dictation', 2, '{"hint": "Условное предложение о совместном выходе", "audio_text": "אם תבוא מוקדם, נצא ביחד"}', '{"correct": "אם תבוא מוקדם, נצא ביחד"}', '{"text": "אם תבוא (им тавО) — если ты придёшь, נצא (нецЕ) — мы выйдем. Реальное условие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1237, 27, 'translate_ru_he', 2, '{"hints": ["אם", "מזג אוויר", "ים"], "text_ru": "Если будет хорошая погода, мы поедем на море"}', '{"correct": "אם מזג האוויר יהיה טוב, ניסע לים", "alternatives": ["אם יהיה מזג אוויר טוב, ניסע לים"]}', '{"text": "Реальное условие: אם + будущее. מזג האוויר (мезег hа-авИр) — погода."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1240, 28, 'fill_blank', 2, '{"hint": "был написан (Нифъаль от כ.ת.ב)", "sentence": "הספר _____ על ידי סופר מפורסם"}', '{"correct": "נכתב", "alternatives": []}', '{"text": "נכתב (нихтАв) — был написан, Нифъаль от корня כ.ת.ב. על ידי — указывает деятеля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1243, 28, 'translate_ru_he', 2, '{"hints": ["מכתב", "נשלח", "אתמול"], "text_ru": "Письмо было отправлено вчера"}', '{"correct": "המכתב נשלח אתמול", "alternatives": []}', '{"text": "נשלח (нишлАх) — был отправлен, Нифъаль от שלח. Обратите внимание на артикль ה перед מכתב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1245, 28, 'dictation', 2, '{"hint": "Пассивная конструкция о школе", "audio_text": "הדלת נפתחה והילדים נכנסו לכיתה"}', '{"correct": "הדלת נפתחה והילדים נכנסו לכיתה"}', '{"text": "נפתחה (нифтехА) — была открыта (ж.р.), Нифъаль от פתח. נכנסו (нихнесУ) — вошли, тоже Нифъаль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1246, 28, 'fill_blank', 3, '{"hint": "была одобрена (Пуаль от אשר)", "sentence": "הבקשה _____ על ידי המנהל (просьба была одобрена директором)"}', '{"correct": "אושרה", "alternatives": []}', '{"text": "אושרה (ушрА) — была одобрена (ж.р.). Пуаль от корня א.ש.ר. Пуаль — пассив от Пиэль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1247, 28, 'translate_ru_he', 3, '{"hints": ["שיר", "נכתב", "שנות השישים"], "text_ru": "Эта песня была написана в 1960-х годах"}', '{"correct": "השיר הזה נכתב בשנות השישים", "alternatives": ["השיר נכתב בשנות השישים"]}', '{"text": "נכתב — Нифъаль, прош. время. שנות השישים (шнот hа-шишИм) — шестидесятые годы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1293, 33, 'translate_ru_he', 2, '{"hints": ["מזג אוויר", "מחר", "קר"], "text_ru": "Послушай и запиши: погода завтра будет холодной"}', '{"correct": "מזג האוויר מחר יהיה קר", "alternatives": []}', '{"text": "מזג האוויר (мезег hа-авИр) — погода. יהיה קר — будет холодно."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1250, 29, 'fill_blank', 2, '{"hint": "потому что (разговорный стиль)", "sentence": "באתי _____ שרציתי לראות אותך"}', '{"correct": "בגלל", "alternatives": ["מפני"]}', '{"text": "בגלל ש (биглАль ше) — потому что (разговорный). Также: מפני ש, כי, משום ש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1251, 29, 'translate_ru_he', 3, '{"hints": ["ספר", "שקראתי", "מעניין"], "text_ru": "Книга, которую я прочитал, была очень интересной"}', '{"correct": "הספר שקראתי היה מאוד מעניין", "alternatives": ["הספר שקראתי היה מעניין מאוד"]}', '{"text": "ש + прошедшее = определительное придаточное. שקראתי — которую я прочитал."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1255, 29, 'dictation', 2, '{"hint": "Придаточное времени", "audio_text": "כשהגעתי הביתה, הילדים כבר ישנו"}', '{"correct": "כשהגעתי הביתה, הילדים כבר ישנו"}', '{"text": "כש (кше) — когда (сокращение от כאשר). כשהגעתי — когда я пришёл. ישנו — спали."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1256, 29, 'fill_blank', 3, '{"hint": "несмотря на то что", "sentence": "_____ שהיה קר, הלכנו לים"}', '{"correct": "למרות", "alternatives": []}', '{"text": "למרות ש (ламрОт ше) — несмотря на то что. Уступительное придаточное."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1257, 29, 'translate_ru_he', 2, '{"hints": ["ללמוד", "כדי", "להצליח"], "text_ru": "Я учусь, чтобы преуспеть"}', '{"correct": "אני לומד כדי להצליח", "alternatives": ["אני לומדת כדי להצליח"]}', '{"text": "При одинаковом субъекте: כדי + инфинитив (без ש). כדי להצליח — чтобы преуспеть."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1260, 30, 'fill_blank', 2, '{"hint": "должен (мягкая рекомендация)", "sentence": "אתה _____ ללמוד יותר לפני המבחן"}', '{"correct": "צריך", "alternatives": []}', '{"text": "צריך (царИх) — нужно, следует. Мягче, чем חייב (обязан)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1261, 30, 'translate_ru_he', 2, '{"hints": ["אפשר", "להיכנס"], "text_ru": "Можно войти?"}', '{"correct": "?אפשר להיכנס", "alternatives": []}', '{"text": "אפשר (эфшАр) + инфинитив = безличная конструкция «можно». אפשר להיכנס? — Можно войти?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1265, 30, 'dictation', 2, '{"hint": "Обязанность оплаты", "audio_text": "אתה חייב לשלם את החשבון עד סוף החודש"}', '{"correct": "אתה חייב לשלם את החשבון עד סוף החודש"}', '{"text": "חייב (хайЯв) — обязан. חשבון (хешбОн) — счёт. עד סוף החודש — до конца месяца."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1281, 32, 'translate_ru_he', 2, '{"hints": ["רשום", "קורס", "בלשנות"], "text_ru": "Я записан на курс лингвистики"}', '{"correct": "אני רשום לקורס בבלשנות", "alternatives": []}', '{"text": "רשום (рашУм) — записан. בלשנות (балшанУт) — лингвистика."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1266, 30, 'fill_blank', 3, '{"hint": "может (негативная вероятность)", "sentence": "הוא _____ ליפול אם לא ייזהר (может упасть — негативная вероятность)"}', '{"correct": "עלול", "alternatives": []}', '{"text": "עלול (алУль) — используется только для нежелательных вероятностей: עלול ליפול — может упасть."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1267, 30, 'translate_ru_he', 3, '{"hints": ["כדאי", "ללמוד", "כל יום"], "text_ru": "Стоит учиться каждый день"}', '{"correct": "כדאי ללמוד כל יום", "alternatives": []}', '{"text": "כדאי (кедАй) — стоит, целесообразно. Безличная конструкция: כדאי + инфинитив."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1270, 31, 'fill_blank', 2, '{"hint": "путешествие/поездка", "sentence": "בקיץ האחרון נסענו ל_____ בנגב"}', '{"correct": "טיול", "alternatives": []}', '{"text": "טיול (тиУль) — путешествие, поездка. Корень ט.י.ל. נסענו לטיול — мы поехали в поездку."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (2909, 182, 'fill_blank', 2, '{"hint": "Повторение", "sentence": "למרות ה_____, הוא הצליח (трудности)"}', '{"correct": "קשיים"}', '{"text": "קשיים — трудности."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1271, 31, 'translate_ru_he', 2, '{"hints": ["ים המלח", "נקודה נמוכה", "עולם"], "text_ru": "Мёртвое море — самая низкая точка на Земле"}', '{"correct": "ים המלח הוא הנקודה הנמוכה ביותר בעולם", "alternatives": []}', '{"text": "הנקודה הנמוכה ביותר — самая низкая точка. ביותר = превосходная степень."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1274, 31, 'dictation', 2, '{"hint": "Описание Голанских высот", "audio_text": "ברמת הגולן יש נופים מדהימים וכרמי יין"}', '{"correct": "ברמת הגולן יש נופים מדהימים וכרמי יין"}', '{"text": "רמת הגולן (рамАт hа-голАн) — Голанские высоты. נופים (нофИм) — пейзажи. כרמי יין — виноградники."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1276, 31, 'fill_blank', 3, '{"hint": "билет туда и обратно (вставьте «туда»)", "sentence": "כרטיס _____ ושוב לירושלים, בבקשה"}', '{"correct": "הלוך", "alternatives": []}', '{"text": "כרטיס הלוך ושוב (картИс hалОх ва-шув) — билет туда и обратно."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1277, 31, 'translate_ru_he', 3, '{"hints": ["אילת", "לשחות", "לצלול", "ים סוף"], "text_ru": "В Эйлате можно плавать и нырять в Красном море"}', '{"correct": "באילת אפשר לשחות ולצלול בים סוף", "alternatives": []}', '{"text": "לשחות (лисхОт) — плавать, לצלול (лицлОл) — нырять. ים סוף (ям суф) — Красное море."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1280, 32, 'fill_blank', 2, '{"hint": "до десяти (числительное)", "sentence": "הספרייה פתוחה עד _____ בלילה"}', '{"correct": "עשר", "alternatives": ["10"]}', '{"text": "עשר (Эсер) — десять (ж.р.). Библиотеки в израильских университетах работают допоздна."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3558, 201, 'dictation', 1, '{"hint": "пожалуйста", "word_he": "בבקשה", "word_translit": "бевакашА"}', '{"accept": ["בבקשה"], "correct": "בבקשה"}', '{"text": "בבקשה (бевакашА) — пожалуйста"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1284, 32, 'dictation', 2, '{"hint": "Дедлайн сдачи работы", "audio_text": "צריך להגיש את העבודה עד סוף השבוע"}', '{"correct": "צריך להגיש את העבודה עד סוף השבוע"}', '{"text": "להגיש (леhагИш) — подать, сдать (Хифъиль). עד סוף השבוע — до конца недели."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1286, 32, 'fill_blank', 3, '{"hint": "семинарская (прилагательное)", "sentence": "עבודה _____ היא חלק חשוב מהלימודים (семинарская работа)"}', '{"correct": "סמינריונית", "alternatives": []}', '{"text": "עבודה סמינריונית (аводА семинарйОнит) — курсовая/семинарская работа."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1287, 32, 'translate_ru_he', 3, '{"hints": ["שבוע הבא", "בחינה", "היסטוריה"], "text_ru": "На следующей неделе у нас экзамен по истории"}', '{"correct": "בשבוע הבא יש לנו בחינה בהיסטוריה", "alternatives": []}', '{"text": "בחינה (бхинА) — экзамен. בהיסטוריה — по истории. יש לנו — у нас есть."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1289, 33, 'dictation', 2, '{"hint": "Закрытие дорог из-за дождя", "audio_text": "בגלל הגשם הכבד, הכבישים נסגרו"}', '{"correct": "בגלל הגשם הכבד, הכבישים נסגרו"}', '{"text": "נסגרו (нисгерУ) — были закрыты, Нифъаль. הגשם הכבד — сильный дождь."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1290, 33, 'dictation', 2, '{"hint": "Предупреждение об опоздании", "audio_text": "אם לא תמהר, תאחר לרכבת"}', '{"correct": "אם לא תמהר, תאחר לרכבת"}', '{"text": "תמהר (темаhЕр) — ты поторопишься. תאחר (теахЕр) — ты опоздаешь. Реальное условие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1291, 33, 'dictation', 3, '{"hint": "Рекомендация врача", "audio_text": "הרופא אמר שצריך לנוח כמה ימים"}', '{"correct": "הרופא אמר שצריך לנוח כמה ימים"}', '{"text": "שצריך לנוח — что нужно отдыхать. Косвенная речь с ש. כמה ימים — несколько дней."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1292, 33, 'dictation', 3, '{"hint": "О трудолюбии", "audio_text": "למרות שהיה לה כאב ראש, היא המשיכה לעבוד"}', '{"correct": "למרות שהיה לה כאב ראש, היא המשיכה לעבוד"}', '{"text": "למרות ש — несмотря на то что. כאב ראש (кеЭв рош) — головная боль. המשיכה — продолжала."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1294, 33, 'fill_blank', 2, '{"hint": "ресторан", "sentence": "כשהגענו ל_____, המסעדה כבר הייתה סגורה"}', '{"correct": "מסעדה", "alternatives": []}', '{"text": "מסעדה (мисадА) — ресторан. סגורה (сгурА) — закрыта (ж.р.). כש — когда."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1311, 49, 'translate_ru_he', 2, '{"hints": ["אם", "זמן", "נבשל", "ביחד"], "text_ru": "Если у тебя есть время, давай готовить вместе"}', '{"correct": "אם יש לך זמן, בוא נבשל ביחד", "alternatives": []}', '{"text": "בוא נבשל (бо невашЕль) — давай готовить. Приглашение: בוא + 1 л. мн.ч. будущего."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1298, 33, 'translate_ru_he', 3, '{"hints": ["למרות", "מבחן", "קשה", "הצליחו"], "text_ru": "Несмотря на то что экзамен был трудным, большинство сдали"}', '{"correct": "למרות שהמבחן היה קשה, רוב התלמידים הצליחו", "alternatives": ["למרות שהמבחן היה קשה, רובם הצליחו"]}', '{"text": "למרות ש + прошедшее = уступительное придаточное. רוב התלמידים — большинство студентов."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1299, 34, 'translate_ru_he', 2, '{"hints": ["רוצה", "שהוא", "יבוא", "מחר"], "text_ru": "Я хочу, чтобы он пришёл завтра"}', '{"correct": "אני רוצה שהוא יבוא מחר", "alternatives": []}', '{"text": "После ש в целевом/желательном придаточном используется будущее время: שהוא יבוא."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1300, 34, 'translate_ru_he', 2, '{"hints": ["בית", "שגרים", "ישן"], "text_ru": "Дом, в котором мы живём, очень старый"}', '{"correct": "הבית שאנחנו גרים בו מאוד ישן", "alternatives": ["הבית שגרים בו מאוד ישן"]}', '{"text": "Определительное придаточное с предлогом: שאנחנו גרים בו — в котором мы живём."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1301, 34, 'translate_ru_he', 3, '{"hints": ["אילו", "יכולתי", "לחזור", "ללמוד"], "text_ru": "Если бы я мог вернуться в прошлое, я бы учился больше"}', '{"correct": "אילו יכולתי לחזור בזמן, הייתי לומד יותר", "alternatives": ["לו יכולתי לחזור בזמן, הייתי לומד יותר"]}', '{"text": "Нереальное условие: אילו + прошедшее → הייתי + причастие. לחזור בזמן — вернуться в прошлое."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1302, 34, 'fill_blank', 2, '{"hint": "я надеюсь (м.р.)", "sentence": "אני _____ שהוא יגיע בזמן (я надеюсь, что он придёт вовремя)"}', '{"correct": "מקווה", "alternatives": []}', '{"text": "מקווה (мекавЕ) — надеюсь, Пиэль от корня ק.ו.ה. שהוא יגיע — что он приедет (будущее после ש)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1305, 34, 'dictation', 2, '{"hint": "Жизненная мудрость", "audio_text": "כדי להצליח בחיים, צריך לעבוד קשה"}', '{"correct": "כדי להצליח בחיים, צריך לעבוד קשה"}', '{"text": "כדי + инфинитив — чтобы (один субъект). להצליח (леhацлИах) — преуспеть. Хифъиль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1307, 34, 'translate_ru_he', 3, '{"hints": ["למרות", "גשם", "טיול", "פארק"], "text_ru": "Несмотря на дождь, мы пошли гулять в парк"}', '{"correct": "למרות הגשם, הלכנו לטייל בפארק", "alternatives": ["למרות הגשם יצאנו לטייל בפארק"]}', '{"text": "למרות (ламрОт) + существительное — без ש. לטייל — гулять, путешествовать."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1308, 34, 'fill_blank', 3, '{"hint": "что она (начало придаточного)", "sentence": "היא אמרה _____ מתכוננת למבחן (что она готовится к экзамену)"}', '{"correct": "שהיא", "alternatives": []}', '{"text": "Косвенная речь: אמרה שהיא — сказала, что она. ש + подлежащее + глагол."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1310, 49, 'fill_blank', 2, '{"hint": "если мы выйдем (будущее, 1 л. мн.ч.)", "sentence": "אם _____ מוקדם, נספיק לראות את ההופעה"}', '{"correct": "נצא", "alternatives": []}', '{"text": "נצא (нецЕ) — мы выйдем. Будущее время от יצא. Реальное условие: אם + будущее."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1313, 49, 'dictation', 2, '{"hint": "Условие на работе", "audio_text": "אם תסיים את הפרויקט בזמן, תקבל בונוס"}', '{"correct": "אם תסיים את הפרויקט בזמן, תקבל בונוס"}', '{"text": "תסיים (тесаЕм) — ты закончишь. תקבל (текабЕль) — ты получишь. בונוס — бонус."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4101, 213, 'fill_blank', 1, '{"hint": "Глагол «играть» (мн.ч.)", "sentence": "הילדים _____ בחצר"}', '{"accept": ["משחקים"], "correct": "משחקים"}', '{"text": "משחקים = играют"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1316, 49, 'fill_blank', 3, '{"hint": "если бы (нереальное условие)", "sentence": "_____ הייתי עשיר, הייתי נוסע לכל העולם"}', '{"correct": "אילו", "alternatives": ["לו"]}', '{"text": "אילו / לו (илУ / лу) — если бы. Вводят нереальное условие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1317, 49, 'translate_ru_he', 3, '{"hints": ["רק אם", "תבטיח", "אספר", "סוד"], "text_ru": "Только если ты обещаешь, я расскажу тебе секрет"}', '{"correct": "רק אם תבטיח, אספר לך את הסוד", "alternatives": []}', '{"text": "רק אם (рак им) — только если. תבטיח — ты пообещаешь. אספר — я расскажу."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1320, 50, 'fill_blank', 2, '{"hint": "после того как", "sentence": "_____ שאכלנו, הלכנו הביתה"}', '{"correct": "אחרי", "alternatives": []}', '{"text": "אחרי ש (ахарЕй ше) — после того как. Временное придаточное."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1321, 50, 'translate_ru_he', 2, '{"hints": ["בזמן ש", "למדתי", "אחי", "שיחק"], "text_ru": "Пока я учился, брат играл"}', '{"correct": "בזמן שלמדתי, אחי שיחק", "alternatives": []}', '{"text": "בזמן ש (бизмАн ше) — в то время как. Одновременность двух действий."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1324, 50, 'dictation', 2, '{"hint": "Напоминание перед выходом", "audio_text": "לפני שיצאת מהבית, כבה את האור"}', '{"correct": "לפני שיצאת מהבית, כבה את האור"}', '{"text": "לפני ש (лифнЕй ше) — до того как. כבה (кабЕ) — выключи. האור (hа-Ор) — свет."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1326, 50, 'fill_blank', 3, '{"hint": "чтобы (при разных субъектах)", "sentence": "למדתי הרבה _____ שאצליח במבחן (чтобы я сдал экзамен)"}', '{"correct": "כדי", "alternatives": []}', '{"text": "כדי ש + будущее — чтобы (разные субъекты). Здесь один субъект, поэтому можно כדי + инфинитив."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1327, 50, 'translate_ru_he', 3, '{"hints": ["אף על פי ש", "הוזהר", "לא שינה", "דעתו"], "text_ru": "Хотя он был предупреждён, он не изменил мнения"}', '{"correct": "אף על פי שהוזהר, לא שינה את דעתו", "alternatives": ["למרות שהוזהר, לא שינה את דעתו"]}', '{"text": "אף על פי ש (аф аль пи ше) — хотя (формальный). הוזהר — был предупреждён (Хуфъаль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1330, 51, 'translate_ru_he', 3, '{"hints": ["ספר", "נכתב", "סופר", "תורגם", "שפות"], "text_ru": "Книга, написанная известным писателем, была переведена на двадцать языков"}', '{"correct": "הספר שנכתב על ידי הסופר המפורסם תורגם לעשרים שפות", "alternatives": []}', '{"text": "Два пассива: נכתב (Нифъаль — был написан), תורגם (Пуаль — был переведён)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1331, 51, 'fill_blank', 2, '{"hint": "может (негативная вероятность)", "sentence": "הוא _____ ליפול אם לא ייזהר (может упасть — негативная вероятность)"}', '{"correct": "עלול", "alternatives": []}', '{"text": "עלול (алУль) — может (только для нежелательных вероятностей). ייזהר — будет осторожен (Нифъаль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1334, 51, 'dictation', 3, '{"hint": "Нереальное условие о подготовке к экзамену", "audio_text": "אם הייתי יודע שהמבחן יהיה כל כך קשה, הייתי לומד יותר"}', '{"correct": "אם הייתי יודע שהמבחן יהיה כל כך קשה, הייתי לומד יותר"}', '{"text": "Нереальное условие: אם הייתי + причастие. כל כך — так, настолько."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1336, 51, 'fill_blank', 3, '{"hint": "сдаваться (инфинитив)", "sentence": "צריך לעבוד קשה ולא _____ (не сдаваться)"}', '{"correct": "לוותר", "alternatives": []}', '{"text": "לוותר (леватЕр) — сдаваться, уступать. Распространённый глагол на уровне B1."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1337, 51, 'translate_ru_he', 2, '{"hints": ["אמר", "שיבוא", "אם", "גשם"], "text_ru": "Он сказал, что придёт, если не будет дождя"}', '{"correct": "הוא אמר שיבוא אם לא ירד גשם", "alternatives": []}', '{"text": "Комбинация конструкций: косвенная речь (אמר ש) + реальное условие (אם + будущее)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1340, 52, 'fill_blank', 2, '{"hint": "очередь / приём", "sentence": "אני צריך להזמין _____ לרופא (записаться к врачу)"}', '{"correct": "תור", "alternatives": []}', '{"text": "תור (тор) — очередь, приём. להזמין תור — записаться на приём (к врачу)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1341, 52, 'translate_ru_he', 2, '{"hints": ["כואב", "גרון", "ראש"], "text_ru": "У меня болит горло и голова"}', '{"correct": "כואב לי הגרון וכואב לי הראש", "alternatives": ["כואב לי הגרון והראש"]}', '{"text": "Конструкция боли: כואב לי + часть тела (с артиклем). כואב лИ — мне больно."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1344, 52, 'dictation', 2, '{"hint": "Визит к врачу", "audio_text": "הרופא כתב לי מרשם לתרופה נגד כאב ראש"}', '{"correct": "הרופא כתב לי מרשם לתרופה נגד כאב ראש"}', '{"text": "מרשם (миршАм) — рецепт. תרופה (труфА) — лекарство. נגד — против. כאב ראש — головная боль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1346, 52, 'fill_blank', 3, '{"hint": "аллергия", "sentence": "יש לי _____ לפניצילין (аллергия на пенициллин)"}', '{"correct": "אלרגיה", "alternatives": []}', '{"text": "אלרגיה (алЕргия) — аллергия. יש לי אלרגיה ל... — у меня аллергия на..."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1347, 52, 'translate_ru_he', 3, '{"hints": ["רופא", "המליץ", "לנוח", "כמה ימים"], "text_ru": "Врач рекомендовал мне отдыхать несколько дней"}', '{"correct": "הרופא המליץ לי לנוח כמה ימים", "alternatives": []}', '{"text": "המליץ (hимлИц) — рекомендовал (Хифъиль). לנוח (ланУах) — отдыхать."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1350, 53, 'fill_blank', 2, '{"hint": "маца (пресный хлеб)", "sentence": "בפסח אוכלים _____ במקום לחם"}', '{"correct": "מצה", "alternatives": ["מצות"]}', '{"text": "מצה (мацА) — пресный хлеб, традиционная еда на Песах. Заменяет обычный хлеб (חמץ)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1351, 53, 'translate_ru_he', 2, '{"hints": ["שנה טובה", "מתוקה"], "text_ru": "С новым годом! Желаю хорошего и сладкого года"}', '{"correct": "שנה טובה ומתוקה", "alternatives": ["שנה טובה"]}', '{"text": "Традиционное поздравление на Рош ха-Шана: שנה טובה ומתוקה (шанА товА у-метукА)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1354, 53, 'dictation', 2, '{"hint": "Традиция Песаха", "audio_text": "בליל הסדר הילד הכי קטן שואל את ארבע הקושיות"}', '{"correct": "בליל הסדר הילד הכי קטן שואל את ארבע הקושיות"}', '{"text": "ליל הסדר (лейль hа-сЕдер) — ночь Седера. ארבע הקושיות — четыре вопроса."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1356, 53, 'fill_blank', 3, '{"hint": "независимость", "sentence": "ביום העצמאות חוגגים את _____ של מדינת ישראל"}', '{"correct": "עצמאות", "alternatives": []}', '{"text": "עצמאות (ацмаУт) — независимость. יום העצמאות — День Независимости Израиля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1357, 53, 'translate_ru_he', 3, '{"hints": ["יום כיפור", "כבישים", "ריקים", "אופניים"], "text_ru": "В Йом Кипур все дороги пустые и дети катаются на велосипедах"}', '{"correct": "ביום כיפור כל הכבישים ריקים וילדים רוכבים על אופניים", "alternatives": []}', '{"text": "Уникальная традиция: в Йом Кипур нет транспорта, дети катаются на великах по пустым дорогам."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1359, 54, 'dictation', 2, '{"hint": "Заказ столика в ресторане", "audio_text": "שלום, אני רוצה שולחן לשניים בבקשה"}', '{"correct": "שלום, אני רוצה שולחן לשניים בבקשה"}', '{"text": "שולחן לשניים — столик на двоих. Типичная фраза при входе в ресторан."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1360, 54, 'dictation', 2, '{"hint": "Вопрос о маршруте", "audio_text": "סליחה, איפה התחנה המרכזית?"}', '{"correct": "סליחה, איפה התחנה המרכזית?"}', '{"text": "התחנה המרכזית (hа-таханА hа-мерказИт) — центральная станция/автостанция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1361, 54, 'dictation', 3, '{"hint": "Утренний распорядок", "audio_text": "בבוקר אני שותה קפה ואוכל לחם עם גבינה"}', '{"correct": "בבוקר אני שותה קפה ואוכל לחם עם גבינה"}', '{"text": "בבוקר (бабОкер) — утром. גבינה (гвинА) — сыр. Типичный израильский завтрак."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1363, 54, 'fill_blank', 2, '{"hint": "билет", "sentence": "כמה עולה _____ הלוך ושוב לירושלים? (билет)"}', '{"correct": "כרטיס", "alternatives": []}', '{"text": "כרטיס (картИс) — билет. כרטיס הלוך ושוב — билет туда и обратно."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1365, 54, 'translate_ru_he', 3, '{"hints": ["תחנה", "הבאה", "מרכזית"], "text_ru": "Следующая остановка — Центральная станция"}', '{"correct": "התחנה הבאה — התחנה המרכזית", "alternatives": ["התחנה הבאה: תחנה מרכזית"]}', '{"text": "Объявление в автобусе/поезде: התחנה הבאה (hа-таханА hа-баА) — следующая остановка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1367, 54, 'dictation', 3, '{"hint": "Покупка одежды", "audio_text": "אני מחפש חולצה כחולה מידה מדיום"}', '{"correct": "אני מחפש חולצה כחולה מידה מדיום"}', '{"text": "חולצה (хулцА) — рубашка/кофта. כחולה (кхулА) — синяя (ж.р.). מידה — размер."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1368, 54, 'fill_blank', 3, '{"hint": "меню", "sentence": "הנה ה_____. מה תרצו להזמין? (меню)"}', '{"correct": "תפריט", "alternatives": []}', '{"text": "תפריט (тафрИт) — меню. להזמין (леhазмИн) — заказать. Хифъиль от корня ז.מ.נ."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1370, 116, 'fill_blank', 2, '{"hint": "причастие Пааль, м.р. ед.ч., корень כ.ת.ב", "sentence": "הוא _____ ספר חדש (он пишет новую книгу — причастие м.р.)"}', '{"correct": "כותב", "alternatives": []}', '{"text": "כותב (котЕв) — пишет / писатель. Причастие Пааль, модель קוֹטֵל."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1386, 117, 'translate_ru_he', 2, '{"hints": ["מורה", "אמרה", "שהם", "להגיש", "למחרת"], "text_ru": "Учительница сказала, что они должны сдать завтра"}', '{"correct": "המורה אמרה שהם צריכים להגיש למחרת", "alternatives": []}', '{"text": "В косвенной речи: מחר → למחרת (на следующий день), אתם → הם."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1372, 116, 'translate_ru_he', 2, '{"hints": ["כתיבה", "יפה"], "text_ru": "Его почерк очень красивый"}', '{"correct": "הכתיבה שלו יפה מאוד", "alternatives": []}', '{"text": "כתיבה (ктивА) — писание, почерк. Герундий от корня כ.ת.ב в Пааль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1375, 116, 'fill_blank', 3, '{"hint": "развитие (герундий от התפתח)", "sentence": "ה_____ הטכנולוגית מהירה מאוד (технологическое развитие)"}', '{"correct": "התפתחות", "alternatives": []}', '{"text": "התפתחות (hитпатхУт) — развитие. Герундий Хитпаэль от корня פ.ת.ח."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1376, 116, 'dictation', 2, '{"hint": "О почерке и чтении", "audio_text": "הכתיבה שלו יפה מאוד ואני אוהב לקרוא את הספרים שלו"}', '{"correct": "הכתיבה שלו יפה מאוד ואני אוהב לקרוא את הספרים שלו"}', '{"text": "כתיבה — почерк/писание. לקרוא — читать (инфинитив Пааль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1378, 116, 'translate_ru_he', 3, '{"hints": ["למידה", "סבלנות", "התמדה"], "text_ru": "Учёба требует терпения и настойчивости"}', '{"correct": "הלמידה דורשת סבלנות והתמדה", "alternatives": []}', '{"text": "התמדה (hатмадА) — настойчивость, упорство. Герундий Хифъиль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1381, 116, 'fill_blank', 2, '{"hint": "воспитывает (ж.р., Пиэль от ח.נ.כ)", "sentence": "היא _____ את הילדים בגן (она воспитывает детей в саду)"}', '{"correct": "מחנכת", "alternatives": []}', '{"text": "מחנכת (механЕкет) — воспитывает (ж.р.). Причастие Пиэль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1382, 116, 'translate_ru_he', 2, '{"hints": ["נהג", "אוטובוס", "מנומס"], "text_ru": "Водитель автобуса очень вежливый"}', '{"correct": "נהג האוטובוס מאוד מנומס", "alternatives": ["נהג האוטובוס מנומס מאוד"]}', '{"text": "נהג (наhАг) — водитель, субстантивированное причастие от נהג (вести)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1383, 116, 'dictation', 3, '{"hint": "О пользе учёбы", "audio_text": "הלמידה דורשת סבלנות אבל ההתפתחות האישית שווה את המאמץ"}', '{"correct": "הלמידה דורשת סבלנות אבל ההתפתחות האישית שווה את המאמץ"}', '{"text": "התפתחות אישית — личностное развитие. מאמץ (маамАц) — усилие. שווה — стоит."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1385, 117, 'fill_blank', 2, '{"hint": "что он (начало придаточного)", "sentence": "הוא אמר _____ רוצה ללמוד שם (он сказал, что хочет учиться там)"}', '{"correct": "שהוא", "alternatives": []}', '{"text": "Косвенная речь: אמר שהוא — он сказал, что он. ש + лицо меняется с 1-го на 3-е."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1807, 137, 'fill_blank', 2, '{"hint": "Пиэль от ר.פ.א", "sentence": "הרופא _____ את החולה מהמחלה (вылечил)"}', '{"correct": "ריפא", "alternatives": ["רִפֵּא"]}', '{"text": "ריפא — Пиэль: вылечил. Интенсивное действие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1390, 117, 'fill_blank', 3, '{"hint": "вводное слово для да/нет-вопроса", "sentence": "הוא שאל _____ אני בא מחר (он спросил, приду ли я завтра)"}', '{"correct": "אם", "alternatives": []}', '{"text": "Косвенный да/нет-вопрос: שאל אם (шаАль им) — спросил, ли..."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1391, 117, 'dictation', 2, '{"hint": "Инструкция учительницы", "audio_text": "המורה אמרה שהתלמידים צריכים להגיש את העבודה עד יום שישי"}', '{"correct": "המורה אמרה שהתלמידים צריכים להגיש את העבודה עד יום שישי"}', '{"text": "Косвенная речь: אמרה ש + подлежащее + сказуемое. עד יום שישי — до пятницы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1392, 117, 'translate_ru_he', 3, '{"hints": ["שאל", "מתי", "תגיע"], "text_ru": "Он спросил, когда она приедет"}', '{"correct": "הוא שאל מתי היא תגיע", "alternatives": []}', '{"text": "Косвенный специальный вопрос: שאל + вопросительное слово (מתי) + подлежащее + глагол."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1395, 117, 'fill_blank', 2, '{"hint": "рассказал (Пиэль от ס.פ.ר)", "sentence": "הוא _____ לי שנסע לחו\"ל (он рассказал мне, что уехал за границу)"}', '{"correct": "סיפר", "alternatives": []}', '{"text": "סיפר (сипЕр) — рассказал. חו\"ל (хуль) — заграница (сокращение от חוץ לארץ)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1397, 117, 'translate_ru_he', 3, '{"hints": ["הסביר", "שצריך", "לפנות", "שמאלה"], "text_ru": "Он объяснил мне, что нужно повернуть налево"}', '{"correct": "הוא הסביר לי שצריך לפנות שמאלה", "alternatives": []}', '{"text": "הסביר (hисбИр) — объяснил, Хифъиль. לפנות (лифнОт) — повернуть."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1398, 117, 'dictation', 3, '{"hint": "Рекомендация врача в косвенной речи", "audio_text": "הרופא הסביר לחולה שהוא צריך לנוח שבועיים ולקחת תרופות"}', '{"correct": "הרופא הסביר לחולה שהוא צריך לנוח שבועיים ולקחת תרופות"}', '{"text": "הסביר — объяснил. שבועיים — две недели (двойственное число). תרופות — лекарства."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1400, 118, 'fill_blank', 2, '{"hint": "была открыта (Нифъаль, ж.р., прош.)", "sentence": "הדלת _____ בשמונה בבוקר (дверь была открыта в 8 утра)"}', '{"correct": "נפתחה", "alternatives": []}', '{"text": "נפתחה (нифтехА) — была открыта (ж.р.). Нифъаль от פתח, значение — пассив."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1490, 124, 'fill_blank', 2, '{"hint": "баскетбол", "sentence": "מכבי תל אביב הוא קבוצת _____ מפורסמת (баскетбол)"}', '{"correct": "כדורסל", "alternatives": []}', '{"text": "כדורסל (кадурсАль) — баскетбол. Маккаби Тель-Авив — многократный чемпион Евролиги."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1402, 118, 'translate_ru_he', 2, '{"hints": ["ספר", "נכתב", "שנות השישים"], "text_ru": "Книга была написана в шестидесятых годах"}', '{"correct": "הספר נכתב בשנות השישים", "alternatives": []}', '{"text": "נכתב (нихтАв) — был написан. Нифъаль, пассивное значение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1405, 118, 'fill_blank', 3, '{"hint": "Нифъаль от ש.מ.ע, м.р. ед.ч., настоящее", "sentence": "אני _____ לסיפור שלך (я прислушиваюсь к твоему рассказу — Нифъаль настоящее, м.р.)"}', '{"correct": "נשמע", "alternatives": ["נשמע לו"]}', '{"text": "נשמע (нишмА) может быть и «звучит», и «слышится». Контекст определяет значение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1406, 118, 'dictation', 2, '{"hint": "Встреча друзей", "audio_text": "הם נפגשו בבית קפה ודיברו שעתיים"}', '{"correct": "הם נפגשו בבית קפה ודיברו שעתיים"}', '{"text": "נפגשו (нифгешУ) — встретились. Нифъаль, возвратное значение. שעתיים — два часа."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1407, 118, 'translate_ru_he', 3, '{"hints": ["נרשם", "קורס", "עברית"], "text_ru": "Он записался на курс иврита"}', '{"correct": "הוא נרשם לקורס עברית", "alternatives": []}', '{"text": "נרשם (нирשАм) — записался. Нифъаль, возвратное значение. Активный: רשם — записал (кого-то)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1511, 125, 'dictation', 2, '{"hint": "О вере и надежде", "audio_text": "בלי אמונה ותקווה, קשה להמשיך הלאה"}', '{"correct": "בלי אמונה ותקווה, קשה להמשיך הלאה"}', '{"text": "אמונה (эмунА) — вера. תקווה (тиквА) — надежда. להמשיך הלאה — продолжать дальше."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1411, 118, 'fill_blank', 2, '{"hint": "встретились (Нифъаль, мн.ч., прош.)", "sentence": "הם _____ בבית קפה ליד הים (они встретились в кафе у моря)"}', '{"correct": "נפגשו", "alternatives": []}', '{"text": "נפגשו (нифгешУ) — встретились (мн.ч.). Нифъаль от פגש, возвратное значение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1412, 118, 'translate_ru_he', 3, '{"hints": ["דלת", "נשברה", "לא נפתחת"], "text_ru": "Дверь сломалась и не открывается"}', '{"correct": "הדלת נשברה ולא נפתחת", "alternatives": []}', '{"text": "נשברה (нишберА) — сломалась (ж.р.). נפתחת (нифтАхат) — открывается (наст., ж.р.). Оба — Нифъаль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1413, 118, 'dictation', 3, '{"hint": "О рождении ребёнка", "audio_text": "הילד נולד בבית חולים בתל אביב ונקרא על שם סבו"}', '{"correct": "הילד נולד בבית חולים בתל אביב ונקרא על שם סבו"}', '{"text": "נולד (нолАд) — родился. נקרא (никрА) — был назван. על שם סבו — в честь дедушки."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1415, 119, 'fill_blank', 2, '{"hint": "для, ради", "sentence": "זה _____ אמא שלי (это для моей мамы)"}', '{"correct": "בשביל", "alternatives": []}', '{"text": "בשביל (бишвИль) — для, ради. זה בשביל אמא — Это для мамы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1460, 122, 'fill_blank', 2, '{"hint": "приложение", "sentence": "ווייז היא _____ ניווט שנמכרה לגוגל (приложение навигации)"}', '{"correct": "אפליקציה", "alternatives": ["אפליקצייה"]}', '{"text": "אפליקציה (апликАция) — приложение. Waze — израильское приложение навигации, купленное Google."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1417, 119, 'translate_ru_he', 2, '{"hints": ["לפי", "חדשות", "חם"], "text_ru": "Согласно новостям, завтра будет жарко"}', '{"correct": "לפי החדשות, מחר יהיה חם", "alternatives": []}', '{"text": "לפי (лефИ) — по, согласно. לפי החדשות — по новостям."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1420, 119, 'fill_blank', 3, '{"hint": "в отличие от", "sentence": "_____ לי, הוא אופטימי (в отличие от меня, он оптимист)"}', '{"correct": "בניגוד", "alternatives": []}', '{"text": "בניגוד ל (бе-нигУд ле) — в отличие от. בניגוד לי — в отличие от меня."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1421, 119, 'dictation', 2, '{"hint": "Отмена из-за дождя", "audio_text": "בגלל הגשם הכבד, ביטלו את המשחק"}', '{"correct": "בגלל הגשם הכבד, ביטלו את המשחק"}', '{"text": "בגלל — из-за. ביטלו (битлУ) — отменили (Пиэль). משחק — игра/матч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1423, 119, 'translate_ru_he', 3, '{"hints": ["מלבד", "עברית", "ערבית"], "text_ru": "Кроме иврита, я также учу арабский"}', '{"correct": "מלבד עברית, אני גם לומד ערבית", "alternatives": ["מלבד עברית, אני לומד גם ערבית"]}', '{"text": "מלבד (мильвАд) — кроме, помимо. מלבד עברית — кроме иврита."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1425, 119, 'fill_blank', 2, '{"hint": "вместо", "sentence": "בואו _____ דני (приходите вместо Дани)"}', '{"correct": "במקום", "alternatives": []}', '{"text": "במקום (бимкОм) — вместо. במקום דני — вместо Дани."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1427, 119, 'translate_ru_he', 2, '{"hints": ["בגלל", "איחרו"], "text_ru": "Из-за меня они опоздали"}', '{"correct": "בגללי הם איחרו", "alternatives": ["הם איחרו בגללי"]}', '{"text": "בגללי (биглалИ) — из-за меня. Предлог בגלל с местоимённым суффиксом 1 л. ед.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1428, 119, 'dictation', 3, '{"hint": "О полиглоте", "audio_text": "מלבד עברית ואנגלית, הוא מדבר גם צרפתית וערבית"}', '{"correct": "מלבד עברית ואנגלית, הוא מדבר גם צרפתית וערבית"}', '{"text": "מלבד — кроме. צרפתית (царфатИт) — французский. ערבית (аравИт) — арабский."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1430, 120, 'fill_blank', 2, '{"hint": "призывается (Хитпаэль от ג.י.ס)", "sentence": "כשצעיר מגיע לגיל 18, הוא _____ לצה\"ל (призывается)"}', '{"correct": "מתגייס", "alternatives": []}', '{"text": "מתגייס (митгайЕс) — призывается. Хитпаэль от корня ג.י.ס."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1475, 123, 'fill_blank', 2, '{"hint": "заголовок", "sentence": "ה_____ הראשית: ממשלה חדשה הושבעה (главный заголовок)"}', '{"correct": "כותרת", "alternatives": []}', '{"text": "כותרת (котЕрет) — заголовок. כותרת ראשית — главный заголовок."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1507, 125, 'translate_ru_he', 2, '{"hints": ["תקווה", "לא", "מתה"], "text_ru": "Надежда не умерла"}', '{"correct": "התקווה לא מתה", "alternatives": []}', '{"text": "התקווה (hа-тиквА) — надежда. Также название гимна Израиля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1432, 120, 'translate_ru_he', 2, '{"hints": ["איפה", "שירתת"], "text_ru": "Где ты служил?"}', '{"correct": "?איפה שירתת", "alternatives": []}', '{"text": "«איפה שירתת?» — один из первых вопросов при знакомстве в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1607, 131, 'translate_ru_he', 2, '{"hints": ["כנסת", "מחוקקת", "חוקים"], "text_ru": "Кнессет принимает законы"}', '{"correct": "הכנסת מחוקקת חוקים", "alternatives": []}', '{"text": "מחוקקת (мехокЕкет) — принимает законы, законодательствует. Пиэль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1435, 120, 'dictation', 2, '{"hint": "День призыва", "audio_text": "ביום הגיוס, החייל מגיע לבסיס ומקבל מדים ונשק"}', '{"correct": "ביום הגיוס, החייל מגיע לבסיס ומקבל מדים ונשק"}', '{"text": "יום הגיוס (йом hа-гиЮс) — день призыва. מדים (мадИм) — форма. נשק (нЕшек) — оружие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1436, 120, 'fill_blank', 3, '{"hint": "курс молодого бойца", "sentence": "אחרי ה_____, כל חייל מקבל תפקיד (после курса молодого бойца)"}', '{"correct": "טירונות", "alternatives": []}', '{"text": "טירונות (тиронУт) — базовый курс, курс молодого бойца."}', 10);
