INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1510, 125, 'fill_blank', 3, '{"hint": "справедливость", "sentence": "ה_____ ינצח בסוף (справедливость победит в конце)"}', '{"correct": "צדק", "alternatives": []}', '{"text": "צדק (цЕдек) — справедливость. ינצח (йенацЕах) — победит (Пиэль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1513, 125, 'translate_ru_he', 3, '{"hints": ["כבוד", "אחרים", "בסיס", "חברה"], "text_ru": "Уважение к другим — основа общества"}', '{"correct": "כבוד לאחרים הוא הבסיס של החברה", "alternatives": ["הכבוד לאחרים הוא בסיס החברה"]}', '{"text": "כבוד (кавОд) — уважение, честь. לאחרים — к другим."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1516, 125, 'fill_blank', 2, '{"hint": "воображение", "sentence": "_____ הוא כוח גדול (воображение — большая сила)"}', '{"correct": "דמיון", "alternatives": []}', '{"text": "דמיון (димьОн) — воображение. От корня ד.מ.ה (быть подобным)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1517, 125, 'translate_ru_he', 2, '{"hints": ["אהבה", "חזקה", "שנאה"], "text_ru": "Любовь сильнее ненависти"}', '{"correct": "אהבה חזקה יותר משנאה", "alternatives": ["האהבה חזקה מהשנאה"]}', '{"text": "אהבה (аhавА) — любовь. שנאה (синА) — ненависть. חזקה יותר — сильнее."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1518, 125, 'dictation', 3, '{"hint": "О ценностях", "audio_text": "האמת והצדק הם ערכים חשובים שצריך לשמור עליהם בכל חברה"}', '{"correct": "האמת והצדק הם ערכים חשובים שצריך לשמור עליהם בכל חברה"}', '{"text": "ערכים (арахИм) — ценности. לשמור עליהם — хранить их. חברה — общество."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1519, 126, 'dictation', 2, '{"hint": "Прогноз погоды", "audio_text": "מזג האוויר: מחר צפוי גשם באזור המרכז"}', '{"correct": "מזג האוויר: מחר צפוי גשם באזור המרכז"}', '{"text": "מזג האוויר (мезег hа-авИр) — погода. צפוי (цафУй) — ожидается. אזור המרכז — центральный район."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1520, 126, 'dictation', 2, '{"hint": "Рекламное объявление", "audio_text": "מבצע מיוחד! קנה אחד, קבל אחד חינם"}', '{"correct": "מבצע מיוחד! קנה אחד, קבל אחד חינם"}', '{"text": "מבצע (мивцА) — акция. חינם (хинАм) — бесплатно. קנה...קבל — купи...получи."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1521, 126, 'dictation', 3, '{"hint": "Новость о забастовке", "audio_text": "שביתה כללית הוכרזה במגזר הציבורי. בתי הספר ייסגרו מחר"}', '{"correct": "שביתה כללית הוכרזה במגזר הציבורי. בתי הספר ייסגרו מחר"}', '{"text": "שביתה (швитА) — забастовка. הוכרזה (hухразА) — была объявлена. ייסגרו — будут закрыты."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1523, 126, 'fill_blank', 2, '{"hint": "процентов", "sentence": "הנחה של חמישים _____ על כל המוצרים (50 процентов скидка)"}', '{"correct": "אחוז", "alternatives": []}', '{"text": "הנחה (hанахА) — скидка. אחוז (ахУз) — процент. הנחה של 50 אחוז — скидка 50%."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1660, 135, 'fill_blank', 3, '{"hint": "по моему мнению", "sentence": "_____, צריך ללמוד שפות כי שפות פותחות דלתות (по-моему...)"}', '{"correct": "לדעתי", "alternatives": ["לפי דעתי"]}', '{"text": "לדעתי (ледаатИ) — по-моему. Начало аргумента с выражения мнения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1525, 126, 'translate_ru_he', 2, '{"hints": ["מזג אוויר", "חום", "כבד", "צפוי"], "text_ru": "Прогноз погоды: ожидается сильная жара"}', '{"correct": "תחזית מזג האוויר: צפוי גל חום כבד", "alternatives": ["מזג האוויר: גל חום כבד צפוי"]}', '{"text": "תחזית (тахазИт) — прогноз. גל חום כבד — сильная волна жары."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1528, 126, 'dictation', 3, '{"hint": "О работе транспорта", "audio_text": "התחבורה הציבורית תפעל במתכונת מצומצמת בימי השביתה"}', '{"correct": "התחבורה הציבורית תפעל במתכונת מצומצמת בימי השביתה"}', '{"text": "תחבורה ציבורית — общественный транспорт. מתכונת מצומצמת — сокращённый режим."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1529, 126, 'fill_blank', 3, '{"hint": "отправится (будущее от יצא)", "sentence": "נמסר כי ראש הממשלה _____ לביקור בארצות הברית (отправится с визитом)"}', '{"correct": "ייצא", "alternatives": ["יצא"]}', '{"text": "ייצא (йецЕ) — отправится. Будущее от יצא. נמסר כי — формальное «сообщается, что»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1530, 126, 'translate_ru_he', 3, '{"hints": ["היום", "הנחה", "אחוז", "בגדים"], "text_ru": "Только сегодня: скидка 30% на всю одежду"}', '{"correct": "רק היום: הנחה של שלושים אחוז על כל הבגדים", "alternatives": ["רק היום: 30% הנחה על כל הבגדים"]}', '{"text": "Типичная рекламная фраза. בגדים (бгадИм) — одежда."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1533, 126, 'dictation', 2, '{"hint": "Реклама для студентов", "audio_text": "הנחה מיוחדת לסטודנטים: חמישים אחוז על כל הקורסים"}', '{"correct": "הנחה מיוחדת לסטודנטים: חמישים אחוז על כל הקורסים"}', '{"text": "הנחה מיוחדת — специальная скидка. לסטודנטים — для студентов."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1535, 127, 'fill_blank', 2, '{"hint": "если бы (нереальное условие)", "sentence": "_____ למדתי יותר, הייתי מצליח במבחן (если бы я учился больше)"}', '{"correct": "אילו", "alternatives": ["לו"]}', '{"text": "אילו / לו — вводят нереальное условие III типа (контрфактуальное)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1536, 127, 'translate_ru_he', 3, '{"hints": ["אילו", "ידעתי", "קודם", "מתכונן"], "text_ru": "Если бы я знал раньше, я бы подготовился"}', '{"correct": "אילו ידעתי קודם, הייתי מתכונן", "alternatives": ["לו ידעתי קודם, הייתי מתכונן"]}', '{"text": "Нереальное условие: אילו + прошедшее → הייתי + причастие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1540, 127, 'fill_blank', 3, '{"hint": "не был бы (вспомогательный глагол)", "sentence": "אילו לא נסעתי, לא _____ פוגש אותה (не встретил бы её)"}', '{"correct": "הייתי", "alternatives": []}', '{"text": "Отрицательный контрфактуал: אילו לא + прошедшее → לא הייתי + причастие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1541, 127, 'dictation', 2, '{"hint": "Мечта о доме у моря", "audio_text": "אילו הייתי עשיר, הייתי קונה בית ליד הים"}', '{"correct": "אילו הייתי עשיר, הייתי קונה בית ליד הים"}', '{"text": "Нереальное условие: אילו הייתי + прилагательное → הייתי + причастие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1542, 127, 'translate_ru_he', 3, '{"hints": ["חבל", "שלא", "למדתי"], "text_ru": "Жаль, что я не учился больше"}', '{"correct": "חבל שלא למדתי יותר", "alternatives": []}', '{"text": "חבל ש (хавАль ше) — жаль, что. В разговорном иврите часто заменяет условие III типа."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1546, 127, 'fill_blank', 2, '{"hint": "о если бы (литературное пожелание)", "sentence": "מי _____ שנוכל לחזור בזמן (о если бы мы могли вернуться)"}', '{"correct": "ייתן", "alternatives": []}', '{"text": "מי ייתן ש (ми йитЕн ше) — о если бы (букв. «кто бы дал, чтобы»). Литературная форма."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1547, 127, 'translate_ru_he', 2, '{"hints": ["אילו", "זמן", "נוסע"], "text_ru": "Если бы у меня было больше времени, я бы путешествовал"}', '{"correct": "אילו היה לי יותר זמן, הייתי נוסע", "alternatives": ["לו היה לי יותר זמן, הייתי נוסע"]}', '{"text": "היה לי — у меня было бы. Нереальное условие: אילו היה + הייתי + причастие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1548, 127, 'dictation', 3, '{"hint": "Размышление о выборе профессии", "audio_text": "אילו למדתי רפואה במקום כלכלה, הייתי רופא היום ולא יועץ פיננסי"}', '{"correct": "אילו למדתי רפואה במקום כלכלה, הייתי רופא היום ולא יועץ פיננסי"}', '{"text": "Смешанное условие: прошлое → настоящее. יועץ פיננסי — финансовый консультант."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1550, 128, 'fill_blank', 2, '{"hint": "настоял (глагол + предлог)", "sentence": "הוא _____ על שלו ולא ויתר (настоял на своём)"}', '{"correct": "עמד", "alternatives": []}', '{"text": "עמד על (амАд аль) — настоял на. עמד על שלו — настоял на своём."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1552, 128, 'translate_ru_he', 2, '{"hints": ["שמתי לב", "שהוא", "לא בא"], "text_ru": "Я обратил внимание, что он не пришёл"}', '{"correct": "שמתי לב שהוא לא בא", "alternatives": []}', '{"text": "שמתי לב ש — я обратил внимание, что. Идиома שם לב в прошедшем времени."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1555, 128, 'fill_blank', 3, '{"hint": "не рассматривается (глагол)", "sentence": "הנושא הזה לא _____ בחשבון (этот вариант не рассматривается)"}', '{"correct": "בא", "alternatives": []}', '{"text": "לא בא בחשבון — не рассматривается, невозможен. Идиоматическое выражение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1556, 128, 'dictation', 2, '{"hint": "О росте цен", "audio_text": "שמתי לב שהמחירים עלו מאוד בחודש האחרון"}', '{"correct": "שמתי לב שהמחירים עלו מאוד בחודש האחרון"}', '{"text": "שמתי לב — я заметил. המחירים עלו — цены выросли. בחודש האחרון — в последнем месяце."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1558, 128, 'translate_ru_he', 3, '{"hints": ["נושא", "לא", "בחשבון"], "text_ru": "Этот вариант не рассматривается"}', '{"correct": "הנושא הזה לא בא בחשבון", "alternatives": ["זה לא בא בחשבון"]}', '{"text": "לא בא בחשבון — не рассматривается, исключён. Идиома."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1826, 139, 'fill_blank', 2, '{"hint": "предлог על + суффикс", "sentence": "הוא מסתכל _____ (на меня)"}', '{"correct": "עליי", "alternatives": ["עָלַי"]}', '{"text": "עליי / עלי — на меня. Склонение предлога על."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1561, 128, 'fill_blank', 2, '{"hint": "приняли (от לקח)", "sentence": "כולם _____ חלק בפרויקט (все приняли участие)"}', '{"correct": "לקחו", "alternatives": []}', '{"text": "לקח חלק (лакАх хЕлек) — принял участие. לקחו — прош. время, мн.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1562, 128, 'translate_ru_he', 2, '{"hints": ["שברה", "ראש", "שאלה"], "text_ru": "Она долго думала над этим вопросом"}', '{"correct": "היא שברה את הראש על השאלה הזאת", "alternatives": []}', '{"text": "שבר את הראש (шавАр эт hа-рош) — ломал голову. Идиома."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1563, 128, 'dictation', 3, '{"hint": "Настойчивость на совещании", "audio_text": "הוא עמד על שלו בישיבה ובסוף כולם הסכימו איתו"}', '{"correct": "הוא עמד על שלו בישיבה ובסוף כולם הסכימו איתו"}', '{"text": "עמד על שלו — настоял. ישיבה (ешивА) — совещание. הסכימו — согласились."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1565, 129, 'fill_blank', 2, '{"hint": "экзамены на аттестат", "sentence": "בסוף התיכון, התלמידים נבחנים ב_____ (аттестат зрелости)"}', '{"correct": "בגרות", "alternatives": []}', '{"text": "בגרות (багрУт) — выпускные экзамены. נבחנים — сдают экзамены (Нифъаль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3559, 201, 'dictation', 1, '{"hint": "напиток", "word_he": "מים", "word_translit": "мАим"}', '{"accept": ["מים"], "correct": "מים"}', '{"text": "מים (мАим) — напиток"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1567, 129, 'translate_ru_he', 2, '{"hints": ["חינוך", "חובה"], "text_ru": "Образование в Израиле обязательное с 3 до 18 лет"}', '{"correct": "החינוך בישראל הוא חובה מגיל 3 עד 18", "alternatives": []}', '{"text": "חינוך (хинУх) — образование. חובה (ховА) — обязательное."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1570, 129, 'fill_blank', 3, '{"hint": "путешествовать (инфинитив)", "sentence": "אחרי הצבא, רוב הישראלים הולכים ל_____ בעולם (путешествовать по миру)"}', '{"correct": "טייל", "alternatives": ["לטייל"]}', '{"text": "Традиция: после армии — путешествие (обычно в Южную Америку, Индию или Юго-Восточную Азию)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1571, 129, 'dictation', 2, '{"hint": "О структуре образования", "audio_text": "מערכת החינוך בישראל מחולקת לכמה שלבים"}', '{"correct": "מערכת החינוך בישראל מחולקת לכמה שלבים"}', '{"text": "מערכת החינוך — система образования. מחולקת (мехулЕкет) — разделена. שלבים — этапы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1573, 129, 'translate_ru_he', 3, '{"hints": ["סטודנטים", "מתחילים", "ללמוד", "מאוחר"], "text_ru": "Студенты в Израиле начинают учиться позже, чем в большинстве стран"}', '{"correct": "סטודנטים בישראל מתחילים ללמוד מאוחר יותר מברוב המדינות", "alternatives": []}', '{"text": "מאוחר יותר — позже. מברוב המדינות — чем в большинстве стран."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1576, 129, 'fill_blank', 2, '{"hint": "учительница", "sentence": "ה_____ שלנו מצוינת ומלמדת היטב (наша учительница)"}', '{"correct": "מורה", "alternatives": []}', '{"text": "מורה (морА) — учительница. מורה (морЕ) — учитель (м.р.). Одинаковое написание!"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1577, 129, 'translate_ru_he', 2, '{"hints": ["ציון", "טוב", "מבחן"], "text_ru": "Я получил хорошую оценку за экзамен"}', '{"correct": "קיבלתי ציון טוב במבחן", "alternatives": []}', '{"text": "ציון (циЮн) — оценка. קיבלתי — я получил (Пиэль от קבל)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1578, 129, 'dictation', 3, '{"hint": "О системе экзаменов багрут", "audio_text": "הבגרות כוללת מקצועות חובה ומקצועות בחירה כמו פיזיקה והיסטוריה"}', '{"correct": "הבגרות כוללת מקצועות חובה ומקצועות בחירה כמו פיזיקה והיסטוריה"}', '{"text": "מקצועות חובה — обязательные предметы. מקצועות בחירה — предметы по выбору."}', 10);
