INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1651, 134, 'fill_blank', 2, '{"hint": "врач (м.р.)", "sentence": "הסיבה היא ש_____ הנוכחי עובד בשעות שלא מתאימות (нынешний врач)"}', '{"correct": "הרופא", "alternatives": []}', '{"text": "הסיבה (hа-сибА) — причина. הרופא הנוכחי — нынешний врач."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1652, 134, 'translate_ru_he', 2, '{"hints": ["תודה", "מראש"], "text_ru": "Заранее спасибо"}', '{"correct": "תודה מראש", "alternatives": []}', '{"text": "תודה מראש (тодА мерОш) — заранее спасибо. Частая формула в формальных письмах."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1653, 134, 'dictation', 3, '{"hint": "Просьба в письме", "audio_text": "אשמח לקבל רשימה של רופאים פנויים באזור מגוריי בהקדם האפשרי"}', '{"correct": "אשמח לקבל רשימה של רופאים פנויים באזור מגוריי בהקדם האפשרי"}', '{"text": "רשימה — список. פנויים — свободные. אזור מגוריי — район проживания. בהקדם האפשרי — как можно скорее."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1655, 135, 'fill_blank', 2, '{"hint": "я думаю (м.р.)", "sentence": "אני _____ שצריך ללמוד שפות (я думаю, что нужно учить языки)"}', '{"correct": "חושב", "alternatives": []}', '{"text": "אני חושב ש (анИ хошЕв ше) — я думаю, что. Выражение мнения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1657, 135, 'translate_ru_he', 2, '{"hints": ["מסכים", "איתך"], "text_ru": "Я согласен с тобой"}', '{"correct": "אני מסכים איתך", "alternatives": ["אני מסכימה איתך"]}', '{"text": "מסכים (маскИм) — согласен. מסכימה (маскимА) — согласна."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1661, 135, 'dictation', 2, '{"hint": "Частичное согласие", "audio_text": "אני מסכים שצריך ללמוד שפות, אבל לא בטוח שכולם צריכים ללמוד שלוש"}', '{"correct": "אני מסכים שצריך ללמוד שפות, אבל לא בטוח שכולם צריכים ללמוד שלוש"}', '{"text": "Частичное согласие: מסכים ש... אבל... — согласен, что... но..."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1663, 135, 'translate_ru_he', 3, '{"hints": ["ראשית", "חינוך", "חשוב", "שנית", "פותח", "דלתות"], "text_ru": "Во-первых, образование очень важно. Во-вторых, оно открывает двери"}', '{"correct": "ראשית, החינוך מאוד חשוב. שנית, הוא פותח דלתות", "alternatives": []}', '{"text": "ראשית (решИт) — во-первых. שנית (шенИт) — во-вторых. Структура аргументации."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1666, 135, 'fill_blank', 2, '{"hint": "прав (м.р.)", "sentence": "אתה _____, שפות באמת חשובות (ты прав, м.р.)"}', '{"correct": "צודק", "alternatives": []}', '{"text": "צודק (цодЕк) — прав (м.р.). צודקת (цодЕкет) — права (ж.р.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1667, 135, 'translate_ru_he', 2, '{"hints": ["אין ספק", "טכנולוגיות", "משנות", "עולם"], "text_ru": "Нет сомнения, что технологии меняют мир"}', '{"correct": "אין ספק שהטכנולוגיות משנות את העולם", "alternatives": []}', '{"text": "אין ספק ש (эйн сАфек ше) — нет сомнения, что."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1668, 135, 'dictation', 3, '{"hint": "Построение аргумента", "audio_text": "לדעתי, צריך ללמוד שפות כי שפות פותחות דלתות. למשל, אנשים שיודעים אנגלית מוצאים עבודה יותר בקלות"}', '{"correct": "לדעתי, צריך ללמוד שפות כי שפות פותחות דלתות. למשל, אנשים שיודעים אנגלית מוצאים עבודה יותר בקלות"}', '{"text": "Структура: тезис (לדעתי) → довод (כי) → пример (למשל). בקלות — легко."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1670, 136, 'translate_ru_he', 3, '{"hints": ["אילו", "ידעתי", "עברית", "עיתון"], "text_ru": "Если бы я знал иврит лучше, я бы читал газеты каждый день"}', '{"correct": "אילו ידעתי עברית יותר טוב, הייתי קורא עיתון כל יום", "alternatives": []}', '{"text": "Нереальное условие + повседневная тема. Комплексное предложение уровня B1."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1671, 136, 'fill_blank', 2, '{"hint": "что он (косвенная речь)", "sentence": "הוא אמר _____ עובד בהייטק (он сказал, что работает в хай-теке)"}', '{"correct": "שהוא", "alternatives": []}', '{"text": "Косвенная речь: אמר שהוא — сказал, что он."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1674, 136, 'translate_ru_he', 3, '{"hints": ["למרות", "קשיים", "כלכלה", "להתפתח"], "text_ru": "Несмотря на трудности, израильская экономика продолжает развиваться"}', '{"correct": "למרות הקשיים, הכלכלה הישראלית ממשיכה להתפתח", "alternatives": []}', '{"text": "Уступка (למרות) + Хифъиль (ממשיכה) + Хитпаэль (להתפתח). Три конструкции."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1676, 136, 'dictation', 3, '{"hint": "Нереальное условие о чтении газет", "audio_text": "אילו ידעתי עברית יותר טוב, הייתי קורא עיתון כל יום"}', '{"correct": "אילו ידעתי עברית יותר טוב, הייתי קורא עיתון כל יום"}', '{"text": "Комплексная конструкция: нереальное условие + повседневная тема."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1677, 136, 'fill_blank', 3, '{"hint": "несмотря на", "sentence": "_____ הקשיים, הכלכלה ממשיכה להתפתח (несмотря на трудности)"}', '{"correct": "למרות", "alternatives": []}', '{"text": "למרות (ламрОт) — несмотря на. Уступительная конструкция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1680, 136, 'translate_ru_he', 2, '{"hints": ["צריך", "ללמוד", "עברית", "כל יום"], "text_ru": "Я должен учить иврит каждый день"}', '{"correct": "אני צריך ללמוד עברית כל יום", "alternatives": ["אני חייב ללמוד עברית כל יום"]}', '{"text": "Модальность: צריך (должен) + инфинитив. Базовая конструкция B1."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1682, 136, 'dictation', 2, '{"hint": "Итоговый диктант", "audio_text": "הספר שקראתי נכתב על ידי סופר ישראלי מפורסם"}', '{"correct": "הספר שקראתי נכתב על ידי סופר ישראלי מפורסם"}', '{"text": "Определительное придаточное (שקראתי) + Нифъаль (נכתב) + на ידי. Три конструкции."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1827, 139, 'fill_blank', 2, '{"hint": "предлог על + 2ms", "sentence": "אנחנו חושבים _____ (о тебе, м.)"}', '{"correct": "עליך", "alternatives": ["עָלֶיךָ"]}', '{"text": "עליך — о тебе. Склонение предлога על, 2ms."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1683, 136, 'translate_ru_he', 3, '{"hints": ["אם", "תלמד", "כל יום", "תצליח"], "text_ru": "Если будешь учиться каждый день, ты обязательно преуспеешь"}', '{"correct": "אם תלמד כל יום, בוודאי תצליח", "alternatives": ["אם תלמד כל יום, בטוח תצליח"]}', '{"text": "Реальное условие: אם + будущее → будущее. בוודאי — обязательно, наверняка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1686, 35, 'fill_blank', 2, '{"hint": "союз причины", "sentence": "הוא לא בא לעבודה _____ שהוא חולה (потому что)"}', '{"correct": "בגלל", "alternatives": ["מכיוון"]}', '{"text": "בגלל ש / מכיוון ש — потому что. Оба вводят придаточное причины."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1687, 35, 'fill_blank', 2, '{"hint": "хотя / несмотря на", "sentence": "_____ הגשם, נשארנו בבית (несмотря на)"}', '{"correct": "למרות", "alternatives": ["על אף"]}', '{"text": "למרות / על אף — несмотря на. Вводят уступительное придаточное."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1690, 35, 'translate_ru_he', 2, '{"hints": ["לא באתי", "כי", "חולה"], "text_ru": "Я не пришёл, потому что был болен"}', '{"correct": "לא באתי כי הייתי חולה", "alternatives": ["לא באתי בגלל שהייתי חולה"]}', '{"text": "כי / בגלל ש — «потому что»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1691, 35, 'translate_ru_he', 2, '{"hints": ["למרות", "הגשם", "טיילנו"], "text_ru": "Несмотря на дождь, мы гуляли в парке"}', '{"correct": "למרות הגשם, טיילנו בפארק", "alternatives": []}', '{"text": "למרות + существительное — уступительная конструкция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1692, 35, 'dictation', 2, '{"hint": "Несмотря на холод, дети вышли играть", "audio_text": "למרות שהיה קר מאוד, הילדים יצאו לשחק בחוץ"}', '{"correct": "למרות שהיה קר מאוד, הילדים יצאו לשחק בחוץ"}', '{"text": "למרות ש — вводит уступительное придаточное."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1693, 35, 'dictation', 2, '{"hint": "Я пришёл рано, чтобы найти хорошее место", "audio_text": "באתי מוקדם כדי למצוא מקום ישיבה טוב"}', '{"correct": "באתי מוקדם כדי למצוא מקום ישיבה טוב"}', '{"text": "כדי + инфинитив — придаточное цели."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1696, 36, 'fill_blank', 2, '{"hint": "отглагольное сущ. от להתכונן", "sentence": "ה_____ של הסטודנטים לבחינה הייתה מאומצת (подготовка)"}', '{"correct": "הִתְכּוֹנְנוּת", "alternatives": ["היערכות"]}', '{"text": "הִתְכּוֹנְנוּת — отглагольное сущ. Хитпаэль: התכוננות от להתכונן."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1697, 36, 'fill_blank', 2, '{"hint": "отглагольное сущ. от להתפתח", "sentence": "_____ התעשייה תרמה לזיהום (развитие)"}', '{"correct": "הִתְפַּתְּחוּת", "alternatives": []}', '{"text": "הִתְפַּתְּחוּת — развитие. Мишкаль הִתְקַטְּלוּת для Хитпаэля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1700, 36, 'translate_ru_he', 2, '{"hints": ["למידה", "עברית", "סבלנות"], "text_ru": "Изучение иврита требует терпения"}', '{"correct": "למידת עברית דורשת סבלנות", "alternatives": ["לימוד עברית דורש סבלנות"]}', '{"text": "למידת — смихут от למידה. Или לימוד (мужской вариант)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1701, 36, 'translate_ru_he', 2, '{"hints": ["התפתחות", "טכנולוגיה", "חברה"], "text_ru": "Развитие технологий изменило общество"}', '{"correct": "התפתחות הטכנולוגיה שינתה את החברה", "alternatives": []}', '{"text": "התפתחות — отглагольное сущ. Хитпаэля от להתפתח."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1702, 36, 'dictation', 2, '{"hint": "Инвестиции в образование — ключ к развитию общества", "audio_text": "ההשקעה בחינוך היא המפתח להתפתחות החברה"}', '{"correct": "ההשקעה בחינוך היא המפתח להתפתחות החברה"}', '{"text": "השקעה — отглагольное от להשקיע, התפתחות — от להתפתח."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1703, 36, 'dictation', 2, '{"hint": "Понимание проблемы — первый шаг к её решению", "audio_text": "הבנת הבעיה היא הצעד הראשון לפתרונה"}', '{"correct": "הבנת הבעיה היא הצעד הראשון לפתרונה"}', '{"text": "הבנת — смихут от הבנה (понимание), פתרונה = פתרון + שלה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1706, 37, 'fill_blank', 2, '{"hint": "Пааль, прошедшее, 3ms", "sentence": "הילד _____ את המכתב (написал — Пааль)"}', '{"correct": "כָּתַב", "alternatives": []}', '{"text": "כָּתַב — Пааль, прошедшее, 3ms. Базовая форма активного действия."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4104, 213, 'fill_blank', 1, '{"hint": "Глагол «говорить»", "sentence": "הוא _____ עברית ורוסית"}', '{"accept": ["מדבר"], "correct": "מדבר"}', '{"text": "מדבר = говорит"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1710, 37, 'translate_ru_he', 2, '{"hints": ["המורה", "הסביר", "שיעור"], "text_ru": "Учитель объяснил урок ученикам"}', '{"correct": "המורה הסביר את השיעור לתלמידים", "alternatives": []}', '{"text": "הסביר — Хифъиль от שורש ס.ב.ר. Каузативное значение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1711, 37, 'translate_ru_he', 2, '{"hints": ["הילדים", "התלבשו", "מהר"], "text_ru": "Дети оделись быстро"}', '{"correct": "הילדים התלבשו מהר", "alternatives": []}', '{"text": "התלבשו — Хитпаэль (рефлексив) от שורש ל.ב.ש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1712, 37, 'dictation', 2, '{"hint": "Учитель учил учеников и они хорошо выучили", "audio_text": "המורה לימד את התלמידים והם למדו היטב"}', '{"correct": "המורה לימד את התלמידים והם למדו היטב"}', '{"text": "לימד (Пиэль) — учил (кого-то), למדו (Пааль) — учились."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1713, 37, 'dictation', 2, '{"hint": "Дверь открылась сама, когда подул сильный ветер", "audio_text": "הדלת נפתחה מעצמה כשהרוח נשבה בחוזקה"}', '{"correct": "הדלת נפתחה מעצמה כשהרוח נשבה בחוזקה"}', '{"text": "נפתחה — Нифъаль от פ.ת.ח, рефлексив: открылась сама."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1716, 38, 'fill_blank', 2, '{"hint": "уровень роста цен", "sentence": "שיעור ה_____ בישראל עומד על כ-3% (инфляция)"}', '{"correct": "אינפלציה", "alternatives": ["אִינְפְלַצְיָה"]}', '{"text": "אינפלציה — инфляция. שיעור האינפלציה — уровень инфляции."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1717, 38, 'fill_blank', 2, '{"hint": "что экспортирует Израиль", "sentence": "ישראל מייצאת _____ רבות בתחום ההייטק (технологии)"}', '{"correct": "טכנולוגיות", "alternatives": []}', '{"text": "Израиль — один из мировых лидеров в экспорте технологий."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1720, 38, 'translate_ru_he', 2, '{"hints": ["שיעור", "אבטלה", "ירד"], "text_ru": "Уровень безработицы снизился"}', '{"correct": "שיעור האבטלה ירד", "alternatives": []}', '{"text": "שיעור האבטלה — уровень безработицы. ירד — снизился."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1721, 38, 'translate_ru_he', 2, '{"hints": ["בנק ישראל", "העלה", "ריבית"], "text_ru": "Центральный банк повысил процентную ставку"}', '{"correct": "בנק ישראל העלה את הריבית", "alternatives": []}', '{"text": "בנק ישראל — Центральный банк Израиля. ריבית — процентная ставка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1722, 38, 'dictation', 2, '{"hint": "Израильская промышленность сосредоточена на хайтеке и инновациях", "audio_text": "התעשייה הישראלית מתמקדת בתחומי ההייטק והחדשנות"}', '{"correct": "התעשייה הישראלית מתמקדת בתחומי ההייטק והחדשנות"}', '{"text": "מתמקדת — Хитпаэль: сосредоточена. תעשייה — промышленность."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1723, 38, 'dictation', 2, '{"hint": "Правительство утвердило новый бюджет на следующий год", "audio_text": "הממשלה אישרה את התקציב החדש לשנה הבאה"}', '{"correct": "הממשלה אישרה את התקציב החדש לשנה הבאה"}', '{"text": "אישרה — Пиэль: утвердила. תקציב — бюджет."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1726, 39, 'fill_blank', 2, '{"hint": "тот кто судит", "sentence": "ה_____ החליט לזכות את הנאשם (судья)"}', '{"correct": "שופט", "alternatives": ["שׁוֹפֵט"]}', '{"text": "שופט (шофЕт) — судья. מ שורש ש.פ.ט — судить."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1727, 39, 'fill_blank', 2, '{"hint": "свободный от обвинений", "sentence": "הנאשם הוכרז _____ מאשמה (невиновным)"}', '{"correct": "חף", "alternatives": ["זכאי"]}', '{"text": "חף מאשמה / זכאי — невиновен. הוכרז — был объявлен (Хуфъаль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1730, 39, 'translate_ru_he', 2, '{"hints": ["עורך דין", "הגן", "לקוח", "בית משפט"], "text_ru": "Адвокат защитил своего клиента в суде"}', '{"correct": "עורך הדין הגן על לקוחו בבית המשפט", "alternatives": []}', '{"text": "הגן על — Хифъиль: защищал. לקוחו = לקוח + שלו."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1731, 39, 'translate_ru_he', 2, '{"hints": ["עד", "העיד", "שופט"], "text_ru": "Свидетель дал показания перед судьёй"}', '{"correct": "העד העיד לפני השופט", "alternatives": []}', '{"text": "העיד — Хифъиль: давал показания. עד — свидетель."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1732, 39, 'dictation', 2, '{"hint": "Верховный суд рассмотрел апелляцию и принял доводы обвиняемого", "audio_text": "בית המשפט העליון דן בערעור וקיבל את טענות הנאשם"}', '{"correct": "בית המשפט העליון דן בערעור וקיבל את טענות הנאשם"}', '{"text": "דן — рассматривал (дело). ערעור — апелляция. טענות — доводы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1733, 39, 'dictation', 2, '{"hint": "Судья приказала адвокатам подать документы до вторника", "audio_text": "השופטת הורתה לעורכי הדין להגיש את המסמכים עד יום שלישי"}', '{"correct": "השופטת הורתה לעורכי הדין להגיש את המסמכים עד יום שלישי"}', '{"text": "הורתה — Хифъиль: приказала. להגיש — подать (Хифъиль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1736, 40, 'fill_blank', 2, '{"hint": "единица текста", "sentence": "בטקסט אקדמי, כל _____ צריכה להכיל רעיון מרכזי אחד (абзац)"}', '{"correct": "פִּסְקָה", "alternatives": ["פיסקה"]}', '{"text": "פסקה — абзац. Каждый абзац академического текста содержит одну главную мысль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1737, 40, 'fill_blank', 2, '{"hint": "знак препинания", "sentence": "יש לשים _____ בין משפטים בפסקה (запятую/точку)"}', '{"correct": "נקודה", "alternatives": ["פסיק"]}', '{"text": "נקודה (точка) или פסיק (запятая) разделяют предложения и части."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1740, 40, 'translate_ru_he', 2, '{"hints": ["כתבו", "פסקה", "נושא", "טיול"], "text_ru": "Напишите абзац на тему путешествия"}', '{"correct": "כתבו פסקה בנושא טיול", "alternatives": []}', '{"text": "כתבו — императив мн.ч. בנושא — на тему."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1741, 40, 'translate_ru_he', 2, '{"hints": ["כל", "משפט", "אות", "גדולה"], "text_ru": "Каждое предложение должно начинаться с заглавной буквы"}', '{"correct": "כל משפט צריך להתחיל באות גדולה", "alternatives": []}', '{"text": "В иврите нет заглавных букв, но правило применяется к латинице."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1742, 40, 'dictation', 2, '{"hint": "Академическое письмо требует точности в использовании слов и структуре предложений", "audio_text": "כתיבה אקדמית דורשת דיוק בשימוש במילים ובמבנה המשפטים"}', '{"correct": "כתיבה אקדמית דורשת דיוק בשימוש במילים ובמבנה המשפטים"}', '{"text": "דיוק — точность. מבנה — структура."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1743, 40, 'dictation', 2, '{"hint": "Первый абзац статьи должен представить главную тему", "audio_text": "הפסקה הראשונה של מאמר צריכה להציג את הנושא המרכזי"}', '{"correct": "הפסקה הראשונה של מאמר צריכה להציג את הנושא המרכזי"}', '{"text": "מאמר — статья. להציג — представить (Хифъиль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1746, 55, 'fill_blank', 2, '{"hint": "Хифъиль от ל.ב.ש", "sentence": "האמא _____ את הילד (одела — Хифъиль)"}', '{"correct": "הִלְבִּישָׁה", "alternatives": ["הלבישה"]}', '{"text": "הלבישה — Хифъиль: одела (кого-то). לבשה — оделась сама."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1747, 55, 'fill_blank', 2, '{"hint": "взаимное действие", "sentence": "התלמידים _____ זה מזה (учились друг у друга — Хитпаэль)"}', '{"correct": "למדו", "alternatives": ["הִתְלַמְּדוּ"]}', '{"text": "Хитпаэль может выражать взаимное действие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1750, 55, 'translate_ru_he', 2, '{"hints": ["היא", "הלבישה", "ילד", "בגדים"], "text_ru": "Она одела ребёнка в тёплую одежду"}', '{"correct": "היא הלבישה את הילד בבגדים חמים", "alternatives": []}', '{"text": "הלבישה — Хифъиль: одела (кого-то). Каузатив."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1751, 55, 'translate_ru_he', 2, '{"hints": ["הספר", "נכתב", "עברית"], "text_ru": "Книга была написана на иврите"}', '{"correct": "הספר נכתב בעברית", "alternatives": []}', '{"text": "נכתב — Нифъаль: был написан. Пассив от כתב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1752, 55, 'dictation', 2, '{"hint": "Учитель объяснил материал и ученики поняли его", "audio_text": "המורה הסביר את החומר והתלמידים הבינו אותו"}', '{"correct": "המורה הסביר את החומר והתלמידים הבינו אותו"}', '{"text": "הסביר — Хифъиль. הבינו — Хифъиль: поняли."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1753, 55, 'dictation', 2, '{"hint": "Ребёнок помылся и оделся прежде чем вышел из дома", "audio_text": "הילד התרחץ והתלבש לפני שיצא מהבית"}', '{"correct": "הילד התרחץ והתלבש לפני שיצא מהבית"}', '{"text": "התרחץ, התלבש — Хитпаэль: рефлексивные действия."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1756, 56, 'fill_blank', 2, '{"hint": "предлог «к» + суффикс 1sg", "sentence": "הוא בא _____ (ко мне)"}', '{"correct": "אליי", "alternatives": ["אֵלַי"]}', '{"text": "אליי / אלי — ко мне. От אל + суффикс первого лица."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1757, 56, 'fill_blank', 2, '{"hint": "предлог «при» + суффикс 3fs", "sentence": "יש לה כסף _____ (с собой / при ней)"}', '{"correct": "אצלה", "alternatives": ["אֶצְלָהּ"]}', '{"text": "אצלה — у неё / при ней. От אצל + суффикс 3fs."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1760, 56, 'translate_ru_he', 2, '{"hints": ["הוא", "התקשר", "אליי", "אתמול"], "text_ru": "Он позвонил мне вчера вечером"}', '{"correct": "הוא התקשר אליי אתמול בערב", "alternatives": []}', '{"text": "אליי — ко мне. התקשר אל — позвонил кому-то."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1761, 56, 'translate_ru_he', 2, '{"hints": ["אצלנו", "בבית", "גינה", "גדולה"], "text_ru": "У нас дома есть большой сад"}', '{"correct": "אצלנו בבית יש גינה גדולה", "alternatives": []}', '{"text": "אצלנו — у нас. Предлог אצל + суффикс 1pl."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1762, 56, 'dictation', 2, '{"hint": "Она отправила мне сообщение и я ответил ей сразу", "audio_text": "היא שלחה לי הודעה ואני עניתי לה מיד"}', '{"correct": "היא שלחה לי הודעה ואני עניתי לה מיד"}', '{"text": "לי — мне (ל + суффикс), לה — ей."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1763, 56, 'dictation', 2, '{"hint": "Эта книга принадлежит ему, но он дал её нам", "audio_text": "הספר הזה שייך לו אבל הוא נתן אותו לנו"}', '{"correct": "הספר הזה שייך לו אבל הוא נתן אותו לנו"}', '{"text": "לו — ему, לנו — нам, אותו — его (прямое дополнение)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1766, 57, 'fill_blank', 2, '{"hint": "отглагольное сущ. от להחליט", "sentence": "ה_____ של הממשלה להקפיא מחירים (решение)"}', '{"correct": "הַחְלָטָה", "alternatives": ["החלטה"]}', '{"text": "הַחְלָטָה — решение. Мишкаль הַקְטָלָה от Хифъиль להחליט."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1767, 57, 'fill_blank', 2, '{"hint": "отглагольное сущ. от לפתור", "sentence": "_____ הבעיה דורש מאמץ רב (решение проблемы)"}', '{"correct": "פִּתְרוֹן", "alternatives": ["פתרון"]}', '{"text": "פתרון — решение (проблемы). Мишкаль קִטְלוֹן."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1770, 57, 'translate_ru_he', 2, '{"hints": ["הכשרה", "עובדים", "חדשים", "שבוע"], "text_ru": "Обучение новых сотрудников продолжается неделю"}', '{"correct": "הכשרת עובדים חדשים נמשכת שבוע", "alternatives": []}', '{"text": "הכשרת — смихут от הכשרה (обучение, Хифъиль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1771, 57, 'translate_ru_he', 2, '{"hints": ["התנהגות", "סטודנטים", "השתפרה"], "text_ru": "Поведение студентов улучшилось"}', '{"correct": "התנהגות הסטודנטים השתפרה", "alternatives": []}', '{"text": "התנהגות — поведение (Хитпаэль). השתפרה — улучшилось."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1772, 57, 'dictation', 2, '{"hint": "Влияние технологий на поведение потребителей значительно", "audio_text": "השפעת הטכנולוגיה על התנהגות הצרכנים היא משמעותית"}', '{"correct": "השפעת הטכנולוגיה על התנהגות הצרכנים היא משמעותית"}', '{"text": "השפעת — смихут от השפעה. התנהגות — поведение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1773, 57, 'dictation', 2, '{"hint": "Понимание проблемы — первый шаг к её решению", "audio_text": "הבנת הבעיה היא השלב הראשון בפתרונה"}', '{"correct": "הבנת הבעיה היא השלב הראשון בפתרונה"}', '{"text": "הבנת, פתרונה — номинализированные формы со смихутом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1111, 108, 'multiple_choice', 2, '{"options": ["חשמלאי", "שרברב", "נגר", "צבעי"], "question": "Как сказать «водопроводчик»?"}', '{"correct": "שרברב", "correct_index": 1}', '{"text": "שרברב (шрабрАв) — водопроводчик."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1776, 58, 'fill_blank', 2, '{"hint": "кто ведёт новостной выпуск", "sentence": "ה_____ הראשי של ערוץ 12 דיווח על האירוע (ведущий)"}', '{"correct": "מגיש", "alternatives": ["מַגִּישׁ"]}', '{"text": "מגיש (магИш) — ведущий (программы). От Хифъиль של ג.ש.ש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1777, 58, 'fill_blank', 2, '{"hint": "פעל в пассиве", "sentence": "הכתבה _____ אמש בחדשות הערב (была передана)"}', '{"correct": "שודרה", "alternatives": ["שֻׁדְּרָה"]}', '{"text": "שודרה — была передана (Пуаль от שידר). Пассив Пиэля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1780, 58, 'translate_ru_he', 2, '{"hints": ["עיתונאי", "ראיין", "שר"], "text_ru": "Журналист взял интервью у министра"}', '{"correct": "העיתונאי ראיין את השר", "alternatives": []}', '{"text": "ראיין — Пиэль: взял интервью. שר — министр."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1781, 58, 'translate_ru_he', 2, '{"hints": ["עיתון", "פרסם", "כתבה", "שחיתות"], "text_ru": "Газета опубликовала статью о коррупции"}', '{"correct": "העיתון פרסם כתבה על שחיתות", "alternatives": []}', '{"text": "פרסם — Пиэль: опубликовал. שחיתות — коррупция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1782, 58, 'dictation', 2, '{"hint": "Журналист расследовал дело и опубликовал спецрепортаж в газете", "audio_text": "העיתונאי חקר את הפרשה ופרסם כתבה מיוחדת בעיתון"}', '{"correct": "העיתונאי חקר את הפרשה ופרסם כתבה מיוחדת בעיתון"}', '{"text": "חקר — исследовал. פרשה — дело/скандал. כתבה — репортаж."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1783, 58, 'dictation', 2, '{"hint": "Ведущая прочитала новости и затем взяла интервью у гостя в студии", "audio_text": "המגישה קראה את החדשות ואחר כך ראיינה את האורח באולפן"}', '{"correct": "המגישה קראה את החדשות ואחר כך ראיינה את האורח באולפן"}', '{"text": "מגישה — ведущая. ראיינה — взяла интервью. אולפן — студия."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1786, 59, 'fill_blank', 2, '{"hint": "процесс превращения солёной воды в пресную", "sentence": "ישראל מובילה בתחום _____ המים (опреснение)"}', '{"correct": "הַתְפָּלָה", "alternatives": ["התפלה"]}', '{"text": "התפלה — опреснение. Израиль опресняет ~80% питьевой воды."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1787, 59, 'fill_blank', 2, '{"hint": "природа и среда вокруг нас", "sentence": "יש לשמור על ה_____ לדורות הבאים (окружающая среда)"}', '{"correct": "סביבה", "alternatives": ["סְבִיבָה"]}', '{"text": "סביבה — окружающая среда. שמירה על הסביבה — охрана природы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1806, 137, 'fill_blank', 2, '{"hint": "Пиэль от ס.ב.ר", "sentence": "המורה _____ לתלמידים את החומר (объяснил)"}', '{"correct": "הסביר", "alternatives": ["הִסְבִּיר"]}', '{"text": "הסביר — Хифъиль от ס.ב.ר. Каузативное: сделал понятным."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1790, 59, 'translate_ru_he', 2, '{"hints": ["עלינו", "לשמור", "סביבה"], "text_ru": "Мы должны беречь окружающую среду"}', '{"correct": "עלינו לשמור על הסביבה", "alternatives": []}', '{"text": "עלינו — мы должны. לשמור על — беречь."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1791, 59, 'translate_ru_he', 2, '{"hints": ["אנרגיה", "סולארית", "זולה"], "text_ru": "Солнечная энергия становится дешевле"}', '{"correct": "האנרגיה הסולארית הופכת לזולה יותר", "alternatives": []}', '{"text": "הופכת ל — становится. Перифраза прогрессивного изменения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1823, 138, 'dictation', 2, '{"hint": "Дверь захлопнулась и окно разбилось от шума", "audio_text": "הדלת נסגרה בחזקה והחלון נשבר מהרעש"}', '{"correct": "הדלת נסגרה בחזקה והחלון נשבר מהרעש"}', '{"text": "נסגרה, נשבר — Нифъаль: инхоативные значения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1792, 59, 'dictation', 2, '{"hint": "Израиль разработал передовые технологии опреснения морской воды", "audio_text": "ישראל פיתחה טכנולוגיות מתקדמות להתפלת מי ים"}', '{"correct": "ישראל פיתחה טכנולוגיות מתקדמות להתפלת מי ים"}', '{"text": "פיתחה — Пиэль: разработала. התפלת — смихут от התפלה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1793, 59, 'dictation', 2, '{"hint": "Рециклинг экономит природные ресурсы и уменьшает загрязнение", "audio_text": "המיחזור חוסך משאבים טבעיים ומפחית את הזיהום"}', '{"correct": "המיחזור חוסך משאבים טבעיים ומפחית את הזיהום"}', '{"text": "חוסך — экономит. מפחית — уменьшает (Хифъиль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1796, 60, 'fill_blank', 2, '{"hint": "предложение закона", "sentence": "הצעת ה_____ אושרה על ידי הוועדה (закон)"}', '{"correct": "חוק", "alternatives": ["חֹק"]}', '{"text": "הצעת חוק — законопроект. אושרה — была утверждена (Пуаль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1797, 60, 'fill_blank', 2, '{"hint": "обязанность действовать", "sentence": "על הממשלה _____ צעדים לשיפור המצב (принять)"}', '{"correct": "לנקוט", "alternatives": ["לאמץ"]}', '{"text": "לנקוט צעדים — принять меры. Или לאמץ צעדים."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1800, 60, 'translate_ru_he', 2, '{"hints": ["חוק", "אושר", "רוב", "קולות"], "text_ru": "Закон был принят большинством голосов"}', '{"correct": "החוק אושר ברוב קולות", "alternatives": []}', '{"text": "אושר — Пуаль: был утверждён. ברוב קולות — большинством голосов."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1801, 60, 'translate_ru_he', 2, '{"hints": ["החלטה", "ממשלה", "השפיעה", "כלכלה"], "text_ru": "Решение правительства повлияло на экономику"}', '{"correct": "החלטת הממשלה השפיעה על הכלכלה", "alternatives": []}', '{"text": "השפיעה — Хифъиль: повлияла. החלטת — смихут."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1802, 60, 'dictation', 2, '{"hint": "Несмотря на политические разногласия, Кнессет утвердил бюджет большинством голосов", "audio_text": "על אף המחלוקות הפוליטיות, הכנסת אישרה את התקציב ברוב קולות"}', '{"correct": "על אף המחלוקות הפוליטיות, הכנסת אישרה את התקציב ברוב קולות"}', '{"text": "מחלוקות — разногласия. אישרה — Пиэль: утвердила."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1803, 60, 'dictation', 2, '{"hint": "Инвестиции в образование приведут к значительному улучшению качества жизни", "audio_text": "ההשקעה בחינוך תביא לשיפור משמעותי באיכות החיים"}', '{"correct": "ההשקעה בחינוך תביא לשיפור משמעותי באיכות החיים"}', '{"text": "השקעה — инвестиция. שיפור — улучшение. איכות החיים — качество жизни."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1810, 137, 'translate_ru_he', 2, '{"hints": ["מורה", "לימד", "ילדים", "שיר"], "text_ru": "Учитель научил детей новой песне"}', '{"correct": "המורה לימד את הילדים שיר חדש", "alternatives": []}', '{"text": "לימד — Пиэль: научил. Интенсивное действие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1811, 137, 'translate_ru_he', 2, '{"hints": ["מנהל", "החליט", "לסגור", "מוקדם"], "text_ru": "Директор решил закрыть школу рано"}', '{"correct": "המנהל החליט לסגור את בית הספר מוקדם", "alternatives": []}', '{"text": "החליט — Хифъиль: решил. לסגור — закрыть."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1812, 137, 'dictation', 2, '{"hint": "Учитель учил студентов и объяснил им правила", "audio_text": "המורה לימד את התלמידים והסביר להם את הכללים"}', '{"correct": "המורה לימד את התלמידים והסביר להם את הכללים"}', '{"text": "לימד — Пиэль: учил. הסביר — Хифъиль: объяснил."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1813, 137, 'dictation', 2, '{"hint": "Врач вылечил больного и вернул ему здоровье", "audio_text": "הרופא ריפא את החולה והחזיר אותו לבריאות"}', '{"correct": "הרופא ריפא את החולה והחזיר אותו לבריאות"}', '{"text": "ריפא — Пиэль. החזיר — Хифъиль: вернул."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1816, 138, 'fill_blank', 2, '{"hint": "Хитпаэль от י.ע.ד", "sentence": "הם _____ לפגישה בשלוש (договорились)"}', '{"correct": "נועדו", "alternatives": ["הִתְיַעֲדוּ"]}', '{"text": "נועדו — Нифъаль: договорились / были назначены."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1817, 138, 'fill_blank', 2, '{"hint": "Нифъаль от ש.ב.ר", "sentence": "הכוס _____ כשנפלה מהשולחן (разбился)"}', '{"correct": "נשברה", "alternatives": ["נִשְׁבְּרָה"]}', '{"text": "נשברה — Нифъаль: разбилась. Инхоативное значение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1820, 138, 'translate_ru_he', 2, '{"hints": ["ילדים", "התפייסו", "ריב"], "text_ru": "Дети помирились после ссоры"}', '{"correct": "הילדים התפייסו אחרי הריב", "alternatives": []}', '{"text": "התפייסו — Хитпаэль: помирились (взаимное действие)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1821, 138, 'translate_ru_he', 2, '{"hints": ["דלת", "נפתחה", "רוח"], "text_ru": "Дверь открылась от ветра"}', '{"correct": "הדלת נפתחה מהרוח", "alternatives": []}', '{"text": "נפתחה — Нифъаль: открылась (инхоативное значение)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1822, 138, 'dictation', 2, '{"hint": "Дети подготовились к экзамену и очень старались", "audio_text": "הילדים התכוננו למבחן והתאמצו מאוד"}', '{"correct": "הילדים התכוננו למבחן והתאמצו מאוד"}', '{"text": "התכוננו, התאמצו — Хитпаэль: рефлексивные действия."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1830, 139, 'translate_ru_he', 2, '{"hints": ["חושב", "עליו", "כל יום"], "text_ru": "Я думаю о нём каждый день"}', '{"correct": "אני חושב עליו כל יום", "alternatives": []}', '{"text": "עליו — о нём. חושב על — думать о."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1831, 139, 'translate_ru_he', 2, '{"hints": ["בינינו", "סוד"], "text_ru": "Между нами, это секрет"}', '{"correct": "בינינו, זה סוד", "alternatives": []}', '{"text": "בינינו — между нами. Предлог בין + суффикс 1pl."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1832, 139, 'dictation', 2, '{"hint": "Он всегда думает о ней и очень скучает по ней", "audio_text": "הוא תמיד חושב עליה ומתגעגע אליה מאוד"}', '{"correct": "הוא תמיד חושב עליה ומתגעגע אליה מאוד"}', '{"text": "עליה — о ней. אליה — по ней."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1833, 139, 'dictation', 2, '{"hint": "Они поговорили между собой и решили решить проблему вместе", "audio_text": "הם דיברו ביניהם והחליטו לפתור את הבעיה ביחד"}', '{"correct": "הם דיברו ביניהם והחליטו לפתור את הבעיה ביחד"}', '{"text": "ביניהם — между собой/ними."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1836, 140, 'fill_blank', 2, '{"hint": "отглагольное сущ. от ללמוד", "sentence": "ה_____ באוניברסיטה נמשכת ארבע שנים (учёба)"}', '{"correct": "לְמִידָה", "alternatives": ["למידה"]}', '{"text": "למידה — учёба. Мишкаль קטילה от Пааль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1837, 140, 'fill_blank', 2, '{"hint": "отглагольное сущ. от לצאת", "sentence": "_____ העובדים לשביתה הפתיעה את ההנהלה (выход)"}', '{"correct": "יציאת", "alternatives": ["יְצִיאַת"]}', '{"text": "יציאת — смихут от יציאה (выход)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1840, 140, 'translate_ru_he', 2, '{"hints": ["הבנה", "טקסט", "ריכוז"], "text_ru": "Понимание текста требует концентрации"}', '{"correct": "הבנת הטקסט דורשת ריכוז", "alternatives": []}', '{"text": "הבנת — смихут. ריכוז — концентрация."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1841, 140, 'translate_ru_he', 2, '{"hints": ["בנייה", "בניין", "שנתיים"], "text_ru": "Строительство здания заняло два года"}', '{"correct": "בניית הבניין נמשכה שנתיים", "alternatives": []}', '{"text": "בניית — смихут от בנייה. נמשכה — продолжалась."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1842, 140, 'dictation', 2, '{"hint": "Инвестиции в образование приводят к заметному улучшению качества жизни", "audio_text": "ההשקעה בחינוך מביאה לשיפור ניכר באיכות החיים"}', '{"correct": "ההשקעה בחינוך מביאה לשיפור ניכר באיכות החיים"}', '{"text": "השקעה, שיפור, איכות — номинализации."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1843, 140, 'dictation', 2, '{"hint": "Поведение правительства подверглось острой критике оппозиции", "audio_text": "התנהלות הממשלה זכתה לביקורת חריפה מצד האופוזיציה"}', '{"correct": "התנהלות הממשלה זכתה לביקורת חריפה מצד האופוזיציה"}', '{"text": "התנהלות — поведение (Хитпаэль). ביקורת — критика."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1846, 141, 'fill_blank', 2, '{"hint": "юрист, представляющий клиента", "sentence": "ה_____ הגיש ערעור לבית המשפט העליון (адвокат)"}', '{"correct": "עורך הדין", "alternatives": ["עוה\"ד"]}', '{"text": "עורך הדין (орЕх ха-дИн) — адвокат."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1847, 141, 'fill_blank', 2, '{"hint": "глагол наказания от суда", "sentence": "בית המשפט _____ את הנאשם לעשר שנות מאסר (приговорил)"}', '{"correct": "גזר", "alternatives": ["דן"]}', '{"text": "גזר דין — вынес приговор. Или דן — судил, приговорил."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1850, 141, 'translate_ru_he', 2, '{"hints": ["בית משפט", "גזר דין", "נאשם"], "text_ru": "Суд вынес приговор обвиняемому"}', '{"correct": "בית המשפט גזר את דינו של הנאשם", "alternatives": []}', '{"text": "גזר דין — вынес приговор. Юридическая формула."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1851, 141, 'translate_ru_he', 2, '{"hints": ["עורך דין", "הגיש", "ערעור"], "text_ru": "Адвокат подал апелляцию"}', '{"correct": "עורך הדין הגיש ערעור", "alternatives": []}', '{"text": "הגיש — Хифъиль: подал. ערעור — апелляция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1852, 141, 'dictation', 2, '{"hint": "Обвиняемый утверждал что невиновен и его адвокат подал апелляцию", "audio_text": "הנאשם טען שהוא חף מפשע ועורך דינו הגיש ערעור"}', '{"correct": "הנאשם טען שהוא חף מפשע ועורך דינו הגיש ערעור"}', '{"text": "חף מפשע — невиновен. ערעור — апелляция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1853, 141, 'dictation', 2, '{"hint": "Верховный суд принял апелляцию и оправдал обвиняемого", "audio_text": "בית המשפט העליון קיבל את הערעור וזיכה את הנאשם"}', '{"correct": "בית המשפט העליון קיבל את הערעור וזיכה את הנאשם"}', '{"text": "זיכה — Пиэль: оправдал."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1856, 142, 'fill_blank', 2, '{"hint": "тот кто пишет в газету", "sentence": "ה_____ פרסם כתבת חקר על שחיתות (журналист)"}', '{"correct": "עיתונאי", "alternatives": ["כתב"]}', '{"text": "עיתונאי — журналист. כתב — корреспондент."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1857, 142, 'fill_blank', 2, '{"hint": "главная строка статьи", "sentence": "ה_____ המרכזית של היום עוסקת בבחירות (заголовок)"}', '{"correct": "כותרת", "alternatives": ["כּוֹתֶרֶת"]}', '{"text": "כותרת — заголовок. כותרת ראשית — главный заголовок."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1860, 142, 'translate_ru_he', 2, '{"hints": ["עורך", "אישר", "פרסום", "כתבה"], "text_ru": "Редактор утвердил публикацию статьи"}', '{"correct": "העורך אישר את פרסום הכתבה", "alternatives": []}', '{"text": "פרסום — публикация. אישר — Пиэль: утвердил."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1861, 142, 'translate_ru_he', 2, '{"hints": ["חדשות", "משודרות", "כל ערב"], "text_ru": "Новости транслируются каждый вечер"}', '{"correct": "החדשות משודרות כל ערב", "alternatives": []}', '{"text": "משודרות — Пуаль: транслируются. Пассив Пиэля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1862, 142, 'dictation', 2, '{"hint": "Корреспондент репортажил с места событий в реальном времени", "audio_text": "הכתב דיווח מהשטח על אירועי היום בזמן אמת"}', '{"correct": "הכתב דיווח מהשטח על אירועי היום בזמן אמת"}', '{"text": "דיווח — Пиэль: репортажил. בזמן אמת — в реальном времени."}', 10);
