INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1, 1, 'multiple_choice', 1, '{"options": ["ג", "ב", "ד", "א"], "question": "Какая буква произносится как ''б'' или ''в''?"}', '{"correct": "ב", "correct_index": 1}', '{"text": "Бет (ב) произносится как ''б'' с дагешем и как ''в'' без дагеша"}', 10);
