INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (12, 11, 'multiple_choice', 2, '{"options": ["כותב", "כותבים", "כותבות", "כותבת"], "question": "Какая форма настоящего времени для женского рода множественного числа (כ.ת.ב)?"}', '{"correct": "כותבות", "correct_index": 2}', '{"text": "כּוֹתְבוֹת (котвОт) — ж.р. мн.ч. от корня כ.ת.ב"}', 10);
