INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (57, 35, 'multiple_choice', 4, '{"options": ["או", "גם", "לכן", "אבל"], "question": "Какой союз означает ''поэтому''?"}', '{"correct": "לכן", "correct_index": 2}', '{"text": "לכן (лахЕн) = поэтому, следовательно"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (60, 37, 'multiple_choice', 4, '{"options": ["למד (Пааль)", "לומד (Пуаль)", "לימד (Пиэль)", "התלמד (Хитпаэль)"], "question": "Какой биньян корня ל.מ.ד означает ''обучал (других)''?"}', '{"correct": "לימד (Пиэль)", "correct_index": 2}', '{"text": "Пиэль = интенсив/каузатив: לימד = обучал"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (63, 41, 'multiple_choice', 5, '{"options": ["учил", "можно учиться", "нужно учиться", "дано учиться"], "question": "Что означает ''ניתן ללמוד''?"}', '{"correct": "можно учиться", "correct_index": 1}', '{"text": "ניתן + инфинитив = безличная конструкция ''можно''"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (66, 45, 'multiple_choice', 6, '{"options": ["Амихай", "Альтерман", "Рахель", "Бялик"], "question": "Кто написал стихотворение ''У меня была любовь'' (היתה לי אהבה)?"}', '{"correct": "Рахель", "correct_index": 2}', '{"text": "Рахель (רחל) — одна из самых любимых поэтесс Израиля"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (71, 50, 'multiple_choice', 3, '{"options": ["כי", "כש-", "כדי ש-", "למרות ש-"], "question": "Какой союз означает «несмотря на то что»?"}', '{"correct": "למרות ש-", "correct_index": 3}', '{"text": "למרות ש- (ламрОт ше-) = несмотря на то что. כי = потому что, כש- = когда, כדי ש- = чтобы."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (75, 52, 'multiple_choice', 3, '{"options": ["לכתוב מכתב לקופת החולים", "ללכת ישר לבית החולים", "להתקשר למשטרה", "לקבל הפניה מרופא המשפחה"], "question": "מה צריך לעשות כדי לקבל תור לרופא מומחה בישראל?"}', '{"correct": "לקבל הפניה מרופא המשפחה", "correct_index": 3}', '{"text": "В Израиле нужно הפניה (направление) от семейного врача, чтобы попасть к специалисту. Без направления — только скорая помощь."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (78, 53, 'multiple_choice', 3, '{"options": ["כי אסור לנהוג ברכב ביום כיפור", "כי זה חג האופניים", "כי בית הספר סגור", "כי יש תחרות אופניים"], "question": "למה ילדים רוכבים על אופניים בכבישים ביום כיפור?"}', '{"correct": "כי אסור לנהוג ברכב ביום כיפור", "correct_index": 0}', '{"text": "В Йом Кипур вся страна останавливается: не ездят машины, не работают магазины, не вещает ТВ. Дети выходят кататься на велосипедах по пустым шоссе — уникальное израильское зрелище!"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (82, 55, 'multiple_choice', 4, '{"options": ["שימר (Пиэль)", "השתמר (Хитпаэль)", "שמר (Пааль)", "נשמר (Нифъаль)"], "question": "Какой биньян корня ש.מ.ר означает «охранял» (активно, как профессия)?"}', '{"correct": "שמר (Пааль)", "correct_index": 2}', '{"text": "שמר (Пааль) = охранял / сторожил. שימר (Пиэль) = сохранял / консервировал. נשמר (Нифъаль) = остерёгся / был сохранён. השתמר (Хитпаэль) = сохранился."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (86, 56, 'multiple_choice', 4, '{"options": ["אלינו", "בשבילנו", "שלנו", "אצלנו"], "question": "Как сказать «у нас» (есть что-то)?"}', '{"correct": "אצלנו", "correct_index": 3}', '{"text": "אצל + נו = אצלנו = у нас (дома, в нашем месте). שלנו = наш (принадлежность). בשבילנו = для нас. אלינו = к нам."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (576, 78, 'multiple_choice', 2, '{"options": ["בדיקה", "תרופה", "מרשם", "ניתוח"], "question": "Как сказать «рецепт» (от врача)?"}', '{"correct": "מרשם", "correct_index": 2}', '{"text": "מרשם (мирШам) — рецепт. תרופה (труфА) — лекарство."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (89, 58, 'multiple_choice', 4, '{"options": ["ערוץ 1", "ערוץ 12", "ערוץ כנסת", "ערוץ הספורט"], "question": "מהו ערוץ החדשות הכי פופולרי בישראל?"}', '{"correct": "ערוץ 12", "correct_index": 1}', '{"text": "Канал 12 (חדשות 12) — самый популярный новостной канал в Израиле. Канал 1 — бывший государственный, сейчас это «Кан» (כאן). В Израиле также популярны Ynet, Walla и подкасты."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (91, 59, 'multiple_choice', 4, '{"options": ["מייבאת מים ממדינות שכנות", "אוספת מי גשם בלבד", "לא פותרת — אין מספיק מים", "משתמשת בהתפלת מי ים"], "question": "כיצד ישראל פותרת את בעיית המים?"}', '{"correct": "משתמשת בהתפלת מי ים", "correct_index": 3}', '{"text": "Израиль — мировой лидер в опреснении морской воды (התפלת מי ים). Пять заводов вдоль побережья дают ~70% питьевой воды страны. Также применяется капельное орошение (השקיה בטפטוף), изобретённое в Израиле."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (97, 61, 'multiple_choice', 5, '{"options": ["порезался", "был точным", "приготовил еду", "рисковал"], "question": "מה הביטוי ''הלך על קצה הסכין'' אומר?"}', '{"correct": "рисковал", "correct_index": 3}', '{"text": "הלך על קצה הסכין = «шёл по лезвию ножа» = рисковал. Аналог русского «ходил по краю»."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (101, 63, 'multiple_choice', 5, '{"options": ["можно сказать", "хочется сказать", "нужно сказать", "дано сказать"], "question": "Что означает безличная конструкция ''ניתן לומר''?"}', '{"correct": "можно сказать", "correct_index": 0}', '{"text": "ניתן + инфинитив = можно (безличная конструкция высокого стиля). Разговорный эквивалент: אפשר + инфинитив."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (104, 64, 'multiple_choice', 5, '{"options": ["Псалмы (Теhилим)", "Пророки", "Тора", "Экклезиаст (Коhелет)"], "question": "Откуда выражение ''אין חדש תחת השמש'' (нет ничего нового под солнцем)?"}', '{"correct": "Экклезиаст (Коhелет)", "correct_index": 3}', '{"text": "קהלת (Экклезиаст) 1:9 — «Что было, то и будет; что делалось, то и будет делаться, и нет ничего нового под солнцем». Одна из самых цитируемых фраз в иврите."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (108, 66, 'multiple_choice', 5, '{"options": ["Буква ת выпадает перед ס", "Это исключение без правила", "Метатеза: ת и ס меняются местами перед свистящими", "Это другой биньян"], "question": "Почему говорят הִסְתַּדֵּר, а не הִתְסַדֵּר?"}', '{"correct": "Метатеза: ת и ס меняются местами перед свистящими", "correct_index": 2}', '{"text": "Когда корень начинается на ס, צ, שׁ, שׂ — буквы ת и первая корневая меняются местами.\nהת + סדר → הסתדר, הת + צלם → הצטלם, הת + שמש → השתמש"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (114, 69, 'multiple_choice', 6, '{"options": ["Иегуда Галеви", "Шмуэль ха-Нагид", "Шломо ибн Габироль", "Моше ибн Эзра"], "question": "Кто из поэтов Золотого века Испании написал «Моё сердце на Востоке, а я на краю Запада» (לבי במזרח ואנוכי בסוף מערב)?"}', '{"correct": "Иегуда Галеви", "correct_index": 0}', '{"text": "Иегуда Галеви (יהודה הלוי, ок. 1075–1141) — величайший поэт еврейского Золотого века в Испании. Строка «לבי במזרח ואנוכי בסוף מערב» выражает тоску по Эрец-Исраэль — центральную тему его поэзии. По преданию, он погиб у стен Иерусалима."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (131, 2, 'multiple_choice', 1, '{"options": ["только согласный в", "и и э", "о и у", "а и э"], "question": "Буква ו (Вав) может выступать как «матерь чтения». Какие гласные звуки она может обозначать?"}', '{"correct": "о и у", "correct_index": 2}', '{"text": "Вав (ו) как матерь чтения передаёт гласные «о» (холам мале — וֹ) и «у» (шурук — וּ). Как согласная буква она читается «в»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (119, 72, 'multiple_choice', 6, '{"options": ["восхитить / поразить", "взорвать что-то", "разозлить кого-то", "головная боль"], "question": "Что означает сленговое выражение ''לפוצץ ת''ראש''?"}', '{"correct": "восхитить / поразить", "correct_index": 0}', '{"text": "לפוצץ ת''ראש (буквально «взорвать голову») = поразить, восхитить. «ההופעה פוצצה לי ת''ראש» = «Концерт снёс мне крышу». Обратите внимание на разговорное ת'' вместо את ה-. Это типичный маркер сленга — сокращение предлога и артикля."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (121, 73, 'multiple_choice', 6, '{"options": ["таргумим", "мидрашим", "пиютим", "лаазим (לעזים)"], "question": "Как называются иноязычные глоссы (пояснения на старофранцузском), которые Раши включал в свои комментарии?"}', '{"correct": "лаазим (לעזים)", "correct_index": 3}', '{"text": "Лаазим (לעזים, от корня ל.ע.ז — говорить на чужом языке) — глоссы Раши на старофранцузском. Он вставлял их, когда не мог подобрать точный эквивалент на иврите. Найдено более 3000 лаазов — они являются ценнейшим источником для изучения старофранцузского языка!"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (159, 15, 'multiple_choice', 2, '{"options": ["אֵיפֹה אַתָּה?", "מֵאַיִן אַתָּה?", "מָה שִׁמְךָ?", "מַה אַתָּה לוֹמֵד?"], "question": "Как сказать «Откуда ты?» на иврите (обращение к мужчине)?"}', '{"correct": "מֵאַיִן אַתָּה?", "correct_index": 1}', '{"text": "מֵאַיִן אַתָּה? (мэ-Аин атА?) — «Откуда ты?» (м.р.). מֵאַיִן — «откуда» (предлог מִן + אַיִן «где»). Ответ: אֲנִי מִ... (ани ми-...) — «Я из...»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (124, 74, 'multiple_choice', 6, '{"options": ["разговорный (сленг)", "стандартный (нейтральный)", "высокий (литературный / юридический)", "смешанный"], "question": "К какому регистру относится предложение: ''אולם, נוכח הנסיבות המשתנות, מן הראוי לשוב ולבחון את הנושא''?"}', '{"correct": "высокий (литературный / юридический)", "correct_index": 2}', '{"text": "Маркеры высокого регистра:\n- אולם (однако) — вместо разговорного אבל\n- נוכח (ввиду) — вместо בגלל\n- מן הראוי (подобает) — вместо צריך\n- לשוב ולבחון (вернуться и рассмотреть) — инфинитивная пара\nВсё это — безошибочные признаки юридического или парламентского стиля."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (599, 80, 'multiple_choice', 1, '{"options": ["הזמנה", "תפריט", "מנה", "חשבון"], "question": "Как сказать «меню» на иврите?"}', '{"correct": "תפריט", "correct_index": 1}', '{"text": "תפריט (тафрИт) — меню."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (130, 2, 'multiple_choice', 1, '{"options": ["ח (Хет)", "ו (Вав)", "ט (Тет)", "ז (Зайин)"], "question": "Какая буква обозначает звук «з»?"}', '{"correct": "ז (Зайин)", "correct_index": 3}', '{"text": "Буква ז (Зайин) обозначает звук «з». Её числовое значение — 7."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (134, 2, 'multiple_choice', 2, '{"options": ["Только ו", "ט, ו и י", "ו и י", "ט и ו"], "question": "В слове טוֹב (тов — «хороший») какие буквы из группы Вав–Йуд присутствуют?"}', '{"correct": "ט и ו", "correct_index": 3}', '{"text": "В слове טוֹב (тов) присутствуют буквы ט (Тет) и ו (Вав с холамом, обозначающая гласный «о»). Буква ב (Бет) не входит в группу этого урока."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (135, 3, 'multiple_choice', 1, '{"options": ["г", "х", "с", "ш"], "question": "Буква כ (Каф) с дагешем читается как «к», а без дагеша — как…"}', '{"correct": "х", "correct_index": 1}', '{"text": "Каф (כ) — одна из букв бегадкефат. С дагешем она читается «к» (כּ), без дагеша — «х» (כ, звучит как ח)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (138, 3, 'multiple_choice', 2, '{"options": ["מ и ל", "Все пять букв группы", "Только מ", "מ, ל и כ"], "question": "В слове מֶלֶךְ (мелех — «царь») какие буквы из группы Каф–Самех используются?"}', '{"correct": "מ, ל и כ", "correct_index": 3}', '{"text": "В слове מֶלֶךְ (мелех) присутствуют три буквы из данной группы: מ (Мем), ל (Ламед) и ך (Каф-софит — конечная форма כ)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (140, 4, 'multiple_choice', 1, '{"options": ["По точке: справа — «ш» (שׁ), слева — «с» (שׂ)", "По соседним гласным", "По положению в слове", "Всегда читается одинаково"], "question": "Буква ש может произноситься двумя способами. Как определить произношение?"}', '{"correct": "По точке: справа — «ш» (שׁ), слева — «с» (שׂ)", "correct_index": 0}', '{"text": "Когда точка стоит над правым «рогом» буквы (שׁ) — это Шин (звук «ш»). Когда точка стоит над левым «рогом» (שׂ) — это Син (звук «с»)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (142, 4, 'multiple_choice', 1, '{"options": ["С дагешем — «п», без дагеша — «ф»", "Всегда «п»", "Всегда «ф»", "С дагешем — «ф», без дагеша — «п»"], "question": "Буква פ (Пей) — одна из букв бегадкефат. Как она произносится с дагешем и без?"}', '{"correct": "С дагешем — «п», без дагеша — «ф»", "correct_index": 0}', '{"text": "Буква פ (Пей): с дагешем (פּ) читается «п», без дагеша (פ) — «ф». Это одна из шести букв бегадкефат (ב ג ד כ פ ת)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (144, 4, 'multiple_choice', 2, '{"options": ["ר (Реш)", "ק (Куф)", "ע (Айин)", "צ (Цади)"], "question": "Какая буква в современном иврите практически не произносится (немая)?"}', '{"correct": "ע (Айин)", "correct_index": 2}', '{"text": "В современном иврите буква ע (Айин) обычно не произносится (гортанная смычка утрачена). Однако в восточном (мизрахи) произношении она сохраняет звук."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (145, 5, 'multiple_choice', 1, '{"options": ["3", "5", "4", "7"], "question": "Сколько букв ивритского алфавита имеют конечную форму (софит)?"}', '{"correct": "5", "correct_index": 1}', '{"text": "Пять букв имеют конечную форму (софит): כ→ך, מ→ם, נ→ן, פ→ף, צ→ץ. Запоминают аббревиатурой כמנפ\"צ (камнапац)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (148, 5, 'multiple_choice', 2, '{"options": ["ו", "ל", "ש", "ם"], "question": "В слове שָׁלוֹם (шалом) какая буква стоит в конечной позиции, но НЕ имеет формы софит?"}', '{"correct": "ם", "correct_index": 3}', '{"text": "Внимание: ם — это и ЕСТЬ конечная форма (Мем-софит). Вопрос с подвохом: в слове שָׁלוֹם буква ם как раз является софитом. Все буквы, стоящие в конце слова и имеющие софит, должны быть записаны именно в конечной форме."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (150, 10, 'multiple_choice', 1, '{"options": ["עַל", "בְּ", "מִ", "לְ"], "question": "Какой предлог в иврите означает «в» / «внутри»?"}', '{"correct": "בְּ", "correct_index": 1}', '{"text": "Предлог בְּ (бэ-) означает «в», «внутри». Он пишется слитно с существительным: בְּבַיִת (бэвАйит) — «в доме»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (155, 15, 'multiple_choice', 1, '{"options": ["Библиотека", "Школа для изучения иврита новыми репатриантами", "Университет", "Детский сад"], "question": "Что такое «ульпан» (אוּלְפָּן)?"}', '{"correct": "Школа для изучения иврита новыми репатриантами", "correct_index": 1}', '{"text": "Ульпан (אוּלְפָּן) — это специальная школа интенсивного изучения иврита, предназначенная прежде всего для новых репатриантов (олим хадашим) в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (160, 13, 'multiple_choice', 2, '{"options": ["Без окончания", "-תָּ (та)", "-נוּ (ну)", "-תִּי (ти)"], "question": "Какое окончание получает глагол в прошедшем времени для формы אֲנִי (я)?"}', '{"correct": "-תִּי (ти)", "correct_index": 3}', '{"text": "В прошедшем времени (עָבָר) форма первого лица единственного числа образуется добавлением суффикса -תִּי: כָּתַבְתִּי (катАвти) — «я написал(а)», לָמַדְתִּי (ламАдти) — «я учил(а)»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (435, 6, 'multiple_choice', 1, '{"options": ["патАх", "цЕре", "хирИк", "кубУц"], "question": "Как называется огласовка, обозначающая звук «у»?"}', '{"correct": "кубУц", "correct_index": 3}', '{"text": "Кубуц (  ֻ ) — три диагональные точки под буквой, обозначает звук «у»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (164, 13, 'multiple_choice', 3, '{"options": ["מְדַבְּרִים", "דִּבְּרוּ", "דִּבַּרְתִּי", "דִּבֵּר"], "question": "Выберите правильную форму: «Они (м.) говорили» — глагол דִּבֵּר (биньян пиэль)"}', '{"correct": "דִּבְּרוּ", "correct_index": 1}', '{"text": "דִּבְּרוּ (дибрУ) — «они говорили». В 3-м лице мн.ч. прошедшего времени к основе добавляется суффикс וּ-. Форма מְדַבְּרִים — это настоящее время."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (165, 14, 'multiple_choice', 2, '{"options": ["Добавлением префиксов (и иногда суффиксов) к корню", "Добавлением суффиксов к корню", "Изменением огласовок без префиксов", "С помощью вспомогательного глагола"], "question": "Как образуется будущее время в иврите?"}', '{"correct": "Добавлением префиксов (и иногда суффиксов) к корню", "correct_index": 0}', '{"text": "Будущее время (עָתִיד) образуется с помощью префиксов: אֶ- (я), תִּ- (ты/она), יִ- (он), נִ- (мы). Во 2-м и 3-м лице мн.ч. добавляются также суффиксы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (169, 14, 'multiple_choice', 3, '{"options": ["אֶקְרָא", "תִּקְרָא", "קוֹרֵאת", "יִקְרָא"], "question": "Какая форма будущего времени правильна для «она будет читать» (глагол לִקְרוֹא)?"}', '{"correct": "תִּקְרָא", "correct_index": 1}', '{"text": "תִּקְרָא (тикрА) — «она будет читать». Форма 3-го лица ж.р. ед.ч. совпадает с формой 2-го лица м.р. ед.ч. (обе с префиксом תִּ-). Форма קוֹרֵאת — настоящее время."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (170, 16, 'multiple_choice', 2, '{"options": ["?מָתַי זֶה", "?כַּמָּה זֶה עוֹלֶה", "?אֵיפֹה זֶה", "?מָה זֶה"], "question": "Как сказать «Сколько это стоит?» на иврите?"}', '{"correct": "?כַּמָּה זֶה עוֹלֶה", "correct_index": 1}', '{"text": "כַּמָּה זֶה עוֹלֶה? (кАма зэ олЕ?) — «Сколько это стоит?». כַּמָּה — «сколько», עוֹלֶה — «стоит» (от глагола לַעֲלוֹת)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (174, 16, 'multiple_choice', 2, '{"options": ["Большое спасибо", "До свидания", "Пожалуйста", "Извините"], "question": "Что означает фраза «!תּוֹדָה רַבָּה»?"}', '{"correct": "Большое спасибо", "correct_index": 0}', '{"text": "תּוֹדָה רַבָּה (тодА рабА) — «Большое спасибо». תּוֹדָה — «спасибо», רַבָּה — «большое» (ж.р., согласуется с תּוֹדָה)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (177, 17, 'multiple_choice', 2, '{"options": ["הָאָח", "אָחִי", "אַחִים", "אָח שֶׁלִּי"], "question": "Как будет «мой брат» на иврите с использованием притяжательного суффикса?"}', '{"correct": "אָחִי", "correct_index": 1}', '{"text": "אָחִי (ахИ) — «мой брат». Притяжательный суффикс -י (-и) означает «мой». Форма אָח שֶׁלִּי (ах шелИ) тоже правильна в разговорной речи, но אָחִי — классическая форма."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (179, 17, 'multiple_choice', 2, '{"options": ["הוֹרִים", "מִשְׁפָּחָה", "קְרוֹבִים", "יְלָדִים"], "question": "Какое слово обозначает «родители» на иврите?"}', '{"correct": "הוֹרִים", "correct_index": 0}', '{"text": "הוֹרִים (хорИм) — «родители». Единственное число: הוֹרֶה (хорЕ) — «родитель». Слово יְלָדִים — «дети», מִשְׁפָּחָה — «семья», קְרוֹבִים — «родственники»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (182, 26, 'multiple_choice', 2, '{"options": ["כִּי", "גַּם", "בְּנוֹסָף", "אֲבָל"], "question": "Какое слово-связка используется в иврите для начала нового абзаца или мысли, аналогично русскому «кроме того» / «также»?"}', '{"correct": "בְּנוֹסָף", "correct_index": 2}', '{"text": "בְּנוֹסָף (бэносАф) — «кроме того», «в дополнение». Другие связки: גַּם (гам) — «тоже/также», אֲבָל (авАль) — «но», כִּי (ки) — «потому что»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (185, 31, 'multiple_choice', 2, '{"options": ["האגם הכי גדול בישראל", "כרם יין ברמת הגולן", "עיר עתיקה על הר גבוה", "נהר בצפון ישראל"], "question": "לפי הטקסט, מה הכינרת?"}', '{"correct": "האגם הכי גדול בישראל", "correct_index": 0}', '{"text": "בטקסט נכתב: «הכינרת היא האגם הכי גדול בישראל» — Кинерет — самое большое озеро в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (189, 31, 'multiple_choice', 2, '{"options": ["современная", "маленькая", "красивая", "древняя"], "question": "Что означает слово «עתיקה»?"}', '{"correct": "древняя", "correct_index": 3}', '{"text": "עֲתִיקָה (атикА) — древняя, старинная. Мужской род: עָתִיק (атИк)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (190, 32, 'multiple_choice', 2, '{"options": ["ספרות עברית", "משפטים", "כלכלה", "מדעי המחשב"], "question": "מה נטלי לומדת באוניברסיטה?"}', '{"correct": "מדעי המחשב", "correct_index": 3}', '{"text": "בטקסט נכתב: «אני לומדת מדעי המחשב» — Натали изучает компьютерные науки (информатику)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (425, 5, 'multiple_choice', 1, '{"options": ["ן", "ף", "ך", "ם"], "question": "Какая конечная форма у буквы Каф?"}', '{"correct": "ך", "correct_index": 2}', '{"text": "Каф-софит (ך) — конечная форма Каф. Пишется с длинным хвостом вниз."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (194, 32, 'multiple_choice', 2, '{"options": ["כי הן לומדות ספרות עברית", "כי הן ישראליות", "כי הפרופסור ביקש", "כי זו השפה המשותפת שלהן"], "question": "למה נטלי והשותפות שלה מדברות עברית?"}', '{"correct": "כי זו השפה המשותפת שלהן", "correct_index": 3}', '{"text": "Натали и соседки говорят на иврите, потому что это их общий язык (השפה המשותפת). Одна из Бразилии, другая из Франции."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (195, 38, 'multiple_choice', 3, '{"options": ["כי יש בה את החברות הגדולות בעולם", "כי כל התושבים עובדים בטכנולוגיה", "כי יש בה יותר חברות סטארט-אפ לנפש מכל מדינה אחרת", "כי הממשלה מנהלת את כל חברות ההייטק"], "question": "לפי הטקסט, מדוע ישראל נקראת ''אומת הסטארט-אפ''?"}', '{"correct": "כי יש בה יותר חברות סטארט-אפ לנפש מכל מדינה אחרת", "correct_index": 2}', '{"text": "В тексте говорится: «יש בה יותר חברות סטארט-אפ לנפש מבכל מדינה אחרת בעולם» — больше стартапов на душу населения, чем в любой другой стране."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (199, 38, 'multiple_choice', 3, '{"options": ["להגן על גבולות ישראל", "להכשיר צעירים בתחומי הסייבר והטכנולוגיה", "לנהל את הכלכלה הישראלית", "לפתח נשק חדש"], "question": "מהו התפקיד של יחידת 8200 לפי הטקסט?"}', '{"correct": "להכשיר צעירים בתחומי הסייבר והטכנולוגיה", "correct_index": 1}', '{"text": "В тексте: «יחידות כמו 8200 מכשירות צעירים בתחומי הסייבר והטכנולוגיה» — подразделения вроде 8200 готовят молодёжь в области кибербезопасности."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (200, 39, 'multiple_choice', 3, '{"options": ["שלוש", "ארבע", "חמש", "שתיים"], "question": "כמה דרגות יש במערכת המשפט הישראלית?"}', '{"correct": "שלוש", "correct_index": 0}', '{"text": "В тексте: «מערכת המשפט בישראל מבוססת על שלושה דרגות» — судебная система основана на трёх уровнях: Верховный суд, окружные суды, мировой суд."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (204, 39, 'multiple_choice', 3, '{"options": ["רק שופטים בכירים", "ראש הממשלה בלבד", "שופטים, פוליטיקאים ונציגי לשכת עורכי הדין", "רק פוליטיקאים"], "question": "מי חברי הוועדה הממנה שופטים לבית המשפט העליון?"}', '{"correct": "שופטים, פוליטיקאים ונציגי לשכת עורכי הדין", "correct_index": 2}', '{"text": "В тексте: «ועדה מיוחדת הכוללת שופטים, פוליטיקאים ונציגי לשכת עורכי הדין» — комиссия включает судей, политиков и представителей коллегии адвокатов."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (205, 43, 'multiple_choice', 5, '{"options": ["שירת הטבע בארץ ישראל", "קונפליקטים פוליטיים בלבד", "ספרות מדע בדיוני", "הזהות הישראלית והמתח בין הפרט לקולקטיב"], "question": "מהו הנושא המרכזי ביצירתו של עמוס עוז?"}', '{"correct": "הזהות הישראלית והמתח בין הפרט לקולקטיב", "correct_index": 3}', '{"text": "עמוס עוז (1939–2018) הוא מגדולי הסופרים הישראליים. יצירותיו חוקרות את הזהות הישראלית, את המתח בין הפרט לחברה, ואת הקשר העמוק בין משפחה לפוליטיקה. רומנים כמו «סיפור על אהבה וחושך» ו-«מיכאל שלי» הם קלאסיקות של הספרות העברית."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (209, 43, 'multiple_choice', 5, '{"options": ["проза с поэтическим, эмоциональным языком", "проза, переведённая с другого языка", "проза для детей", "проза, написанная в стихотворной форме"], "question": "מהי המשמעות של הביטוי ''פרוזה לירית''?"}', '{"correct": "проза с поэтическим, эмоциональным языком", "correct_index": 0}', '{"text": "פרוזה לירית (лирическая проза) — жанр, в котором прозаический текст обладает ритмом и образностью поэзии. Давид Гроссман и Меир Шалев часто пишут в этом стиле, сочетая повествование с глубокой метафоричностью."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (212, 44, 'multiple_choice', 5, '{"options": ["פתאום (вдруг)", "בקיצור (короче говоря)", "אז (тогда / ну)", "ראשית (во-первых)"], "question": "איזו מילת קישור מתאימה לפתוח פסקת טיעון בחיבור?"}', '{"correct": "ראשית (во-первых)", "correct_index": 3}', '{"text": "Связки для структурирования эссе: ראשית (во-первых), שנית (во-вторых), בנוסף לכך (кроме того), לעומת זאת (с другой стороны), לסיכום (в заключение). Использование этих маркеров — признак академического стиля."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (215, 47, 'multiple_choice', 6, '{"options": ["официальные источники / представители", "случайные свидетели", "простые граждане", "иностранные журналисты"], "question": "מהי המשמעות של הביטוי ''גורמים רשמיים'' בכתבה עיתונאית?"}', '{"correct": "официальные источники / представители", "correct_index": 0}', '{"text": "גורמים רשמיים (гормИм ришмийИм) = официальные источники / представители. В газетных статьях часто встречается: «לפי גורמים רשמיים» = по данным официальных источников. Другие клише: גורמים מדיניים (политические круги), גורמים בכירים (высокопоставленные лица)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (431, 5, 'multiple_choice', 2, '{"options": ["ך", "ם", "מ", "ן"], "question": "В слове שלום конечная Мем пишется как…"}', '{"correct": "ם", "correct_index": 1}', '{"text": "В конце слова שלום Мем пишется в конечной форме — ם."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (433, 5, 'multiple_choice', 2, '{"options": ["200", "500", "400", "300"], "question": "Числовое значение буквы ת (Тав)?"}', '{"correct": "400", "correct_index": 2}', '{"text": "Тав (ת) — числовое значение 400, самое большое среди букв."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (441, 6, 'multiple_choice', 2, '{"options": ["знак отсутствия гласной или краткий «э»", "долгий звук «а»", "звук «о»", "ударение"], "question": "Шва (  ְ ) — это…"}', '{"correct": "знак отсутствия гласной или краткий «э»", "correct_index": 0}', '{"text": "Шва (  ְ ) — две вертикальные точки. Может быть немым или подвижным (краткий «э»)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (220, 48, 'multiple_choice', 6, '{"options": ["מסקנות, מבוא, גוף העבודה, ביבליוגרפיה", "מבוא, סקירת ספרות, ממצאים, דיון, מסקנות", "גוף העבודה, מבוא, ביבליוגרפיה, סקירת ספרות", "ביבליוגרפיה, מבוא, מסקנות, ממצאים"], "question": "מהו הסדר הנכון של חלקי עבודה אקדמית?"}', '{"correct": "מבוא, סקירת ספרות, ממצאים, דיון, מסקנות", "correct_index": 1}', '{"text": "Структура академической работы: מבוא (мавО) = введение, סקירת ספרות (скирАт сифрУт) = обзор литературы, ממצאים (мимцаИм) = результаты, דיון (диЮн) = обсуждение, מסקנות (маскенОт) = выводы. Эта структура стандартна для всех научных работ на иврите."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (413, 3, 'multiple_choice', 2, '{"options": ["50", "80", "70", "60"], "question": "Какое числовое значение у буквы ס (Самех)?"}', '{"correct": "60", "correct_index": 3}', '{"text": "Самех (ס) — числовое значение 60."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (393, 1, 'multiple_choice', 2, '{"options": ["בית (дом)", "הר (гора)", "גן (сад)", "דלת (дверь)"], "question": "Какое слово начинается с буквы ג (Гимель)?"}', '{"correct": "גן (сад)", "correct_index": 2}', '{"text": "גן (ган) — сад, начинается с буквы Гимель."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (384, 1, 'multiple_choice', 1, '{"options": ["ד (Далет)", "ב (Бет)", "א (Алеф)", "ג (Гимель)"], "question": "Какая буква ивритского алфавита идёт первой?"}', '{"correct": "א (Алеф)", "correct_index": 2}', '{"text": "Алеф (א) — первая буква ивритского алфавита. Она обозначает гортанную смычку."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (385, 1, 'multiple_choice', 1, '{"options": ["б", "д", "г", "в"], "question": "Буква ב с дагешем читается как…"}', '{"correct": "б", "correct_index": 0}', '{"text": "Бет (ב) с дагешем (точкой внутри) читается «б», без дагеша — «в»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (391, 1, 'multiple_choice', 2, '{"options": ["читается «х»", "не произносится", "читается «г»", "удваивается"], "question": "Буква ה (Хей) в конце слова обычно…"}', '{"correct": "не произносится", "correct_index": 1}', '{"text": "Буква Хей в конце слова, как правило, не произносится (немая)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (394, 2, 'multiple_choice', 1, '{"options": ["у", "о", "з", "в"], "question": "Буква ו (Вав) как согласная обозначает звук…"}', '{"correct": "в", "correct_index": 3}', '{"text": "Вав (ו) как согласная читается «в». Как матерь чтения — «о» или «у»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (395, 2, 'multiple_choice', 1, '{"options": ["ח (Хет)", "י (Йуд)", "ז (Зайин)", "ט (Тет)"], "question": "Какая буква из этой группы обозначает звук «т»?"}', '{"correct": "ט (Тет)", "correct_index": 3}', '{"text": "Тет (ט) — обозначает звук «т». Не путайте с Тав (ת)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (401, 2, 'multiple_choice', 2, '{"options": ["а", "о", "и", "у"], "question": "Буква י (Йуд) как матерь чтения обозначает гласный…"}', '{"correct": "и", "correct_index": 2}', '{"text": "Йуд (י) как матерь чтения (אם קריאה) обозначает гласную «и»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (403, 2, 'multiple_choice', 2, '{"options": ["י (Йуд)", "ז (Зайин)", "ו (Вав)", "ח (Хет)"], "question": "В слове זית (маслина) какая первая буква?"}', '{"correct": "ז (Зайин)", "correct_index": 1}', '{"text": "זית (зАит) — маслина, начинается с буквы Зайин."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (404, 3, 'multiple_choice', 1, '{"options": ["к", "с", "х", "г"], "question": "Буква כ (Каф) без дагеша читается как…"}', '{"correct": "х", "correct_index": 2}', '{"text": "Каф (כ) без дагеша читается «х». С дагешем (כּ) — «к»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (405, 3, 'multiple_choice', 1, '{"options": ["נ (Нун)", "מ (Мем)", "כ (Каф)", "ל (Ламед)"], "question": "Какая буква из этой группы самая высокая в написании?"}', '{"correct": "ל (Ламед)", "correct_index": 3}', '{"text": "Ламед (ל) — единственная буква, выходящая за верхнюю линию строки."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (411, 3, 'multiple_choice', 2, '{"options": ["ף", "ך", "ן", "ם"], "question": "Конечная форма буквы Нун выглядит как…"}', '{"correct": "ן", "correct_index": 2}', '{"text": "Нун-софит (ן) — длинная вертикальная палочка, спускающаяся ниже строки."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (414, 4, 'multiple_choice', 1, '{"options": ["к", "п", "б", "ф"], "question": "Буква פ (Пей) с дагешем читается как…"}', '{"correct": "п", "correct_index": 1}', '{"text": "Пей (פ) с дагешем (פּ) читается «п», без дагеша — «ф»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (415, 4, 'multiple_choice', 1, '{"options": ["с", "з", "ц", "ш"], "question": "Буква ש (Шин) с точкой слева читается как…"}', '{"correct": "с", "correct_index": 0}', '{"text": "Шин с точкой слева (שׂ) читается «с» (Син). С точкой справа (שׁ) — «ш»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (421, 4, 'multiple_choice', 2, '{"options": ["ע и ק", "פ и צ", "ר и ש", "только ק"], "question": "У какой буквы из этой группы есть конечная форма (софит)?"}', '{"correct": "פ и צ", "correct_index": 1}', '{"text": "Пей-софит (ף) и Цади-софит (ץ) — конечные формы букв из этой группы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (423, 4, 'multiple_choice', 2, '{"options": ["קול (голос)", "שם (имя)", "ראש (голова)", "עין (глаз)"], "question": "Какое слово содержит букву ר (Реш)?"}', '{"correct": "ראש (голова)", "correct_index": 2}', '{"text": "ראש (рош) — голова, начинается с Реш."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (424, 5, 'multiple_choice', 1, '{"options": ["7", "3", "5", "4"], "question": "Сколько конечных форм (софиёт) в ивритском алфавите?"}', '{"correct": "5", "correct_index": 2}', '{"text": "В иврите 5 букв имеют конечную форму: ך ם ן ף ץ."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (443, 6, 'multiple_choice', 2, '{"options": ["цере", "патах", "хирик", "сеголь"], "question": "В слове מֶלֶךְ (царь) какая огласовка стоит под буквой מ?"}', '{"correct": "сеголь", "correct_index": 3}', '{"text": "В слове מֶלֶךְ (мЕлех) под Мем стоит сеголь (  ֶ ) — звук «э»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (444, 7, 'multiple_choice', 1, '{"options": ["ה с патахом (הַ)", "מ с цере", "ב с камацем", "ל с хириком"], "question": "Определённый артикль в иврите — это…"}', '{"correct": "ה с патахом (הַ)", "correct_index": 0}', '{"text": "Определённый артикль הַ (ха-) присоединяется к началу слова слитно."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (445, 7, 'multiple_choice', 1, '{"options": ["בספר", "לספר", "אספר", "הספר"], "question": "Как будет «книга» с определённым артиклем?"}', '{"correct": "הספר", "correct_index": 3}', '{"text": "הספר (ха-сЕфер) — определённая книга (та самая книга)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (451, 7, 'multiple_choice', 2, '{"options": ["הָ (ха с камацем)", "הַ (обычно)", "не ставится", "הֶ (хе)"], "question": "Перед гортанными буквами (א, ה, ח, ע) артикль звучит…"}', '{"correct": "הָ (ха с камацем)", "correct_index": 0}', '{"text": "Перед гортанными буквами артикль принимает камац: הָאִישׁ (ха-Иш)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (453, 7, 'multiple_choice', 2, '{"options": ["только перед существительным: הבית טוב", "перед существительным и прилагательным: הבית הטוב", "только перед прилагательным: בית הטוב", "нигде: בית טוב"], "question": "В словосочетании «хороший дом» артикль ставится…"}', '{"correct": "перед существительным и прилагательным: הבית הטוב", "correct_index": 1}', '{"text": "В определённом словосочетании артикль ставится перед обоими словами: הבית הטוב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (454, 8, 'multiple_choice', 1, '{"options": ["ים-", "ה- или ת-", "ות-", "ן-"], "question": "Типичное окончание существительных женского рода?"}', '{"correct": "ה- или ת-", "correct_index": 1}', '{"text": "Женский род обычно оканчивается на ה- (ялдА) или ת- (мехонИт)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (455, 8, 'multiple_choice', 1, '{"options": ["окончание ן-", "окончание ות-", "окончание ים-", "окончание ת-"], "question": "Как образуется множественное число мужского рода?"}', '{"correct": "окончание ים-", "correct_index": 2}', '{"text": "Множественное число мужского рода: ילד→ילדים (добавляем -ים)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (461, 8, 'multiple_choice', 2, '{"options": ["женского", "общего", "среднего", "мужского"], "question": "Слово שולחן (стол) — какого рода?"}', '{"correct": "мужского", "correct_index": 3}', '{"text": "שולחן (шулхАн) — мужской род, хотя не имеет типичного окончания."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (463, 8, 'multiple_choice', 2, '{"options": ["שנהות", "שנים", "שנות", "שנהים"], "question": "Слово שנה (год) во множественном числе — это…"}', '{"correct": "שנים", "correct_index": 1}', '{"text": "שנה (шанА) → שנים (шанИм). Исключение: женское слово с мужским окончанием во мн.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (464, 9, 'multiple_choice', 1, '{"options": ["אני", "אתה", "אנחנו", "הוא"], "question": "Как переводится «я» на иврит?"}', '{"correct": "אני", "correct_index": 0}', '{"text": "אני (анИ) — я. Одинаково для мужского и женского рода."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (465, 9, 'multiple_choice', 1, '{"options": ["הוא", "את", "אני", "אתה"], "question": "«Ты» для мужчины на иврите — это…"}', '{"correct": "אתה", "correct_index": 3}', '{"text": "אתה (атА) — ты (м.р.). את (ат) — ты (ж.р.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (471, 9, 'multiple_choice', 2, '{"options": ["אתה / את", "אני / הוא", "הוא / אני", "אנחנו / הם"], "question": "Какая пара местоимений различается только по роду?"}', '{"correct": "אתה / את", "correct_index": 0}', '{"text": "אתה (атА) — ты (м.р.) и את (ат) — ты (ж.р.) различаются только родом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (473, 9, 'multiple_choice', 2, '{"options": ["אתם", "אנחנו", "אתן", "הם"], "question": "В иврите «вы» (м.р.) — это…"}', '{"correct": "אתם", "correct_index": 0}', '{"text": "אתם (атЭм) — вы (м.р.). אתן (атЭн) — вы (ж.р.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (474, 10, 'multiple_choice', 1, '{"options": ["מ (ми-)", "על (аль)", "ב (бэ-)", "ל (лэ-)"], "question": "Предлог «в, внутри» на иврите — это…"}', '{"correct": "ב (бэ-)", "correct_index": 2}', '{"text": "ב (бэ-) — предлог «в, внутри». Присоединяется слитно: בבית (ба-бАйит)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (475, 10, 'multiple_choice', 1, '{"options": ["ב (бэ-)", "ל (лэ-)", "מ (ми-)", "את (эт)"], "question": "Предлог «к, для» на иврите — это…"}', '{"correct": "ל (лэ-)", "correct_index": 1}', '{"text": "ל (лэ-) — предлог «к, для, в направлении». Слитно: לבית (ле-бАйит)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (481, 10, 'multiple_choice', 2, '{"options": ["для обозначения времени", "перед прямым определённым дополнением", "для обозначения направления", "для обозначения места"], "question": "Предлог את (эт) используется…"}', '{"correct": "перед прямым определённым дополнением", "correct_index": 1}', '{"text": "את (эт) ставится перед определённым прямым дополнением: אני רואה את הילד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (483, 10, 'multiple_choice', 2, '{"options": ["бу- (בֻּ)", "ба- (בַּ)", "бэ- (בְּ)", "би- (בִּ)"], "question": "Как предлог ב звучит перед определённым артиклем?"}', '{"correct": "ба- (בַּ)", "correct_index": 1}', '{"text": "Перед артиклем הַ предлог ב сливается: ב+ה = בַּ (ба-): בבית → בַּבַּיִת."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (484, 11, 'multiple_choice', 1, '{"options": ["4", "6", "2", "8"], "question": "Сколько форм настоящего времени в биньяне Пааль?"}', '{"correct": "4", "correct_index": 0}', '{"text": "4 формы: м.р. ед.ч., ж.р. ед.ч., м.р. мн.ч., ж.р. мн.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (485, 11, 'multiple_choice', 1, '{"options": ["כותב", "יכתוב", "כתב", "כותבת"], "question": "Глагол לכתוב (писать) в настоящем времени м.р. ед.ч. — это…"}', '{"correct": "כותב", "correct_index": 0}', '{"text": "כותב (котЕв) — пишет (м.р. ед.ч.). Шаблон: ___о___э___."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (503, 12, 'multiple_choice', 2, '{"options": ["7", "3", "10", "5"], "question": "Сколько всего биньянов в иврите?"}', '{"correct": "7", "correct_index": 0}', '{"text": "В иврите 7 биньянов: Пааль, Нифъаль, Пиэль, Пуаль, Хифъиль, Хуфъаль, Хитпаэль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (491, 11, 'multiple_choice', 2, '{"options": ["ת.כ.ב", "כ.ת.ב", "כ.ת.ו", "ל.כ.ת"], "question": "Какой корень у глагола לכתוב (писать)?"}', '{"correct": "כ.ת.ב", "correct_index": 1}', '{"text": "Корень כ.ת.ב (каф-тав-бет). Все формы образуются от этого корня."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (493, 11, 'multiple_choice', 2, '{"options": ["משחקים", "משחקות", "משחקת", "משחק"], "question": "В предложении «Дети играют» глагол «играют» будет…"}', '{"correct": "משחקים", "correct_index": 0}', '{"text": "ילדים משחקים — дети (м.р. или смешанная группа) играют. Окончание -ים."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (494, 12, 'multiple_choice', 1, '{"options": ["Хифъиль (הפעיל)", "Пиэль (פיעל)", "Нифъаль (נפעל)", "Пааль (פעל)"], "question": "Какой биньян является базовым (простым)?"}', '{"correct": "Пааль (פעל)", "correct_index": 3}', '{"text": "Пааль (פעל) — базовый биньян, выражает простое действие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (495, 12, 'multiple_choice', 1, '{"options": ["взаимность", "каузатив", "пассив или возвратность", "усиление"], "question": "Биньян Нифъаль (נפעל) обычно выражает…"}', '{"correct": "пассив или возвратность", "correct_index": 2}', '{"text": "Нифъаль — пассивная форма Пааля или возвратное действие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (501, 12, 'multiple_choice', 2, '{"options": ["Нифъаль (נפעל)", "Хуфъаль (הופעל)", "Хитпаэль (התפעל)", "Пуаль (פועל)"], "question": "Какой биньян является пассивной формой Пиэля?"}', '{"correct": "Пуаль (פועל)", "correct_index": 3}', '{"text": "Пуаль (פועל) — пассивная форма Пиэля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (504, 13, 'multiple_choice', 1, '{"options": ["-та (ת-)", "-ти (תי-)", "-ну (נו-)", "без окончания"], "question": "Какое окончание прошедшего времени для «я» (אני)?"}', '{"correct": "-ти (תי-)", "correct_index": 1}', '{"text": "אני כתבתי (анИ катАвти) — я написал(а). Окончание -תי."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (505, 13, 'multiple_choice', 1, '{"options": ["למדנו", "למד", "למדתי", "למדה"], "question": "Глагол למד (учиться) в прошедшем времени «он» — это…"}', '{"correct": "למד", "correct_index": 1}', '{"text": "הוא למד (hу ламАд) — он учился. Форма 3 л. м.р. ед.ч. — корневая."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (511, 13, 'multiple_choice', 2, '{"options": ["-а (ה-)", "-ну (נו-)", "-ти (תי-)", "-тем (תם-)"], "question": "Какое окончание прошедшего времени для «она» (היא)?"}', '{"correct": "-а (ה-)", "correct_index": 0}', '{"text": "היא כתבה (hи катвА) — она написала. Окончание -ה (а)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (513, 13, 'multiple_choice', 2, '{"options": ["3 лицо мн.ч. (הם)", "2 лицо м.р. ед.ч. (אתה)", "3 лицо м.р. ед.ч. (הוא)", "1 лицо ед.ч. (אני)"], "question": "В каком лице прошедшего времени форма совпадает с инфинитивным корнем?"}', '{"correct": "3 лицо м.р. ед.ч. (הוא)", "correct_index": 2}', '{"text": "Форма 3 л. м.р. ед.ч. — базовая: הוא כתב, הוא למד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (514, 14, 'multiple_choice', 1, '{"options": ["י- (й-)", "נ- (н-)", "ת- (т-)", "א- (э-)"], "question": "Какой префикс будущего времени для «я» (אני)?"}', '{"correct": "א- (э-)", "correct_index": 3}', '{"text": "אני אכתוב (анИ эхтОв) — я напишу. Префикс א-."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (515, 14, 'multiple_choice', 1, '{"options": ["ילמד", "נלמד", "תלמד", "אלמד"], "question": "Глагол ללמוד (учиться) в будущем времени «он» — это…"}', '{"correct": "ילמד", "correct_index": 0}', '{"text": "הוא ילמד (hу йилмАд) — он будет учиться. Префикс י-."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (521, 14, 'multiple_choice', 2, '{"options": ["א- (э-)", "נ- (н-)", "י- (й-)", "ת- (т-)"], "question": "Какой префикс будущего времени для «она» (היא)?"}', '{"correct": "ת- (т-)", "correct_index": 3}', '{"text": "היא תכתוב (hи тихтОв) — она напишет. Префикс ת-."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (582, 78, 'multiple_choice', 2, '{"options": ["שיעול", "חום", "כאב", "צינון"], "question": "Как сказать «температура» (жар)?"}', '{"correct": "חום", "correct_index": 1}', '{"text": "חום (хом) — температура, жар. יש לי חום — у меня температура."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (523, 14, 'multiple_choice', 2, '{"options": ["только ты (м)", "только вы", "только она", "ты (м/ж), она, вы (м/ж)"], "question": "В будущем времени префикс ת- используется для…"}', '{"correct": "ты (м/ж), она, вы (м/ж)", "correct_index": 3}', '{"text": "Префикс ת- общий для: אתה, את, היא, אתם, אתן."}', 10);
