INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (531, 15, 'multiple_choice', 2, '{"options": ["סליחה (извините)", "שלום (привет)", "טוב, תודה (хорошо, спасибо)", "כן (да)"], "question": "Как ответить на вопрос «מה שלומך?» (Как дела?)?"}', '{"correct": "טוב, תודה (хорошо, спасибо)", "correct_index": 2}', '{"text": "טוב, תודה (тов, тодА) — хорошо, спасибо. Стандартный ответ."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (533, 15, 'multiple_choice', 2, '{"options": ["אני לא רוצה", "אני לא מבין", "אני לא יודע", "אני לא כותב"], "question": "Как сказать «Я не понимаю» (м.р.)?"}', '{"correct": "אני לא מבין", "correct_index": 1}', '{"text": "אני לא מבין (анИ ло мевИн) — я не понимаю."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (534, 16, 'multiple_choice', 1, '{"options": ["?כמה זה עולה", "?מה זה", "?מתי זה", "?איפה זה"], "question": "Как спросить «Сколько это стоит?» на иврите?"}', '{"correct": "?כמה זה עולה", "correct_index": 0}', '{"text": "כמה זה עולה? (кАма зе олЕ?) — сколько это стоит?"}', 10);
