INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (651, 83, 'multiple_choice', 1, '{"options": ["רכבת", "מונית", "מכונית", "אוטובוס"], "question": "Как сказать «такси» на иврите?"}', '{"correct": "מונית", "correct_index": 1}', '{"text": "מונית (монИт) — такси. מכונית (мехонИт) — автомобиль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (657, 83, 'multiple_choice', 2, '{"options": ["светофор", "водительские права", "маршрутка", "транспортная карта"], "question": "Что значит «רב-קו» (рав-кав)?"}', '{"correct": "транспортная карта", "correct_index": 3}', '{"text": "רב-קו (рав-кав) — электронная транспортная карта в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (659, 84, 'multiple_choice', 1, '{"options": ["גשם", "שמש", "שלג", "רוח"], "question": "Как сказать «солнце» на иврите?"}', '{"correct": "שמש", "correct_index": 1}', '{"text": "שמש (шЕмеш) — солнце."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (660, 84, 'multiple_choice', 1, '{"options": ["שלג", "ברק", "ענן", "גשם"], "question": "«Дождь» на иврите — это…"}', '{"correct": "גשם", "correct_index": 3}', '{"text": "גשם (гЕшем) — дождь."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (666, 84, 'multiple_choice', 1, '{"options": ["לח", "חם", "יבש", "קר"], "question": "Как сказать «холодно» на иврите?"}', '{"correct": "קר", "correct_index": 3}', '{"text": "קר (кар) — холодно. היום קר — сегодня холодно."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (735, 89, 'multiple_choice', 1, '{"options": ["ל (лэ-)", "עם (им)", "ב (бэ-)", "מ (ми-)"], "question": "Предлог «из, от» на иврите — это…"}', '{"correct": "מ (ми-)", "correct_index": 3}', '{"text": "מ (ми-) — из, от. בא מהעיר — приехал из города."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (672, 84, 'multiple_choice', 2, '{"options": ["зима (חורף)", "лето (קיץ)", "осень (סתיו)", "весна (אביב)"], "question": "Какое время года в Израиле самое дождливое?"}', '{"correct": "зима (חורף)", "correct_index": 0}', '{"text": "Зима (חורף) — сезон дождей в Израиле (декабрь-февраль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (674, 85, 'multiple_choice', 1, '{"options": ["אני צריך לקרוא", "אני רוצה לקרוא", "אני אוהב לקרוא", "אני יכול לקרוא"], "question": "Как сказать «Я люблю читать» (м.р.)?"}', '{"correct": "אני אוהב לקרוא", "correct_index": 2}', '{"text": "אני אוהב לקרוא (анИ оhЕв ликрО) — я люблю читать."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (675, 85, 'multiple_choice', 1, '{"options": ["תיאטרון", "קולנוע", "ספורט", "מוזיקה"], "question": "«Музыка» на иврите — это…"}', '{"correct": "מוזיקה", "correct_index": 3}', '{"text": "מוזיקה (мУзика) — музыка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (681, 85, 'multiple_choice', 1, '{"options": ["תיאטרון", "מוזיקה", "סרט", "קולנוע"], "question": "Как сказать «кино» (как место)?"}', '{"correct": "קולנוע", "correct_index": 3}', '{"text": "קולנוע (кольнОа) — кино. סרט (сЕрет) — фильм."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (687, 85, 'multiple_choice', 2, '{"options": ["לצייר", "לצלם", "לכתוב", "לשיר"], "question": "Как сказать «фотографировать»?"}', '{"correct": "לצלם", "correct_index": 1}', '{"text": "לצלם (лецалЕм) — фотографировать. צילום (цилУм) — фотография."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (689, 86, 'multiple_choice', 1, '{"options": ["-ה (а)", "-ות (от)", "-ים (им)", "-ת (т)"], "question": "Какое окончание множественного числа для мужского рода?"}', '{"correct": "-ים (им)", "correct_index": 2}', '{"text": "Мужской род мн.ч.: ילד→ילדים, ספר→ספרים. Окончание -ים."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (690, 86, 'multiple_choice', 1, '{"options": ["-ות (от)", "-ה (а)", "-ים (им)", "-ן (н)"], "question": "Какое окончание множественного числа для женского рода?"}', '{"correct": "-ות (от)", "correct_index": 0}', '{"text": "Женский род мн.ч.: ילדה→ילדות, מורה→מורות. Окончание -ות."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (696, 86, 'multiple_choice', 2, '{"options": ["שניים", "שנים (с мужским окончанием)", "שנות", "שנהים"], "question": "Слово שנה (год) во множественном числе…"}', '{"correct": "שנים (с мужским окончанием)", "correct_index": 1}', '{"text": "שנה → שנים — исключение: женское слово с мужским окончанием во мн.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (702, 86, 'multiple_choice', 2, '{"options": ["כסאים", "כסאות", "כיסאים", "כיסאות"], "question": "Какое множественное число у слова כיסא (стул)?"}', '{"correct": "כיסאות", "correct_index": 3}', '{"text": "כיסא → כיסאות. Хотя слово мужского рода, окончание -ות."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (704, 87, 'multiple_choice', 1, '{"options": ["приставка הַ", "окончание", "суффикс", "отдельное слово"], "question": "Определённый артикль в иврите — это…"}', '{"correct": "приставка הַ", "correct_index": 0}', '{"text": "הַ — приставка, пишется слитно с существительным: הספר, הילד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (705, 87, 'multiple_choice', 1, '{"options": ["всегда", "когда предмет неизвестен", "когда речь о конкретном предмете", "только с именами собственными"], "question": "В каком случае используется определённый артикль?"}', '{"correct": "когда речь о конкретном предмете", "correct_index": 2}', '{"text": "Артикль הַ указывает на конкретный, известный предмет: הספר — (та самая) книга."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (711, 87, 'multiple_choice', 2, '{"options": ["הִ (хи)", "הַ (обычно)", "הָ (ха с камацем)", "הֶ (хе)"], "question": "Артикль перед гортанными буквами (ח, ע) звучит как…"}', '{"correct": "הָ (ха с камацем)", "correct_index": 2}', '{"text": "Перед ח и ע артикль получает камац: הָעיר, הָחדר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (734, 89, 'multiple_choice', 1, '{"options": ["ל (лэ-)", "ב (бэ-)", "על (аль)", "מ (ми-)"], "question": "Предлог «к, в направлении» на иврите — это…"}', '{"correct": "ל (лэ-)", "correct_index": 0}', '{"text": "ל (лэ-) — к, в направлении, для. הולך לבית — идёт домой."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (717, 87, 'multiple_choice', 2, '{"options": ["перед именами собственными и местоимениями", "перед предлогами", "перед прилагательными", "перед существительными во мн.ч."], "question": "Перед какими словами артикль НЕ ставится?"}', '{"correct": "перед именами собственными и местоимениями", "correct_index": 0}', '{"text": "Имена собственные (דוד, ישראל) и местоимения (אני, הוא) не получают артикль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (719, 88, 'multiple_choice', 1, '{"options": ["על (аль)", "מתחת (митАхат)", "ליד (леяд)", "ב (бэ-)"], "question": "Как сказать «в» (внутри) на иврите?"}', '{"correct": "ב (бэ-)", "correct_index": 3}', '{"text": "ב (бэ-) — в, внутри. Присоединяется слитно: בבית — в доме."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (720, 88, 'multiple_choice', 1, '{"options": ["ליד (леяд)", "ב (бэ-)", "בין (бейн)", "על (аль)"], "question": "Предлог «на» на иврите — это…"}', '{"correct": "על (аль)", "correct_index": 3}', '{"text": "על (аль) — на, над. הספר על השולחן — книга на столе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (2735, 147, 'multiple_choice', 2, '{"options": ["примечания", "титры", "субтитры", "заголовки"], "question": "Что такое כתוביות?"}', '{"correct": "субтитры", "correct_index": 2}', '{"text": "כתוביות — субтитры."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (726, 88, 'multiple_choice', 2, '{"options": ["ליד (леяд)", "מול (муль)", "אחרי (ахарЭй)", "לפני (лифнЭй)"], "question": "Как сказать «напротив» на иврите?"}', '{"correct": "מול (муль)", "correct_index": 1}', '{"text": "מול (муль) — напротив. הבית מול הפארק — дом напротив парка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (732, 88, 'multiple_choice', 2, '{"options": ["בתוך (бетОх)", "ב (бэ-)", "על (аль)", "ליד (леяд)"], "question": "Как сказать «внутри» (более формально, чем ב)?"}', '{"correct": "בתוך (бетОх)", "correct_index": 0}', '{"text": "בתוך (бетОх) — внутри. Более эмфатично, чем просто ב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (741, 89, 'multiple_choice', 2, '{"options": ["ל (лэ-)", "מ (ми-)", "עד (ад)", "אל (эль)"], "question": "Как сказать «до» (предел)?"}', '{"correct": "עד (ад)", "correct_index": 2}', '{"text": "עד (ад) — до. הלכתי עד הים — я дошёл до моря."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (747, 89, 'multiple_choice', 2, '{"options": ["אל используется только с местами", "они полностью одинаковы", "אל более формальный и не присоединяется слитно", "ל используется только с людьми"], "question": "В чём разница между ל и אל?"}', '{"correct": "אל более формальный и не присоединяется слитно", "correct_index": 2}', '{"text": "אל (эль) — более формальный вариант, пишется отдельно. ל — разговорный, слитный."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (749, 90, 'multiple_choice', 1, '{"options": ["?מה השעה", "?מתי השעה", "?איזה שעה", "?כמה הזמן"], "question": "Как спросить «Который час?» на иврите?"}', '{"correct": "?מה השעה", "correct_index": 0}', '{"text": "מה השעה? (ма ха-шаА?) — который час?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (750, 90, 'multiple_choice', 1, '{"options": ["שלוש (шалОш)", "שלושה (шлошА)", "שלישי (шлишИ)", "שלושת (шлОшет)"], "question": "Как сказать «три часа»?"}', '{"correct": "שלוש (шалОш)", "correct_index": 0}', '{"text": "שלוש (шалОш) — три (ж.р.). Часы в иврите — женского рода: השעה שלוש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (756, 90, 'multiple_choice', 2, '{"options": ["רבע ל- (рЕва ле-)", "חצי (хЕци)", "עשר ל- (Эсер ле-)", "חמש ל- (хамЕш ле-)"], "question": "Как сказать «без четверти» (например, 2:45)?"}', '{"correct": "רבע ל- (рЕва ле-)", "correct_index": 0}', '{"text": "רבע לשלוש (рЕва ле-шалОш) — без четверти три (2:45)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (762, 90, 'multiple_choice', 2, '{"options": ["צהריים (цоhорАим)", "בוקר (бОкер)", "לילה (лАйла)", "ערב (Эрев)"], "question": "Как сказать «полдень»?"}', '{"correct": "צהריים (цоhорАим)", "correct_index": 0}', '{"text": "צהריים (цоhорАим) — полдень."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (764, 91, 'multiple_choice', 1, '{"options": ["יום ראשון (воскресенье)", "יום חמישי (четверг)", "יום שני (понедельник)", "יום שבת (суббота)"], "question": "Как называется первый день недели в Израиле?"}', '{"correct": "יום ראשון (воскресенье)", "correct_index": 0}', '{"text": "В Израиле неделя начинается с воскресенья — יום ראשון (йом ришОн)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (765, 91, 'multiple_choice', 1, '{"options": ["שני", "שישי", "שבת", "ראשון"], "question": "Как будет «суббота» на иврите?"}', '{"correct": "שבת", "correct_index": 2}', '{"text": "שבת (шабАт) — суббота, день отдыха в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (771, 91, 'multiple_choice', 1, '{"options": ["כל שבוע", "כל שנה", "כל יום (коль йом)", "כל חודש"], "question": "Как сказать «каждый день»?"}', '{"correct": "כל יום (коль йом)", "correct_index": 2}', '{"text": "כל יום (коль йом) — каждый день."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (777, 91, 'multiple_choice', 2, '{"options": ["שישי (пятница)", "שני (понедельник)", "שבת (суббота)", "ראשון (воскресенье)"], "question": "Какой день в Израиле выходной?"}', '{"correct": "שבת (суббота)", "correct_index": 2}', '{"text": "שבת (шабАт) — главный выходной день в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (779, 92, 'multiple_choice', 1, '{"options": ["...שמי", "...אני קורא", "...אני הולך", "...יש לי"], "question": "Как сказать «Меня зовут…» на иврите?"}', '{"correct": "...שמי", "correct_index": 0}', '{"text": "שמי (шмИ) — меня зовут (буквально: «моё имя»). שמי דוד — меня зовут Давид."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (780, 92, 'multiple_choice', 1, '{"options": ["אני לרוסיה", "אני ברוסיה", "אני רוסיה", "אני מרוסיה"], "question": "Как сказать «Я из России»?"}', '{"correct": "אני מרוסיה", "correct_index": 3}', '{"text": "אני מרוסיה (анИ ми-рУсия) — я из России. Предлог מ — из."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (786, 92, 'multiple_choice', 1, '{"options": ["?מאיפה אתה", "?בן כמה אתה", "?מה אתה עושה", "?מה שמך"], "question": "Как спросить «Сколько тебе лет?» (м.р.)?"}', '{"correct": "?בן כמה אתה", "correct_index": 1}', '{"text": "בן כמה אתה? (бен кАма атА?) — сколько тебе лет?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (792, 92, 'multiple_choice', 2, '{"options": ["?לאן אתה", "?מתי אתה", "?מאיפה אתה", "?איפה אתה"], "question": "Как сказать «Откуда ты?» (м.р.)?"}', '{"correct": "?מאיפה אתה", "correct_index": 2}', '{"text": "מאיפה אתה? (мэ-Эйфо атА?) — откуда ты?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (794, 93, 'multiple_choice', 1, '{"options": ["תחנת רכבת", "מלון", "שדה תעופה", "נמל"], "question": "Как сказать «аэропорт» на иврите?"}', '{"correct": "שדה תעופה", "correct_index": 2}', '{"text": "שדה תעופה (сдЕ теуфА) — аэропорт. Буквально: «поле полётов»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (795, 93, 'multiple_choice', 1, '{"options": ["אשרה", "דרכון", "מזוודה", "כרטיס"], "question": "«Паспорт» на иврите — это…"}', '{"correct": "דרכון", "correct_index": 1}', '{"text": "דרכון (даркОн) — паспорт."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (801, 93, 'multiple_choice', 1, '{"options": ["תיק", "ארנק", "מזוודה", "שקית"], "question": "Как сказать «чемодан» на иврите?"}', '{"correct": "מזוודה", "correct_index": 2}', '{"text": "מזוודה (мизвадА) — чемодан. תיק (тик) — сумка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (807, 93, 'multiple_choice', 2, '{"options": ["נחיתה", "עלייה", "המראה", "טיסה"], "question": "Как сказать «приземление» на иврите?"}', '{"correct": "נחיתה", "correct_index": 0}', '{"text": "נחיתה (нехитА) — приземление. המראה (хамраА) — взлёт."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (809, 94, 'multiple_choice', 1, '{"options": ["33", "22", "26", "28"], "question": "Сколько букв в ивритском алфавите?"}', '{"correct": "22", "correct_index": 1}', '{"text": "В ивритском алфавите 22 буквы (не считая конечных форм)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4310, 215, 'fill_blank', 3, '{"hint": "Наречие «успешно»", "sentence": "הפרויקט הסתיים _____"}', '{"accept": ["בהצלחה"], "correct": "בהצלחה"}', '{"text": "בהצלחה = успешно"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (810, 94, 'multiple_choice', 1, '{"options": ["שלום", "לילה טוב", "ערב טוב", "בוקר טוב"], "question": "Как сказать «Доброе утро» на иврите?"}', '{"correct": "בוקר טוב", "correct_index": 3}', '{"text": "בוקר טוב (бОкер тов) — доброе утро."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (816, 94, 'multiple_choice', 1, '{"options": ["сверху вниз", "слева направо", "снизу вверх", "справа налево"], "question": "В иврите пишут и читают…"}', '{"correct": "справа налево", "correct_index": 3}', '{"text": "Иврит пишется и читается справа налево (מימין לשמאל)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (822, 94, 'multiple_choice', 2, '{"options": ["מדבר (говорит)", "מתלבש (одевается)", "כותב (пишет)", "מלמד (преподаёт)"], "question": "Какой из этих глаголов в биньяне Пааль, настоящее время м.р. ед.ч.?"}', '{"correct": "כותב (пишет)", "correct_index": 2}', '{"text": "כותב (котЕв) — Пааль. מדבר — Пиэль. מתלבש — Хитпаэль. מלמד — Пиэль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (824, 18, 'multiple_choice', 1, '{"options": ["הִפְעִיל (Хифъиль)", "הִתְפַּעֵל (Хитпаэль)", "פָּעַל (Пааль)", "פִּעֵל (Пиэль)"], "question": "Какой биньян является базовым (простое действие)?"}', '{"correct": "פָּעַל (Пааль)", "correct_index": 2}', '{"text": "Пааль (פָּעַל) — базовый биньян, выражает простое действие: כָּתַב (писал), לָמַד (учил)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (825, 18, 'multiple_choice', 1, '{"options": ["פּוּעַל (Пуаль)", "הוּפְעַל (Хуфъаль)", "הִתְפַּעֵל (Хитпаэль)", "נִפְעַל (Нифъаль)"], "question": "Какой биньян образует пассив от Пааль?"}', '{"correct": "נִפְעַל (Нифъаль)", "correct_index": 3}', '{"text": "Нифъаль (נפעל) — пассивная или возвратная форма биньяна Пааль: נִכְתַּב (был написан)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (826, 18, 'multiple_choice', 2, '{"options": ["пассив", "усиление действия", "каузатив", "возвратное действие"], "question": "Биньян Пиэль выражает:"}', '{"correct": "усиление действия", "correct_index": 1}', '{"text": "Пиэль (פִּעֵל) выражает интенсивное / усиленное действие: דִּבֵּר (разговаривал), לִמֵּד (обучал)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (833, 18, 'multiple_choice', 2, '{"options": ["Хифъиль", "Пиэль", "Пааль", "Нифъаль"], "question": "Глагол «הִכְנִיס» (ввёл, внёс) относится к биньяну:"}', '{"correct": "Хифъиль", "correct_index": 0}', '{"text": "הכניס — Хифъиль от корня כ.נ.ס. Хифъиль выражает побудительность: נכנס (вошёл) → הכניס (ввёл)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (834, 19, 'multiple_choice', 1, '{"options": ["-תִּי", "-תָּ", "-וּ", "-נוּ"], "question": "Какой суффикс прошедшего времени для «я» (אני)?"}', '{"correct": "-תִּי", "correct_index": 0}', '{"text": "Суффикс 1-го лица ед.ч. — -תִּי: כָּתַבְתִּי (я написал), לָמַדְתִּי (я учил)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (835, 19, 'multiple_choice', 1, '{"options": ["כָּתַבְתִּי", "כָּתְבָה", "כָּתְבוּ", "כָּתַבְתָּ"], "question": "Как сказать «она написала» в прошедшем времени?"}', '{"correct": "כָּתְבָה", "correct_index": 1}', '{"text": "3-е лицо ж.р. ед.ч. в прошедшем: כָּתְבָה (катвА) — суффикс -ָה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (843, 19, 'multiple_choice', 2, '{"options": ["настоящее", "будущее", "повелительное", "прошедшее"], "question": "В каком времени стоит глагол «שָׁמַרְנוּ»?"}', '{"correct": "прошедшее", "correct_index": 3}', '{"text": "שמרנו (шамАрну) — мы хранили/берегли. Суффикс -נו указывает на прошедшее, 1 л. мн.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (844, 20, 'multiple_choice', 1, '{"options": ["תִּ-", "אֶ-", "נִ-", "יִ-"], "question": "Какая приставка будущего времени для «я» (אני)?"}', '{"correct": "אֶ-", "correct_index": 1}', '{"text": "Приставка 1-го лица ед.ч. будущего — אֶ-: אֶכְתֹּב (я напишу), אֶלְמַד (я буду учить)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (845, 20, 'multiple_choice', 1, '{"options": ["יִכְתְּבוּ", "תִּכְתְּבוּ", "נִכְתֹּב", "אֶכְתֹּב"], "question": "Как сказать «мы напишем»?"}', '{"correct": "נִכְתֹּב", "correct_index": 2}', '{"text": "Приставка נִ- для «мы»: נכתוב (нихтОв) — мы напишем."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (853, 20, 'multiple_choice', 2, '{"options": ["она", "ты (м.р.)", "я", "ты (ж.р.)"], "question": "Форма «תִּכְתְּבִי» — это будущее время для:"}', '{"correct": "ты (ж.р.)", "correct_index": 3}', '{"text": "תכתבי (тихтевИ) — ты напишешь (ж.р.). Суффикс -י отличает 2 л. ж.р. от 3 л. ж.р. (תכתוב)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (854, 21, 'multiple_choice', 1, '{"options": ["?כמה זה עולה", "?איפה זה", "?מה זה", "?למה זה"], "question": "Как спросить «Сколько это стоит?» на иврите?"}', '{"correct": "?כמה זה עולה", "correct_index": 0}', '{"text": "כמה זה עולה? (кАма зэ олЕ?) — Сколько это стоит? Основной вопрос в магазине."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (855, 21, 'multiple_choice', 1, '{"options": ["улица", "школа", "магазин", "дом"], "question": "Что значит «חֲנוּת»?"}', '{"correct": "магазин", "correct_index": 2}', '{"text": "חנות (ханУт) — магазин. Множественное число: חנויות (хануйОт)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (864, 22, 'multiple_choice', 1, '{"options": ["אמא שלי", "אבא שלי", "אח שלי", "אחות שלי"], "question": "Как сказать «моя мама» на иврите?"}', '{"correct": "אמא שלי", "correct_index": 0}', '{"text": "אמא שלי (Има шелИ) — моя мама. שלי — мой/моя (от של + суффикс 1 л.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (865, 22, 'multiple_choice', 1, '{"options": ["бабушка", "дядя", "дедушка", "брат"], "question": "Что значит «סָבָא»?"}', '{"correct": "дедушка", "correct_index": 2}', '{"text": "סבא (сАба) — дедушка. סבתא (сАвта) — бабушка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (873, 22, 'multiple_choice', 2, '{"options": ["ילדות", "ילדים", "ילדי", "ילדן"], "question": "Множественное число от «ילד» (ребёнок):"}', '{"correct": "ילדים", "correct_index": 1}', '{"text": "ילדים (еладИм) — дети (м.р. мн.ч.). Женская форма: ילדות (еладОт) — девочки."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (879, 23, 'multiple_choice', 1, '{"options": ["בית ספר", "בית כנסת", "בית חולים", "בית קפה"], "question": "Какое слово означает «больница»?"}', '{"correct": "בית חולים", "correct_index": 2}', '{"text": "בית חולים (бэйт холИм) — больница (букв. дом больных). Это смихут."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (883, 23, 'multiple_choice', 1, '{"options": ["בית ספור", "בית ספר", "בית צפר", "בית סופר"], "question": "Как правильно написать «школа» на иврите?"}', '{"correct": "בית ספר", "correct_index": 1}', '{"text": "בית ספר (бэйт сЭфер) — школа (букв. дом книги). Пишется как два слова."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (884, 24, 'multiple_choice', 1, '{"options": ["ударением", "первой согласной", "количеством слогов", "гласным звуком: у vs и"], "question": "Чем различаются слова «סוּס» (сус) и «סִיס»?"}', '{"correct": "гласным звуком: у vs и", "correct_index": 3}', '{"text": "סוס (сус — лошадь) содержит шурук (у), а סיס — хирик (и). Согласные одинаковые."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (885, 24, 'multiple_choice', 1, '{"options": ["а и о", "а и у", "э и о", "о и и"], "question": "Какой гласный звук в слове «שָׁלוֹם»?"}', '{"correct": "а и о", "correct_index": 0}', '{"text": "שָׁלוֹם: камац (а) + холам (о). Произносится «шалОм»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (886, 24, 'multiple_choice', 1, '{"options": ["кулЕв", "калАв", "кЕлев", "кИлев"], "question": "Как произносится слово «כֶּלֶב» (собака)?"}', '{"correct": "кЕлев", "correct_index": 2}', '{"text": "כלב — два сеголя (э-э): кЕлев. Ударение на первом слоге."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (893, 24, 'multiple_choice', 2, '{"options": ["гласными звуками", "согласными", "ничем", "количеством букв"], "question": "Слова «דוֹד» (дод — дядя) и «דָּוִד» (давИд — Давид) различаются:"}', '{"correct": "гласными звуками", "correct_index": 0}', '{"text": "דוד (дод) — дядя, с холамом. דָּוִד (давИд) — имя, с камацом и хириком. Одни согласные, разные гласные."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (901, 25, 'multiple_choice', 1, '{"options": ["אני אוהב אותך", "אני אוהב אותך", "אני אוהב שלך", "אני אוהב לך"], "question": "Как правильно написать «Я люблю тебя» (к женщине)?"}', '{"correct": "אני אוהב אותך", "correct_index": 0}', '{"text": "אני אוהב אותך (анИ оhЭв отАх) — я люблю тебя (ж.). Прямое дополнение через את."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (904, 26, 'multiple_choice', 1, '{"options": ["כי", "אבל", "לכן", "גם"], "question": "Какое слово-связка означает «поэтому»?"}', '{"correct": "לכן", "correct_index": 2}', '{"text": "לכן (лахЭн) — поэтому. Связывает причину и следствие: הוא חולה, לכן הוא בבית."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (905, 26, 'multiple_choice', 1, '{"options": ["אבל", "גם", "כי", "לכן"], "question": "Какое слово означает «но» (противопоставление)?"}', '{"correct": "אבל", "correct_index": 0}', '{"text": "אבל (авАль) — но: אני רוצה ללכת, אבל אין לי זמן."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (914, 95, 'multiple_choice', 1, '{"options": ["-תָּ", "-וּ", "-תִּי", "-נוּ"], "question": "Какой суффикс прошедшего времени для 1 л. ед.ч. (אני)?"}', '{"correct": "-תִּי", "correct_index": 2}', '{"text": "Суффикс -תי: כתבתי (я написал), למדתי (я учил)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (915, 95, 'multiple_choice', 1, '{"options": ["они", "она (3 л. ж.р.)", "ты (ж.р.)", "я"], "question": "Форма «כָּתְבָה» — это прошедшее время для:"}', '{"correct": "она (3 л. ж.р.)", "correct_index": 1}', '{"text": "Суффикс -ָה для 3 л. ж.р. ед.ч.: כתבה (катвА) — она написала."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (916, 95, 'multiple_choice', 2, '{"options": ["на первый слог", "на суффикс", "ударение не меняется", "на корень"], "question": "Куда перемещается ударение в прошедшем времени?"}', '{"correct": "на суффикс", "correct_index": 1}', '{"text": "В прошедшем ударение обычно падает на суффикс: כָּתַבְתִּי, לָמַדְתָּ."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (929, 96, 'multiple_choice', 1, '{"options": ["פ\"נ (нун в начале корня)", "ע\"ו (вав в середине)", "правильный", "ל\"ה (hей в конце)"], "question": "К какой группе относится глагол «לתת» (давать)?"}', '{"correct": "פ\"נ (нун в начале корня)", "correct_index": 0}', '{"text": "לתת — корень נ.ת.נ, группа פ\"נ. Буква נ ассимилируется: נָתַן, נָתַתִּי."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3563, 201, 'dictation', 1, '{"hint": "ребёнок мужского пола", "word_he": "ילד", "word_translit": "йЕлед"}', '{"accept": ["ילד"], "correct": "ילד"}', '{"text": "ילד (йЕлед) — ребёнок мужского пола"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (930, 96, 'multiple_choice', 2, '{"options": ["רָאוּ", "רָאָה", "רָאִיתִי", "רָאֲתָה"], "question": "Как будет «я видел» от לראות?"}', '{"correct": "רָאִיתִי", "correct_index": 2}', '{"text": "ראיתי (раИти) — я видел. Группа ל\"ה: конечная ה заменяется на -יתי."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (931, 96, 'multiple_choice', 1, '{"options": ["בָּאנוּ", "בָּא", "בָּאתִי", "בָּאוּ"], "question": "Форма «בָּא» (пришёл) в 1 л. ед.ч.:"}', '{"correct": "בָּאתִי", "correct_index": 2}', '{"text": "באתי (бАти) — я пришёл. Группа ע\"ו: средняя буква «растягивается» в гласную."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4107, 213, 'fill_blank', 1, '{"hint": "Предлог «в» (направление)", "sentence": "אני הולך _____ הספרייה"}', '{"accept": ["ל", "לספרייה", "אל"], "correct": "ל"}', '{"text": "ל = в (направление)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (944, 97, 'multiple_choice', 1, '{"options": ["אֶ-", "נִ-", "תִּ-", "יִ-"], "question": "Какая приставка будущего для 1 л. ед.ч. (אני)?"}', '{"correct": "אֶ-", "correct_index": 0}', '{"text": "Приставка אֶ-: אֶכְתֹּב (я напишу), אֶלְמַד (буду учить)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (945, 97, 'multiple_choice', 1, '{"options": ["אֶ-", "נִ-", "יִ-", "תִּ-"], "question": "Приставка будущего для «мы» (אנחנו):"}', '{"correct": "נִ-", "correct_index": 1}', '{"text": "Приставка נִ-: נכתוב (мы напишем), נלמד (будем учить)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (946, 97, 'multiple_choice', 2, '{"options": ["по контексту и подлежащему", "по ударению", "никак", "по суффиксу"], "question": "Формы «אתה תכתוב» и «היא תכתוב» совпадают. Как различить?"}', '{"correct": "по контексту и подлежащему", "correct_index": 0}', '{"text": "2 м.р. и 3 ж.р. имеют одну приставку תִּ-. Различаются по контексту."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (959, 98, 'multiple_choice', 1, '{"options": ["אלך", "אלכת", "אהלך", "הולך"], "question": "Как сказать «я пойду» от ללכת?"}', '{"correct": "אלך", "correct_index": 0}', '{"text": "אלך (элЭх) — я пойду. Корень ה.ל.כ, неправильный: ה выпадает."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (960, 98, 'multiple_choice', 1, '{"options": ["אל + глагол", "בלי + глагол", "אין + глагол", "לא + глагол в будущем"], "question": "Как образуется отрицание в будущем времени?"}', '{"correct": "לא + глагол в будущем", "correct_index": 3}', '{"text": "Просто לא перед глаголом: לא אלך (не пойду), לא תבוא (не придёт)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (961, 98, 'multiple_choice', 2, '{"options": ["намерение (собираюсь)", "условие", "прошедшее", "приказ"], "question": "Конструкция «הולך + инфинитив» выражает:"}', '{"correct": "намерение (собираюсь)", "correct_index": 0}', '{"text": "אני הולך ללמוד — я собираюсь учиться. Аналог англ. «going to»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (974, 99, 'multiple_choice', 1, '{"options": ["יש אני", "אני יש", "יש שלי", "יש לי"], "question": "Как сказать «у меня есть» на иврите?"}', '{"correct": "יש לי", "correct_index": 3}', '{"text": "יש לי (еш ли) — у меня есть. Предлог ל с суффиксом 1 л."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (975, 99, 'multiple_choice', 1, '{"options": ["их", "его", "её", "наш"], "question": "Форма «שלו» означает:"}', '{"correct": "его", "correct_index": 1}', '{"text": "שלו (шелО) — его. Предлог של с суффиксом 3 м.р."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (976, 99, 'multiple_choice', 2, '{"options": ["הוא ראה אותי", "הוא ראה עלי", "הוא ראה שלי", "הוא ראה לי"], "question": "Как сказать «он увидел меня»?"}', '{"correct": "הוא ראה אותי", "correct_index": 0}', '{"text": "אותי (отИ) — меня. Предлог את с суффиксом 1 л. для прямого дополнения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (989, 100, 'multiple_choice', 1, '{"options": ["сопряжённая конструкция из двух существительных", "вид глагола", "род существительного", "тип предложения"], "question": "Что такое смихут?"}', '{"correct": "сопряжённая конструкция из двух существительных", "correct_index": 0}', '{"text": "Смихут — соединение двух существительных без של: בית ספר (школа = дом книги)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (990, 100, 'multiple_choice', 1, '{"options": ["оба", "ספר", "ни одно", "בית"], "question": "В смихуте «בית ספר» какое слово — нисмах (определяемое)?"}', '{"correct": "בית", "correct_index": 3}', '{"text": "Нисмах (определяемое) стоит первым: בית. Сомех (определяющее): ספר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (991, 100, 'multiple_choice', 2, '{"options": ["перед вторым словом (сомехом)", "перед обоими", "нигде", "перед первым словом"], "question": "Где ставится артикль ה в определённом смихуте?"}', '{"correct": "перед вторым словом (сомехом)", "correct_index": 0}', '{"text": "Артикль ставится только перед сомехом: בית הספר (та школа)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1004, 101, 'multiple_choice', 1, '{"options": ["без -ה (напр. שלוש)", "всегда одинаково", "-ה (напр. שלושה)", "зависит от буквы"], "question": "С мужскими существительными используется форма числительного на:"}', '{"correct": "-ה (напр. שלושה)", "correct_index": 2}', '{"text": "Нелогично: с муж. сущ. — форма на ה: שלושה ילדים (три мальчика)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1005, 101, 'multiple_choice', 1, '{"options": ["חמשה", "חמש", "חמישית", "חמישה"], "question": "Как сказать «пять» с женским существительным?"}', '{"correct": "חמש", "correct_index": 1}', '{"text": "חמש (хамЭш) — пять (с ж.р.): חמש עוגות (пять пирожных)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1006, 101, 'multiple_choice', 2, '{"options": ["понедельник", "вторник", "четверг", "среда"], "question": "Какой день недели — «יום שלישי»?"}', '{"correct": "вторник", "correct_index": 1}', '{"text": "יום שלישי — третий день = вторник. Неделя начинается с воскресенья."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1019, 102, 'multiple_choice', 1, '{"options": ["עורך דין", "רופא", "מהנדס", "מורה"], "question": "Как сказать «инженер» на иврите?"}', '{"correct": "מהנדס", "correct_index": 2}', '{"text": "מהנדס (мэhандЭс) — инженер. Ж.р.: מהנדסת."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1020, 102, 'multiple_choice', 1, '{"options": ["зарплата", "офис", "резюме", "собеседование"], "question": "Что значит «ראיון עבודה»?"}', '{"correct": "собеседование", "correct_index": 3}', '{"text": "ראיון עבודה (реайОн аводА) — собеседование (букв. интервью работы)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4108, 213, 'fill_blank', 1, '{"hint": "Предлог «рядом с»", "sentence": "הכלב _____ הבית"}', '{"accept": ["ליד"], "correct": "ליד"}', '{"text": "ליד = рядом с"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1021, 102, 'multiple_choice', 2, '{"options": ["?מה הניסיון שלך", "?איפה אתה עובד", "?כמה אתה מרוויח", "?מה העבודה שלך"], "question": "Как спросить «Какой у тебя опыт?»"}', '{"correct": "?מה הניסיון שלך", "correct_index": 0}', '{"text": "ניסיון (нисайОн) — опыт. מה הניסיון שלך? — Какой у тебя опыт?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1034, 103, 'multiple_choice', 1, '{"options": ["כואב לי הראש", "אני ראש", "יש לי ראש", "הראש שלי"], "question": "Как сказать «У меня болит голова»?"}', '{"correct": "כואב לי הראש", "correct_index": 0}', '{"text": "כואב לי הראש (коЭв ли hа-рош). Безличная конструкция: болит + мне + часть тела."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1035, 103, 'multiple_choice', 1, '{"options": ["поликлиника", "больница", "аптека", "лаборатория"], "question": "Что значит «בית מרקחת»?"}', '{"correct": "аптека", "correct_index": 2}', '{"text": "בית מרקחת (бэйт миркАхат) — аптека (букв. дом снадобий)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1036, 103, 'multiple_choice', 2, '{"options": ["אני חום", "יש לי חום", "חום שלי", "כואב לי חום"], "question": "Как сказать «У меня температура»?"}', '{"correct": "יש לי חום", "correct_index": 1}', '{"text": "יש לי חום (еш ли хом) — у меня температура. חום — жар/температура."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1049, 104, 'multiple_choice', 1, '{"options": ["?מה זה", "?למה", "?איך מגיעים ל", "?איפה זה"], "question": "Как спросить «Как добраться до...?»"}', '{"correct": "?איך מגיעים ל", "correct_index": 2}', '{"text": "איך מגיעים ל... (эйх магиИм ле...) — Как добраться до..."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1050, 104, 'multiple_choice', 1, '{"options": ["поезд", "такси", "автобус", "самолёт"], "question": "Что значит «רכבת»?"}', '{"correct": "поезд", "correct_index": 0}', '{"text": "רכבת (ракЕвет) — поезд. Удобен для маршрута ТА ↔ Иерусалим."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1051, 104, 'multiple_choice', 2, '{"options": ["?למה כרטיס", "?מתי כרטיס", "?איפה כרטיס", "?כמה עולה כרטיס"], "question": "Как сказать «Сколько стоит билет?»"}', '{"correct": "?כמה עולה כרטיס", "correct_index": 3}', '{"text": "כמה עולה כרטיס? (кАма олЕ картИс?) — Сколько стоит билет?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1064, 105, 'multiple_choice', 1, '{"options": ["ירוק", "אדום", "כחול", "צהוב"], "question": "Как сказать «синий» на иврите (м.р.)?"}', '{"correct": "כחול", "correct_index": 2}', '{"text": "כחול (кахОль) — синий. Ж.р.: כחולה (кхулА)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1065, 105, 'multiple_choice', 1, '{"options": ["Можно примерить?", "Можно скидку?", "Можно поменять?", "Можно посмотреть?"], "question": "Что означает «אפשר למדוד?»"}', '{"correct": "Можно примерить?", "correct_index": 0}', '{"text": "אפשר למדוד (эфшАр лимдОд) — Можно примерить?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1066, 105, 'multiple_choice', 2, '{"options": ["!יקר מדי", "!גדול מדי", "!זול מדי", "!קטן מדי"], "question": "Как сказать «Слишком дорого!»?"}', '{"correct": "!יקר מדי", "correct_index": 0}', '{"text": "יקר מדי (якАр мидАй) — слишком дорого. מדי — слишком."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1079, 106, 'multiple_choice', 1, '{"options": ["אני כועס", "אני שמח", "אני עייף", "אני עצוב"], "question": "Как сказать «Я рад» (м.р.)?"}', '{"correct": "אני שמח", "correct_index": 1}', '{"text": "שמח (самЭах) — радостный. אני שמח — я рад."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1080, 106, 'multiple_choice', 1, '{"options": ["мне жаль", "мне грустно", "мне хочется", "мне страшно"], "question": "Что значит «בא לי»?"}', '{"correct": "мне хочется", "correct_index": 2}', '{"text": "בא לי (ба ли) — мне хочется. Безличная конструкция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1081, 106, 'multiple_choice', 2, '{"options": ["חשוב לי", "כואב לי", "בא לי", "נמאס לי"], "question": "Как сказать «мне надоело»?"}', '{"correct": "נמאס לי", "correct_index": 3}', '{"text": "נמאס לי (нимАс ли) — мне надоело."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1094, 107, 'multiple_choice', 1, '{"options": ["школа", "библиотека", "книжный магазин", "университет"], "question": "Что значит «ספריה»?"}', '{"correct": "библиотека", "correct_index": 1}', '{"text": "ספריה (сифриЯ) — библиотека. От ספר (книга)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1095, 107, 'multiple_choice', 1, '{"options": ["מגרש", "בריכה", "חדר כושר", "אולם"], "question": "Как сказать «спортзал» на иврите?"}', '{"correct": "חדר כושר", "correct_index": 2}', '{"text": "חדר כושר (хадАр кОшер) — спортзал (букв. комната фитнеса)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1096, 107, 'multiple_choice', 2, '{"options": ["театр", "музей", "общинный культурный центр", "парк"], "question": "Что такое «מתנס»?"}', '{"correct": "общинный культурный центр", "correct_index": 2}', '{"text": "מתנ\"ס (матнАс) = מרכז תרבות, נוער וספורט — центр культуры, молодёжи и спорта."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1109, 108, 'multiple_choice', 1, '{"options": ["חדר אמבטיה", "סלון", "חדר שינה", "מטבח"], "question": "Как сказать «кухня» на иврите?"}', '{"correct": "מטבח", "correct_index": 3}', '{"text": "מטבח (митбАх) — кухня. От корня ט.ב.ח (готовить)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1124, 109, 'multiple_choice', 1, '{"options": ["в четверг", "в воскресенье", "в субботу утром", "в пятницу вечером"], "question": "Когда начинается шаббат?"}', '{"correct": "в пятницу вечером", "correct_index": 3}', '{"text": "Шаббат начинается в пятницу вечером (ערב שבת) с зажигания свечей."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1125, 109, 'multiple_choice', 1, '{"options": ["благословение над вином", "ужин", "танец", "молитва"], "question": "Что такое «קידוש»?"}', '{"correct": "благословение над вином", "correct_index": 0}', '{"text": "קידוש (кидУш) — освящение/благословение над вином в шаббат."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1126, 109, 'multiple_choice', 2, '{"options": ["Суккот", "Пурим", "Ханука", "Песах"], "question": "В какой праздник едят мацу?"}', '{"correct": "Песах", "correct_index": 3}', '{"text": "В Песах (פסח) едят мацу (מצה) — пресный хлеб."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1139, 110, 'multiple_choice', 1, '{"options": ["שקשוקה (шакшука)", "פיצה (пицца)", "המבורגר (гамбургер)", "סושי (суши)"], "question": "Какое блюдо является символом израильской кухни?"}', '{"correct": "שקשוקה (шакшука)", "correct_index": 0}', '{"text": "שקשוקה — яйца в томатном соусе со специями, национальное блюдо."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1140, 110, 'multiple_choice', 1, '{"options": ["рис", "суп", "мясное блюдо", "паста из нута"], "question": "Что такое «חומוס»?"}', '{"correct": "паста из нута", "correct_index": 3}', '{"text": "חומוס (хУмус) — паста из нута с тхиной, чесноком и лимонным соком."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1141, 110, 'multiple_choice', 2, '{"options": ["לחתוך", "להוסיף", "לטגן", "לערבב"], "question": "Как сказать «нарезать» в рецепте?"}', '{"correct": "לחתוך", "correct_index": 0}', '{"text": "לחתוך (лахтОх) — нарезать. В рецептах часто: חתכו (нарежьте)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1154, 111, 'multiple_choice', 1, '{"options": ["родственник", "сосед", "коллега", "друг"], "question": "Что значит «שכן»?"}', '{"correct": "сосед", "correct_index": 1}', '{"text": "שכן (шахЭн) — сосед. Ж.р.: שכנה (шхенА)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1155, 111, 'multiple_choice', 1, '{"options": ["совет района", "мэрия", "домовой комитет", "полиция"], "question": "Что такое «ועד בית»?"}', '{"correct": "домовой комитет", "correct_index": 2}', '{"text": "ועד בית (ваАд бАйит) — домовой комитет, управляющий общими делами здания."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1156, 111, 'multiple_choice', 2, '{"options": ["ישיבת עבודה", "מסיבת שכנים", "אסיפת דיירים", "פגישת חברים"], "question": "Как сказать «собрание жильцов»?"}', '{"correct": "אסיפת דיירים", "correct_index": 2}', '{"text": "אסיפת דיירים (асифАт даярИм) — собрание жильцов. Смихут."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1169, 112, 'multiple_choice', 1, '{"options": ["פחות", "הכי", "כמו", "יותר"], "question": "Какое слово означает «больше / более» для сравнения?"}', '{"correct": "יותר", "correct_index": 3}', '{"text": "יותר (йотЭр) — больше/более: יותר גדול — больше."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1170, 112, 'multiple_choice', 1, '{"options": ["בלי", "פחות + מ-", "יותר + מ-", "הכי + прилагательное"], "question": "Как образуется превосходная степень?"}', '{"correct": "הכי + прилагательное", "correct_index": 3}', '{"text": "הכי (hахИ) + прилагательное: הכי יפה — самый красивый."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1171, 112, 'multiple_choice', 2, '{"options": ["כמו יקר", "פחות יקר", "יותר יקר", "הכי יקר"], "question": "Как сказать «менее дорого»?"}', '{"correct": "פחות יקר", "correct_index": 1}', '{"text": "פחות (пахОт) — менее: פחות יקר — менее дорого."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1184, 113, 'multiple_choice', 1, '{"options": ["?אפשר לשבת כאן", "?חייב לשבת כאן", "?אסור לשבת כאן", "?צריך לשבת כאן"], "question": "Как сказать «Можно здесь сесть?»"}', '{"correct": "?אפשר לשבת כאן", "correct_index": 0}', '{"text": "אפשר (эфшАр) — можно (безличное). + инфинитив."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1185, 113, 'multiple_choice', 1, '{"options": ["רוצה", "יכול", "חייב", "צריך"], "question": "Какое слово означает «должен» (сильная обязанность)?"}', '{"correct": "חייב", "correct_index": 2}', '{"text": "חייב (хайЯв) — должен, обязан. Сильнее, чем צריך."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1186, 113, 'multiple_choice', 2, '{"options": ["יכול לעשן", "צריך לעשן", "אפשר לעשן", "אסור לעשן"], "question": "Как сказать «запрещено курить»?"}', '{"correct": "אסור לעשן", "correct_index": 3}', '{"text": "אסור (асУр) — запрещено: אסור לעשן — запрещено курить."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1204, 114, 'multiple_choice', 1, '{"options": ["чай", "латте (перевёрнутый кофе)", "сок", "чёрный кофе"], "question": "Что значит «קפה הפוך»?"}', '{"correct": "латте (перевёрнутый кофе)", "correct_index": 1}', '{"text": "קפה הפוך — латте: много молока, мало кофе (перевёрнутые пропорции)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1205, 114, 'multiple_choice', 2, '{"options": ["?לשבת כאן או לקחת", "?חם או קר", "?עם או בלי", "?גדול או קטן"], "question": "Как сказать «здесь или с собой?»"}', '{"correct": "?לשבת כאן או לקחת", "correct_index": 0}', '{"text": "לשבת כאן או לקחת — здесь или с собой (на вынос)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1206, 114, 'multiple_choice', 1, '{"options": ["остановись", "поверни направо", "иди прямо", "вернись"], "question": "Что означает «פנה ימינה»?"}', '{"correct": "поверни направо", "correct_index": 1}', '{"text": "פנה ימינה (пнЭ ямИна) — поверни направо."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1219, 115, 'multiple_choice', 1, '{"options": ["-תם", "-נו", "-תי", "-ו"], "question": "Какой суффикс прошедшего для «мы»?"}', '{"correct": "-נו", "correct_index": 1}', '{"text": "Суффикс -נו: כתבנו (мы написали), למדנו (мы учили)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1220, 115, 'multiple_choice', 1, '{"options": ["נִ-", "תִּ-", "אֶ-", "יִ-"], "question": "Какая приставка будущего для «он»?"}', '{"correct": "יִ-", "correct_index": 3}', '{"text": "Приставка י: יכתוב (он напишет), ילמד (он будет учить)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1221, 115, 'multiple_choice', 2, '{"options": ["сопряжённая конструкция", "вид глагола", "время", "тип предложения"], "question": "Что такое смихут?"}', '{"correct": "сопряжённая конструкция", "correct_index": 0}', '{"text": "Смихут — соединение двух существительных: בית ספר (школа)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1229, 27, 'multiple_choice', 2, '{"options": ["אם", "למרות", "כי", "אילו"], "question": "Какой союз используется для нереального условия в прошлом?"}', '{"correct": "אילו", "correct_index": 3}', '{"text": "אילו (илУ) вводит нереальное условие: אילו ידעתי, הייתי בא — Если бы я знал, пришёл бы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1233, 27, 'multiple_choice', 3, '{"options": ["אם יש לי זמן, אני בא", "כי היה לי זמן, באתי", "אם יהיה לי זמן, אבוא", "אילו היה לי זמן, הייתי בא"], "question": "Выберите правильный перевод: «Если бы у меня было время, я бы пришёл»"}', '{"correct": "אילו היה לי זמן, הייתי בא", "correct_index": 3}', '{"text": "Нереальное условие в настоящем: אילו היה לי + הייתי + причастие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1239, 28, 'multiple_choice', 2, '{"options": ["Хуфъаль", "Пуаль", "Хитпаэль", "Нифъаль"], "question": "Какой биньян является пассивом от Пиэль?"}', '{"correct": "Пуаль", "correct_index": 1}', '{"text": "Пуаль (פועל) — пассивная пара Пиэля. Пример: סיפר (рассказал) → סופר (был рассказан)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1244, 28, 'multiple_choice', 3, '{"options": ["Ребёнок родил в Тель-Авиве", "Ребёнок родился в Тель-Авиве", "Ребёнок вырос в Тель-Авиве", "Ребёнок живёт в Тель-Авиве"], "question": "Что означает предложение: «הילד נולד בתל אביב»?"}', '{"correct": "Ребёнок родился в Тель-Авиве", "correct_index": 1}', '{"text": "נולד (нолАд) — родился. Это Нифъаль от корня י.ל.ד с возвратным значением."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1249, 29, 'multiple_choice', 2, '{"options": ["כש", "כי", "ש", "כדי ש"], "question": "Какой союз означает «чтобы» при разных субъектах?"}', '{"correct": "כדי ש", "correct_index": 3}', '{"text": "כדי ש (кедЕй ше) — «для того чтобы» при разных подлежащих: עזרתי לו כדי שיצליח."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1254, 29, 'multiple_choice', 3, '{"options": ["לפני שאכלנו, הלכנו הביתה", "כדי שנאכל, הלכנו הביתה", "אחרי שאכלנו, הלכנו הביתה", "בזמן שאכלנו, הלכנו הביתה"], "question": "Выберите правильное предложение со значением «после того как мы поели, мы пошли домой»:"}', '{"correct": "אחרי שאכלנו, הלכנו הביתה", "correct_index": 2}', '{"text": "אחרי ש (ахарЕй ше) — после того как. אחרי שאכלנו — после того как мы поели."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1259, 30, 'multiple_choice', 2, '{"options": ["אסור", "צריך", "יכול", "כדאי"], "question": "Какое модальное слово выражает запрет?"}', '{"correct": "אסור", "correct_index": 0}', '{"text": "אסור (асУр) — запрещено. Безличная конструкция: אסור לעשן פה — Здесь запрещено курить."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1264, 30, 'multiple_choice', 3, '{"options": ["צריך — мягкая рекомендация, חייב — строгая обязанность", "Нет разницы", "צריך — запрещено, חייב — разрешено", "צריך — может, חייב — хочет"], "question": "Чем отличается צריך от חייב?"}', '{"correct": "צריך — мягкая рекомендация, חייב — строгая обязанность", "correct_index": 0}', '{"text": "צריך — «нужно, следует» (мягко). חייב — «обязан, должен» (строгая обязанность)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1269, 31, 'multiple_choice', 2, '{"options": ["הכינרת", "ים המלח", "ים התיכון", "ים סוף"], "question": "Как называется озеро на севере Израиля?"}', '{"correct": "הכינרת", "correct_index": 0}', '{"text": "הכינרת (hа-кинЕрет) — озеро Кинерет (Галилейское море) на севере Израиля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1275, 31, 'multiple_choice', 3, '{"options": ["природный заповедник", "ботанический сад", "зоопарк", "национальный парк"], "question": "Что означает слово «שמורת טבע»?"}', '{"correct": "природный заповедник", "correct_index": 0}', '{"text": "שמורת טבע (шмурАт тЕва) — природный заповедник. В Израиле более 400 заповедников."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1279, 32, 'multiple_choice', 2, '{"options": ["докторская степень", "аттестат зрелости", "степень бакалавра", "степень магистра"], "question": "Что такое «תואר ראשון»?"}', '{"correct": "степень бакалавра", "correct_index": 2}', '{"text": "תואר ראשון (тоАр ришОн) — первая степень, бакалавриат. Длится 3 года."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1285, 32, 'multiple_choice', 3, '{"options": ["20 лет", "18 лет", "26 лет", "22-24 года"], "question": "В каком возрасте большинство израильтян начинают учёбу в университете?"}', '{"correct": "22-24 года", "correct_index": 3}', '{"text": "Из-за армейской службы и традиционного путешествия, израильтяне начинают учёбу в 22-24 года."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1295, 33, 'multiple_choice', 2, '{"options": ["בגלל- ש", "ב-גלל-ש", "בגללש", "בגלל ש"], "question": "Как правильно записать «из-за того что»?"}', '{"correct": "בגלל ש", "correct_index": 3}', '{"text": "Составные союзы пишутся раздельно: בגלל ש (биглАль ше). Аналогично: למרות ש, כדי ש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1303, 34, 'multiple_choice', 2, '{"options": ["אני רואה את הבית הזה", "אני רואה בית הזה", "אני רואה הבית הזה", "אני רואה של הבית הזה"], "question": "Как правильно перевести «Я вижу этот дом»?"}', '{"correct": "אני רואה את הבית הזה", "correct_index": 0}', '{"text": "Перед определённым прямым дополнением ставится את: אני רואה את הבית הזה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1775, 58, 'multiple_choice', 2, '{"options": ["трансляция", "реклама", "интервью", "газета"], "question": "Слово שידור означает:"}', '{"correct": "трансляция", "correct_index": 0}', '{"text": "שידור (шидУр) — трансляция, вещание. От שורש ש.ד.ר — Пиэль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1309, 49, 'multiple_choice', 2, '{"options": ["только если", "кроме если", "даже если", "если нет"], "question": "Что означает «אפילו אם»?"}', '{"correct": "даже если", "correct_index": 2}', '{"text": "אפילו אם (афИлу им) — даже если. Усиливает условие: אפילו אם ירד גשם, אצא."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1315, 49, 'multiple_choice', 3, '{"options": ["אפילו אם", "אם כך", "אם לא", "רק אם"], "question": "Как сказать «в таком случае»?"}', '{"correct": "אם כך", "correct_index": 1}', '{"text": "אם כך (им ках) — если так, в таком случае. Используется для выводов из условия."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1319, 50, 'multiple_choice', 2, '{"options": ["כש", "עד ש", "אחרי ש", "לפני ש"], "question": "Какой союз означает «пока не»?"}', '{"correct": "עד ש", "correct_index": 1}', '{"text": "עד ש (ад ше) — пока не. חכה עד שאחזור — Подожди, пока я не вернусь."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1325, 50, 'multiple_choice', 3, '{"options": ["כי — нейтральный, בגלל ש — разговорный с оттенком причины", "כי — причина, בגלל ש — цель", "כי — формальный, בגלל ש — разговорный", "Нет разницы"], "question": "В чём разница между «כי» и «בגלל ש»?"}', '{"correct": "כי — нейтральный, בגלל ש — разговорный с оттенком причины", "correct_index": 0}', '{"text": "כי — нейтральный причинный союз. בגלל ש — более разговорный, подчёркивает причинно-следственную связь."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1329, 51, 'multiple_choice', 3, '{"options": ["причина + время + условие", "определение + результат", "условие + пассив", "уступка + модальность + цель"], "question": "Определите конструкции в предложении: «למרות שהוא חייב לעבוד, הוא רוצה ללמוד כדי שיוכל להתקדם»"}', '{"correct": "уступка + модальность + цель", "correct_index": 3}', '{"text": "למרות ש — уступка, חייב/רוצה — модальность, כדי ש — цель. Три конструкции в одном предложении."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1335, 51, 'multiple_choice', 2, '{"options": ["Нифъаль", "Пиэль", "Пааль", "Хитпаэль"], "question": "Какой биньян используется в слове «התפתח»?"}', '{"correct": "Хитпаэль", "correct_index": 3}', '{"text": "התפתח — Хитпаэль от корня פ.ת.ח. Возвратное значение: פיתח (развивал) → התפתח (развивался)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1339, 52, 'multiple_choice', 2, '{"options": ["четыре", "пять", "три", "две"], "question": "Сколько больничных касс существует в Израиле?"}', '{"correct": "четыре", "correct_index": 0}', '{"text": "В Израиле 4 больничные кассы: כללית, מכבי, מאוחדת, לאומית. Каждый житель обязан состоять в одной."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1345, 52, 'multiple_choice', 3, '{"options": ["ביטוח רכב", "ביטוח בריאות ממלכתי", "ביטוח לאומי", "ביטוח דירה"], "question": "Как называется медицинская страховка в Израиле?"}', '{"correct": "ביטוח בריאות ממלכתי", "correct_index": 1}', '{"text": "ביטוח בריאות ממלכתי (битУах бриЮт мамлахтИ) — государственное медицинское страхование."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1349, 53, 'multiple_choice', 2, '{"options": ["ראש השנה", "יום כיפור", "פסח", "חנוכה"], "question": "Какой праздник отмечается постом в течение 25 часов?"}', '{"correct": "יום כיפור", "correct_index": 1}', '{"text": "יום כיפור (Йом КипУр) — День Искупления. 25-часовой пост, самый святой день в еврейском календаре."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1355, 53, 'multiple_choice', 3, '{"options": ["еврейская олимпиада", "музыкальный фестиваль", "военный парад", "религиозный праздник"], "question": "Что такое «המכביה»?"}', '{"correct": "еврейская олимпиада", "correct_index": 0}', '{"text": "המכביה (hа-макабиА) — Маккабиада, «еврейская олимпиада», проводится раз в 4 года в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1362, 54, 'multiple_choice', 2, '{"options": ["Что ты слышишь?", "Как дела? (разг.)", "Что случилось?", "Что нового?"], "question": "Что означает фраза «מה נשמע?»"}', '{"correct": "Как дела? (разг.)", "correct_index": 1}', '{"text": "מה נשמע (ма нишмА) — «Как дела?» в разговорном иврите. Буквально: «Что слышно?»"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1369, 116, 'multiple_choice', 2, '{"options": ["причина и условие", "прошедшее время и будущее время", "инфинитив и повелительное наклонение", "настоящее время и прилагательное/существительное"], "question": "Какую двойную роль выполняют причастия (בינוניים) в иврите?"}', '{"correct": "настоящее время и прилагательное/существительное", "correct_index": 3}', '{"text": "Причастия (бейнонийИм) — одновременно форма настоящего времени и прилагательное/существительное."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1374, 116, 'multiple_choice', 3, '{"options": ["קטילה", "קיטול", "הקטלה", "התקטלות"], "question": "Какой герундий образуется от биньяна Хитпаэль?"}', '{"correct": "התקטלות", "correct_index": 3}', '{"text": "Герундий Хитпаэль: התקטלות. Пример: התפתחות (hитпатхУт) — развитие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1380, 116, 'multiple_choice', 2, '{"options": ["מלמד", "נוהג", "כותב", "שומר"], "question": "Какое слово является причастием Пиэль?"}', '{"correct": "מלמד", "correct_index": 0}', '{"text": "מלמד (меламЕд) — преподаёт/преподаватель. Причастие Пиэль, модель מְקַטֵּל."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (2705, 141, 'multiple_choice', 2, '{"options": ["иск", "приговор", "свидетель", "адвокат"], "question": "Что означает слово תביעה?"}', '{"correct": "иск", "correct_index": 0}', '{"text": "תביעה — иск, судебное требование."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1384, 117, 'multiple_choice', 2, '{"options": ["становится אנחנו", "становится הוא / היא", "опускается", "остаётся אני"], "question": "Как изменяется «אני» при переходе в косвенную речь?"}', '{"correct": "становится הוא / היא", "correct_index": 1}', '{"text": "В косвенной речи 1-е лицо → 3-е: דני אמר: «אני רוצה» → דני אמר שהוא רוצה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1389, 117, 'multiple_choice', 3, '{"options": ["שאל", "סיפר", "אמר", "הודיע"], "question": "Какой глагол используется для передачи вопроса в косвенной речи?"}', '{"correct": "שאל", "correct_index": 0}', '{"text": "שאל (шаАль) — спросил. Для да/нет-вопросов: שאל אם... Для специальных: שאל + вопросительное слово."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1394, 117, 'multiple_choice', 2, '{"options": ["объяснил", "сказал", "рассказал", "спросил"], "question": "Что означает «סיפר»?"}', '{"correct": "рассказал", "correct_index": 2}', '{"text": "סיפר (сипЕр) — рассказал. Пиэль от корня ס.פ.ר. Отличать от אמר (сказал)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1399, 118, 'multiple_choice', 2, '{"options": ["одно — пассив", "три — пассив, возвратное, начинательное", "два — пассив и возвратное", "четыре — пассив, возвратное, начинательное, стативное"], "question": "Сколько значений имеет биньян Нифъаль?"}', '{"correct": "четыре — пассив, возвратное, начинательное, стативное", "correct_index": 3}', '{"text": "Нифъаль имеет 4 значения: пассив (נכתב), возвратное (נרשם), начинательное (נרדם), стативное (נשמע)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1404, 118, 'multiple_choice', 3, '{"options": ["возвратное", "пассив", "начинательное", "стативное"], "question": "Какое значение имеет Нифъаль в «זה נשמע טוב»?"}', '{"correct": "стативное", "correct_index": 3}', '{"text": "נשמע (нишмА) — звучит. Стативное значение Нифъаля: описывает состояние."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1409, 118, 'multiple_choice', 2, '{"options": ["ה", "מ", "נ", "ת"], "question": "Какая приставка характерна для Нифъаля в прошедшем и настоящем времени?"}', '{"correct": "נ", "correct_index": 2}', '{"text": "Приставка נ — ключевой маркер Нифъаля: נכתב, נפתח, נשבר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1414, 119, 'multiple_choice', 2, '{"options": ["ради", "вместо", "из-за", "согласно"], "question": "Что означает предлог «בגלל»?"}', '{"correct": "из-за", "correct_index": 2}', '{"text": "בגלל (биглАль) — из-за. בגלל הגשם לא יצאנו — Из-за дождя мы не вышли."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1419, 119, 'multiple_choice', 3, '{"options": ["בעוד ש", "למרות ש", "בגלל ש", "מאחר ש"], "question": "Какой союз означает «поскольку» (формальный)?"}', '{"correct": "מאחר ש", "correct_index": 3}', '{"text": "מאחר ש (меахАр ше) — поскольку (формальный). מאחר שאיחרנו — поскольку мы опоздали."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1426, 119, 'multiple_choice', 2, '{"options": ["בגלל", "בשביל", "לפי", "ביחס ל"], "question": "Какой предлог означает «по отношению к»?"}', '{"correct": "ביחס ל", "correct_index": 3}', '{"text": "ביחס ל (бе-йАхас ле) — по отношению к. ביחס לנושא הזה — по отношению к этой теме."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1429, 120, 'multiple_choice', 2, '{"options": ["צבא הגבורה לישראל", "צבא הגנה לישראל", "ציוד הגנה לאומי", "ציון הגנה לעם"], "question": "Как расшифровывается צה\"ל?"}', '{"correct": "צבא הגנה לישראל", "correct_index": 1}', '{"text": "צה\"ל = צבא הגנה לישראל (цва hаганА ле-исраЭль) — Армия обороны Израиля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1434, 120, 'multiple_choice', 3, '{"options": ["גולני", "8200", "נח\"ל", "שייטת 13"], "question": "Какое подразделение ЦАХАЛа славится подготовкой IT-специалистов?"}', '{"correct": "8200", "correct_index": 1}', '{"text": "יחידת 8200 — подразделение военной разведки, известное подготовкой IT-специалистов."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1440, 120, 'multiple_choice', 2, '{"options": ["резервист", "тыловой солдат", "боевой солдат", "командир"], "question": "Что означает «ג''ובניק»?"}', '{"correct": "тыловой солдат", "correct_index": 1}', '{"text": "ג''ובניק (джОбник) — тыловой солдат (от англ. «job»). Сленговое выражение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1444, 121, 'multiple_choice', 2, '{"options": ["מדבר הנגב", "יערות", "הרים", "שפלה"], "question": "Что занимает более половины территории Израиля?"}', '{"correct": "מדבר הנגב", "correct_index": 0}', '{"text": "מדבר הנגב (мидбАр hа-нЕгев) — пустыня Негев. Занимает более половины территории."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1449, 121, 'multiple_choice', 3, '{"options": ["возобновляемая энергия", "солнечная батарея", "электрическая энергия", "ядерная энергия"], "question": "Что такое «אנרגיה מתחדשת»?"}', '{"correct": "возобновляемая энергия", "correct_index": 0}', '{"text": "אנרגיה מתחדשת (энЕргия митхадЕшет) — возобновляемая энергия. Хитпаэль מתחדשת = обновляющаяся."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1454, 121, 'multiple_choice', 2, '{"options": ["הנגב והערבה", "עין גדי, החולה והכרמל", "ים סוף ואילת", "רמת הגולן ומצדה"], "question": "Какие заповедники упоминаются как самые известные?"}', '{"correct": "עין גדי, החולה והכרמל", "correct_index": 1}', '{"text": "Самые известные заповедники: עין גדי (Эйн-Геди), החולה (Хула), הכרמל (Кармель)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (2710, 142, 'multiple_choice', 2, '{"options": ["журналист", "статья", "газета", "редактор"], "question": "Что означает מאמר?"}', '{"correct": "статья", "correct_index": 1}', '{"text": "מאמר — статья."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1459, 122, 'multiple_choice', 2, '{"options": ["עמק הסיליקון", "ארץ הסייבר", "אומת הסטארט-אפ", "מדינת היזמים"], "question": "Как называют Израиль в мире технологий?"}', '{"correct": "אומת הסטארט-אפ", "correct_index": 2}', '{"text": "אומת הסטארט-אפ (Умат hа-стартАп) — «нация стартапов», прозвище Израиля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1464, 122, 'multiple_choice', 3, '{"options": ["только университеты", "только финансирование", "армия, культура инноваций, университеты и иммиграция", "только армия"], "question": "Что способствует технологическому успеху Израиля?"}', '{"correct": "армия, культура инноваций, университеты и иммиграция", "correct_index": 2}', '{"text": "Четыре фактора: армейская подготовка, культура инноваций, университеты и иммиграция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1470, 122, 'multiple_choice', 2, '{"options": ["программист", "инвестор", "инженер", "предприниматель"], "question": "Что означает слово «יזם»?"}', '{"correct": "предприниматель", "correct_index": 3}', '{"text": "יזם (язАм) — предприниматель. Женский род: יזמית (язамИт)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1474, 123, 'multiple_choice', 2, '{"options": ["גלובס", "הארץ", "מעריב", "ידיעות אחרונות"], "question": "Как называется крупнейшая газета Израиля?"}', '{"correct": "ידיעות אחרונות", "correct_index": 3}', '{"text": "ידיעות אחרונות (йедиОт ахронОт) — «Последние известия», крупнейшая газета."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1479, 123, 'multiple_choice', 3, '{"options": ["пассивные конструкции и формальная лексика", "только разговорные формы", "сленг и сокращения", "простые предложения"], "question": "Что характерно для новостного стиля иврита?"}', '{"correct": "пассивные конструкции и формальная лексика", "correct_index": 0}', '{"text": "Новостной иврит: пассивные конструкции (נעצר חשוד), безличные формы (נמסר כי), формальная лексика."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1485, 123, 'multiple_choice', 2, '{"options": ["выпуск новостей", "журналистское расследование", "газетная статья", "пресс-конференция"], "question": "Что означает «מהדורת חדשות»?"}', '{"correct": "выпуск новостей", "correct_index": 0}', '{"text": "מהדורת חדשות (маhадурАт хадашОт) — выпуск новостей."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1489, 124, 'multiple_choice', 2, '{"options": ["теннис", "футбол", "плавание", "баскетбол"], "question": "Какой вид спорта самый популярный в Израиле?"}', '{"correct": "футбол", "correct_index": 1}', '{"text": "כדורגל (кадурЕгель) — футбол, самый популярный вид спорта в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1494, 124, 'multiple_choice', 3, '{"options": ["военные соревнования", "еврейская олимпиада", "баскетбольная лига", "футбольный турнир"], "question": "Что такое «המכביה»?"}', '{"correct": "еврейская олимпиада", "correct_index": 1}', '{"text": "המכביה (hа-макабиА) — Маккабиада, «еврейская олимпиада», проводится раз в 4 года."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1500, 124, 'multiple_choice', 2, '{"options": ["משחק", "אימון", "הופעה", "תחרות"], "question": "Как сказать «тренировка» на иврите?"}', '{"correct": "אימון", "correct_index": 1}', '{"text": "אימון (имУн) — тренировка. אימון (Пиэль от אמן) — также дрессировка, тренинг."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1504, 125, 'multiple_choice', 2, '{"options": ["-ון", "-ות", "-וּת и -וֹן", "-ים"], "question": "Какой суффикс образует абстрактные существительные в иврите?"}', '{"correct": "-וּת и -וֹן", "correct_index": 2}', '{"text": "Суффиксы -וּת (-Ут) и -וֹן (-Он): אחריות (ответственность), זיכרון (память)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1509, 125, 'multiple_choice', 3, '{"options": ["אחראי", "אחרת", "אחרון", "אחר"], "question": "От какого прилагательного образовано «אחריות»?"}', '{"correct": "אחראי", "correct_index": 0}', '{"text": "אחראי (ахраИ) — ответственный → אחריות (ахраЮт) — ответственность. Суффикс -ות."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1515, 125, 'multiple_choice', 2, '{"options": ["ненависть", "милость, доброта", "страх", "гордость"], "question": "Что означает «חסד»?"}', '{"correct": "милость, доброта", "correct_index": 1}', '{"text": "חסד (хЕсед) — милость, доброта. Одно из важнейших понятий в еврейской традиции."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1522, 126, 'multiple_choice', 2, '{"options": ["производство", "достижение", "акция/распродажа", "операция"], "question": "Что означает «מבצע» в рекламном контексте?"}', '{"correct": "акция/распродажа", "correct_index": 2}', '{"text": "מבצע (мивцА) — акция, распродажа. В военном контексте — операция."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1605, 131, 'multiple_choice', 2, '{"options": ["ח\"כ", "שר", "שופט", "נשיא"], "question": "Как сказать «министр» на иврите?"}', '{"correct": "שר", "correct_index": 1}', '{"text": "שר (сар) — министр. Женский род: שרה (сарА). שר החינוך — министр образования."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3564, 201, 'dictation', 1, '{"hint": "ребёнок женского пола", "word_he": "ילדה", "word_translit": "йалдА"}', '{"accept": ["ילדה"], "correct": "ילדה"}', '{"text": "ילדה (йалдА) — ребёнок женского пола"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1609, 132, 'multiple_choice', 2, '{"options": ["חאן", "הבימה", "הקאמרי", "גשר"], "question": "Какой театр является национальным театром Израиля?"}', '{"correct": "הבימה", "correct_index": 1}', '{"text": "הבימה (hа-бимА) — национальный театр Израиля, основан в 1917 г. в Москве."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1527, 126, 'multiple_choice', 3, '{"options": ["разговорные сокращения", "пассивные конструкции, безличные формы и инверсия", "только простые предложения", "повелительное наклонение и сленг"], "question": "Какие конструкции характерны для новостного стиля?"}', '{"correct": "пассивные конструкции, безличные формы и инверсия", "correct_index": 1}', '{"text": "Новостной стиль: пассив (נעצר), безличные (נמסר כי), инверсия (הגיע ראש הממשלה)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1534, 127, 'multiple_choice', 2, '{"options": ["כי", "אם", "אילו", "למרות"], "question": "Какой союз вводит нереальное условие в прошлом?"}', '{"correct": "אילו", "correct_index": 2}', '{"text": "אילו (илУ) вводит нереальное условие III типа: אילו למדתי יותר, הייתי מצליח."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1539, 127, 'multiple_choice', 3, '{"options": ["אילו — прошлое, לו — настоящее", "Нет разницы", "אילו — книжный, לו — поэтичный/библейский", "אילו — разговорный, לו — формальный"], "question": "В чём разница между «אילו» и «לו»?"}', '{"correct": "אילו — книжный, לו — поэтичный/библейский", "correct_index": 2}', '{"text": "אילו — стандартный книжный вариант. לו — более поэтичный, библейский оттенок."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1544, 127, 'multiple_choice', 2, '{"options": ["жаль, что не", "хорошо, что", "надеюсь, что", "несмотря на"], "question": "Что означает выражение «חבל שלא»?"}', '{"correct": "жаль, что не", "correct_index": 0}', '{"text": "חבל שלא (хавАль ше-ло) — жаль, что не. Часто заменяет нереальное условие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1549, 128, 'multiple_choice', 2, '{"options": ["положил сердце", "обратил внимание", "влюбился", "потерял сердце"], "question": "Что означает «שם לב»?"}', '{"correct": "обратил внимание", "correct_index": 1}', '{"text": "שם לב (сам лев) — обратил внимание. Буквально: «положил сердце»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1554, 128, 'multiple_choice', 3, '{"options": ["заплатил по счёту", "рассматривается, возможен", "сосчитал", "пришёл в банк"], "question": "Что означает «בא בחשבון»?"}', '{"correct": "рассматривается, возможен", "correct_index": 1}', '{"text": "בא בחשבון (ба бе-хешбОн) — учитывается, рассматривается как вариант."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1560, 128, 'multiple_choice', 2, '{"options": ["замахал", "поздоровался", "поднял кого-то", "сдался"], "question": "Что означает «הרים ידיים»?"}', '{"correct": "сдался", "correct_index": 3}', '{"text": "הרים ידיים (hерИм ядАйим) — сдался. Буквально: «поднял руки»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1564, 129, 'multiple_choice', 2, '{"options": ["выпускной вечер", "аттестат зрелости / выпускные экзамены", "стипендия", "начальная школа"], "question": "Что такое «בגרות» в системе образования Израиля?"}', '{"correct": "аттестат зрелости / выпускные экзамены", "correct_index": 1}', '{"text": "בגרות (багрУт) — аттестат зрелости, система выпускных экзаменов в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1569, 129, 'multiple_choice', 3, '{"options": ["18", "20", "22-24", "26"], "question": "В каком возрасте большинство израильтян начинают университет?"}', '{"correct": "22-24", "correct_index": 2}', '{"text": "Из-за армии и путешествия после службы, израильтяне начинают учёбу в 22-24 года."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1575, 129, 'multiple_choice', 2, '{"options": ["עבודת צוות", "שיעורי בית", "מבחן בית", "עבודה סמינריונית"], "question": "Как сказать «домашнее задание» на иврите?"}', '{"correct": "שיעורי בית", "correct_index": 1}', '{"text": "שיעורי בית (шиурЕй бАйит) — домашние задания. Буквально: «уроки дома»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1579, 130, 'multiple_choice', 2, '{"options": ["психическое здоровье", "спорт", "здоровое питание", "физическое здоровье"], "question": "Что такое «בריאות הנפש»?"}', '{"correct": "психическое здоровье", "correct_index": 0}', '{"text": "בריאות הנפש (бриЮт hа-нЕфеш) — психическое здоровье. נפש — душа."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1584, 130, 'multiple_choice', 3, '{"options": ["хирургия", "альтернативная медицина", "психотерапия", "скорая помощь"], "question": "Что такое «רפואה משלימה»?"}', '{"correct": "альтернативная медицина", "correct_index": 1}', '{"text": "רפואה משלימה (рефуА машлИма) — альтернативная/комплементарная медицина."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1590, 130, 'multiple_choice', 2, '{"options": ["אני שותה תרופות", "אני אוכל תרופות", "אני מקבל תרופות", "אני לוקח תרופות"], "question": "Как сказать «я принимаю лекарства»?"}', '{"correct": "אני לוקח תרופות", "correct_index": 3}', '{"text": "אני לוקח/ת תרופות — я принимаю лекарства. לוקח — от לקח (брать)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1594, 131, 'multiple_choice', 2, '{"options": ["80", "120", "100", "150"], "question": "Сколько депутатов заседает в Кнессете?"}', '{"correct": "120", "correct_index": 1}', '{"text": "В Кнессете 120 членов — חברי כנסת (ח\"כים). Число символизирует Великое собрание."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1599, 131, 'multiple_choice', 3, '{"options": ["5%", "3.25%", "2%", "1%"], "question": "Какой процент голосов нужен партии для прохождения в Кнессет?"}', '{"correct": "3.25%", "correct_index": 1}', '{"text": "אחוז החסימה (ахУз hа-хасимА) — электоральный барьер = 3.25%."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3565, 201, 'dictation', 1, '{"hint": "отец", "word_he": "אבא", "word_translit": "Аба"}', '{"accept": ["אבא"], "correct": "אבא"}', '{"text": "אבא (Аба) — отец"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1614, 132, 'multiple_choice', 3, '{"options": ["Москва", "Иерусалим", "Одесса", "Тель-Авив"], "question": "Где был основан театр «Габима»?"}', '{"correct": "Москва", "correct_index": 0}', '{"text": "הבימה основан в 1917 г. в Москве и переехал в Эрец-Исраэль в 1928 г."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1620, 132, 'multiple_choice', 2, '{"options": ["мюзикл", "драма", "триллер", "комедия"], "question": "Что означает слово «מותחן»?"}', '{"correct": "триллер", "correct_index": 2}', '{"text": "מותחן (мотхАн) — триллер. От מתח (мЕтах) — напряжение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1624, 133, 'multiple_choice', 2, '{"options": ["משרה", "ראיון", "משכורת", "קורות חיים"], "question": "Как сказать «резюме» (CV) на иврите?"}', '{"correct": "קורות חיים", "correct_index": 3}', '{"text": "קורות חיים (корОт хаЙим) — резюме, CV. Буквально: «события жизни»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1629, 133, 'multiple_choice', 3, '{"options": ["зарплата до вычетов", "зарплата после вычетов", "средняя зарплата", "минимальная зарплата"], "question": "Что означает «שכר ברוטו»?"}', '{"correct": "зарплата до вычетов", "correct_index": 0}', '{"text": "שכר ברוטו — зарплата до вычетов (брутто). שכר נטו — после вычетов (нетто)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1635, 133, 'multiple_choice', 2, '{"options": ["повышение", "отпуск", "увольнение", "больничный"], "question": "Что такое «פיטורים»?"}', '{"correct": "увольнение", "correct_index": 2}', '{"text": "פיטורים (питурИм) — увольнение (со стороны работодателя). Пиэль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1639, 134, 'multiple_choice', 2, '{"options": ["מה נשמע", "לכבוד", "היי", "שלום"], "question": "Как начинается формальное обращение на иврите?"}', '{"correct": "לכבוד", "correct_index": 1}', '{"text": "לכבוד (ликвОд) — уважаемый/ая. Стандартное формальное обращение в письмах."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1644, 134, 'multiple_choice', 3, '{"options": ["הנדון", "שלום", "לכבוד", "בברכה"], "question": "Какое слово вводит тему формального письма?"}', '{"correct": "הנדון", "correct_index": 0}', '{"text": "הנדון (hа-нидОн) — тема письма. הנדון: בקשה להחלפת רופא — Тема: просьба о замене врача."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1650, 134, 'multiple_choice', 2, '{"options": ["תודה", "שלום", "בברכה", "להתראות"], "question": "Какой альтернативный вариант подписи используется в формальных письмах?"}', '{"correct": "בברכה", "correct_index": 2}', '{"text": "בברכה (бивраха) — с наилучшими пожеланиями. Альтернатива בכבוד רב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1654, 135, 'multiple_choice', 2, '{"options": ["בהחלט", "אין ספק", "לפי דעתי", "בדיוק"], "question": "Как сказать «по-моему» на иврите?"}', '{"correct": "לפי דעתי", "correct_index": 2}', '{"text": "לפי דעתי / לדעתי (ледаатИ) — по-моему, по моему мнению."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1659, 135, 'multiple_choice', 3, '{"options": ["довод → пример → тезис", "тезис → довод → пример → вывод", "пример → тезис → вывод", "вывод → тезис → пример"], "question": "Какова правильная структура аргумента?"}', '{"correct": "тезис → довод → пример → вывод", "correct_index": 1}', '{"text": "Структура: טענה (тезис) → נימוק (довод) → דוגמה (пример) → מסקנה (вывод)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1665, 135, 'multiple_choice', 2, '{"options": ["может быть", "конечно нет", "к сожалению", "безусловно, конечно"], "question": "Что означает «בהחלט»?"}', '{"correct": "безусловно, конечно", "correct_index": 3}', '{"text": "בהחלט (бехехлЕт) — безусловно, конечно. Сильное выражение согласия."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1669, 136, 'multiple_choice', 2, '{"options": ["Хифъиль", "Хитпаэль", "Пиэль", "Нифъаль"], "question": "Какой биньян выражает пассивное значение от Пааль?"}', '{"correct": "Нифъаль", "correct_index": 3}', '{"text": "Нифъаль — пассивная пара Пааля. כתב → נכתב, שבר → נשבר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1675, 136, 'multiple_choice', 3, '{"options": ["только здороваться", "только читать буквы", "только слушать", "читать газеты, писать письма, аргументировать, понимать новости"], "question": "Что вы умеете на уровне B1?"}', '{"correct": "читать газеты, писать письма, аргументировать, понимать новости", "correct_index": 3}', '{"text": "На B1: чтение газет, формальные письма, аргументация, понимание новостей, сложные конструкции."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1681, 136, 'multiple_choice', 2, '{"options": ["אם", "כי", "כדי ש", "למרות ש"], "question": "Какой союз вводит уступительное придаточное?"}', '{"correct": "למרות ש", "correct_index": 3}', '{"text": "למרות ש (ламрОт ше) — несмотря на то что. Уступительное придаточное."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1684, 35, 'multiple_choice', 2, '{"options": ["למרות", "בגלל", "כי", "אם"], "question": "Какой союз вводит придаточное причины?"}', '{"correct": "כי", "correct_index": 2}', '{"text": "כי (ки) — основной союз причины: באתי כי רציתי ללמוד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1685, 35, 'multiple_choice', 2, '{"options": ["כאשר", "אולם", "לפיכך", "כדי"], "question": "Какое слово вводит придаточное цели?"}', '{"correct": "כדי", "correct_index": 3}', '{"text": "כדי + инфинитив = «чтобы»: באתי כדי ללמוד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1694, 36, 'multiple_choice', 2, '{"options": ["לוֹמֵד", "תַּלְמִיד", "מְלַמֵּד", "לְמִידָה"], "question": "Какое отглагольное существительное образовано от לִלְמוֹד?"}', '{"correct": "לְמִידָה", "correct_index": 3}', '{"text": "לְמִידָה (лемидА) — отглагольное существительное мишкаль קְטִילָה от ללמוד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1695, 36, 'multiple_choice', 2, '{"options": ["Хифъиль", "Пиэль", "Пааль", "Нифъаль"], "question": "Мишкаль הַקְטָלָה характерен для биньяна:"}', '{"correct": "Хифъиль", "correct_index": 0}', '{"text": "הַקְטָלָה — мишкаль отглагольных существительных Хифъиля: הַכְנָסָה, הַפְסָקָה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1704, 37, 'multiple_choice', 2, '{"options": ["התפעל", "פיעל", "הפעיל", "נפעל"], "question": "Какой биньян выражает каузативное значение?"}', '{"correct": "הפעיל", "correct_index": 2}', '{"text": "הפעיל (Хифъиль) — каузативный: הכניס (заставил войти), הוציא (вывел)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1705, 37, 'multiple_choice', 2, '{"options": ["пассив Пааля", "каузатив", "интенсив", "рефлексив"], "question": "Биньян נפעל обычно выражает:"}', '{"correct": "пассив Пааля", "correct_index": 0}', '{"text": "נפעל — пассив от פעל: כתב → נכתב (был написан)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1714, 38, 'multiple_choice', 2, '{"options": ["בנק ישראל", "הכנסת", "שוק הכרמל", "הבורסה לניירות ערך"], "question": "Как называется фондовый рынок Израиля?"}', '{"correct": "הבורסה לניירות ערך", "correct_index": 3}', '{"text": "הבורסה לניירות ערך בתל אביב — Тель-Авивская фондовая биржа."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1715, 38, 'multiple_choice', 2, '{"options": ["бюджет", "валовой внутренний продукт", "центральный банк", "налог на добавленную стоимость"], "question": "Что означает תמ\"ג?"}', '{"correct": "валовой внутренний продукт", "correct_index": 1}', '{"text": "תמ\"ג = תוצר מקומי גולמי — ВВП (валовой внутренний продукт)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1724, 39, 'multiple_choice', 2, '{"options": ["בית המשפט המחוזי", "הכנסת", "בית הדין הרבני", "בית המשפט העליון"], "question": "Как называется Верховный суд Израиля?"}', '{"correct": "בית המשפט העליון", "correct_index": 3}', '{"text": "בית המשפט העליון — Верховный суд Израиля, расположен в Иерусалиме."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1725, 39, 'multiple_choice', 2, '{"options": ["адвокат", "прокурор", "судья", "свидетель"], "question": "Что означает слово עורך דין?"}', '{"correct": "адвокат", "correct_index": 0}', '{"text": "עורך דין (орЕх дин) — адвокат. От ערך (вёл) + דין (закон)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1734, 40, 'multiple_choice', 2, '{"options": ["סימן קריאה (!)", "סימן שאלה (?)", "נקודה (.)", "נקודתיים (:)"], "question": "Какой знак препинания ставится в конце вопроса на иврите?"}', '{"correct": "סימן שאלה (?)", "correct_index": 1}', '{"text": "סימן שאלה (?) — знак вопроса. Ставится в конце вопросительного предложения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1735, 40, 'multiple_choice', 2, '{"options": ["запятая", "слово", "предложение", "абзац"], "question": "Что означает слово פִּסְקָה?"}', '{"correct": "абзац", "correct_index": 3}', '{"text": "פִּסְקָה (пискА) — абзац. От שורש פ.ס.ק — разделять."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1744, 55, 'multiple_choice', 2, '{"options": ["נלבש (был одет)", "התלבש (оделся)", "לבש (оделся)", "הלביש (одел кого-то)"], "question": "Какую форму от корня ל.ב.ש даёт Хифъиль?"}', '{"correct": "הלביש (одел кого-то)", "correct_index": 3}', '{"text": "הלביש — Хифъиль: одел кого-то. Каузативное значение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1745, 55, 'multiple_choice', 2, '{"options": ["פיעל", "נפעל", "הפעיל", "פעל"], "question": "Какой биньян образует от כ.נ.ס слово הכניס?"}', '{"correct": "הפעיל", "correct_index": 2}', '{"text": "הכניס — Хифъиль (הפעיל): «ввёл, внёс». Каузатив от נכנס."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1754, 56, 'multiple_choice', 2, '{"options": ["עבורי", "בשבילי", "בעדי", "все варианты верны"], "question": "Как будет ''для меня'' на иврите?"}', '{"correct": "все варианты верны", "correct_index": 3}', '{"text": "בשבילי, עבורי, בעדי — все формы означают «для меня», в разных контекстах."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1755, 56, 'multiple_choice', 2, '{"options": ["от нас", "к нам", "с нами", "у нас"], "question": "Форма אצלנו означает:"}', '{"correct": "у нас", "correct_index": 3}', '{"text": "אצלנו (эцлЕну) — у нас. אצל + -נו = у нас (дома/рядом)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1805, 137, 'multiple_choice', 2, '{"options": ["נזכר (вспомнил)", "הזדכר (вспомнил)", "הזכיר (напомнил)", "זכר (помнил)"], "question": "Хифъиль от корня ז.כ.ר даёт:"}', '{"correct": "הזכיר (напомнил)", "correct_index": 2}', '{"text": "הזכיר — Хифъиль: напомнил (каузатив). זכר — Пааль: помнил."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1764, 57, 'multiple_choice', 2, '{"options": ["קִטּוּל", "הַקְטָלָה", "קְטִילָה", "הִתְקַטְּלוּת"], "question": "Какой мишкаль образует абстрактные существительные в Хифъиле?"}', '{"correct": "הַקְטָלָה", "correct_index": 1}', '{"text": "הַקְטָלָה — мишкаль отглагольных существительных Хифъиля: הַשְׁפָּעָה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1765, 57, 'multiple_choice', 2, '{"options": ["Нифъаль", "Хифъиль", "Пиэль", "Хитпаэль"], "question": "Слово הִתְנַהֲגוּת образовано от биньяна:"}', '{"correct": "Хитпаэль", "correct_index": 3}', '{"text": "הִתְנַהֲגוּת (поведение) — мишкаль הִתְקַטְּלוּת, характерный для Хитпаэля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1774, 58, 'multiple_choice', 2, '{"options": ["עורך", "все варианты по контексту", "עיתונאי", "כתב"], "question": "Как называется на иврите «журналист»?"}', '{"correct": "все варианты по контексту", "correct_index": 1}', '{"text": "עיתונאי — журналист (газетный), כתב — корреспондент, עורך — редактор."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1784, 59, 'multiple_choice', 2, '{"options": ["энергия", "пустыня", "загрязнение", "переработка/рециклинг"], "question": "Как переводится מיחזור?"}', '{"correct": "переработка/рециклинг", "correct_index": 3}', '{"text": "מיחזור (михзУр) — переработка, рециклинг. От שורש ח.ז.ר — Пиэль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1785, 59, 'multiple_choice', 2, '{"options": ["орошение", "загрязнение воды", "опреснение воды", "наводнение"], "question": "Что такое התפלת מים?"}', '{"correct": "опреснение воды", "correct_index": 2}', '{"text": "התפלת מים — опреснение воды. Израиль — мировой лидер в этой технологии."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1794, 60, 'multiple_choice', 2, '{"options": ["התפעל", "הופעל", "נפעל", "פועל (Пуаль)"], "question": "Какой биньян используется для пассива Пиэля?"}', '{"correct": "פועל (Пуаль)", "correct_index": 3}', '{"text": "Пуаль — пассив Пиэля: לימד → לומד (был обучен)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1795, 60, 'multiple_choice', 2, '{"options": ["агент пассива", "причина", "цель", "условие"], "question": "В конструкции על ידי используется:"}', '{"correct": "агент пассива", "correct_index": 0}', '{"text": "על ידי — «агентом»: הספר נכתב על ידי הסופר — книга написана писателем."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1804, 137, 'multiple_choice', 2, '{"options": ["לְהִתְקַטֵּל", "לִקְטוֹל", "לְקַטֵּל", "לְהַקְטִיל"], "question": "Какой мишкаль характерен для инфинитива Пиэль?"}', '{"correct": "לְקַטֵּל", "correct_index": 2}', '{"text": "לקטל — инфинитив Пиэль: ללמד, לדבר, לספר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1814, 138, 'multiple_choice', 2, '{"options": ["пассив", "простое действие", "каузатив", "рефлексивное действие"], "question": "Хитпаэль обычно выражает:"}', '{"correct": "рефлексивное действие", "correct_index": 3}', '{"text": "Хитпаэль — рефлексив/взаимность: התלבש (оделся), התקשר (позвонил)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1815, 138, 'multiple_choice', 2, '{"options": ["נשבר (сломался)", "שיבר (разбил)", "השביר (дал сломать)", "התשבר (не существует)"], "question": "Нифъаль от שבר:"}', '{"correct": "נשבר (сломался)", "correct_index": 0}', '{"text": "נשבר — Нифъаль: сломался. Пассив/рефлексив от שבר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1824, 139, 'multiple_choice', 2, '{"options": ["עליו", "עלינו", "על אני", "עליי"], "question": "Какая форма правильная для ''обо мне''?"}', '{"correct": "עליי", "correct_index": 3}', '{"text": "עליי — обо мне. Предлог על с суффиксом 1sg."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1825, 139, 'multiple_choice', 2, '{"options": ["между ними", "к ним", "от них", "между нами"], "question": "Форма ביניהם означает:"}', '{"correct": "между ними", "correct_index": 0}', '{"text": "ביניהם — между ними. בין + суффикс 3mp."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1834, 140, 'multiple_choice', 2, '{"options": ["הִתְקַטְּלוּת", "קִטּוּל", "קְטִילָה", "הַקְטָלָה"], "question": "Какой мишкаль у слова הַגָּנָה (защита)?"}', '{"correct": "הַקְטָלָה", "correct_index": 3}', '{"text": "הגנה — мишкаль הַקְטָלָה, характерный для Хифъиля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1835, 140, 'multiple_choice', 2, '{"options": ["Нифъаль נכתב", "Пиэль כיתב", "Пааль כתב", "Хифъиль הכתיב"], "question": "Слово כתיבה образовано от:"}', '{"correct": "Пааль כתב", "correct_index": 2}', '{"text": "כתיבה — мишкаль קְטִילָה от Пааль כתב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1844, 141, 'multiple_choice', 2, '{"options": ["военный закон", "гражданский закон", "основной закон", "уголовный кодекс"], "question": "Что означает חוק יסוד?"}', '{"correct": "основной закон", "correct_index": 2}', '{"text": "חוק יסוד — основной (конституционный) закон. У Израиля нет конституции, её заменяют חוקי יסוד."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1845, 141, 'multiple_choice', 2, '{"options": ["иск", "апелляция", "оправдание", "приговор"], "question": "Слово תביעה означает:"}', '{"correct": "иск", "correct_index": 0}', '{"text": "תביעה — иск, обвинение. От שורש ת.ב.ע. תובע — истец/обвинитель."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1854, 142, 'multiple_choice', 2, '{"options": ["запись", "трансляция", "редактирование", "публикация"], "question": "Что означает עריכה в контексте СМИ?"}', '{"correct": "редактирование", "correct_index": 2}', '{"text": "עריכה — редактирование. עורך — редактор."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1855, 142, 'multiple_choice', 2, '{"options": ["пропаганда", "дезинформация", "журналистика", "информация"], "question": "Слово דיסאינפורמציה означает:"}', '{"correct": "дезинформация", "correct_index": 1}', '{"text": "דיסאינפורמציה — дезинформация. Заимствование из английского."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1864, 143, 'multiple_choice', 2, '{"options": ["грусть", "тревога", "злость", "радость"], "question": "Слово חרדה означает:"}', '{"correct": "тревога", "correct_index": 1}', '{"text": "חרדה (харадА) — тревога, тревожность."}', 10);
