INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3282, 167, 'fill_blank', 2, '{"hint": "центральное понятие", "sentence": "ה_____ משחק תפקיד חשוב בהבנת הנושא"}', '{"correct": "наиболее", "alternatives": []}', '{"text": "наиболее (בלשנות) — ключевое слово урока."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3234, 199, 'dictation', 2, '{"hint": "Запишите услышанное", "audio_text": "אנחנו לומדים על העניין כי הוא רלוונטי בחיי היומיום"}', '{"correct": "אנחנו לומדים על העניין כי הוא רלוונטי בחיי היומיום"}', '{"text": "Предложение содержит тематическую лексику. עניין — центральный термин."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3235, 200, 'multiple_choice', 2, '{"options": ["תכונה", "מאפיין", "סימן", "беглость"], "question": "Выберите правильный перевод слова רהיטות:"}', '{"correct": "беглость", "correct_index": 3}', '{"text": "רהיטות — беглость. Лексика темы «полное владение»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3236, 200, 'fill_blank', 2, '{"hint": "центральное понятие", "sentence": "כדי להבין את הנושא, צריך להכיר את ה_____ (полное владение)"}', '{"correct": "דבר", "alternatives": []}', '{"text": "דבר — ключевое слово в теме «полное владение»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3237, 200, 'dictation', 2, '{"hint": "Диктант: запишите на иврите", "audio_text": "הדבר התפתח מאוד בעשורים האחרונים"}', '{"correct": "הדבר התפתח מאוד בעשורים האחרונים"}', '{"text": "Внимание на предлоги: ב — в, ל — к/для, על — о/на."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (241, 12, 'multiple_choice', 2, '{"options": ["7", "5", "9", "3"], "text_he": "", "question": "Сколько биньянов в иврите?"}', '{"correct": "7", "correct_index": 0}', '{"text": "В иврите 7 биньянов: Пааль, Нифъаль, Пиэль, Пуаль, Хифъиль, Хуфъаль, Хитпаэль"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3851, 207, 'translate_ru_he', 1, '{"hint": "קרים", "prompt_ru": "Вода холодная", "target_he": "המים קרים"}', '{"accept": ["המים קרים", "מים קרים"], "correct": "המים קרים"}', '{"text": "Вода холодная = המים קרים"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3239, 42, 'fill_blank', 2, '{"hint": "מושג מרכזי שלמדנו", "sentence": "אנחנו לומדים על _____ בכיתה"}', '{"correct": "הנושא", "alternatives": []}', '{"text": "הנושא (вышел из себя, старался изо всех сил) — ключевое слово урока."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3262, 147, 'fill_blank', 2, '{"hint": "центральное понятие", "sentence": "הבנת ה_____ דורשת ידע בסיסי בתחום"}', '{"correct": "наиболее", "alternatives": []}', '{"text": "наиболее (חדשות) — ключевое слово урока."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (225, 6, 'multiple_choice', 1, '{"options": ["патах", "хирик", "холам", "цере"], "text_he": "פַּ", "question": "Какая огласовка обозначает звук «а»?"}', '{"correct": "патах", "correct_index": 0}', '{"text": "Патах (פַּ) — горизонтальная чёрточка под буквой, обозначает звук «а»"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (226, 6, 'multiple_choice', 1, '{"options": ["и", "а", "о", "у"], "text_he": "בִּ", "question": "Какой звук обозначает огласовка хирик?"}', '{"correct": "и", "correct_index": 0}', '{"text": "Хирик (בִּ) — точка под буквой, обозначает звук «и»"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (228, 7, 'multiple_choice', 1, '{"options": ["הבית", "בהית", "אבית", "לבית"], "text_he": "בית", "question": "Как будет «дом» с определённым артиклем?"}', '{"correct": "הבית", "correct_index": 0}', '{"text": "Определённый артикль ה присоединяется к началу слова: הבית (ха-бАйит)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (231, 8, 'multiple_choice', 1, '{"options": ["ה-", "ים-", "ת-", "ן-"], "text_he": "", "question": "Какое окончание обычно имеют существительные женского рода?"}', '{"correct": "ה-", "correct_index": 0}', '{"text": "Женский род обычно оканчивается на ה- (hей) или ת- (тав)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (234, 9, 'multiple_choice', 1, '{"options": ["הם", "הן", "אנחנו", "אתם"], "text_he": "", "question": "Как переводится «они» (м.р.) на иврит?"}', '{"correct": "הם", "correct_index": 0}', '{"text": "הם (hэм) — они, мужской род"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (240, 20, 'multiple_choice', 1, '{"options": ["Который час?", "Как дела?", "Где ты?", "Что это?"], "text_he": "", "question": "Что значит «מה השעה?»"}', '{"correct": "Который час?", "correct_index": 0}', '{"text": "מה השעה (ма hа-шаА) — Который час?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (243, 12, 'multiple_choice', 2, '{"options": ["Хитпаэль", "Пааль", "Пуаль", "Хуфъаль"], "text_he": "", "question": "Какой биньян выражает взаимное действие?"}', '{"correct": "Хитпаэль", "correct_index": 0}', '{"text": "Хитпаэль (התפעל) выражает возвратное и взаимное действие"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (245, 22, 'multiple_choice', 2, '{"options": ["последний согласный: г vs к", "гласный", "ударение", "род"], "text_he": "", "question": "Чем отличаются слова דָּג и דָּק?"}', '{"correct": "последний согласный: г vs к", "correct_index": 0}', '{"text": "דג (даг) — рыба, דק (дак) — тонкий. Различие в последнем согласном"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (246, 22, 'multiple_choice', 2, '{"options": ["кЕлев", "калАв", "калЕв", "кулАв"], "text_he": "", "question": "Как звучит слово כֶּלֶב?"}', '{"correct": "кЕлев", "correct_index": 0}', '{"text": "כלב (кЕлев) — собака, два сеголя (э-э)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (252, 28, 'multiple_choice', 3, '{"options": ["Нифъаль", "Пааль", "Пиэль", "Хифъиль"], "text_he": "", "question": "В каком биньяне стоит глагол «נכתב»?"}', '{"correct": "Нифъаль", "correct_index": 0}', '{"text": "נכתב (нихтАв) — был написан, Нифъаль — пассив от כתב"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (258, 30, 'multiple_choice', 3, '{"options": ["חייב", "יכול", "רוצה", "צריך"], "text_he": "", "question": "Как сказать «должен» (м.р.) на иврите?"}', '{"correct": "צריך", "correct_index": 3}', '{"text": "צריך (царИх) — нужно/должен, חייב (хайЯв) — обязан. Оба переводятся как «должен»"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (267, 49, 'multiple_choice', 3, '{"options": ["אם", "כי", "גם", "אז"], "text_he": "", "question": "Какое слово начинает условное предложение?"}', '{"correct": "אם", "correct_index": 0}', '{"text": "אם (им) — если, начинает условное предложение"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (273, 51, 'multiple_choice', 3, '{"options": ["Хитпаэль", "Пааль", "Нифъаль", "Пиэль"], "text_he": "", "question": "Какой биньян у слова «להתלבש» (одеваться)?"}', '{"correct": "Хитпаэль", "correct_index": 0}', '{"text": "להתלבש — Хитпаэль, возвратное действие (одевать себя)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (275, 52, 'multiple_choice', 3, '{"options": ["קופת חולים", "בית חולים", "מרפאה", "בית מרקחת"], "text_he": "", "question": "Как называется больничная касса в Израиле?"}', '{"correct": "קופת חולים", "correct_index": 0}', '{"text": "קופת חולים (купАт холИм) — больничная касса, основа системы здравоохранения"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (350, 71, 'multiple_choice', 5, '{"options": ["כותרת", "מאמר", "טור", "עורך"], "text_he": "", "question": "Как называется газетный заголовок на иврите?"}', '{"correct": "כותרת", "correct_index": 0}', '{"text": "כותרת (котЕрет) — заголовок"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (279, 53, 'multiple_choice', 3, '{"options": ["Ханука", "Пурим", "Суккот", "Шавуот"], "text_he": "", "question": "В какой праздник зажигают ханукию?"}', '{"correct": "Ханука", "correct_index": 0}', '{"text": "В Хануку (חנוכה) зажигают ханукию — девятисвечник, 8 дней"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (283, 54, 'multiple_choice', 3, '{"options": ["Большое спасибо", "Пожалуйста", "Извините", "До свидания"], "text_he": "", "question": "Что означает «תודה רבה»?"}', '{"correct": "Большое спасибо", "correct_index": 0}', '{"text": "תודה רבה (тодА рабА) — большое спасибо"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (287, 36, 'multiple_choice', 3, '{"options": ["כתיבה", "כותב", "מכתב", "כתובת"], "text_he": "", "question": "Какое отглагольное существительное от «לכתוב» (писать)?"}', '{"correct": "כתיבה", "correct_index": 0}', '{"text": "כתיבה (ктивА) — писание/письмо (процесс), мишкаль ктилА"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (291, 37, 'multiple_choice', 3, '{"options": ["Хуфъаль", "Нифъаль", "Пуаль", "Хитпаэль"], "text_he": "", "question": "Какой биньян является пассивной парой Хифъиля?"}', '{"correct": "Хуфъаль", "correct_index": 0}', '{"text": "Хуфъаль (הופעל) — пассивная пара Хифъиля, как Пуаль для Пиэля"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (297, 57, 'multiple_choice', 4, '{"options": ["hitCaCCut", "CtiCA", "miCCAC", "taCCiC"], "text_he": "", "question": "Какой мишкаль у слова «התנהגות» (поведение)?"}', '{"correct": "hitCaCCut", "correct_index": 0}', '{"text": "התנהגות — мишкаль hitkatLut (הִתְקַטְּלוּת), отглагольное сущ. от Хитпаэль"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (300, 58, 'multiple_choice', 4, '{"options": ["כאן", "ערוץ 12", "ערוץ 13", "רשת"], "text_he": "", "question": "Как называется основной канал общественного ТВ?"}', '{"correct": "כאן", "correct_index": 0}', '{"text": "כאן (кан) — израильская общественная телерадиокорпорация, осн. 2017"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (303, 59, 'multiple_choice', 4, '{"options": ["опреснение воды", "водоснабжение", "очистка", "орошение"], "text_he": "", "question": "Что такое «התפלת מים»?"}', '{"correct": "опреснение воды", "correct_index": 0}', '{"text": "התפלת מים (hатпалАт мАйим) — опреснение воды, ключевая технология Израиля"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (306, 41, 'multiple_choice', 4, '{"options": ["перестановка подлежащего и сказуемого", "двойное отрицание", "опущение глагола", "повтор"], "text_he": "", "question": "Что такое инверсия в иврите?"}', '{"correct": "перестановка подлежащего и сказуемого", "correct_index": 0}', '{"text": "Инверсия — изменение порядка SVO на VSO для стилистического эффекта"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3251, 66, 'fill_blank', 2, '{"hint": "основной термин темы", "sentence": "ה_____ נחקר רבות בשנים האחרונות"}', '{"correct": "הנושא", "alternatives": []}', '{"text": "הנושא (Метатеза: ת и ס меняются местами перед свистящими) — ключевое слово урока."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (310, 42, 'multiple_choice', 4, '{"options": ["вышел из себя, старался изо всех сил", "вышел из дома", "уволился", "убежал"], "text_he": "", "question": "Что значит «יצא מגדרו»?"}', '{"correct": "вышел из себя, старался изо всех сил", "correct_index": 0}', '{"text": "יצא מגדרו — приложил все усилия (букв. вышел из своих рамок)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (313, 61, 'multiple_choice', 4, '{"options": ["ориентироваться в ситуации", "знать географию", "путешествовать", "учить карту"], "text_he": "", "question": "Что значит «להכיר את השטח»?"}', '{"correct": "ориентироваться в ситуации", "correct_index": 0}', '{"text": "להכיר את השטח — знать обстановку, ориентироваться (букв. знать местность)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (316, 62, 'multiple_choice', 5, '{"options": ["השערה", "הנחה", "תיאוריה", "מסקנה"], "text_he": "", "question": "Какое слово означает «гипотеза» на иврите?"}', '{"correct": "השערה", "correct_index": 0}', '{"text": "השערה (hашъарА) — гипотеза/предположение"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (323, 64, 'multiple_choice', 4, '{"options": ["Екклесиаст", "Бытие", "Псалмы", "Притчи"], "text_he": "", "question": "Откуда фраза «הבל הבלים»?"}', '{"correct": "Екклесиаст", "correct_index": 0}', '{"text": "הבל הבלים הכל הבל — Суета сует, всё суета (Коhелет/Екклесиаст 1:2)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (325, 65, 'multiple_choice', 5, '{"options": ["когда пишет / в процессе написания", "без написания", "до написания", "после написания"], "text_he": "", "question": "Что значит инфинитив с предлогом ב (בכתוב)?"}', '{"correct": "когда пишет / в процессе написания", "correct_index": 0}', '{"text": "ב + инфинитив = во время действия: בכתבו — когда он пишет"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (328, 66, 'multiple_choice', 5, '{"options": ["кажется / виден", "видит", "показывает", "смотрит"], "text_he": "", "question": "Какое значение у Нифъаля в слове «נראה»?"}', '{"correct": "кажется / виден", "correct_index": 0}', '{"text": "נראה (нирЭ) — кажется, виден (стативное значение Нифъаля)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (333, 67, 'multiple_choice', 5, '{"options": ["подводить итоги", "рисковать", "считать", "соглашаться"], "text_he": "", "question": "Что значит «לסכם»?"}', '{"correct": "подводить итоги", "correct_index": 0}', '{"text": "לסכם (лесакЭм) — подводить итоги, резюмировать"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (336, 68, 'multiple_choice', 5, '{"options": ["формальный с академическими коннекторами", "разговорный с идиомами", "поэтический", "газетный"], "text_he": "", "question": "Какой регистр уместен в академическом эссе?"}', '{"correct": "формальный с академическими коннекторами", "correct_index": 0}', '{"text": "Академический текст использует לפיכך, אי לכך, מן הראוי и другие формальные связки"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (337, 45, 'multiple_choice', 5, '{"options": ["рифма", "метафора", "ритм", "аллитерация"], "text_he": "", "question": "Что такое «חריזה» в поэзии?"}', '{"correct": "рифма", "correct_index": 0}', '{"text": "חריזה (харизА) — рифма, один из основных поэтических приёмов"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (341, 46, 'multiple_choice', 5, '{"options": ["חוזה", "הסכם", "עסקה", "שטר"], "text_he": "", "question": "Как сказать «договор» на юридическом иврите?"}', '{"correct": "חוזה", "correct_index": 0}', '{"text": "חוזה (хозЭ) — договор/контракт, הסכם — соглашение"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (344, 69, 'multiple_choice', 5, '{"options": ["Хаим Нахман Бялик", "Иегуда Амихай", "Рахель", "Натан Альтерман"], "text_he": "", "question": "Кто является «национальным поэтом» Израиля?"}', '{"correct": "Хаим Нахман Бялик", "correct_index": 0}', '{"text": "Х.Н. Бялик — המשורר הלאומי, заложил основы современной ивритской поэзии"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (348, 70, 'multiple_choice', 5, '{"options": ["при условии / с оговоркой", "в дополнение к", "вместо", "против"], "text_he": "", "question": "Что значит «בכפוף ל»?"}', '{"correct": "при условии / с оговоркой", "correct_index": 0}', '{"text": "בכפוף ל — юридический термин: «при условии соблюдения», «с учётом»"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (354, 72, 'multiple_choice', 5, '{"options": ["из арабского", "из английского", "из идиша", "из русского"], "text_he": "", "question": "Откуда пришло слово «יאללה»?"}', '{"correct": "из арабского", "correct_index": 0}', '{"text": "יאללה — из арабского يا الله, одно из самых частых сленговых слов"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (356, 73, 'multiple_choice', 5, '{"options": ["литургическая поэзия", "молитва", "закон", "комментарий"], "text_he": "", "question": "Что такое «пиют»?"}', '{"correct": "литургическая поэзия", "correct_index": 0}', '{"text": "פיוט (пиЮт) — литургическая поэзия, расцвет в средневековье"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (359, 74, 'multiple_choice', 5, '{"options": ["переход между стилями речи в одном разговоре", "перевод с иврита на другой язык", "использование сленга", "письменная речь"], "text_he": "", "question": "Что такое code-switching в контексте иврита?"}', '{"correct": "переход между стилями речи в одном разговоре", "correct_index": 0}', '{"text": "Переключение регистров — когда говорящий переходит между формальным, разговорным, сленгом"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3252, 67, 'fill_blank', 2, '{"hint": "центральное понятие", "sentence": "חקירת ה_____ חשפה תובנות חדשות"}', '{"correct": "הנושא", "alternatives": []}', '{"text": "הנושא (подводить итоги) — ключевое слово урока."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (364, 75, 'multiple_choice', 5, '{"options": ["он не является", "он является", "мы не", "они не"], "text_he": "", "question": "Что означает «אינו»?"}', '{"correct": "он не является", "correct_index": 0}', '{"text": "אינו (эйнО) — он не является, формальное отрицание (вместо разг. הוא לא)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (367, 76, 'multiple_choice', 5, '{"options": ["публицистический", "академический", "юридический", "разговорный"], "text_he": "", "question": "Какой стиль речи сочетает формальность и эмоциональность?"}', '{"correct": "публицистический", "correct_index": 0}', '{"text": "Публицистический стиль (סגנון פובליציסטי) — газетные колонки, мнения"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (368, 1, 'multiple_choice', 1, '{"options": ["Алеф (א)", "Бет (ב)", "Гимель (ג)", "Далет (ד)"], "text_he": "א ב ג ד ה", "question": "Какая буква из первых пяти ивритского алфавита является немой (не имеет собственного звука)?"}', '{"correct": "Алеф (א)", "correct_index": 0}', '{"text": "Алеф (א) — немая буква, она принимает звук огласовки. Сама по себе она не произносится, а служит «подставкой» для гласного звука, например: אָב (ав) — отец."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (369, 1, 'multiple_choice', 1, '{"options": ["Гимель (ג)", "Бет (ב)", "Далет (ד)", "Хей (ה)"], "text_he": "א ב ג ד ה", "question": "Какая буква идёт третьей в ивритском алфавите?"}', '{"correct": "Гимель (ג)", "correct_index": 0}', '{"text": "Порядок первых пяти букв: Алеф (א), Бет (ב), Гимель (ג), Далет (ד), Хей (ה). Гимель — третья буква, произносится как «г»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (378, 55, 'multiple_choice', 4, '{"options": ["Хитпаэль", "Пааль", "Пиэль", "Нифъаль"], "text_he": "להתפתח", "question": "К какому биньяну относится глагол «להתפתח» (развиваться)?"}', '{"correct": "Хитпаэль", "correct_index": 0}', '{"text": "להתפתח (леhитпатЕах) — Хитпаэль от корня פ-ת-ח. Приставка הת- указывает на возвратное значение: פיתח (Пиэль) — развивал, התפתח (Хитпаэль) — развивался (сам)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (9, 8, 'multiple_choice', 1, '{"options": ["мужской", "תהליך", "женский", "מבנה"], "question": "Слово יַלְדָּה — какого рода?"}', '{"correct": "женский", "correct_index": 2}', '{"text": "Окончание -ה указывает на женский род: יַלְדָּה (девочка)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3238, 41, 'fill_blank', 2, '{"hint": "מילת מפתח בנושא השיעור", "sentence": "ה_____ הוא מושג מרכזי בתחום"}', '{"correct": "''ניתן ללמוד''", "alternatives": []}', '{"text": "''ניתן ללמוד'' (можно учиться) — ключевое слово урока."}', 10);
