INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3581, 201, 'minimal_pairs', 1, '{"pair_a": {"he": "סוס", "meaning": "лошадь", "translit": "сус"}, "pair_b": {"he": "סוף", "meaning": "конец", "translit": "соф"}, "question": "Какое слово вы слышите?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "סוס заканчивается на «с», סוף — на «ф»"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3582, 201, 'minimal_pairs', 1, '{"pair_a": {"he": "גדול", "meaning": "большой", "translit": "гадОль"}, "pair_b": {"he": "גמל", "meaning": "верблюд", "translit": "гамАль"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "גדול — ударение на последний слог «оль», גמל — на «аль»"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3583, 201, 'minimal_pairs', 1, '{"pair_a": {"he": "טוב", "meaning": "хорошо", "translit": "тов"}, "pair_b": {"he": "תוב", "meaning": "(нет значения)", "translit": "тов"}, "question": "С какой буквы начинается слово «хорошо»?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "ט (тет) и ת (тав) звучат одинаково, но טוב пишется через ט"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3584, 201, 'minimal_pairs', 1, '{"pair_a": {"he": "אש", "meaning": "огонь", "translit": "эш"}, "pair_b": {"he": "איש", "meaning": "мужчина/человек", "translit": "иш"}, "question": "Какое слово вы слышите?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "אש — один слог «эш», איש — один слог «иш» с другим гласным"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3585, 201, 'listening_comprehension', 1, '{"text_he": "שלום! אני דני. אני גר בתל אביב. אני תלמיד.", "questions": [{"correct": "Дани", "options": ["Давид", "Дани", "Дина"], "question": "Как зовут говорящего?"}], "text_translit": "шалОм! анИ дАни. анИ гар бетЕль авИв. анИ талмИд."}', '{"correct_answers": ["Дани"]}', '{"text": "Прослушайте текст ещё раз и обратите внимание на ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3598, 202, 'dictation', 1, '{"hint": "описание действия", "word_he": "הילדים משחקים בחצר", "word_translit": "хайеладИм месахакИм бехацЕр"}', '{"accept": ["הילדים משחקים בחצר"], "correct": "הילדים משחקים בחצר"}', '{"text": "הילדים משחקים בחצר — описание действия. Транслитерация: хайеладИм месахакИм бехацЕр"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3586, 201, 'listening_comprehension', 1, '{"text_he": "בוקר טוב! היום יום שישי. אני לא הולך לעבודה. אני הולך לים.", "questions": [{"correct": "Пятница", "options": ["Понедельник", "Пятница", "Суббота"], "question": "Какой сегодня день?"}], "text_translit": "бОкер тов! хайОм йом шишИ. анИ ло олЕх лаавода. анИ олЕх лаям."}', '{"correct_answers": ["Пятница"]}', '{"text": "Прослушайте текст ещё раз и обратите внимание на ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3587, 201, 'listening_comprehension', 1, '{"text_he": "אני אוהבת קפה. כל בוקר אני שותה קפה עם חלב. זה טעים מאוד.", "questions": [{"correct": "Кофе", "options": ["Чай", "Кофе", "Сок"], "question": "Что она любит?"}], "text_translit": "анИ охЕвет кафЕ. коль бОкер анИ шотА кафЕ им халАв. зе таИм меОд."}', '{"correct_answers": ["Кофе"]}', '{"text": "Прослушайте текст ещё раз и обратите внимание на ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3588, 201, 'listening_comprehension', 1, '{"text_he": "המשפחה שלי גדולה. יש לי אבא, אמא, אח ושתי אחיות.", "questions": [{"correct": "Две", "options": ["Одна", "Две", "Три"], "question": "Сколько сестёр у говорящего?"}], "text_translit": "хамишпахА шелИ гдолА. йеш ли Аба, Има, ах ушТей ахайОт."}', '{"correct_answers": ["Две"]}', '{"text": "Прослушайте текст ещё раз и обратите внимание на ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3589, 201, 'listening_comprehension', 1, '{"text_he": "אני לומד עברית בבית ספר. המורה שלי טובה. אנחנו לומדים כל יום.", "questions": [{"correct": "Иврит", "options": ["Английский", "Иврит", "Математику"], "question": "Что он учит?"}], "text_translit": "анИ ломЕд иврИт бебЕйт сЕфер. хаморА шелИ товА. анАхну ломдИм коль йом."}', '{"correct_answers": ["Иврит"]}', '{"text": "Прослушайте текст ещё раз и обратите внимание на ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3590, 201, 'listening_comprehension', 1, '{"text_he": "הדירה שלי קטנה. יש חדר שינה, מטבח וסלון. אני אוהב את הדירה.", "questions": [{"correct": "Маленькая", "options": ["Большая", "Маленькая", "Новая"], "question": "Какая квартира у говорящего?"}], "text_translit": "хадирА шелИ ктанА. йеш хадАр шенА, митбАх весалОн. анИ охЕв эт хадирА."}', '{"correct_answers": ["Маленькая"]}', '{"text": "Прослушайте текст ещё раз и обратите внимание на ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3591, 201, 'listening_comprehension', 1, '{"text_he": "היום חם מאוד. השמש זורחת. אני רוצה לשתות מים קרים.", "questions": [{"correct": "Жарко", "options": ["Холодно", "Жарко", "Дождливо"], "question": "Какая сегодня погода?"}], "text_translit": "хайОм хам меОд. хашЕмеш зорАхат. анИ роцЕ лиштОт мАим карИм."}', '{"correct_answers": ["Жарко"]}', '{"text": "Прослушайте текст ещё раз и обратите внимание на ключевые слова."}', 20);
