INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3592, 201, 'listening_comprehension', 1, '{"text_he": "בערב אני אוכל ארוחת ערב עם המשפחה. אנחנו מדברים ושמחים.", "questions": [{"correct": "С семьёй", "options": ["С друзьями", "Один", "С семьёй"], "question": "С кем он ужинает?"}], "text_translit": "баЭрев анИ охЕль арухАт Эрев им хамишпахА. анАхну медабрИм ве-смехИм."}', '{"correct_answers": ["С семьёй"]}', '{"text": "Прослушайте текст ещё раз и обратите внимание на ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3593, 201, 'listening_comprehension', 1, '{"text_he": "אני הולך לחנות. אני קונה לחם, חלב וביצים. זה עולה עשרים שקלים.", "questions": [{"correct": "20 шекелей", "options": ["10 шекелей", "20 шекелей", "30 шекелей"], "question": "Сколько стоит покупка?"}], "text_translit": "анИ олЕх лаханУт. анИ конЕ лЕхем, халАв вебейцИм. зе олЕ эсрИм шкалИм."}', '{"correct_answers": ["20 шекелей"]}', '{"text": "Прослушайте текст ещё раз и обратите внимание на ключевые слова."}', 20);
