INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3614, 202, 'dictation', 1, '{"hint": "выходной", "word_he": "בשבת אני לא עובד", "word_translit": "бешабАт анИ ло овЕд"}', '{"accept": ["בשבת אני לא עובד"], "correct": "בשבת אני לא עובד"}', '{"text": "בשבת אני לא עובד — выходной. Транслитерация: бешабАт анИ ло овЕд"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3615, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "חולה", "meaning": "больной", "translit": "холЕ"}, "pair_b": {"he": "חולצה", "meaning": "рубашка", "translit": "хульцА"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "חולה (больной) — два слога, חולצה (рубашка) — три слога"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3617, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "כתב", "meaning": "писал", "translit": "катАв"}, "pair_b": {"he": "כאב", "meaning": "болел/боль", "translit": "каАв"}, "question": "Какое слово вы слышите?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "כתב — «т» в середине, כאב — «а» в середине"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3618, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "רחוב", "meaning": "улица", "translit": "рехОв"}, "pair_b": {"he": "רחוק", "meaning": "далеко", "translit": "рахОк"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "רחוב оканчивается на «в», רחוק — на «к»"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3619, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "שמח", "meaning": "счастливый", "translit": "самЕах"}, "pair_b": {"he": "צמח", "meaning": "вырос/растение", "translit": "цамАх"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "ש (шин/син) — «с», צ (цади) — «ц». Разная первая буква"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3620, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "קנה", "meaning": "купил", "translit": "канА"}, "pair_b": {"he": "בנה", "meaning": "построил", "translit": "банА"}, "question": "Какое слово вы слышите?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "קנה начинается с «к», בנה — с «б»"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3621, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "חדר", "meaning": "комната", "translit": "хЕдер"}, "pair_b": {"he": "חדש", "meaning": "новый", "translit": "хадАш"}, "question": "Какое слово вы слышите?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "חדר — ударение на первый слог, חדש — на второй"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3622, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "עבודה", "meaning": "работа", "translit": "аводА"}, "pair_b": {"he": "עבירה", "meaning": "нарушение", "translit": "аверА"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "עבודה — «аводА», עבירה — «аверА», разный второй слог"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3623, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "משרד", "meaning": "офис", "translit": "мисрАд"}, "pair_b": {"he": "משרת", "meaning": "прислуга", "translit": "мешарЕт"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "משרד — два слога, משרת — три слога"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3624, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "שעה", "meaning": "час", "translit": "шаА"}, "pair_b": {"he": "שעון", "meaning": "часы (прибор)", "translit": "шаОн"}, "question": "Какое слово вы слышите?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "שעה — два слога «ша-а», שעון — два слога «ша-он»"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3625, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "אוכל", "meaning": "еда", "translit": "Охель"}, "pair_b": {"he": "אוכל", "meaning": "ем (я ем)", "translit": "охЕль"}, "question": "Какое значение здесь: «еда» или «я ем»?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "Одно и то же слово! Ударение: Охель=еда, охЕль=я ем"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3626, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "בוקר", "meaning": "утро", "translit": "бОкер"}, "pair_b": {"he": "בקר", "meaning": "скот/говядина", "translit": "бакАр"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "בוקר — с «о» в первом слоге, בקר — с «а»"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3627, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "דרך", "meaning": "дорога/путь", "translit": "дЕрех"}, "pair_b": {"he": "דרום", "meaning": "юг", "translit": "дарОм"}, "question": "Какое слово вы слышите?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "דרך — «дЕрех», ударение в начале; דרום — «дарОм», ударение в конце"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3628, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "לבן", "meaning": "белый", "translit": "лавАн"}, "pair_b": {"he": "לבנה", "meaning": "луна", "translit": "леванА"}, "question": "Какое слово вы слышите?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "לבן — два слога, לבנה — три слога с окончанием «а»"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3629, 202, 'minimal_pairs', 1, '{"pair_a": {"he": "חנות", "meaning": "магазин", "translit": "ханУт"}, "pair_b": {"he": "חנויות", "meaning": "магазины", "translit": "ханойОт"}, "question": "Единственное или множественное число?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "חנות — ед.ч., חנויות — мн.ч. (окончание «-йот»)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3630, 202, 'listening_comprehension', 2, '{"text_he": "אני קם בשבע בבוקר. אני אוכל ארוחת בוקר ונוסע לעבודה באוטובוס. העבודה שלי במרכז העיר.", "questions": [{"correct": "В 7", "options": ["В 6", "В 7", "В 8"], "question": "Во сколько он встаёт?"}, {"correct": "На автобусе", "options": ["На машине", "На автобусе", "Пешком"], "question": "Как он добирается до работы?"}], "text_translit": "анИ кам бешЕва бабОкер. анИ охЕль арухАт бОкер веносЕа лаавода беОтобус. хаавода шелИ бемерказ хаИр."}', '{"correct_answers": ["В 7", "На автобусе"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3631, 202, 'listening_comprehension', 2, '{"text_he": "בשבת הלכנו למסעדה. הזמנו סלט, בשר וירקות. האוכל היה טעים מאוד. שילמנו מאה ועשרים שקלים.", "questions": [{"correct": "В субботу", "options": ["В пятницу", "В субботу", "В воскресенье"], "question": "Когда они ходили в ресторан?"}, {"correct": "120 шекелей", "options": ["100 шекелей", "120 шекелей", "150 шекелей"], "question": "Сколько они заплатили?"}], "text_translit": "бешабАт халАхну лемисадА. хизмАну салАт, басАр вейракОт. хаОхель хайА таИм меОд. шилАмну мЕа веэсрИм шкалИм."}', '{"correct_answers": ["В субботу", "120 шекелей"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3632, 202, 'listening_comprehension', 2, '{"text_he": "הבת שלי לומדת בכיתה ג׳. היא אוהבת מתמטיקה וציור. אחרי בית הספר היא הולכת לשיעור פסנתר.", "questions": [{"correct": "В 3-м", "options": ["Во 2-м", "В 3-м", "В 4-м"], "question": "В каком классе учится дочь?"}, {"correct": "На фортепиано", "options": ["На танцы", "На фортепиано", "На плавание"], "question": "Куда она идёт после школы?"}], "text_translit": "хабАт шелИ ломЕдет бекитА гИмел. хи охЕвет математИка вецийУр. ахарЕй бейт хасЕфер хи олЕхет лешиУр псантЕр."}', '{"correct_answers": ["В 3-м", "На фортепиано"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3633, 202, 'listening_comprehension', 2, '{"text_he": "אתמול היה גשם חזק. הרחובות היו רטובים. היום השמש יצאה ויש קשת בענן.", "questions": [{"correct": "Сильный дождь", "options": ["Солнечно", "Сильный дождь", "Снег"], "question": "Какая была погода вчера?"}, {"correct": "Радуга", "options": ["Облака", "Радуга", "Ветер"], "question": "Что появилось сегодня?"}], "text_translit": "этмОль хайА гЕшем хазАк. харховОт хайУ ретувИм. хайОм хашЕмеш яцА вейЕш кЕшет беанАн."}', '{"correct_answers": ["Сильный дождь", "Радуга"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3634, 202, 'listening_comprehension', 2, '{"text_he": "אנחנו גרים בדירה בקומה שלישית. יש לנו שלושה חדרים, מטבח גדול ומרפסת עם נוף יפה.", "questions": [{"correct": "На 3-м", "options": ["На 2-м", "На 3-м", "На 4-м"], "question": "На каком этаже квартира?"}, {"correct": "Балкон", "options": ["Сад", "Балкон", "Крыша"], "question": "Что есть с красивым видом?"}], "text_translit": "анАхну гарИм бедирА бекомА шлишИт. йеш лАну шлошА хадарИм, митбАх гадОль умирпЕсет им ноф яфЕ."}', '{"correct_answers": ["На 3-м", "Балкон"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3635, 202, 'listening_comprehension', 2, '{"text_he": "בחנות קניתי שתי חולצות ומכנסיים. החולצות עלו שמונים שקל והמכנסיים מאה חמישים.", "questions": [{"correct": "Две", "options": ["Одну", "Две", "Три"], "question": "Сколько рубашек он купил?"}, {"correct": "150 шекелей", "options": ["80 шекелей", "100 шекелей", "150 шекелей"], "question": "Сколько стоили брюки?"}], "text_translit": "баханУт канИти штЕй хульцОт умихнасАим. хахульцОт алУ шмонИм шЕкель вехамихнасАим мЕа хамишИм."}', '{"correct_answers": ["Две", "150 шекелей"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3636, 202, 'listening_comprehension', 2, '{"text_he": "הרופא אמר לי לנוח שלושה ימים. אני חולה ויש לי חום גבוה. אני שותה תה חם ולוקח תרופות.", "questions": [{"correct": "3 дня", "options": ["2 дня", "3 дня", "5 дней"], "question": "Сколько дней нужно отдыхать?"}, {"correct": "Горячий чай", "options": ["Кофе", "Горячий чай", "Воду"], "question": "Что он пьёт?"}], "text_translit": "харофЕ амАр ли ланУах шлошА ямИм. анИ холЕ вейЕш ли хом гавОа. анИ шотЕ тэ хам велокЕах труфОт."}', '{"correct_answers": ["3 дня", "Горячий чай"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3637, 202, 'listening_comprehension', 2, '{"text_he": "אחי עובד בבית חולים. הוא רופא שיניים. הוא עובד מיום ראשון עד יום חמישי, משמונה בבוקר עד ארבע.", "questions": [{"correct": "Стоматолог", "options": ["Хирург", "Стоматолог", "Терапевт"], "question": "Кем работает его брат?"}, {"correct": "Вс-Чт", "options": ["Вс-Чт", "Пн-Пт", "Вс-Пт"], "question": "В какие дни он работает?"}], "text_translit": "ахИ овЕд бебЕйт холИм. ху рофЕ шинАим. ху овЕд мийОм ришОн ад йом хамишИ, мишмОне бабОкер ад Арба."}', '{"correct_answers": ["Стоматолог", "Вс-Чт"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3638, 202, 'listening_comprehension', 2, '{"text_he": "נסענו לכנרת בסוף השבוע. שחינו בים, אכלנו דגים ונהנינו מאוד. חזרנו הביתה ביום שישי בערב.", "questions": [{"correct": "На Кинерет", "options": ["В Эйлат", "На Кинерет", "В Иерусалим"], "question": "Куда они поехали?"}, {"correct": "В пятницу вечером", "options": ["В четверг утром", "В пятницу вечером", "В субботу днём"], "question": "Когда вернулись?"}], "text_translit": "насАну леКинЕрет бесОф хашавУа. сахИну баЯм, ахАлну дагИм венеенИну меОд. хазАрну хабАйта бейОм шишИ баЭрев."}', '{"correct_answers": ["На Кинерет", "В пятницу вечером"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3654, 203, 'dictation', 2, '{"hint": "карьера", "word_he": "הוא עבד במפעל עשרים שנה ופרש", "word_translit": "ху авАд бемифАль эсрИм шанА уфарАш"}', '{"accept": ["הוא עבד במפעל עשרים שנה ופרש"], "correct": "הוא עבד במפעל עשרים שנה ופרש"}', '{"text": "הוא עבד במפעל עשרים שנה ופרש — карьера"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3655, 203, 'dictation', 2, '{"hint": "хобби", "word_he": "נרשמתי לקורס בישול איטלקי", "word_translit": "нирашАмти лекУрс бишУль италкИ"}', '{"accept": ["נרשמתי לקורס בישול איטלקי"], "correct": "נרשמתי לקורס בישול איטלקי"}', '{"text": "נרשמתי לקורס בישול איטלקי — хобби"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3639, 202, 'listening_comprehension', 2, '{"text_he": "יש לי כלב גדול ושתי חתולות. הכלב אוהב לרוץ בפארק. החתולות ישנות כל היום על הספה.", "questions": [{"correct": "Две", "options": ["Одна", "Две", "Три"], "question": "Сколько кошек у говорящего?"}, {"correct": "Бегать в парке", "options": ["Спать", "Бегать в парке", "Есть"], "question": "Что любит делать собака?"}], "text_translit": "йеш ли кЕлев гадОль уштЕй хатулОт. хакЕлев охЕв ларУц бапАрк. хахатулОт ешенОт коль хайОм аль хасапА."}', '{"correct_answers": ["Две", "Бегать в парке"]}', '{"text": "Прослушайте текст ещё раз, обращая внимание на числа и ключевые слова."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3640, 203, 'dictation', 2, '{"hint": "прошедшее время", "word_he": "אתמול הלכתי לקניון עם חברים", "word_translit": "этмОль халАхти лаканьОн им хаверИм"}', '{"accept": ["אתמול הלכתי לקניון עם חברים"], "correct": "אתמול הלכתי לקניון עם חברים"}', '{"text": "אתמול הלכתי לקניון עם חברים — прошедшее время"}', 15);
