INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3675, 203, 'listening_comprehension', 2, '{"text_he": "אתמול חגגנו את יום ההולדת של סבתא. כל המשפחה הגיעה — דודים, דודות ובני דודים. אכלנו עוגה גדולה ושרנו שירים. סבתא הייתה מאוד שמחה ואמרה שזה היום הכי יפה בשנה.", "questions": [{"correct": "Бабушки", "options": ["Мамы", "Бабушки", "Дедушки"], "question": "Чей день рождения отмечали?"}, {"correct": "Вся семья", "options": ["Только родители", "Вся семья", "Только дети"], "question": "Кто пришёл?"}, {"correct": "Что это самый красивый день в году", "options": ["Что устала", "Что это самый красивый день в году", "Что торт невкусный"], "question": "Что сказала бабушка?"}], "text_translit": "этмОль хагАгну эт йом хахуледЕт шель савтА..."}', '{"correct_answers": ["Бабушки", "Вся семья", "Что это самый красивый день в году"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3719, 204, 'minimal_pairs', 3, '{"pair_a": {"he": "רפורמה", "meaning": "реформа", "translit": "рефОрма"}, "pair_b": {"he": "פלטפורמה", "meaning": "платформа", "translit": "платфОрма"}, "question": "Реформа или платформа?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "רפורמה — 3 слога. פלטפורמה — 4 слога"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3676, 203, 'listening_comprehension', 2, '{"text_he": "דני עבר לדירה חדשה בשבוע שעבר. הדירה נמצאת ליד הים בתל אביב. יש בה שני חדרים, סלון גדול ומרפסת. השכירות גבוהה אבל הנוף שווה את זה.", "questions": [{"correct": "На прошлой неделе", "options": ["В прошлом месяце", "На прошлой неделе", "Вчера"], "question": "Когда Дани переехал?"}, {"correct": "Возле моря в Тель-Авиве", "options": ["В Иерусалиме", "Возле моря в Тель-Авиве", "В центре Хайфы"], "question": "Где находится квартира?"}, {"correct": "Дорогая, но вид стоит того", "options": ["Дешёвая", "Дорогая, но вид стоит того", "Слишком дорогая"], "question": "Что говорит Дани об аренде?"}], "text_translit": "дАни авАр ледирА хадашА бешавУа шеавАр..."}', '{"correct_answers": ["На прошлой неделе", "Возле моря в Тель-Авиве", "Дорогая, но вид стоит того"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3677, 203, 'listening_comprehension', 2, '{"text_he": "בכל בוקר מיכל יוצאת לריצה בפארק. היא רצה חמישה קילומטרים ואחר כך עושה תרגילים. אחרי האימון היא מתקלחת ונוסעת לעבודה. היא אומרת שהריצה נותנת לה אנרגיה לכל היום.", "questions": [{"correct": "5 км", "options": ["3 км", "5 км", "10 км"], "question": "Сколько километров бегает Михаль?"}, {"correct": "Делает упражнения", "options": ["Завтракает", "Делает упражнения", "Идёт на работу"], "question": "Что она делает после бега?"}, {"correct": "Это даёт ей энергию на весь день", "options": ["Для похудения", "Это даёт ей энергию на весь день", "Готовится к марафону"], "question": "Почему она бегает?"}], "text_translit": "бехОль бОкер михАль йоцЕт лерицА бапАрк..."}', '{"correct_answers": ["5 км", "Делает упражнения", "Это даёт ей энергию на весь день"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3678, 203, 'listening_comprehension', 2, '{"text_he": "השבוע התחלנו קורס חדש באוניברסיטה — מבוא לפסיכולוגיה. המרצה מעניינת מאוד ויש הרבה סטודנטים. צריך לקרוא שני ספרים ולכתוב עבודה עד סוף הסמסטר.", "questions": [{"correct": "Введение в психологию", "options": ["Введение в философию", "Введение в психологию", "Введение в социологию"], "question": "Какой курс начался?"}, {"correct": "Интересная", "options": ["Скучная", "Интересная", "Строгая"], "question": "Какая преподаватель?"}, {"correct": "Прочитать 2 книги и написать работу", "options": ["Сдать экзамен", "Прочитать 2 книги и написать работу", "Написать 3 эссе"], "question": "Что нужно сделать до конца семестра?"}], "text_translit": "хашавУа хитхАлну кУрс хадАш баунивЕрсита..."}', '{"correct_answers": ["Введение в психологию", "Интересная", "Прочитать 2 книги и написать работу"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3850, 207, 'translate_ru_he', 1, '{"hint": "גדול", "prompt_ru": "Собака большая", "target_he": "הכלב גדול"}', '{"accept": ["הכלב גדול", "כלב גדול"], "correct": "הכלב גדול"}', '{"text": "Собака большая = הכלב גדול"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3679, 203, 'listening_comprehension', 2, '{"text_he": "בסוף השבוע האחרון טיילנו בגליל. ביום שישי עלינו על הר מירון ובשבת ביקרנו בצפת העתיקה. ראינו בתי כנסת יפים ואכלנו ארוחת צהריים במסעדה דרוזית. היה קר למעלה אבל הנוף היה מדהים.", "questions": [{"correct": "В Галилее", "options": ["В Негеве", "В Галилее", "На побережье"], "question": "Где они гуляли?"}, {"correct": "Гора Мирон", "options": ["Гора Кармель", "Гора Мирон", "Масада"], "question": "Куда поднялись в пятницу?"}, {"correct": "В друзском ресторане", "options": ["В еврейском ресторане", "В друзском ресторане", "Дома"], "question": "Где обедали?"}], "text_translit": "бесОф хашавУа хаахарОн тиЯлну багалИль..."}', '{"correct_answers": ["В Галилее", "Гора Мирон", "В друзском ресторане"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3680, 203, 'listening_comprehension', 2, '{"text_he": "אני עובד כמתכנת בחברת הייטק. העבודה מעניינת אבל לחוצה. אנחנו עובדים בצוותים של חמישה אנשים. כל שבועיים יש פגישה עם המנהל. המשכורת טובה אבל השעות ארוכות.", "questions": [{"correct": "В хайтек-компании", "options": ["В банке", "В хайтек-компании", "В больнице"], "question": "Где он работает?"}, {"correct": "5", "options": ["3", "5", "10"], "question": "Сколько человек в команде?"}, {"correct": "Интересная но напряжённая", "options": ["Скучная но лёгкая", "Интересная но напряжённая", "Плохо оплачиваемая"], "question": "Что он говорит о работе?"}], "text_translit": "анИ овЕд кеметахнЕт бехеврАт хАйтек..."}', '{"correct_answers": ["В хайтек-компании", "5", "Интересная но напряжённая"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3687, 204, 'dictation', 3, '{"hint": "право", "word_he": "בית המשפט העליון דן בעתירה נגד החוק", "word_translit": "бейт хамишпАт хаэльОн дан баатирА нЕгед хахОк"}', '{"accept": ["בית המשפט העליון דן בעתירה נגד החוק"], "correct": "בית המשפט העליון דן בעתירה נגד החוק"}', '{"text": "(право) בית המשפט העליון דן בעתירה נגד החוק"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3681, 203, 'listening_comprehension', 2, '{"text_he": "הבן שלי בן שש ובספטמבר הוא מתחיל כיתה א׳. קנינו לו ילקוט חדש, מחברות ועפרונות. הוא מתרגש מאוד ומחכה ליום הראשון. גם אני קצת מתרגש.", "questions": [{"correct": "6", "options": ["5", "6", "7"], "question": "Сколько лет сыну?"}, {"correct": "Ранец, тетради и карандаши", "options": ["Форму и обувь", "Ранец, тетради и карандаши", "Компьютер"], "question": "Что они купили?"}, {"correct": "Тоже немного волнуется", "options": ["Спокоен", "Тоже немного волнуется", "Расстроен"], "question": "Как чувствует себя отец?"}], "text_translit": "хабЕн шелИ бен шеш увесептЕмбер ху матхИль китА Алеф..."}', '{"correct_answers": ["6", "Ранец, тетради и карандаши", "Тоже немного волнуется"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3682, 203, 'listening_comprehension', 2, '{"text_he": "המכולת בפינת הרחוב שלנו נסגרה. הבעלים פרש אחרי ארבעים שנה. עכשיו צריך ללכת לסופרמרקט שנמצא רחוק יותר. כל השכנים עצובים כי אהבו את החנות הקטנה.", "questions": [{"correct": "Закрылся", "options": ["Переехал", "Закрылся", "Отремонтирован"], "question": "Что произошло с магазинчиком?"}, {"correct": "40 лет", "options": ["20 лет", "30 лет", "40 лет"], "question": "Сколько лет работал владелец?"}, {"correct": "Грустят — любили маленький магазин", "options": ["Рады — теперь тише", "Грустят — любили маленький магазин", "Им всё равно"], "question": "Как реагируют соседи?"}], "text_translit": "хамаколЕт бепинАт харехОв шелАну нисгерА..."}', '{"correct_answers": ["Закрылся", "40 лет", "Грустят — любили маленький магазин"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3683, 203, 'listening_comprehension', 2, '{"text_he": "הזמנתי טכנאי לתקן את המכונת כביסה. הוא הגיע, בדק ואמר שצריך להחליף חלק. ההחלפה עולה שלוש מאות שקל. החלטתי לתקן כי מכונה חדשה עולה הרבה יותר.", "questions": [{"correct": "Стиральная машина", "options": ["Холодильник", "Стиральная машина", "Кондиционер"], "question": "Что сломалось?"}, {"correct": "300 шекелей", "options": ["200 шекелей", "300 шекелей", "500 шекелей"], "question": "Сколько стоит ремонт?"}, {"correct": "Новая машина стоит гораздо дороже", "options": ["Ремонт дешёвый", "Новая машина стоит гораздо дороже", "Мастер дал скидку"], "question": "Почему он решил чинить?"}], "text_translit": "хизмАнти теханАй летакЕн эт хамехонАт квисА..."}', '{"correct_answers": ["Стиральная машина", "300 шекелей", "Новая машина стоит гораздо дороже"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3697, 204, 'dictation', 3, '{"hint": "экология", "word_he": "המומחים חלוקים בדעותיהם לגבי ההשפעה הסביבתית", "word_translit": "хамумхИм халукИм бедеотехЕм лагабЕй хахашпаА хасвиватИт"}', '{"accept": ["המומחים חלוקים בדעותיהם לגבי ההשפעה הסביבתית"], "correct": "המומחים חלוקים בדעותיהם לגבי ההשפעה הסביבתית"}', '{"text": "(экология) המומחים חלוקים בדעותיהם לגבי ההשפעה הסביבתית"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3698, 204, 'dictation', 3, '{"hint": "финансы", "word_he": "שוק ההון רשם עליות חדות בשבוע האחרון", "word_translit": "шук хахОн рашАм алийОт хадОт бешавУа хаахарОн"}', '{"accept": ["שוק ההון רשם עליות חדות בשבוע האחרון"], "correct": "שוק ההון רשם עליות חדות בשבוע האחרון"}', '{"text": "(финансы) שוק ההון רשם עליות חדות בשבוע האחרון"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3684, 203, 'listening_comprehension', 2, '{"text_he": "חברה שלי חזרה מטיול בדרום אמריקה. היא הייתה שם חודשיים. היא סיפרה על ההרים בפרו ועל החופים בברזיל. היא אמרה שהאוכל היה מדהים והאנשים מאוד חמים.", "questions": [{"correct": "Два месяца", "options": ["Месяц", "Два месяца", "Три месяца"], "question": "Сколько времени подруга была в поездке?"}, {"correct": "Перу и Бразилия", "options": ["Аргентина и Чили", "Перу и Бразилия", "Колумбия и Мексика"], "question": "О каких странах она рассказала?"}, {"correct": "Потрясающая", "options": ["Невкусная", "Потрясающая", "Обычная"], "question": "Что она сказала о еде?"}], "text_translit": "хаверА шелИ хазрА метиУль бедрОм амЕрика..."}', '{"correct_answers": ["Два месяца", "Перу и Бразилия", "Потрясающая"]}', '{"text": "Обратите внимание на ключевые слова: числа, имена, места."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3685, 204, 'dictation', 3, '{"hint": "политика", "word_he": "הממשלה אישרה את התקציב לשנה הבאה", "word_translit": "хамемшалА ишрА эт хатакцИв лешанА хабаА"}', '{"accept": ["הממשלה אישרה את התקציב לשנה הבאה"], "correct": "הממשלה אישרה את התקציב לשנה הבאה"}', '{"text": "(политика) הממשלה אישרה את התקציב לשנה הבאה"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3686, 204, 'dictation', 3, '{"hint": "наука", "word_he": "המחקר מצביע על עלייה בתוחלת החיים", "word_translit": "хамехкАр мацбИа аль алийА бетохЕлет хахайИм"}', '{"accept": ["המחקר מצביע על עלייה בתוחלת החיים"], "correct": "המחקר מצביע על עלייה בתוחלת החיים"}', '{"text": "(наука) המחקר מצביע על עלייה בתוחלת החיים"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4090, 213, 'multiple_choice', 1, '{"options": ["אני רוצה", "אני אוהב", "אני צריך", "אני יודע"], "question": "Как сказать «мне нравится»?"}', '{"correct": "אני אוהב", "correct_index": 1}', '{"text": "אוהב = люблю / нравится"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3688, 204, 'dictation', 3, '{"hint": "экономика", "word_he": "התעשייה הישראלית מתמודדת עם אתגרים חדשים", "word_translit": "хатаасийА хайисреэлИт митмодЕдет им этгарИм хадашИм"}', '{"accept": ["התעשייה הישראלית מתמודדת עם אתגרים חדשים"], "correct": "התעשייה הישראלית מתמודדת עם אתגרים חדשים"}', '{"text": "(экономика) התעשייה הישראלית מתמודדת עם אתגרים חדשים"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3689, 204, 'dictation', 3, '{"hint": "статистика", "word_he": "שיעור האבטלה ירד לרמה הנמוכה ביותר", "word_translit": "шиУр хаавталА ярАд ларамА ханемухА бейотЕр"}', '{"accept": ["שיעור האבטלה ירד לרמה הנמוכה ביותר"], "correct": "שיעור האבטלה ירד לרמה הנמוכה ביותר"}', '{"text": "(статистика) שיעור האבטלה ירד לרמה הנמוכה ביותר"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3690, 204, 'dictation', 3, '{"hint": "протест", "word_he": "ההפגנה נגד היוקר התקיימה בכיכר רבין", "word_translit": "хахафганА нЕгед хайОкер хиткаймА бекикАр рабИн"}', '{"accept": ["ההפגנה נגד היוקר התקיימה בכיכר רבין"], "correct": "ההפגנה נגד היוקר התקיימה בכיכר רבין"}', '{"text": "(протест) ההפגנה נגד היוקר התקיימה בכיכר רבין"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3691, 204, 'dictation', 3, '{"hint": "образование", "word_he": "הוועדה המליצה לשנות את מערכת החינוך", "word_translit": "хаваадА хемлИца лешанОт эт маарЕхет хахинУх"}', '{"accept": ["הוועדה המליצה לשנות את מערכת החינוך"], "correct": "הוועדה המליצה לשנות את מערכת החינוך"}', '{"text": "(образование) הוועדה המליצה לשנות את מערכת החינוך"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3692, 204, 'dictation', 3, '{"hint": "общество", "word_he": "סקר חדש מראה שרוב הציבור תומך ברפורמה", "word_translit": "сЕкер хадАш мараЕ шерОв хацибУр томЕх бареформА"}', '{"accept": ["סקר חדש מראה שרוב הציבור תומך ברפורמה"], "correct": "סקר חדש מראה שרוב הציבור תומך ברפורמה"}', '{"text": "(общество) סקר חדש מראה שרוב הציבור תומך ברפורמה"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3693, 204, 'dictation', 3, '{"hint": "история", "word_he": "הסכם השלום כלל נסיגה מהשטחים הכבושים", "word_translit": "хахескЕм хашалОм калАль несигА мехаштахИм хакевушИм"}', '{"accept": ["הסכם השלום כלל נסיגה מהשטחים הכבושים"], "correct": "הסכם השלום כלל נסיגה מהשטחים הכבושים"}', '{"text": "(история) הסכם השלום כלל נסיגה מהשטחים הכבושים"}', 15);
