INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3700, 204, 'dictation', 3, '{"hint": "природа", "word_he": "הרשות לשמירת הטבע הכריזה על שמורה חדשה", "word_translit": "харашУт лишмирАт хатЕва хихрИза аль шмурА хадашА"}', '{"accept": ["הרשות לשמירת הטבע הכריזה על שמורה חדשה"], "correct": "הרשות לשמירת הטבע הכריזה על שמורה חדשה"}', '{"text": "(природа) הרשות לשמירת הטבע הכריזה על שמורה חדשה"}', 15);
