INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3716, 204, 'minimal_pairs', 3, '{"pair_a": {"he": "עמדה", "meaning": "позиция/мнение", "translit": "эмдА"}, "pair_b": {"he": "עמידה", "meaning": "стояние/выстойка", "translit": "амидА"}, "question": "Позиция или стояние?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "עמדה — позиция (мнение). עמידה — физическое стояние"}', 15);
