INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4091, 213, 'multiple_choice', 1, '{"options": ["спасибо", "пожалуйста", "извините", "привет"], "question": "Что означает «סליחה»?"}', '{"correct": "извините", "correct_index": 2}', '{"text": "סליחה = извините/простите"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3720, 204, 'listening_comprehension', 3, '{"text_he": "סקר חדש שפורסם היום מראה שכשישים אחוז מהישראלים מרוצים מאיכות החיים שלהם. עם זאת, יותר ממחצית המשיבים ציינו את יוקר המחיה כבעיה המרכזית. מחירי הדיור, המזון והחינוך עלו בשנים האחרונות, ורבים מתקשים לעמוד בהוצאות החודשיות.", "questions": [{"correct": "60%", "options": ["40%", "50%", "60%"], "question": "Сколько процентов довольны качеством жизни?"}, {"correct": "Дороговизна жизни", "options": ["Безопасность", "Дороговизна жизни", "Экология"], "question": "Какая главная проблема по мнению опрошенных?"}, {"correct": "Цены на жильё, еду и образование", "options": ["Зарплаты", "Цены на жильё, еду и образование", "Качество услуг"], "question": "Что выросло в последние годы?"}], "text_translit": "сЕкер хадАш шефурсАм хайОм мараЕ шекешишИм ахУз..."}', '{"correct_answers": ["60%", "Дороговизна жизни", "Цены на жильё, еду и образование"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3721, 204, 'listening_comprehension', 3, '{"text_he": "פרופסור רונית לוי מהפקולטה לרפואה הציגה מחקר פורץ דרך. המחקר בדק את ההשפעה של תזונה ים-תיכונית על בריאות הלב. הממצאים מראים ירידה של שלושים אחוז בסיכון למחלות לב בקרב אנשים שהקפידו על תזונה זו במשך חמש שנים.", "questions": [{"correct": "Влияние средиземноморской диеты на сердце", "options": ["Влияние спорта", "Влияние средиземноморской диеты на сердце", "Новое лекарство"], "question": "Что исследовали?"}, {"correct": "На 30%", "options": ["На 20%", "На 30%", "На 50%"], "question": "На сколько снизился риск?"}, {"correct": "5 лет", "options": ["3 года", "5 лет", "10 лет"], "question": "Сколько лет длилось наблюдение?"}], "text_translit": "профЕсор ронИт лЕви мехафакультА лерефуА хицигА мехкАр порЕц дЕрех..."}', '{"correct_answers": ["Влияние средиземноморской диеты на сердце", "На 30%", "5 лет"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3722, 204, 'listening_comprehension', 3, '{"text_he": "עיריית תל אביב הודיעה על פרויקט חדש: הקמת שלוש גשרים להולכי רגל מעל כביש איילון. הפרויקט ייקח שלוש שנים ויעלה כמאתיים מיליון שקל. ראש העירייה אמר שהגשרים ישפרו את הנגישות בין מזרח העיר למערבה.", "questions": [{"correct": "3", "options": ["2", "3", "5"], "question": "Сколько мостов планируют построить?"}, {"correct": "200 миллионов", "options": ["100 миллионов", "200 миллионов", "500 миллионов"], "question": "Сколько будет стоить проект?"}, {"correct": "Связь между востоком и западом города", "options": ["Пробки", "Связь между востоком и западом города", "Наводнения"], "question": "Какую проблему решат мосты?"}], "text_translit": "ирийАт тель авИв одиА аль проЕкт хадАш..."}', '{"correct_answers": ["3", "200 миллионов", "Связь между востоком и западом города"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3855, 207, 'translate_ru_he', 1, '{"hint": "שלי", "prompt_ru": "Мой дом", "target_he": "הבית שלי"}', '{"accept": ["הבית שלי", "בית שלי"], "correct": "הבית שלי"}', '{"text": "Мой дом = הבית שלי"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3723, 204, 'listening_comprehension', 3, '{"text_he": "הסופר הישראלי דויד גרוסמן זכה השנה בפרס ספרותי בינלאומי. הפרס הוענק לו על ספרו האחרון שעוסק בקונפליקט הישראלי-פלסטיני מנקודת מבט אנושית. גרוסמן נחשב לאחד הסופרים החשובים ביותר בישראל. ספריו תורגמו ליותר משלושים שפות.", "questions": [{"correct": "Международную литературную премию", "options": ["Нобелевскую премию", "Международную литературную премию", "Государственную премию"], "question": "Какой приз получил Гроссман?"}, {"correct": "Об израильско-палестинском конфликте", "options": ["О Холокосте", "Об израильско-палестинском конфликте", "О любви"], "question": "О чём его последняя книга?"}, {"correct": "Более 30", "options": ["Более 10", "Более 20", "Более 30"], "question": "На сколько языков переведены его книги?"}], "text_translit": "хасофЕр хайисреэлИ давИд грОсман захА хашанА бефрАс сифрутИ бейнлеумИ..."}', '{"correct_answers": ["Международную литературную премию", "Об израильско-палестинском конфликте", "Более 30"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3739, 205, 'dictation', 3, '{"hint": "лингвистика", "word_he": "הניתוח הלשוני חושף שכבות משמעות סמויות בטקסט", "word_translit": "ханитУах халешонИ хосЕф шхавОт машмаУт смуйОт батЕкст"}', '{"accept": ["הניתוח הלשוני חושף שכבות משמעות סמויות בטקסט"], "correct": "הניתוח הלשוני חושף שכבות משמעות סמויות בטקסט"}', '{"text": "(лингвистика) הניתוח הלשוני חושף שכבות משמעות סמויות בטקסט"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3751, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "ביקורת", "meaning": "критика (литературная)", "translit": "бикОрет"}, "pair_b": {"he": "ביקורת", "meaning": "контроль/проверка", "translit": "бикОрет"}, "question": "Литературная критика или контроль?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "Одно слово — два значения! Контекст определяет: ביקורת ספרותית vs ביקורת חשבונות"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3724, 204, 'listening_comprehension', 3, '{"text_he": "ועדת החינוך של הכנסת דנה היום בהצעה להאריך את שנת הלימודים בשבועיים. התומכים טענו שהארכת השנה תשפר את ההישגים הלימודיים. המתנגדים טענו שילדים צריכים חופשה ארוכה יותר לפיתוח אישי ויצירתיות.", "questions": [{"correct": "Продлить учебный год на 2 недели", "options": ["Сократить учебный год", "Продлить учебный год на 2 недели", "Отменить каникулы"], "question": "Что предложили?"}, {"correct": "Улучшение учебных результатов", "options": ["Экономия бюджета", "Улучшение учебных результатов", "Снижение преступности"], "question": "Аргумент сторонников?"}, {"correct": "Детям нужен отпуск для развития", "options": ["Дорого стоит", "Детям нужен отпуск для развития", "Учителя против"], "question": "Аргумент противников?"}], "text_translit": "ваадАт хахинУх шель хакнЕсет данА хайОм бехацаА лехаарИх..."}', '{"correct_answers": ["Продлить учебный год на 2 недели", "Улучшение учебных результатов", "Детям нужен отпуск для развития"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3725, 204, 'listening_comprehension', 3, '{"text_he": "חברת אלביט מערכות הודיעה על עסקה בשווי מיליארד דולר עם מדינה באירופה. העסקה כוללת אספקת מערכות הגנה מתקדמות. מניות החברה עלו בחמישה אחוזים בבורסה בעקבות ההודעה.", "questions": [{"correct": "1 миллиард долларов", "options": ["100 млн долларов", "500 млн долларов", "1 миллиард долларов"], "question": "Какова сумма сделки?"}, {"correct": "Системы обороны", "options": ["Военные самолёты", "Системы обороны", "Кибер-технологии"], "question": "Что включает сделка?"}, {"correct": "Выросли на 5%", "options": ["Упали на 5%", "Выросли на 5%", "Не изменились"], "question": "Как отреагировали акции?"}], "text_translit": "хеврАт элбИт маарахОт одиА аль ускА бешОви мильЯрд долАр..."}', '{"correct_answers": ["1 миллиард долларов", "Системы обороны", "Выросли на 5%"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3726, 204, 'listening_comprehension', 3, '{"text_he": "חוקרים מהטכניון בחיפה פיתחו חומר חדש שיכול לנקות מים מזוהמים בצורה יעילה. החומר מסוגל לספוג מתכות כבדות וחומרי הדברה מהמים. הטכנולוגיה נבדקת כעת במספר מדינות מתפתחות באפריקה.", "questions": [{"correct": "Материал для очистки воды", "options": ["Новый фильтр", "Материал для очистки воды", "Робота"], "question": "Что разработали учёные?"}, {"correct": "Тяжёлые металлы и пестициды", "options": ["Бактерии", "Тяжёлые металлы и пестициды", "Соль"], "question": "Что может поглощать материал?"}, {"correct": "В Африке", "options": ["В Европе", "В Африке", "В Азии"], "question": "Где тестируют технологию?"}], "text_translit": "хокрИм мехатехниОн бехейфА питхУ хОмер хадАш..."}', '{"correct_answers": ["Материал для очистки воды", "Тяжёлые металлы и пестициды", "В Африке"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3727, 204, 'listening_comprehension', 3, '{"text_he": "עמותת \"לתת\" פרסמה דו\"ח שנתי על העוני בישראל. לפי הדו\"ח, כאחד מכל חמישה ילדים בישראל חי מתחת לקו העוני. הדו\"ח קורא לממשלה להגדיל את קצבאות הילדים ולהשקיע בחינוך בפריפריה.", "questions": [{"correct": "Каждый пятый", "options": ["Каждый десятый", "Каждый пятый", "Каждый третий"], "question": "Какой процент детей живёт за чертой бедности?"}, {"correct": "Увеличить пособия на детей", "options": ["Сократить расходы", "Увеличить пособия на детей", "Повысить налоги"], "question": "К чему призывает отчёт?"}], "text_translit": "амутАт латЕт пирсемА дОх шнатИ аль хаОни бейисраЭль..."}', '{"correct_answers": ["Каждый пятый", "Увеличить пособия на детей"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3728, 204, 'listening_comprehension', 3, '{"text_he": "פסטיבל הקולנוע בירושלים ייפתח השבוע עם הקרנת בכורה של סרט ישראלי חדש. הסרט מספר את סיפורו של עולה חדש מאתיופיה שמנסה למצוא את מקומו בחברה הישראלית. הבמאית אמרה שהסרט מבוסס על סיפור אמיתי.", "questions": [{"correct": "В Иерусалиме", "options": ["В Тель-Авиве", "В Иерусалиме", "В Хайфе"], "question": "Где пройдёт фестиваль?"}, {"correct": "О новом репатрианте из Эфиопии", "options": ["О солдате", "О новом репатрианте из Эфиопии", "О музыканте"], "question": "О ком фильм?"}, {"correct": "Реальной истории", "options": ["Книге", "Реальной истории", "Театральной пьесе"], "question": "Фильм основан на...?"}], "text_translit": "фестивАль хаколнОа бийерушалАим йипатЕах хашавУа..."}', '{"correct_answers": ["В Иерусалиме", "О новом репатрианте из Эфиопии", "Реальной истории"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4092, 213, 'multiple_choice', 1, '{"options": ["בוקר טוב", "צהריים טובים", "ערב טוב", "לילה טוב"], "question": "Какое приветствие используют вечером?"}', '{"correct": "ערב טוב", "correct_index": 2}', '{"text": "ערב טוב = добрый вечер"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3729, 204, 'listening_comprehension', 3, '{"text_he": "משרד התחבורה הכריז על הרחבת הרכבת הקלה בתל אביב. שני קווים חדשים יוקמו בשלוש השנים הקרובות. הקו הראשון יחבר את יפו לרמת גן, והשני ירוץ מהרצלייה לחולון. הפרויקט צפוי להקל על עומסי התנועה.", "questions": [{"correct": "2", "options": ["1", "2", "3"], "question": "Сколько новых линий построят?"}, {"correct": "Из Яфо в Рамат-Ган", "options": ["Из Яфо в Рамат-Ган", "Из центра в аэропорт", "Из Герцлии в Холон"], "question": "Куда будет идти первая линия?"}, {"correct": "Транспортные пробки", "options": ["Загрязнение воздуха", "Транспортные пробки", "Шум"], "question": "Какую проблему решит проект?"}], "text_translit": "мисрАд хатахбурА хихрИз аль хархавАт харакЕвет хакалА..."}', '{"correct_answers": ["2", "Из Яфо в Рамат-Ган", "Транспортные пробки"]}', '{"text": "Обратите внимание на числа, имена организаций и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3730, 205, 'dictation', 3, '{"hint": "академия", "word_he": "התופעה הזאת מעוררת דיון ער בקרב החוקרים", "word_translit": "хатофаА хазОт меорЕрет диЮн эр бекЕрев хахокрИм"}', '{"accept": ["התופעה הזאת מעוררת דיון ער בקרב החוקרים"], "correct": "התופעה הזאת מעוררת דיון ער בקרב החוקרים"}', '{"text": "(академия) התופעה הזאת מעוררת דיון ער בקרב החוקרים"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3731, 205, 'dictation', 3, '{"hint": "социология", "word_he": "הממצאים מצביעים על מגמה מדאיגה בחברה הישראלית", "word_translit": "хамемцаИм мацбиИм аль мегамА мадиА бахеврА хайисреэлИт"}', '{"accept": ["הממצאים מצביעים על מגמה מדאיגה בחברה הישראלית"], "correct": "הממצאים מצביעים על מגמה מדאיגה בחברה הישראלית"}', '{"text": "(социология) הממצאים מצביעים על מגמה מדאיגה בחברה הישראלית"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3732, 205, 'dictation', 3, '{"hint": "публицистика", "word_he": "השיח הציבורי סביב הסוגייה הולך ומתעצם", "word_translit": "хасИах хацибурИ свИв хасугийА олЕх умитацЕм"}', '{"accept": ["השיח הציבורי סביב הסוגייה הולך ומתעצם"], "correct": "השיח הציבורי סביב הסוגייה הולך ומתעצם"}', '{"text": "(публицистика) השיח הציבורי סביב הסוגייה הולך ומתעצם"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3733, 205, 'dictation', 3, '{"hint": "философия", "word_he": "הפער בין התיאוריה לפרקטיקה עדיין רחב", "word_translit": "хапЕар бейн хатеорИя лапрАктика адАин рахАв"}', '{"accept": ["הפער בין התיאוריה לפרקטיקה עדיין רחב"], "correct": "הפער בין התיאוריה לפרקטיקה עדיין רחב"}', '{"text": "(философия) הפער בין התיאוריה לפרקטיקה עדיין רחב"}', 20);
