INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3735, 205, 'dictation', 3, '{"hint": "критика", "word_he": "הביקורת הפמיניסטית שינתה את דרכי הקריאה של טקסטים", "word_translit": "хабикОрет хафеминИстит шинтА эт дархЕй хакриА шель текстИм"}', '{"accept": ["הביקורת הפמיניסטית שינתה את דרכי הקריאה של טקסטים"], "correct": "הביקורת הפמיניסטית שינתה את דרכי הקריאה של טקסטים"}', '{"text": "(критика) הביקורת הפמיניסטית שינתה את דרכי הקריאה של טקסטים"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3736, 205, 'dictation', 3, '{"hint": "философия", "word_he": "הפילוסופיה האקזיסטנציאליסטית השפיעה על הספרות העברית", "word_translit": "хафилосОфья хаэкзистенциалИстит хишпИа аль хасифрУт хаиврИт"}', '{"accept": ["הפילוסופיה האקזיסטנציאליסטית השפיעה על הספרות העברית"], "correct": "הפילוסופיה האקזיסטנציאליסטית השפיעה על הספרות העברית"}', '{"text": "(философия) הפילוסופיה האקזיסטנציאליסטית השפיעה על הספרות העברית"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3762, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "הנחה", "meaning": "предпосылка/скидка", "translit": "ханахА"}, "pair_b": {"he": "הנחיה", "meaning": "инструкция/руководство", "translit": "ханхайА"}, "question": "Предпосылка или инструкция?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "הנחה — предпосылка (или скидка). הנחיה — указание, инструкция"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3737, 205, 'dictation', 3, '{"hint": "технологии", "word_he": "המהפכה הדיגיטלית מאתגרת את מושגי הפרטיות המסורתיים", "word_translit": "хамахапехА хадигитАлит меатгЕрет эт мусагЕй хапратИют хамасортиИм"}', '{"accept": ["המהפכה הדיגיטלית מאתגרת את מושגי הפרטיות המסורתיים"], "correct": "המהפכה הדיגיטלית מאתגרת את מושגי הפרטיות המסורתיים"}', '{"text": "(технологии) המהפכה הדיגיטלית מאתגרת את מושגי הפרטיות המסורתיים"}', 20);
