INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3741, 205, 'dictation', 3, '{"hint": "методология", "word_he": "המתודולוגיה הנבחרת קובעת במידה רבה את תוצאות המחקר", "word_translit": "хаметодолОгья ханивхЕрет ковАат бемидА рабА эт тоцаОт хамехкАр"}', '{"accept": ["המתודולוגיה הנבחרת קובעת במידה רבה את תוצאות המחקר"], "correct": "המתודולוגיה הנבחרת קובעת במידה רבה את תוצאות המחקר"}', '{"text": "(методология) המתודולוגיה הנבחרת קובעת במידה רבה את תוצאות המחקר"}', 20);
