INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3745, 205, 'dictation', 3, '{"hint": "психология", "word_he": "הפסיכולוגיה החברתית חוקרת את השפעת הקבוצה על הפרט", "word_translit": "хапсихолОгья хахевратИт хокЕрет эт хашпаАт хаквуцА аль хапрАт"}', '{"accept": ["הפסיכולוגיה החברתית חוקרת את השפעת הקבוצה על הפרט"], "correct": "הפסיכולוגיה החברתית חוקרת את השפעת הקבוצה על הפרט"}', '{"text": "(психология) הפסיכולוגיה החברתית חוקרת את השפעת הקבוצה על הפרט"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3746, 205, 'dictation', 3, '{"hint": "междисциплинарность", "word_he": "הגישה הבין-תחומית מאפשרת הבנה מעמיקה יותר של התופעה", "word_translit": "хагишА хабейн-тхумИт меафшЕрет хаванА маамИка йотЕр шель хатофаА"}', '{"accept": ["הגישה הבין-תחומית מאפשרת הבנה מעמיקה יותר של התופעה"], "correct": "הגישה הבין-תחומית מאפשרת הבנה מעמיקה יותר של התופעה"}', '{"text": "(междисциплинарность) הגישה הבין-תחומית מאפשרת הבנה מעמיקה יותר של התופעה"}', 20);
