INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3750, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "עיון", "meaning": "изучение/обзор", "translit": "июн"}, "pair_b": {"he": "עניין", "meaning": "дело/интерес", "translit": "иньЯн"}, "question": "Изучение или дело?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "עיון — академическое изучение. עניין — дело, интерес"}', 20);
