INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3754, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "מושג", "meaning": "понятие/концепт", "translit": "мусАг"}, "pair_b": {"he": "מוסג", "meaning": "(нет значения — ловушка)", "translit": "мусАг"}, "question": "Как пишется слово «понятие»?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "מושג — через שׂ (шин/син). Это распространённый академический термин"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3755, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "סוגייה", "meaning": "вопрос/тема/проблема", "translit": "сугийА"}, "pair_b": {"he": "סוגיה", "meaning": "то же слово (вариант написания)", "translit": "сугийА"}, "question": "Оба варианта написания верны. Какой чаще?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "סוגייה с двойным йод — академическое написание. סוגיה — упрощённое"}', 20);
