INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3758, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "השלכות", "meaning": "последствия/импликации", "translit": "хашлахОт"}, "pair_b": {"he": "השלכה", "meaning": "проекция/бросание", "translit": "хашлахА"}, "question": "Множественное или единственное число?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "השלכות — мн.ч. «последствия». השלכה — ед.ч. «проекция»"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3759, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "פרשנות", "meaning": "интерпретация", "translit": "паршанУт"}, "pair_b": {"he": "פרשנית", "meaning": "комментаторша", "translit": "паршанИт"}, "question": "Интерпретация или комментаторша?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "פרשנות — абстрактное сущ. (-ут). פרשנית — конкретное, ж.р. (-ит)"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3760, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "היגיון", "meaning": "логика/разум", "translit": "хигайОн"}, "pair_b": {"he": "הגיון", "meaning": "то же (вариант без יוד)", "translit": "хигайОн"}, "question": "Оба написания означают одно и то же — «логика»", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "היגיון и הגיון — варианты. Произношение одинаковое"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3761, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "מסורת", "meaning": "традиция", "translit": "масОрет"}, "pair_b": {"he": "מסירות", "meaning": "преданность", "translit": "месирУт"}, "question": "Традиция или преданность?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "מסורת — традиция. מסירות — преданность/самоотверженность"}', 20);
