INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3764, 205, 'minimal_pairs', 3, '{"pair_a": {"he": "תובנה", "meaning": "инсайт/прозрение", "translit": "тованА"}, "pair_b": {"he": "תבונה", "meaning": "мудрость/разумность", "translit": "твунА"}, "question": "Инсайт или мудрость?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "תובנה — конкретный инсайт. תבונה — общая мудрость, разумность"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3765, 205, 'listening_comprehension', 3, '{"text_he": "בעשורים האחרונים אנו עדים לתמורות מעמיקות בתחום החינוך הגבוה בישראל. מספר הסטודנטים גדל פי שלושה, אך האם האיכות עמדה בקצב? מחקרים מצביעים על ירידה ברמת הכתיבה האקדמית ובחשיבה הביקורתית. מנגד, הנגישות להשכלה גבוהה גדלה משמעותית, במיוחד בפריפריה ובקרב אוכלוסיות שבעבר הודרו מהאקדמיה.", "questions": [{"correct": "В 3 раза", "options": ["В 2 раза", "В 3 раза", "В 5 раз"], "question": "Во сколько раз выросло число студентов?"}, {"correct": "Снижение уровня письма и критического мышления", "options": ["Рост стоимости обучения", "Снижение уровня письма и критического мышления", "Нехватка преподавателей"], "question": "Какая негативная тенденция отмечена?"}, {"correct": "Увеличение доступности образования для периферии", "options": ["Рост зарплат", "Увеличение доступности образования для периферии", "Больше международных связей"], "question": "Какой позитивный аспект выделен?"}], "text_translit": "баасорИм хаахаронИм Ану эдИм литмурОт маамикОт бетхУм хахинУх хагавОа..."}', '{"correct_answers": ["В 3 раза", "Снижение уровня письма и критического мышления", "Увеличение доступности образования для периферии"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3766, 205, 'listening_comprehension', 3, '{"text_he": "שירתו של יהודה עמיחי מייצגת מפנה בשירה העברית. עמיחי שבר את המוסכמות של השירה הנשגבת והכניס לשירה שפה יומיומית, הומור ואירוניה. הוא כתב על מלחמה ואהבה, על ירושלים ועל גופו, בשפה פשוטה שמאחוריה עומקים רבים. ביקורת הספרות רואה בו את המשורר הישראלי המשפיע ביותר של המחצית השנייה של המאה העשרים.", "questions": [{"correct": "Ввёл разговорный язык, юмор и иронию", "options": ["Вернул библейский стиль", "Ввёл разговорный язык, юмор и иронию", "Отказался от рифмы"], "question": "Что сделал Амихай с поэзией?"}, {"correct": "О войне, любви, Иерусалиме, своём теле", "options": ["Только о любви", "О войне, любви, Иерусалиме, своём теле", "Только о природе"], "question": "О чём он писал?"}, {"correct": "Самый влиятельный израильский поэт 2-й половины XX века", "options": ["Второстепенный поэт", "Самый влиятельный израильский поэт 2-й половины XX века", "Спорная фигура"], "question": "Как оценивает его критика?"}], "text_translit": "ширАтo шель йехудА амихАй мейацЕгет мифнЕ баширА хаиврИт..."}', '{"correct_answers": ["Ввёл разговорный язык, юмор и иронию", "О войне, любви, Иерусалиме, своём теле", "Самый влиятельный израильский поэт 2-й половины XX века"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3767, 205, 'listening_comprehension', 3, '{"text_he": "התחייה של השפה העברית היא תופעה ייחודית בהיסטוריה של הלשונות. אליעזר בן-יהודה הגיע לארץ ישראל בשנת 1881 עם חלום להפוך את העברית משפת תפילה ולימוד לשפה חיה מדוברת. הוא יצר אלפי מילים חדשות, חלקן התקבלו וחלקן נדחו. כיום, יותר מתשעה מיליון אנשים מדברים עברית כשפת אם או כשפה שנייה.", "questions": [{"correct": "1881", "options": ["1861", "1881", "1901"], "question": "Когда Бен-Йехуда приехал в Эрец-Исраэль?"}, {"correct": "Языком молитвы и учёбы", "options": ["Разговорным языком", "Языком молитвы и учёбы", "Мёртвым языком"], "question": "Чем была иврит до возрождения?"}, {"correct": "Более 9 миллионов", "options": ["Более 5 миллионов", "Более 9 миллионов", "Более 15 миллионов"], "question": "Сколько людей сейчас говорят на иврите?"}], "text_translit": "хатхийА шель хасафА хаиврИт хи тофаА йихудИт бехисторИя шель халешонОт..."}', '{"correct_answers": ["1881", "Языком молитвы и учёбы", "Более 9 миллионов"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3768, 205, 'listening_comprehension', 3, '{"text_he": "הסוציולוג אהרן אורנשטיין טוען כי החברה הישראלית עוברת תהליך של אינדיבידואליזציה מואצת. ערכים קולקטיביים שהיו מרכזיים בעשורים הראשונים של המדינה — כגון שירות צבאי, התיישבות והקרבה למען הכלל — מפנים את מקומם לערכים אישיים. מנגד, יש הטוענים כי תחושת השייכות הלאומית עדיין חזקה, במיוחד בזמני משבר.", "questions": [{"correct": "Ускоренная индивидуализация", "options": ["Глобализация", "Ускоренная индивидуализация", "Радикализация"], "question": "Какой процесс описывает Орнштейн?"}, {"correct": "Армия, поселенчество, жертвенность ради общества", "options": ["Религия и традиция", "Армия, поселенчество, жертвенность ради общества", "Наука и прогресс"], "question": "Какие ценности были центральными ранее?"}, {"correct": "Во время кризисов", "options": ["Всегда", "Во время кризисов", "Только у старшего поколения"], "question": "Когда национальная принадлежность особенно сильна?"}], "text_translit": "хасоциолОг аhарОн орнштАйн тоЭн ки хахеврА хайисреэлИт оврА тахалИх..."}', '{"correct_answers": ["Ускоренная индивидуализация", "Армия, поселенчество, жертвенность ради общества", "Во время кризисов"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3839, 207, 'hebrew_typing', 1, '{"prompt": "Напишите «спокойной ночи»", "target_he": "לילה טוב", "transliteration": "лАйла тов"}', '{"accept": ["לילה טוב"], "correct": "לילה טוב"}', '{"text": "לילה טוב = лАйла тов"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3840, 207, 'translate_ru_he', 1, '{"hint": "שלום", "prompt_ru": "Привет", "target_he": "שלום"}', '{"accept": ["שלום", "שלום!"], "correct": "שלום"}', '{"text": "Привет = שלום"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3769, 205, 'listening_comprehension', 3, '{"text_he": "מחקר חדש שפורסם בכתב העת \"לשוננו\" בוחן את השפעת הערבית על העברית המדוברת. החוקרים מצאו כי מאות מילים ערביות חדרו לסלנג הישראלי, בעיקר בתחומי המזון, הרגשות והקללות. הדבר מעיד על מגע תרבותי עמוק, למרות הקונפליקט הפוליטי. בעבר ניסתה האקדמיה ללשון העברית להילחם בתופעה, אך כיום הגישה מקלה יותר.", "questions": [{"correct": "Влияние арабского на разговорный иврит", "options": ["Влияние английского на иврит", "Влияние арабского на разговорный иврит", "Историю иврита"], "question": "Что исследует статья?"}, {"correct": "Еда, эмоции и ругательства", "options": ["Наука и техника", "Еда, эмоции и ругательства", "Политика и право"], "question": "В каких областях больше всего арабских заимствований?"}, {"correct": "Стала терпимее", "options": ["Борется активно", "Стала терпимее", "Игнорирует"], "question": "Как Академия языка иврит относится к этому сейчас?"}], "text_translit": "мехкАр хадАш шефурсАм бихтАв хаЭт лешонЕну бохЕн эт хашпаАт хааравИт..."}', '{"correct_answers": ["Влияние арабского на разговорный иврит", "Еда, эмоции и ругательства", "Стала терпимее"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3775, 206, 'dictation', 4, '{"hint": "юридический", "word_he": "על המבקש להוכיח את תביעתו מוטל נטל ההוכחה", "word_translit": "аль хамевакЕш лехохИах эт твиатО мутАль нЕтель хахохахА"}', '{"accept": ["על המבקש להוכיח את תביעתו מוטל נטל ההוכחה"], "correct": "על המבקש להוכיח את תביעתו מוטל נטל ההוכחה"}', '{"text": "(юридический) על המבקש להוכיח את תביעתו מוטל נטל ההוכחה"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3882, 208, 'translate_ru_he', 2, '{"hint": "ארוחת צהריים", "prompt_ru": "Мы едим обед", "target_he": "אנחנו אוכלים ארוחת צהריים"}', '{"accept": ["אנחנו אוכלים ארוחת צהריים"], "correct": "אנחנו אוכלים ארוחת צהריים"}', '{"text": "Мы едим обед = אנחנו אוכלים ארוחת צהריים"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3770, 205, 'listening_comprehension', 3, '{"text_he": "הפילוסוף מרטין בובר, שעלה לארץ ישראל ב-1938, פיתח את הפילוסופיה הדיאלוגית שלו בספר \"אני ואתה\". בובר הבחין בין יחסי \"אני-אתה\" — יחסים אותנטיים של מפגש — לבין יחסי \"אני-זה\" — יחסים שבהם האדם מתייחס לאחר כאל אובייקט. רעיונותיו השפיעו על חינוך, פסיכותרפיה ותיאולוגיה.", "questions": [{"correct": "1938", "options": ["1928", "1938", "1948"], "question": "Когда Бубер приехал в Эрец-Исраэль?"}, {"correct": "«Я-Ты» и «Я-Оно»", "options": ["Добро и зло", "«Я-Ты» и «Я-Оно»", "Личное и общественное"], "question": "Между какими типами отношений различал Бубер?"}, {"correct": "Образование, психотерапия и теология", "options": ["Физика и математика", "Образование, психотерапия и теология", "Экономика и право"], "question": "На какие области повлияли его идеи?"}], "text_translit": "хафилОсоф мАртин бУбер шеалА леЭрец йисраЭль бе-1938..."}', '{"correct_answers": ["1938", "«Я-Ты» и «Я-Оно»", "Образование, психотерапия и теология"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3771, 205, 'listening_comprehension', 3, '{"text_he": "הסיפור הקצר של אתגר קרת \"פצצות\" מספר על ילד שאביו נרצח בפיגוע. הסיפור, הכתוב בשפה פשוטה ותמציתית, נמנע מפאתוס ומסנטימנטליות. קרת משתמש באירוניה ובהומור שחור כדי לעסוק בטראומה. הגישה הזו — שבה הפשטות מסתירה עומק — הפכה לסמן היכר של הפרוזה הישראלית החדשה.", "questions": [{"correct": "О ребёнке, чей отец погиб в теракте", "options": ["О войне", "О ребёнке, чей отец погиб в теракте", "О школе"], "question": "О чём рассказ Керета?"}, {"correct": "Простой, с иронией и чёрным юмором", "options": ["Пафосный и эмоциональный", "Простой, с иронией и чёрным юмором", "Документальный"], "question": "Какой стиль использует Керет?"}, {"correct": "Простота, скрывающая глубину", "options": ["Длинные предложения", "Простота, скрывающая глубину", "Библейский стиль"], "question": "Что стало характерной чертой новой израильской прозы?"}], "text_translit": "хасипУр хакацАр шель этгАр кЕрет «пцацОт» месапЕр аль йЕлед шеавИв нирцАх бефигУа..."}', '{"correct_answers": ["О ребёнке, чей отец погиб в теракте", "Простой, с иронией и чёрным юмором", "Простота, скрывающая глубину"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3772, 205, 'listening_comprehension', 3, '{"text_he": "בהרצאה על מוסר ופוליטיקה, פרופסור תמר הרמן ניתחה את הקשר בין דמוקרטיה לזכויות מיעוטים. היא הציגה את הטענה שדמוקרטיה אינה רק שלטון הרוב, אלא גם מנגנון להגנה על זכויות הפרט והמיעוט. הרמן הדגימה זאת באמצעות פסיקות של בית המשפט העליון בישראל.", "questions": [{"correct": "Демократия и права меньшинств", "options": ["Экономика и политика", "Демократия и права меньшинств", "Религия и государство"], "question": "Какую связь анализировала профессор Херман?"}, {"correct": "Демократия — также защита прав меньшинства и личности", "options": ["Демократия — только власть большинства", "Демократия — также защита прав меньшинства и личности", "Демократия не работает"], "question": "Какой тезис она выдвинула?"}, {"correct": "Решениями Верховного суда Израиля", "options": ["Примерами из США", "Решениями Верховного суда Израиля", "Международными договорами"], "question": "Чем она проиллюстрировала тезис?"}], "text_translit": "бехарцаА аль мусАр уполИтика, профЕсор тамАр хЕрман нитхА эт хакЕшер..."}', '{"correct_answers": ["Демократия и права меньшинств", "Демократия — также защита прав меньшинства и личности", "Решениями Верховного суда Израиля"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3773, 205, 'listening_comprehension', 3, '{"text_he": "הכנסת אישרה בקריאה ראשונה חוק המחייב שקיפות במימון ארגוני מגזר שלישי. לפי ההצעה, כל ארגון שמקבל יותר ממחצית תקציבו ממקורות זרים יהיה חייב לדווח על כך. התומכים טוענים שמדובר בשקיפות דמוקרטית, בעוד המבקרים רואים בכך ניסיון להשתיק ארגוני חברה אזרחית.", "questions": [{"correct": "Отчитываться об иностранном финансировании", "options": ["Платить больше налогов", "Отчитываться об иностранном финансировании", "Регистрировать всех членов"], "question": "Что обязывает новый закон?"}, {"correct": "Демократическая прозрачность", "options": ["Экономическая необходимость", "Демократическая прозрачность", "Национальная безопасность"], "question": "Аргумент сторонников?"}, {"correct": "Попытка заставить замолчать гражданское общество", "options": ["Закон слишком мягкий", "Попытка заставить замолчать гражданское общество", "Закон не нужен"], "question": "Что говорят критики?"}], "text_translit": "хакнЕсет ишрА бикриА ришонА хОк хамехайЕв шкифУт бемимУн..."}', '{"correct_answers": ["Отчитываться об иностранном финансировании", "Демократическая прозрачность", "Попытка заставить замолчать гражданское общество"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3774, 205, 'listening_comprehension', 3, '{"text_he": "מחקר ארכיאולוגי באזור ים המלח חשף שרידים של יישוב מתקופת בית שני. נמצאו כלי חרס, מטבעות ושאריות של מקווה טהרה. הממצאים מחזקים את ההשערה שהקהילה שחיה כאן הייתה קשורה לכת האיסיים, שלפי חוקרים רבים כתבו את מגילות ים המלח.", "questions": [{"correct": "Керамику, монеты и миквэ", "options": ["Оружие и доспехи", "Керамику, монеты и миквэ", "Золотые украшения"], "question": "Что нашли в раскопках?"}, {"correct": "Второй Храм", "options": ["Первый Храм", "Второй Храм", "Средневековье"], "question": "К какому периоду относятся находки?"}, {"correct": "Ессеи", "options": ["Фарисеи", "Ессеи", "Зелоты"], "question": "С какой группой связывают поселение?"}], "text_translit": "мехкАр археолОги баэзОр йам хамЕлах хасАф шридИм шель йишУв миткуфАт бейт шенИ..."}', '{"correct_answers": ["Керамику, монеты и миквэ", "Второй Храм", "Ессеи"]}', '{"text": "Обратите внимание на академическую лексику, имена и причинно-следственные связи."}', 25);
