INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3793, 206, 'dictation', 4, '{"hint": "Декларация независимости", "word_he": "מדינת ישראל תהא פתוחה לעלייה יהודית ולקיבוץ גלויות", "word_translit": "мединАт йисраЭль тихЕ птухА лаалийА йехудИт улекибУц галуйОт"}', '{"accept": ["מדינת ישראל תהא פתוחה לעלייה יהודית ולקיבוץ גלויות"], "correct": "מדינת ישראל תהא פתוחה לעלייה יהודית ולקיבוץ גלויות"}', '{"text": "(Декларация независимости) מדינת ישראל תהא פתוחה לעלייה יהודית ולקיבוץ גלויות"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3794, 206, 'dictation', 4, '{"hint": "сравнительная литература", "word_he": "הריאליזם המאגי בספרות הלטינו-אמריקאית השפיע על כותבים ישראלים", "word_translit": "хареалИзм хамАги басифрУт халАтино-америкАит хишпИа аль котвИм йисреэлиИм"}', '{"accept": ["הריאליזם המאגי בספרות הלטינו-אמריקאית השפיע על כותבים ישראלים"], "correct": "הריאליזם המאגי בספרות הלטינו-אמריקאית השפיע על כותבים ישראלים"}', '{"text": "(сравнительная литература) הריאליזם המאגי בספרות הלטינו-אמריקאית השפיע על כותבים ישראלים"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3795, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "חוק", "meaning": "закон (юр.)", "translit": "хок"}, "pair_b": {"he": "חוק", "meaning": "закономерность (науч.)", "translit": "хок"}, "question": "Закон юридический или научная закономерность?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "Одно слово — разные регистры: חוק פלילי (уголовный закон) vs חוק פיזיקלי (физический закон)"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3841, 207, 'translate_ru_he', 1, '{"hint": "תודה", "prompt_ru": "Спасибо", "target_he": "תודה"}', '{"accept": ["תודה", "תודה!"], "correct": "תודה"}', '{"text": "Спасибо = תודה"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3796, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "עדות", "meaning": "свидетельское показание", "translit": "эдУт"}, "pair_b": {"he": "עדות", "meaning": "этническая община (напр. עדות המזרח)", "translit": "эдУт"}, "question": "Показание или этническая община?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "עדות = показание (юр.) или этническая община (соц.). Контекст решает"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3797, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "פסק", "meaning": "вынес решение (суд)", "translit": "пасАк"}, "pair_b": {"he": "פסק", "meaning": "прекратился", "translit": "пасАк"}, "question": "Вынес решение или прекратился?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "בית המשפט פסק = суд постановил. הגשם פסק = дождь прекратился"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3798, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "תקנה", "meaning": "предписание/устав", "translit": "таканА"}, "pair_b": {"he": "תקנה", "meaning": "исправление/ремедия", "translit": "таканА"}, "question": "Устав или исправление?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "В юридическом контексте — предписание. В бытовом — исправление"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3799, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "עלייה", "meaning": "репатриация в Израиль", "translit": "алийА"}, "pair_b": {"he": "עלייה", "meaning": "подъём/рост", "translit": "алийА"}, "question": "Репатриация или рост?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "עלייה לארץ = алия (репатриация). עלייה במחירים = рост цен"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3800, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "דין", "meaning": "суд/закон", "translit": "дин"}, "pair_b": {"he": "דיין", "meaning": "судья (религиозный)", "translit": "даЯн"}, "question": "Закон или судья?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "דין — закон/суд (абстрактно). דיין — религиозный судья (конкретный)"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3801, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "עתירה", "meaning": "петиция (в суд)", "translit": "атирА"}, "pair_b": {"he": "עתיקה", "meaning": "древность/антиквариат", "translit": "атикА"}, "question": "Петиция или древность?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "עתירה — юридическая петиция. עתיקה — древняя вещь"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3802, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "משנה", "meaning": "Мишна (талмудический текст)", "translit": "мишнА"}, "pair_b": {"he": "משנה", "meaning": "заместитель (משנה לנשיא)", "translit": "мишнЕ"}, "question": "Талмудический текст или заместитель?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "המשנה (с определённым артиклем) — Мишна. משנה לנשיא — вице-президент"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3803, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "כתב", "meaning": "писал", "translit": "катАв"}, "pair_b": {"he": "כתב", "meaning": "документ/письмо (юр.)", "translit": "ктАв"}, "question": "Глагол «писал» или «документ»?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "כתב (сущ.) = כתב תביעה (исковое заявление). כתב (гл.) = он писал"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3804, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "דבר", "meaning": "вещь/дело", "translit": "давАр"}, "pair_b": {"he": "דיבר", "meaning": "говорил", "translit": "дибЕр"}, "question": "Вещь или говорил?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "דבר (существительное) — вещь. דיבר (глагол Пиэль) — говорил"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3805, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "לשון", "meaning": "язык (лингв.)", "translit": "лашОн"}, "pair_b": {"he": "לשון", "meaning": "клевета (לשון הרע)", "translit": "лашОн"}, "question": "Язык как речь или клевета?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "לשון = язык/речь. לשון הרע = злословие, клевета (юридический термин)"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3806, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "ערך", "meaning": "ценность/значение", "translit": "Эрех"}, "pair_b": {"he": "ערך", "meaning": "редактировал/устроил", "translit": "арАх"}, "question": "Существительное или глагол?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "ערך (сущ.) — ценность. ערך (гл., Пааль) — устроил/редактировал"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3807, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "גזר", "meaning": "отрезал / вынес приговор", "translit": "газАр"}, "pair_b": {"he": "גזר", "meaning": "морковь", "translit": "гЕзер"}, "question": "Приговор или морковь?", "correct_pair": "b"}', '{"correct": "b"}', '{"text": "גזר דין — приговор. גזר (сущ.) — морковь. Разное ударение!"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3808, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "הלכה", "meaning": "Галаха (религиозный закон)", "translit": "халахА"}, "pair_b": {"he": "הלכה", "meaning": "она шла", "translit": "халхА"}, "question": "Религиозный закон или «она шла»?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "ההלכה — Галаха (с артиклем). היא הלכה — она шла (без артикля)"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3809, 206, 'minimal_pairs', 4, '{"pair_a": {"he": "מדרש", "meaning": "Мидраш (толкование)", "translit": "мидрАш"}, "pair_b": {"he": "מדרש", "meaning": "ступенька (мн.ч. מדרשים нет)", "translit": "мидрАш"}, "question": "Талмудическое толкование или ступенька?", "correct_pair": "a"}', '{"correct": "a"}', '{"text": "מדרש — жанр раввинистической литературы. Омонимии со «ступенькой» нет — это בית מדרש"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3842, 207, 'translate_ru_he', 1, '{"hint": "בבקשה", "prompt_ru": "Пожалуйста", "target_he": "בבקשה"}', '{"accept": ["בבקשה"], "correct": "בבקשה"}', '{"text": "Пожалуйста = בבקשה"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3843, 207, 'translate_ru_he', 1, '{"hint": "סליחה", "prompt_ru": "Извините", "target_he": "סליחה"}', '{"accept": ["סליחה"], "correct": "סליחה"}', '{"text": "Извините = סליחה"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3810, 206, 'listening_comprehension', 4, '{"text_he": "בפסק דין תקדימי, בית המשפט העליון בשבתו כבג\"ץ קבע כי זכות הביטוי כוללת גם את הזכות לפרסם ביקורת חריפה נגד נבחרי ציבור, כל עוד אינה מהווה הסתה לאלימות. השופטים פסקו פה אחד כי חופש הביטוי הוא אבן יסוד בדמוקרטיה ואין להגבילו אלא במקרים חריגים ומוגדרים.", "questions": [{"correct": "БАГАЦ (Верховный суд)", "options": ["Окружной суд", "БАГАЦ (Верховный суд)", "Мировой суд"], "question": "Какой суд вынес решение?"}, {"correct": "Свобода слова", "options": ["Свобода собраний", "Свобода слова", "Свобода вероисповедания"], "question": "О какой свободе идёт речь?"}, {"correct": "Критика разрешена, если нет подстрекательства к насилию", "options": ["Запретить критику", "Критика разрешена, если нет подстрекательства к насилию", "Отправить на пересмотр"], "question": "Каково было решение?"}], "text_translit": "бефсАк дин такдимИ, бейт хамишпАт хаэльОн бешивтО кебагАц..."}', '{"correct_answers": ["БАГАЦ (Верховный суд)", "Свобода слова", "Критика разрешена, если нет подстрекательства к насилию"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3883, 208, 'translate_ru_he', 2, '{"hint": "עובד", "prompt_ru": "Он работает каждый день", "target_he": "הוא עובד כל יום"}', '{"accept": ["הוא עובד כל יום"], "correct": "הוא עובד כל יום"}', '{"text": "Он работает каждый день = הוא עובד כל יום"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3811, 206, 'listening_comprehension', 4, '{"text_he": "שיר \"ארצנו הקטנטונת\" של לאה גולדברג, שנכתב ב-1940, מתאר את ארץ ישראל כארץ קטנה ושקטה. הפרדוקס בשיר הוא שגולדברג כותבת על שקט ושלווה בזמן שהעולם בוער במלחמת עולם. הביקורת הספרותית רואה בשיר ביטוי לאסקפיזם מודע — בריחה שהמשוררת יודעת שהיא בריחה.", "questions": [{"correct": "1940", "options": ["1920", "1940", "1960"], "question": "Когда написано стихотворение?"}, {"correct": "Писала о тишине во время мировой войны", "options": ["Писала о войне в мирное время", "Писала о тишине во время мировой войны", "Писала на иврите, не зная языка"], "question": "В чём парадокс стихотворения?"}, {"correct": "Осознанный эскапизм", "options": ["Наивный оптимизм", "Осознанный эскапизм", "Политический протест"], "question": "Как критика трактует стихотворение?"}], "text_translit": "шИр «арцЕну хакатантОнет» шель лЕа гОлдберг, шенихтАв бе-1940..."}', '{"correct_answers": ["1940", "Писала о тишине во время мировой войны", "Осознанный эскапизм"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3812, 206, 'listening_comprehension', 4, '{"text_he": "מגילת העצמאות של מדינת ישראל, שהוכרזה ביום 14 במאי 1948, משלבת מספר מקורות סמכות: ההיסטוריה היהודית, החלטת האו\"ם מ-1947, והזכות הטבעית של העם היהודי לריבונות. המגילה מבטיחה שוויון זכויות מלא לכל אזרחיה ללא הבדל דת, גזע ומין. שאלת מעמדה המשפטי של המגילה שנויה במחלוקת עד היום.", "questions": [{"correct": "Еврейская история, решение ООН и естественное право", "options": ["Только решение ООН", "Еврейская история, решение ООН и естественное право", "Библейское обещание"], "question": "Какие источники легитимности перечисляет Декларация?"}, {"correct": "Равные права всем гражданам без различия религии, расы и пола", "options": ["Только права евреев", "Равные права всем гражданам без различия религии, расы и пола", "Религиозный закон"], "question": "Что гарантирует Декларация?"}, {"correct": "Юридический статус Декларации", "options": ["Дата провозглашения", "Юридический статус Декларации", "Автор текста"], "question": "Какой вопрос остаётся спорным?"}], "text_translit": "мегилАт хаацмаУт шель мединАт йисраЭль, шехухразА бейОм 14 бемАй 1948..."}', '{"correct_answers": ["Еврейская история, решение ООН и естественное право", "Равные права всем гражданам без различия религии, расы и пола", "Юридический статус Декларации"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3813, 206, 'listening_comprehension', 4, '{"text_he": "הפיוט \"אדון עולם\", שמיוחס לשלמה אבן גבירול מהמאה ה-11, הוא אחד הטקסטים הליטורגיים הנפוצים ביותר. בעוד שהפיוט מתחיל בתיאור פילוסופי של אלוהים כישות נצחית ואינסופית, הוא מסתיים בנימה אישית ואינטימית: \"בידו אפקיד רוחי\". המעבר מן האוניברסלי אל האישי הוא מה שהופך את הפיוט לנוגע ללב.", "questions": [{"correct": "Шломо Ибн Гвиролю", "options": ["Маймониду", "Шломо Ибн Гвиролю", "Йехуде Галеви"], "question": "Кому приписывают «Адон Олам»?"}, {"correct": "С философского описания Бога", "options": ["С личной молитвы", "С философского описания Бога", "С просьбы о дожде"], "question": "Как начинается пиют?"}, {"correct": "Переход от универсального к личному", "options": ["Древний язык", "Переход от универсального к личному", "Мелодия"], "question": "Что делает пиют трогательным?"}], "text_translit": "хапиЮт «адОн олАм», шемейухАс лишлОмо ибн гвирОль мехамеА ха-11..."}', '{"correct_answers": ["Шломо Ибн Гвиролю", "С философского описания Бога", "Переход от универсального к личному"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3844, 207, 'translate_ru_he', 1, '{"hint": "ילד", "prompt_ru": "Я мальчик", "target_he": "אני ילד"}', '{"accept": ["אני ילד"], "correct": "אני ילד"}', '{"text": "Я мальчик = אני ילד"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3845, 207, 'translate_ru_he', 1, '{"hint": "ילדה", "prompt_ru": "Я девочка", "target_he": "אני ילדה"}', '{"accept": ["אני ילדה"], "correct": "אני ילדה"}', '{"text": "Я девочка = אני ילדה"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3814, 206, 'listening_comprehension', 4, '{"text_he": "בתלמוד הבבלי, מסכת בבא מציעא, מסופר על \"תנורו של עכנאי\" — סיפור שבו רבי אליעזר מביא ראיות ניסיות ואף קול משמיים לתמיכה בעמדתו, אך החכמים דוחים את כולן ופוסקים לפי רוב. הסיפור מסתיים באמירה מפורסמת: \"לא בשמיים היא\" — התורה ניתנה לבני אדם, והם מכריעים בפרשנותה.", "questions": [{"correct": "О ритуальной чистоте печи", "options": ["О ритуальной чистоте печи", "О Шаббате", "О пище"], "question": "О чём спор в «Печи Ахная»?"}, {"correct": "Чудеса и голос с небес", "options": ["Логические аргументы", "Чудеса и голос с небес", "Цитаты из Торы"], "question": "Какие доказательства привёл рабби Элиэзер?"}, {"correct": "Люди сами решают, как толковать Тору", "options": ["Тора — не для ангелов", "Люди сами решают, как толковать Тору", "Бог не вмешивается в мир"], "question": "Что означает «Не на небесах она»?"}], "text_translit": "баталмУд хабавлИ, масЕхет бавА мециА, месупАр аль «танурО шель ахнАй»..."}', '{"correct_answers": ["О ритуальной чистоте печи", "Чудеса и голос с небес", "Люди сами решают, как толковать Тору"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3815, 206, 'listening_comprehension', 4, '{"text_he": "השירה העברית בימי הביניים בספרד חולקה לשני זרמים: שירה חילונית ושירה דתית. בשירה החילונית שלטו נושאים כמו יין, אהבה וטבע, בהשפעת השירה הערבית. בשירה הדתית — פיוטים, סליחות ובקשות — התבטאו געגועים לציון ותפילה. משוררים כמו יהודה הלוי ושלמה אבן גבירול כתבו בשני הז׳אנרים.", "questions": [{"correct": "Светская и религиозная", "options": ["Любовная и военная", "Светская и религиозная", "Мужская и женская"], "question": "На какие два течения делилась поэзия?"}, {"correct": "Арабская поэзия", "options": ["Латинская литература", "Арабская поэзия", "Греческая философия"], "question": "Что влияло на светскую поэзию?"}, {"correct": "Тоска по Сиону и молитвы", "options": ["Восхваление природы", "Тоска по Сиону и молитвы", "Описание войн"], "question": "Что характерно для религиозной поэзии?"}], "text_translit": "хашИра хаиврИт бимЕй хабейнАим бисфарАд хулкА лишнЕй зрамИм..."}', '{"correct_answers": ["Светская и религиозная", "Арабская поэзия", "Тоска по Сиону и молитвы"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3816, 206, 'listening_comprehension', 4, '{"text_he": "בהרצאה על נרטיב ושיח, ד\"ר ענת בלום הציגה את הקשר בין זיכרון קולקטיבי למבנה הזהות הלאומית. היא הראתה כיצד סיפורי ייסוד — כגון יציאת מצרים או מלחמת העצמאות — מעצבים את התודעה הקולקטיבית ומשמשים כלגיטימציה לסדר הפוליטי הקיים. בלום טענה שביקורת על הנרטיב הלאומי אינה בהכרח אנטי-לאומית, אלא חלק מתהליך ההבשלה של חברה דמוקרטית.", "questions": [{"correct": "Нарратив и коллективная идентичность", "options": ["Нарратив и коллективная идентичность", "Экономика Израиля", "Литературные жанры"], "question": "О чём лекция доктора Блюм?"}, {"correct": "Исход из Египта и Война за независимость", "options": ["Холокост и создание государства", "Исход из Египта и Война за независимость", "Разрушение Храма и изгнание"], "question": "Какие примеры «основополагающих нарративов» она привела?"}, {"correct": "Это часть созревания демократического общества", "options": ["Это предательство", "Это часть созревания демократического общества", "Это бесполезно"], "question": "Что она сказала о критике национального нарратива?"}], "text_translit": "бехарцаА аль наратИв весИах, доктОр анАт блюм хицигА..."}', '{"correct_answers": ["Нарратив и коллективная идентичность", "Исход из Египта и Война за независимость", "Это часть созревания демократического общества"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3817, 206, 'listening_comprehension', 4, '{"text_he": "חוק יסוד: כבוד האדם וחירותו, שנחקק ב-1992, נחשב למהפכה חוקתית בישראל. החוק קובע כי \"זכויות היסוד של האדם בישראל מושתתות על ההכרה בערך האדם, בקדושת חייו ובהיותו בן-חורין\". בית המשפט העליון, בהנהגת השופט אהרן ברק, פירש חוק זה כמקנה סמכות לביקורת שיפוטית על חוקי הכנסת.", "questions": [{"correct": "1992", "options": ["1948", "1992", "2005"], "question": "Когда был принят Основной закон о достоинстве?"}, {"correct": "Ценность человека, святость жизни и свобода", "options": ["Только безопасность", "Ценность человека, святость жизни и свобода", "Только свобода слова"], "question": "Какие ценности закрепляет закон?"}, {"correct": "Как дающий право на судебный контроль над законами Кнессета", "options": ["Как декларативный", "Как дающий право на судебный контроль над законами Кнессета", "Как применимый только к арабам"], "question": "Как Верховный суд интерпретировал закон?"}], "text_translit": "хОк йесОд: квОд хаадАм вехерутО, шенехкАк бе-1992..."}', '{"correct_answers": ["1992", "Ценность человека, святость жизни и свобода", "Как дающий право на судебный контроль над законами Кнессета"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3846, 207, 'translate_ru_he', 1, '{"hint": "בית", "prompt_ru": "Это дом", "target_he": "זה בית"}', '{"accept": ["זה בית"], "correct": "זה בית"}', '{"text": "Это дом = זה בית"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3848, 207, 'translate_ru_he', 1, '{"hint": "אוהב + אמא", "prompt_ru": "Я люблю маму", "target_he": "אני אוהב את אמא"}', '{"accept": ["אני אוהב את אמא", "אני אוהבת את אמא"], "correct": "אני אוהב את אמא"}', '{"text": "Я люблю маму = אני אוהב את אמא"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3818, 206, 'listening_comprehension', 4, '{"text_he": "\"מצלה\" הוא מונח מרכזי בפילוסופיה של היידגר. במובן המקורי, הוא מתייחס לתנועה של חשיפה והסתרה בו-זמנית. בהשפעת היידגר, חוקרי השפה העברית הצביעו על כך שהמילה \"אמת\" בעברית נגזרת מהשורש א.מ.נ — אמינות, אמונה — בעוד שביוונית \"אלתיאה\" משמעותה \"גילוי\", \"הסרת הכיסוי\". ההבדל הזה חושף תפיסות שונות של אמת בשתי התרבויות.", "questions": [{"correct": "Одновременное раскрытие и сокрытие", "options": ["Бытие", "Одновременное раскрытие и сокрытие", "Свобода"], "question": "Что означает термин «мацела» у Хайдеггера?"}, {"correct": "א.מ.נ (верить)", "options": ["א.מ.ר (говорить)", "א.מ.נ (верить)", "א.מ.ד (оценивать)"], "question": "От какого корня происходит слово «эмет» (правда)?"}, {"correct": "Разные культуры понимают «правду» по-разному", "options": ["Иврит древнее греческого", "Разные культуры понимают «правду» по-разному", "Хайдеггер знал иврит"], "question": "Какой вывод делается из сравнения?"}], "text_translit": "«мацелА» ху монАх мерказИ бафилосОфья шель хАйдегер..."}', '{"correct_answers": ["Одновременное раскрытие и сокрытие", "א.מ.נ (верить)", "Разные культуры понимают «правду» по-разному"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3862, 208, 'hebrew_typing', 1, '{"prompt": "Напишите: «Ты говоришь на иврите?»", "target_he": "את מדברת עברית?", "transliteration": "ат медабЕрет иврИт?"}', '{"accept": ["את מדברת עברית?"], "correct": "את מדברת עברית?"}', '{"text": "את מדברת עברית? — ат медабЕрет иврИт?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4195, 214, 'fill_blank', 2, '{"hint": "Глагол «делать», прошедшее (ж.р.)", "sentence": "היא _____ את השיעורים אתמול"}', '{"accept": ["עשתה"], "correct": "עשתה"}', '{"text": "עשתה = она сделала"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3819, 206, 'listening_comprehension', 4, '{"text_he": "בעידן הפוסט-מודרני, מושג ה\"אמת\" עצמו הפך לבעייתי. ז׳אן-פרנסואה ליוטאר הגדיר את המצב הפוסט-מודרני כ\"חוסר אמון במטא-נרטיבים\" — ספקנות כלפי הסיפורים הגדולים שנתנו משמעות לחיים. בישראל, השיח הפוסט-ציוני — שמערער על הנרטיב הציוני הקלאסי — הוא דוגמה מקומית לתופעה עולמית זו.", "questions": [{"correct": "Недоверие к мета-нарративам", "options": ["Вера в прогресс", "Недоверие к мета-нарративам", "Конец истории"], "question": "Как Лиотар определил постмодерн?"}, {"correct": "Критика классического сионистского нарратива", "options": ["Движение за мир", "Критика классического сионистского нарратива", "Новая партия"], "question": "Что такое пост-сионизм в данном контексте?"}, {"correct": "Местный пример мирового постмодернистского тренда", "options": ["Чисто израильское явление", "Местный пример мирового постмодернистского тренда", "Антисемитизм"], "question": "Пост-сионизм — это..."}], "text_translit": "баидАн хапОст-модЕрни, мусАг ха«эмЕт» ацмО хафАх лебааятИ..."}', '{"correct_answers": ["Недоверие к мета-нарративам", "Критика классического сионистского нарратива", "Местный пример мирового постмодернистского тренда"]}', '{"text": "Текст содержит специализированную лексику. Обратите внимание на стилистический регистр."}', 30);
