INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3934, 209, 'translate_ru_he', 3, '{"hint": "חנייה + משרד", "prompt_ru": "Мне удалось найти парковку рядом с офисом", "target_he": "הצלחתי למצוא חנייה ליד המשרד"}', '{"accept": ["הצלחתי למצוא חנייה ליד המשרד"], "correct": "הצלחתי למצוא חנייה ליד המשרד"}', '{"text": "Мне удалось найти парковку рядом с офисом = הצלחתי למצוא חנייה ליד המשרד"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3935, 209, 'translate_ru_he', 3, '{"hint": "לבשל + אמא", "prompt_ru": "Он научился готовить от своей мамы", "target_he": "הוא למד לבשל מאמא שלו"}', '{"accept": ["הוא למד לבשל מאמא שלו", "הוא למד לבשל מאימא שלו"], "correct": "הוא למד לבשל מאמא שלו"}', '{"text": "Он научился готовить от своей мамы = הוא למד לבשל מאמא שלו"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3936, 209, 'translate_ru_he', 3, '{"hint": "חורף + שלג", "prompt_ru": "Зимой в Иерусалиме иногда идёт снег", "target_he": "בחורף בירושלים לפעמים יורד שלג"}', '{"accept": ["בחורף בירושלים לפעמים יורד שלג"], "correct": "בחורף בירושלים לפעמים יורד שלג"}', '{"text": "Зимой в Иерусалиме иногда идёт снег = בחורף בירושלים לפעמים יורד שלג"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3937, 209, 'translate_ru_he', 3, '{"hint": "שולחן + יום שישי", "prompt_ru": "Мы заказали столик в ресторане на пятницу", "target_he": "הזמנו שולחן במסעדה ליום שישי"}', '{"accept": ["הזמנו שולחן במסעדה ליום שישי"], "correct": "הזמנו שולחן במסעדה ליום שישי"}', '{"text": "Мы заказали столик в ресторане на пятницу = הזמנו שולחן במסעדה ליום שישי"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3938, 209, 'translate_ru_he', 3, '{"hint": "נהג + מנומס", "prompt_ru": "Водитель автобуса был очень вежливый", "target_he": "נהג האוטובוס היה מאוד מנומס"}', '{"accept": ["נהג האוטובוס היה מאוד מנומס"], "correct": "נהג האוטובוס היה מאוד מנומס"}', '{"text": "Водитель автобуса был очень вежливый = נהג האוטובוס היה מאוד מנומס"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4076, 213, 'multiple_choice', 1, '{"options": ["אני רוצה", "אני יכול", "אני צריך", "אני אוהב"], "question": "Как сказать «я хочу» на иврите?"}', '{"correct": "אני רוצה", "correct_index": 0}', '{"text": "רוצה = хочу"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3939, 209, 'translate_ru_he', 3, '{"hint": "מעדיף + ברגל", "prompt_ru": "Я предпочитаю ходить пешком, чем ездить на автобусе", "target_he": "אני מעדיף ללכת ברגל מאשר לנסוע באוטובוס"}', '{"accept": ["אני מעדיף ללכת ברגל מאשר לנסוע באוטובוס"], "correct": "אני מעדיף ללכת ברגל מאשר לנסוע באוטובוס"}', '{"text": "Я предпочитаю ходить пешком, чем ездить на автобусе = אני מעדיף ללכת ברגל מאשר לנסוע באוטובוס"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3940, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Правительство приняло решение повысить бюджет на образование»", "target_he": "הממשלה החליטה להגדיל את תקציב החינוך", "transliteration": "хамемшалА хехлИта лехагдИль эт такцИв хахинУх"}', '{"accept": ["הממשלה החליטה להגדיל את תקציב החינוך"], "correct": "הממשלה החליטה להגדיל את תקציב החינוך"}', '{"text": "הממשלה החליטה להגדיל את תקציב החינוך — хамемшалА хехлИта лехагдИль эт такцИв хахинУх"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3941, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Общественный транспорт должен быть доступен для всех»", "target_he": "התחבורה הציבורית צריכה להיות נגישה לכולם", "transliteration": "хатахбурА хацибурИт цриха лихьОт негишА лекулАм"}', '{"accept": ["התחבורה הציבורית צריכה להיות נגישה לכולם"], "correct": "התחבורה הציבורית צריכה להיות נגישה לכולם"}', '{"text": "התחבורה הציבורית צריכה להיות נגישה לכולם — хатахбурА хацибурИт цриха лихьОт негишА лекулАм"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3942, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Исследование показало значительное улучшение»", "target_he": "המחקר הראה שיפור משמעותי", "transliteration": "хамехкАр хэрА шипУр машмаутИ"}', '{"accept": ["המחקר הראה שיפור משמעותי"], "correct": "המחקר הראה שיפור משמעותי"}', '{"text": "המחקר הראה שיפור משמעותי — хамехкАр хэрА шипУр машмаутИ"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4095, 213, 'fill_blank', 1, '{"hint": "Глагол «читать» (ж.р.)", "sentence": "היא _____ ספר"}', '{"accept": ["קוראת"], "correct": "קוראת"}', '{"text": "קוראת = читает (ж.р.)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3943, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Необходимо найти баланс между работой и жизнью»", "target_he": "צריך למצוא איזון בין עבודה לחיים", "transliteration": "царИх лимцО изУн бейн аводА лехаИм"}', '{"accept": ["צריך למצוא איזון בין עבודה לחיים"], "correct": "צריך למצוא איזון בין עבודה לחיים"}', '{"text": "צריך למצוא איזון בין עבודה לחיים — царИх лимцО изУн бейн аводА лехаИм"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3944, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Ситуация с безопасностью влияет на экономику»", "target_he": "מצב הביטחון משפיע על הכלכלה", "transliteration": "мацАв хабитахОн машпИа аль хакалкалА"}', '{"accept": ["מצב הביטחון משפיע על הכלכלה"], "correct": "מצב הביטחון משפיע על הכלכלה"}', '{"text": "מצב הביטחון משפיע על הכלכלה — мацАв хабитахОн машпИа аль хакалкалА"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3945, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Демократия требует участия всех граждан»", "target_he": "הדמוקרטיה דורשת השתתפות של כל האזרחים", "transliteration": "хадемокрАтия дорЕшет хиштатфУт шель коль хаэзрахИм"}', '{"accept": ["הדמוקרטיה דורשת השתתפות של כל האזרחים"], "correct": "הדמוקרטיה דורשת השתתפות של כל האזרחים"}', '{"text": "הדמוקרטיה דורשת השתתפות של כל האזרחים — хадемокрАтия дорЕшет хиштатфУт шель коль хаэзрахИм"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3946, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Организация объявила о проведении конференции»", "target_he": "הארגון הודיע על קיום כנס", "transliteration": "хаиргУн ходИа аль киЮм кЕнес"}', '{"accept": ["הארגון הודיע על קיום כנס"], "correct": "הארגון הודיע על קיום כנס"}', '{"text": "הארגון הודיע על קיום כנס — хаиргУн ходИа аль киЮм кЕнес"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3947, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «По мнению экспертов, это положительная тенденция»", "target_he": "לדעת המומחים, זוהי מגמה חיובית", "transliteration": "ледаАт хамумхИм, зОхи мегамА хиювИт"}', '{"accept": ["לדעת המומחים, זוהי מגמה חיובית"], "correct": "לדעת המומחים, זוהי מגמה חיובית"}', '{"text": "לדעת המומחים, זוהי מגמה חיובית — ледаАт хамумхИм, зОхи мегамА хиювИт"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3948, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Население города выросло вдвое за десять лет»", "target_he": "אוכלוסיית העיר גדלה פי שניים בעשר שנים", "transliteration": "ухлусиЯт хаИр гадлА пи шнАйим беЭсер шанИм"}', '{"accept": ["אוכלוסיית העיר גדלה פי שניים בעשר שנים"], "correct": "אוכלוסיית העיר גדלה פי שניים בעשר שנים"}', '{"text": "אוכלוסיית העיר גדלה פי שניים בעשר שנים — ухлусиЯт хаИр гадлА пи шнАйим беЭсер шанИм"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3949, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Закон вступит в силу в начале следующего года»", "target_he": "החוק ייכנס לתוקף בתחילת השנה הבאה", "transliteration": "хахОк йиканЕс летОкеф битхилАт хашанА хабаА"}', '{"accept": ["החוק ייכנס לתוקף בתחילת השנה הבאה"], "correct": "החוק ייכנס לתוקף בתחילת השנה הבאה"}', '{"text": "החוק ייכנס לתוקף בתחילת השנה הבאה — хахОк йиканЕс летОкеф битхилАт хашанА хабаА"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3950, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Культурное разнообразие обогащает общество»", "target_he": "הגיוון התרבותי מעשיר את החברה", "transliteration": "хагивУн хатарбутИ маашИр эт хахеврА"}', '{"accept": ["הגיוון התרבותי מעשיר את החברה"], "correct": "הגיוון התרבותי מעשיר את החברה"}', '{"text": "הגיוון התרבותי מעשיר את החברה — хагивУн хатарбутИ маашИр эт хахеврА"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3951, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Больница приняла решение расширить отделение»", "target_he": "בית החולים החליט להרחיב את המחלקה", "transliteration": "бейт хахолИм хехлИт лехархИв эт хамахлакА"}', '{"accept": ["בית החולים החליט להרחיב את המחלקה"], "correct": "בית החולים החליט להרחיב את המחלקה"}', '{"text": "בית החולים החליט להרחיב את המחלקה — бейт хахолИм хехлИт лехархИв эт хамахлакА"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3952, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Студенты организовали протест против повышения платы»", "target_he": "הסטודנטים ארגנו מחאה נגד העלאת שכר הלימוד", "transliteration": "хастудЕнтим иргенУ мехаА нЕгед хааляАт схАр халимУд"}', '{"accept": ["הסטודנטים ארגנו מחאה נגד העלאת שכר הלימוד"], "correct": "הסטודנטים ארגנו מחאה נגד העלאת שכר הלימוד"}', '{"text": "הסטודנטים ארגנו מחאה נגד העלאת שכר הלימוד — хастудЕнтим иргенУ мехаА нЕгед хааляАт схАр халимУд"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3984, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Этот феномен требует междисциплинарного исследования»", "target_he": "תופעה זו מחייבת מחקר בין-תחומי", "transliteration": "тофаА зо мехаЕвет мехкАр бейн-тхумИ"}', '{"accept": ["תופעה זו מחייבת מחקר בין-תחומי"], "correct": "תופעה זו מחייבת מחקר בין-תחומי"}', '{"text": "תופעה זו מחייבת מחקר בין-תחומי — тофаА зо мехаЕвет мехкАр бейн-тхумИ"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3953, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Технологии изменили нашу повседневную жизнь»", "target_he": "הטכנולוגיה שינתה את חיי היום-יום שלנו", "transliteration": "хатехнолОгия шинтА эт хаЕй хайОм-йом шелАну"}', '{"accept": ["הטכנולוגיה שינתה את חיי היום-יום שלנו"], "correct": "הטכנולוגיה שינתה את חיי היום-יום שלנו"}', '{"text": "הטכנולוגיה שינתה את חיי היום-יום שלנו — хатехнолОгия шинтА эт хаЕй хайОм-йом шелАну"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3954, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Климатический кризис требует немедленных действий»", "target_he": "משבר האקלים דורש פעולה מיידית", "transliteration": "машбЕр хааклИм дорЕш пеулА мийадИт"}', '{"accept": ["משבר האקלים דורש פעולה מיידית"], "correct": "משבר האקלים דורש פעולה מיידית"}', '{"text": "משבר האקלים דורש פעולה מיידית — машбЕр хааклИм дорЕш пеулА мийадИт"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3955, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Министерство здравоохранения опубликовало новые рекомендации»", "target_he": "משרד הבריאות פרסם המלצות חדשות", "transliteration": "мисрАд хабриУт пирсЕм хамлацОт хадашОт"}', '{"accept": ["משרד הבריאות פרסם המלצות חדשות"], "correct": "משרד הבריאות פרסם המלצות חדשות"}', '{"text": "משרד הבריאות פרסם המלצות חדשות — мисрАд хабриУт пирсЕм хамлацОт хадашОт"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3956, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Уровень безработицы снизился в третьем квартале»", "target_he": "שיעור האבטלה ירד ברבעון השלישי", "transliteration": "шиУр хаавталА йарАд барибъОн хашлишИ"}', '{"accept": ["שיעור האבטלה ירד ברבעון השלישי"], "correct": "שיעור האבטלה ירד ברבעון השלישי"}', '{"text": "שיעור האבטלה ירד ברבעון השלישי — шиУр хаавталА йарАд барибъОн хашлишИ"}', 20);
