INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3958, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Комиссия рекомендовала реформу системы образования»", "target_he": "הוועדה המליצה על רפורמה במערכת החינוך", "transliteration": "хаваадА хемлИца аль рефОрма бемаарЕхет хахинУх"}', '{"accept": ["הוועדה המליצה על רפורמה במערכת החינוך"], "correct": "הוועדה המליצה על רפורמה במערכת החינוך"}', '{"text": "הוועדה המליצה על רפורמה במערכת החינוך — хаваадА хемлИца аль рефОрма бемаарЕхет хахинУх"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3959, 210, 'hebrew_typing', 4, '{"prompt": "Напишите: «Международное сотрудничество помогает решать глобальные проблемы»", "target_he": "שיתוף פעולה בינלאומי עוזר לפתור בעיות גלובליות", "transliteration": "шитУф пеулА бейнлеумИ озЕр лифтОр беаЙот глобалиЙот"}', '{"accept": ["שיתוף פעולה בינלאומי עוזר לפתור בעיות גלובליות"], "correct": "שיתוף פעולה בינלאומי עוזר לפתור בעיות גלובליות"}', '{"text": "שיתוף פעולה בינלאומי עוזר לפתור בעיות גלובליות — шитУф пеулА бейнлеумИ озЕр лифтОр беаЙот глобалиЙот"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3960, 210, 'translate_ru_he', 4, '{"hint": "הזדמנויות שוות", "prompt_ru": "Правительство обязано обеспечить равные возможности для всех граждан", "target_he": "הממשלה מחויבת להבטיח הזדמנויות שוות לכל האזרחים"}', '{"accept": ["הממשלה מחויבת להבטיח הזדמנויות שוות לכל האזרחים"], "correct": "הממשלה מחויבת להבטיח הזדמנויות שוות לכל האזרחים"}', '{"text": "Правительство обязано обеспечить равные возможности для всех граждан = הממשלה מחויבת להבטיח הזדמנויות שוות לכל האזרחים"}', 20);
