INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3980, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Исследователи пришли к выводу, что гипотеза подтвердилась»", "target_he": "החוקרים הגיעו למסקנה שההשערה אוששה", "transliteration": "хахокрИм хигИу лемасканА шехахашерА ушшА"}', '{"accept": ["החוקרים הגיעו למסקנה שההשערה אוששה"], "correct": "החוקרים הגיעו למסקנה שההשערה אוששה"}', '{"text": "החוקרים הגיעו למסקנה שההשערה אוששה — хахокрИм хигИу лемасканА шехахашерА ушшА"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3981, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Философия Маймонида оказала глубокое влияние на еврейскую мысль»", "target_he": "הפילוסופיה של הרמב\"ם השפיעה השפעה עמוקה על המחשבה היהודית", "transliteration": "хафилосОфия шель харамбАм хишпИа хашпаА амукА аль хамахшавА хайехудИт"}', '{"accept": ["הפילוסופיה של הרמב\"ם השפיעה השפעה עמוקה על המחשבה היהודית"], "correct": "הפילוסופיה של הרמב\"ם השפיעה השפעה עמוקה על המחשבה היהודית"}', '{"text": "הפילוסופיה של הרמב\"ם השפיעה השפעה עמוקה על המחשבה היהודית — хафилосОфия шель харамбАм хишпИа хашпаА амукА аль хамахшавА хайехудИт"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4020, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «БАГАЦ постановил, что закон противоречит Основному закону»", "target_he": "בג\"ץ פסק שהחוק סותר את חוק היסוד", "transliteration": "багАц пасАк шехахОк сотЕр эт хОк хайесОд"}', '{"accept": ["בג\"ץ פסק שהחוק סותר את חוק היסוד"], "correct": "בג\"ץ פסק שהחוק סותר את חוק היסוד"}', '{"text": "בג\"ץ פסק שהחוק סותר את חוק היסוד — багАц пасАк шехахОк сотЕр эт хОк хайесОд"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3982, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Литературная критика рассматривает произведение в контексте эпохи»", "target_he": "הביקורת הספרותית בוחנת את היצירה בהקשר של התקופה", "transliteration": "хабикОрет хасифрутИт бохЕнет эт хайецирА бехЕкшер шель хаткуфА"}', '{"accept": ["הביקורת הספרותית בוחנת את היצירה בהקשר של התקופה"], "correct": "הביקורת הספרותית בוחנת את היצירה בהקשר של התקופה"}', '{"text": "הביקורת הספרותית בוחנת את היצירה בהקשר של התקופה — хабикОрет хасифрутИт бохЕнет эт хайецирА бехЕкшер шель хаткуфА"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3983, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Судебная система основана на принципе верховенства закона»", "target_he": "מערכת המשפט מבוססת על עקרון שלטון החוק", "transliteration": "маарЕхет хамишпАт мевусЕсет аль икарОн шильтОн хахОк"}', '{"accept": ["מערכת המשפט מבוססת על עקרון שלטון החוק"], "correct": "מערכת המשפט מבוססת על עקרון שלטון החוק"}', '{"text": "מערכת המשפט מבוססת על עקרון שלטון החוק — маарЕхет хамишпАт мевусЕсет аль икарОн шильтОн хахОк"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4096, 213, 'fill_blank', 1, '{"hint": "Глагол «идти» (м.р.)", "sentence": "הוא _____ לבית הספר"}', '{"accept": ["הולך"], "correct": "הולך"}', '{"text": "הולך = идёт"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3985, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Дискурс о правах человека формировался на протяжении столетий»", "target_he": "השיח על זכויות האדם עוצב במשך מאות שנים", "transliteration": "хасИах аль зхуЙот хаадАм уцАв бемЕшех меОт шанИм"}', '{"accept": ["השיח על זכויות האדם עוצב במשך מאות שנים"], "correct": "השיח על זכויות האדם עוצב במשך מאות שנים"}', '{"text": "השיח על זכויות האדם עוצב במשך מאות שנים — хасИах аль зхуЙот хаадАм уцАв бемЕшех меОт шанИм"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3986, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Социологическое исследование выявило новые тенденции»", "target_he": "המחקר הסוציולוגי חשף מגמות חדשות", "transliteration": "хамехкАр хасоциолОги хасАф мегамОт хадашОт"}', '{"accept": ["המחקר הסוציולוגי חשף מגמות חדשות"], "correct": "המחקר הסוציולוגי חשף מגמות חדשות"}', '{"text": "המחקר הסוציולוגי חשף מגמות חדשות — хамехкАр хасоциолОги хасАф мегамОт хадашОт"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3987, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Образовательная реформа предполагает изменение парадигмы»", "target_he": "הרפורמה בחינוך מבקשת לשנות את הפרדיגמה", "transliteration": "харефОрма бахинУх мевакЕшет лешанОт эт хапарадИгма"}', '{"accept": ["הרפורמה בחינוך מבקשת לשנות את הפרדיגמה"], "correct": "הרפורמה בחינוך מבקשת לשנות את הפרדיגמה"}', '{"text": "הרפורמה בחינוך מבקשת לשנות את הפרדיגמה — харефОрма бахинУх мевакЕшет лешанОт эт хапарадИгма"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3988, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Автор критикует общепринятые предположения»", "target_he": "המחבר מבקר את ההנחות המקובלות", "transliteration": "хамехабЕр мевакЕр эт хаханахОт хамекублОт"}', '{"accept": ["המחבר מבקר את ההנחות המקובלות"], "correct": "המחבר מבקר את ההנחות המקובלות"}', '{"text": "המחבר מבקר את ההנחות המקובלות — хамехабЕр мевакЕр эт хаханахОт хамекублОт"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3989, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Этимология этого слова восходит к арамейскому языку»", "target_he": "האטימולוגיה של מילה זו מקורה בארמית", "transliteration": "хаэтимолОгия шель милА зо мекорА баарамИт"}', '{"accept": ["האטימולוגיה של מילה זו מקורה בארמית"], "correct": "האטימולוגיה של מילה זו מקורה בארמית"}', '{"text": "האטימולוגיה של מילה זו מקורה בארמית — хаэтимолОгия шель милА зо мекорА баарамИт"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3990, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Процесс модернизации языка начался с Бен-Йехуды»", "target_he": "תהליך חידוש השפה החל עם בן-יהודה", "transliteration": "тахалИх хидУш хасафА хехЕль им бен-йехудА"}', '{"accept": ["תהליך חידוש השפה החל עם בן-יהודה"], "correct": "תהליך חידוש השפה החל עם בן-יהודה"}', '{"text": "תהליך חידוש השפה החל עם בן-יהודה — тахалИх хидУш хасафА хехЕль им бен-йехудА"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3991, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Идентичность формируется в диалоге между личностью и обществом»", "target_he": "הזהות מתעצבת בדיאלוג בין הפרט לחברה", "transliteration": "хазехУт митъацЕвет бедиалОг бейн хапрАт лахеврА"}', '{"accept": ["הזהות מתעצבת בדיאלוג בין הפרט לחברה"], "correct": "הזהות מתעצבת בדיאלוג בין הפרט לחברה"}', '{"text": "הזהות מתעצבת בדיאלוג בין הפרט לחברה — хазехУт митъацЕвет бедиалОг бейн хапрАт лахеврА"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3992, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Нарратив коллективной памяти создаёт национальное самосознание»", "target_he": "הנרטיב של הזיכרון הקולקטיבי יוצר תודעה לאומית", "transliteration": "ханаратИв шель хазикарОн хаколектИви йоцЕр тодаА леумИт"}', '{"accept": ["הנרטיב של הזיכרון הקולקטיבי יוצר תודעה לאומית"], "correct": "הנרטיב של הזיכרון הקולקטיבי יוצר תודעה לאומית"}', '{"text": "הנרטיב של הזיכרון הקולקטיבי יוצר תודעה לאומית — ханаратИв шель хазикарОн хаколектИви йоцЕр тодаА леумИт"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3993, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Данные свидетельствуют о корреляции между факторами»", "target_he": "הנתונים מצביעים על מתאם בין הגורמים", "transliteration": "ханетунИм мацбиИм аль мэтаАм бейн хагормИм"}', '{"accept": ["הנתונים מצביעים על מתאם בין הגורמים"], "correct": "הנתונים מצביעים על מתאם בין הגורמים"}', '{"text": "הנתונים מצביעים על מתאם בין הגורמים — ханетунИм мацбиИм аль мэтаАм бейн хагормИм"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4022, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Бубер утверждал, что истинный диалог — основа бытия»", "target_he": "בובר טען שהדיאלוג האמיתי הוא יסוד הקיום", "transliteration": "бУбер таАн шехадиалОг хаамитИ ху йесОд хакиЮм"}', '{"accept": ["בובר טען שהדיאלוג האמיתי הוא יסוד הקיום"], "correct": "בובר טען שהדיאלוג האמיתי הוא יסוד הקיום"}', '{"text": "בובר טען שהדיאלוג האמיתי הוא יסוד הקיום — бУбер таАн шехадиалОг хаамитИ ху йесОд хакиЮм"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3994, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Интерпретация текста зависит от культурного контекста читателя»", "target_he": "הפרשנות של הטקסט תלויה בהקשר התרבותי של הקורא", "transliteration": "хапаршанУт шель хатЕкст тлуйА бехЕкшер хатарбутИ шель хакорЕ"}', '{"accept": ["הפרשנות של הטקסט תלויה בהקשר התרבותי של הקורא"], "correct": "הפרשנות של הטקסט תלויה בהקשר התרבותי של הקורא"}', '{"text": "הפרשנות של הטקסט תלויה בהקשר התרבותי של הקורא — хапаршанУт шель хатЕкст тлуйА бехЕкшер хатарбутИ шель хакорЕ"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3995, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Бялик возродил поэтический иврит как живой литературный язык»", "target_he": "ביאליק החיה את העברית הפואטית כשפה ספרותית חיה", "transliteration": "биалИк хехеЯ эт хаиврИт хапоЭтит кесафА сифрутИт хайА"}', '{"accept": ["ביאליק החיה את העברית הפואטית כשפה ספרותית חיה"], "correct": "ביאליק החיה את העברית הפואטית כשפה ספרותית חיה"}', '{"text": "ביאליק החיה את העברית הפואטית כשפה ספרותית חיה — биалИк хехеЯ эт хаиврИт хапоЭтит кесафА сифрутИт хайА"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3996, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Абстракция позволяет выйти за рамки частного случая»", "target_he": "ההפשטה מאפשרת לחרוג מגבולות המקרה הפרטי", "transliteration": "хахафшатА меафшЕрет лахрОг мигвулОт хамикрЕ хапратИ"}', '{"accept": ["ההפשטה מאפשרת לחרוג מגבולות המקרה הפרטי"], "correct": "ההפשטה מאפשרת לחרוג מגבולות המקרה הפרטי"}', '{"text": "ההפשטה מאפשרת לחרוג מגבולות המקרה הפרטי — хахафшатА меафшЕрет лахрОг мигвулОт хамикрЕ хапратИ"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3997, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Критический анализ предполагает сомнение в очевидном»", "target_he": "ניתוח ביקורתי מחייב הטלת ספק במובן מאליו", "transliteration": "нитУах бикуртИ мехаЕв хаталАт сАфек бемувАн меэлАв"}', '{"accept": ["ניתוח ביקורתי מחייב הטלת ספק במובן מאליו"], "correct": "ניתוח ביקורתי מחייב הטלת ספק במובן מאליו"}', '{"text": "ניתוח ביקורתי מחייב הטלת ספק במובן מאליו — нитУах бикуртИ мехаЕв хаталАт сАфек бемувАн меэлАв"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3998, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Диалектика Гегеля основана на противоречиях»", "target_he": "הדיאלקטיקה של הגל מבוססת על סתירות", "transliteration": "хадиалЕктика шель хЕгель мевусЕсет аль стирОт"}', '{"accept": ["הדיאלקטיקה של הגל מבוססת על סתירות"], "correct": "הדיאלקטיקה של הגל מבוססת על סתירות"}', '{"text": "הדיאלקטיקה של הגל מבוססת על סתירות — хадиалЕктика шель хЕгель мевусЕсет аль стирОт"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3999, 211, 'hebrew_typing', 5, '{"prompt": "Напишите: «Эстетическое восприятие искусства субъективно»", "target_he": "התפיסה האסתטית של האמנות היא סובייקטיבית", "transliteration": "хатфисА хаэстЭтит шель хаоманУт хи субъектИвит"}', '{"accept": ["התפיסה האסתטית של האמנות היא סובייקטיבית"], "correct": "התפיסה האסתטית של האמנות היא סובייקטיבית"}', '{"text": "התפיסה האסתטית של האמנות היא סובייקטיבית — хатфисА хаэстЭтит шель хаоманУт хи субъектИвит"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4000, 211, 'translate_ru_he', 5, '{"hint": "דיון אקדמי", "prompt_ru": "Академическая дискуссия обогащает понимание проблемы", "target_he": "דיון אקדמי מעשיר את ההבנה של הבעיה"}', '{"accept": ["דיון אקדמי מעשיר את ההבנה של הבעיה"], "correct": "דיון אקדמי מעשיר את ההבנה של הבעיה"}', '{"text": "Академическая дискуссия обогащает понимание проблемы = דיון אקדמי מעשיר את ההבנה של הבעיה"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4001, 211, 'translate_ru_he', 5, '{"hint": "מגבלות + מחקר", "prompt_ru": "Следует отметить ограничения данного исследования", "target_he": "יש לציין את מגבלות המחקר הנוכחי"}', '{"accept": ["יש לציין את מגבלות המחקר הנוכחי"], "correct": "יש לציין את מגבלות המחקר הנוכחי"}', '{"text": "Следует отметить ограничения данного исследования = יש לציין את מגבלות המחקר הנוכחי"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4077, 213, 'multiple_choice', 1, '{"options": ["קטן", "גדול", "יפה", "חדש"], "question": "Как будет «большой» на иврите?"}', '{"correct": "גדול", "correct_index": 1}', '{"text": "גדול = большой"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4002, 211, 'translate_ru_he', 5, '{"hint": "שירה + קיום", "prompt_ru": "Поэзия Амихая отражает экзистенциальные вопросы человеческого бытия", "target_he": "שירת עמיחי משקפת שאלות אקזיסטנציאליות של הקיום האנושי"}', '{"accept": ["שירת עמיחי משקפת שאלות אקזיסטנציאליות של הקיום האנושי"], "correct": "שירת עמיחי משקפת שאלות אקזיסטנציאליות של הקיום האנושי"}', '{"text": "Поэзия Амихая отражает экзистенциальные вопросы человеческого бытия = שירת עמיחי משקפת שאלות אקזיסטנציאליות של הקיום האנושי"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4041, 212, 'translate_ru_he', 6, '{"hint": "ויאמר + יהי אור", "prompt_ru": "И сказал Бог: да будет свет. И стал свет", "target_he": "ויאמר אלהים יהי אור ויהי אור"}', '{"accept": ["ויאמר אלהים יהי אור ויהי אור"], "correct": "ויאמר אלהים יהי אור ויהי אור"}', '{"text": "И сказал Бог: да будет свет. И стал свет = ויאמר אלהים יהי אור ויהי אור"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4003, 211, 'translate_ru_he', 5, '{"hint": "מתודולוגיה + מטרות", "prompt_ru": "Методология исследования должна соответствовать поставленным целям", "target_he": "מתודולוגיית המחקר חייבת להתאים למטרות שהוגדרו"}', '{"accept": ["מתודולוגיית המחקר חייבת להתאים למטרות שהוגדרו"], "correct": "מתודולוגיית המחקר חייבת להתאים למטרות שהוגדרו"}', '{"text": "Методология исследования должна соответствовать поставленным целям = מתודולוגיית המחקר חייבת להתאים למטרות שהוגדרו"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4004, 211, 'translate_ru_he', 5, '{"hint": "היפותטי + סיבתי", "prompt_ru": "Гипотетически, мы можем предположить обратную причинно-следственную связь", "target_he": "באופן היפותטי, ניתן להניח קשר סיבתי הפוך"}', '{"accept": ["באופן היפותטי, ניתן להניח קשר סיבתי הפוך"], "correct": "באופן היפותטי, ניתן להניח קשר סיבתי הפוך"}', '{"text": "Гипотетически, мы можем предположить обратную причинно-следственную связь = באופן היפותטי, ניתן להניח קשר סיבתי הפוך"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4005, 211, 'translate_ru_he', 5, '{"hint": "מדיניות לשונית + מורשת", "prompt_ru": "Языковая политика государства влияет на сохранение культурного наследия", "target_he": "המדיניות הלשונית של המדינה משפיעה על שימור המורשת התרבותית"}', '{"accept": ["המדיניות הלשונית של המדינה משפיעה על שימור המורשת התרבותית"], "correct": "המדיניות הלשונית של המדינה משפיעה על שימור המורשת התרבותית"}', '{"text": "Языковая политика государства влияет на сохранение культурного наследия = המדיניות הלשונית של המדינה משפיעה על שימור המורשת התרבותית"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4006, 211, 'translate_ru_he', 5, '{"hint": "הרמנויטיקה + משמעויות", "prompt_ru": "Герменевтический подход позволяет раскрыть скрытые смыслы текста", "target_he": "הגישה ההרמנויטית מאפשרת לחשוף משמעויות סמויות בטקסט"}', '{"accept": ["הגישה ההרמנויטית מאפשרת לחשוף משמעויות סמויות בטקסט"], "correct": "הגישה ההרמנויטית מאפשרת לחשוף משמעויות סמויות בטקסט"}', '{"text": "Герменевтический подход позволяет раскрыть скрытые смыслы текста = הגישה ההרמנויטית מאפשרת לחשוף משמעויות סמויות בטקסט"}', 25);
