INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4008, 211, 'translate_ru_he', 5, '{"hint": "חפירות + ציוויליזציות", "prompt_ru": "Многолетние археологические раскопки пролили свет на древние цивилизации", "target_he": "חפירות ארכיאולוגיות רבות-שנים שפכו אור על ציוויליזציות קדומות"}', '{"accept": ["חפירות ארכיאולוגיות רבות-שנים שפכו אור על ציוויליזציות קדומות"], "correct": "חפירות ארכיאולוגיות רבות-שנים שפכו אור על ציוויליזציות קדומות"}', '{"text": "Многолетние археологические раскопки пролили свет на древние цивилизации = חפירות ארכיאולוגיות רבות-שנים שפכו אור על ציוויליזציות קדומות"}', 25);
