INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4017, 211, 'translate_ru_he', 5, '{"hint": "אמפיריים + תיאורטיים", "prompt_ru": "Эмпирические данные не всегда подтверждают теоретические модели", "target_he": "נתונים אמפיריים לא תמיד מאששים מודלים תיאורטיים"}', '{"accept": ["נתונים אמפיריים לא תמיד מאששים מודלים תיאורטיים"], "correct": "נתונים אמפיריים לא תמיד מאששים מודלים תיאורטיים"}', '{"text": "Эмпирические данные не всегда подтверждают теоретические модели = נתונים אמפיריים לא תמיד מאששים מודלים תיאורטיים"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4018, 211, 'translate_ru_he', 5, '{"hint": "אינטרטקסטואליות + דיאלוג", "prompt_ru": "Интертекстуальность создаёт диалог между произведениями разных эпох", "target_he": "אינטרטקסטואליות יוצרת דיאלוג בין יצירות מתקופות שונות"}', '{"accept": ["אינטרטקסטואליות יוצרת דיאלוג בין יצירות מתקופות שונות"], "correct": "אינטרטקסטואליות יוצרת דיאלוג בין יצירות מתקופות שונות"}', '{"text": "Интертекстуальность создаёт диалог между произведениями разных эпох = אינטרטקסטואליות יוצרת דיאלוג בין יצירות מתקופות שונות"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4019, 211, 'translate_ru_he', 5, '{"hint": "פרדיגמה + מהפכות מדעיות", "prompt_ru": "Парадигма научных революций Куна изменила понимание научного прогресса", "target_he": "הפרדיגמה של המהפכות המדעיות של קון שינתה את ההבנה של הקדמה המדעית"}', '{"accept": ["הפרדיגמה של המהפכות המדעיות של קון שינתה את ההבנה של הקדמה המדעית"], "correct": "הפרדיגמה של המהפכות המדעיות של קון שינתה את ההבנה של הקדמה המדעית"}', '{"text": "Парадигма научных революций Куна изменила понимание научного прогресса = הפרדיגמה של המהפכות המדעיות של קון שינתה את ההבנה של הקדמה המדעית"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4021, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «В начале сотворил Бог небо и землю»", "target_he": "בראשית ברא אלהים את השמים ואת הארץ", "transliteration": "берешИт барА элохИм эт хашамАйим вээт хаАрец"}', '{"accept": ["בראשית ברא אלהים את השמים ואת הארץ"], "correct": "בראשית ברא אלהים את השמים ואת הארץ"}', '{"text": "בראשית ברא אלהים את השמים ואת הארץ — берешИт барА элохИм эт хашамАйим вээт хаАрец"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4023, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Обвинение обязано доказать вину подсудимого вне разумных сомнений»", "target_he": "התביעה מחויבת להוכיח את אשמת הנאשם מעבר לספק סביר", "transliteration": "хатвиА мехуЕвет лехохИах эт ашмАт ханеэшАм меЭвер лесАфек савИр"}', '{"accept": ["התביעה מחויבת להוכיח את אשמת הנאשם מעבר לספק סביר"], "correct": "התביעה מחויבת להוכיח את אשמת הנאשם מעבר לספק סביר"}', '{"text": "התביעה מחויבת להוכיח את אשמת הנאשם מעבר לספק סביר — хатвиА мехуЕвет лехохИах эт ашмАт ханеэшАм меЭвер лесАфек савИр"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4024, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Не хлебом единым жив человек»", "target_he": "לא על הלחם לבדו יחיה האדם", "transliteration": "ло аль халЕхем левадО йихъЕ хаадАм"}', '{"accept": ["לא על הלחם לבדו יחיה האדם"], "correct": "לא על הלחם לבדו יחיה האדם"}', '{"text": "לא על הלחם לבדו יחיה האדם — ло аль халЕхем левадО йихъЕ хаадАм"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4025, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Лейбовиц провёл чёткую границу между религией и государством»", "target_he": "ליבוביץ'' הציב גבול ברור בין דת למדינה", "transliteration": "лейбОвич хецИв гвУль барУр бейн дат лемединА"}', '{"accept": ["ליבוביץ'' הציב גבול ברור בין דת למדינה"], "correct": "ליבוביץ'' הציב גבול ברור בין דת למדינה"}', '{"text": "ליבוביץ'' הציב גבול ברור בין דת למדינה — лейбОвич хецИв гвУль барУр бейн дат лемединА"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4026, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Суд вынес прецедентное решение по вопросу свободы слова»", "target_he": "בית המשפט קבע הלכה תקדימית בסוגיית חופש הביטוי", "transliteration": "бейт хамишпАт кавА хилхатА такдимИт бесугиЯт хОфеш хабитУй"}', '{"accept": ["בית המשפט קבע הלכה תקדימית בסוגיית חופש הביטוי"], "correct": "בית המשפט קבע הלכה תקדימית בסוגיית חופש הביטוי"}', '{"text": "בית המשפט קבע הלכה תקדימית בסוגיית חופש הביטוי — бейт хамишпАт кавА хилхатА такдимИт бесугиЯт хОфеш хабитУй"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4027, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Левитикус устанавливает правила ритуальной чистоты»", "target_he": "ספר ויקרא קובע כללי טהרה וטומאה", "transliteration": "сЕфер вайикрА ковЕа клалЕй тохорА ветумъА"}', '{"accept": ["ספר ויקרא קובע כללי טהרה וטומאה"], "correct": "ספר ויקרא קובע כללי טהרה וטומאה"}', '{"text": "ספר ויקרא קובע כללי טהרה וטומאה — сЕфер вайикрА ковЕа клалЕй тохорА ветумъА"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4028, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Экзистенциализм утверждает, что существование предшествует сущности»", "target_he": "האקזיסטנציאליזם טוען שהקיום קודם למהות", "transliteration": "хаэкзистенциалИзм тоЕн шехакиЮм кодЕм ламахУт"}', '{"accept": ["האקזיסטנציאליזם טוען שהקיום קודם למהות"], "correct": "האקזיסטנציאליזם טוען שהקיום קודם למהות"}', '{"text": "האקזיסטנציאליזם טוען שהקיום קודם למהות — хаэкзистенциалИзм тоЕн шехакиЮм кодЕм ламахУт"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4029, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Договор имеет обязательную юридическую силу для обеих сторон»", "target_he": "החוזה מחייב משפטית את שני הצדדים", "transliteration": "хахозЕ мехаЕв мишпатИт эт шнЕй хацдадИм"}', '{"accept": ["החוזה מחייב משפטית את שני הצדדים"], "correct": "החוזה מחייב משפטית את שני הצדדים"}', '{"text": "החוזה מחייב משפטית את שני הצדדים — хахозЕ мехаЕв мишпатИт эт шнЕй хацдадИм"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4030, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Пророк Исайя призывал к справедливости и милосердию»", "target_he": "ישעיהו הנביא קרא לצדק ולחסד", "transliteration": "йешаяху ханавИ карА лецЕдек ульхЕсед"}', '{"accept": ["ישעיהו הנביא קרא לצדק ולחסד"], "correct": "ישעיהו הנביא קרא לצדק ולחסד"}', '{"text": "ישעיהו הנביא קרא לצדק ולחסד — йешаяху ханавИ карА лецЕдек ульхЕсед"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4031, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Талмудический принцип «закон государства — закон» применяется и сегодня»", "target_he": "העיקרון התלמודי \"דינא דמלכותא דינא\" חל גם היום", "transliteration": "хаикарОн хаталмудИ динА демальхутА динА халь гам хайОм"}', '{"accept": ["העיקרון התלמודי \"דינא דמלכותא דינא\" חל גם היום"], "correct": "העיקרון התלמודי \"דינא דמלכותא דינא\" חל גם היום"}', '{"text": "העיקרון התלמודי \"דינא דמלכותא דינא\" חל גם היום — хаикарОн хаталмудИ динА демальхутА динА халь гам хайОм"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4032, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Декларация независимости провозгласила создание еврейского государства»", "target_he": "הכרזת העצמאות הכריזה על הקמת מדינה יהודית", "transliteration": "хахразАт хаацмаУт хихрИза аль хакамАт мединА йехудИт"}', '{"accept": ["הכרזת העצמאות הכריזה על הקמת מדינה יהודית"], "correct": "הכרזת העצמאות הכריזה על הקמת מדינה יהודית"}', '{"text": "הכרזת העצמאות הכריזה על הקמת מדינה יהודית — хахразАт хаацмаУт хихрИза аль хакамАт мединА йехудИт"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4033, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Ответчик должен представить отзыв на иск в установленный срок»", "target_he": "הנתבע חייב להגיש כתב הגנה במועד הקבוע", "transliteration": "ханитбА хайАв лехагИш ктАв хаганА бемоЭд хакавУа"}', '{"accept": ["הנתבע חייב להגיש כתב הגנה במועד הקבוע"], "correct": "הנתבע חייב להגיש כתב הגנה במועד הקבוע"}', '{"text": "הנתבע חייב להגיש כתב הגנה במועד הקבוע — ханитбА хайАв лехагИш ктАв хаганА бемоЭд хакавУа"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4034, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Мидраш толкует библейский текст аллегорически»", "target_he": "המדרש מפרש את הטקסט המקראי באופן אלגורי", "transliteration": "хамидрАш мефарЕш эт хатЕкст хамикраИ беОфен алегорИ"}', '{"accept": ["המדרש מפרש את הטקסט המקראי באופן אלגורי"], "correct": "המדרש מפרש את הטקסט המקראי באופן אלגורי"}', '{"text": "המדרש מפרש את הטקסט המקראי באופן אלגורי — хамидрАш мефарЕш эт хатЕкст хамикраИ беОфен алегорИ"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4035, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Спиноза был отлучён от амстердамской общины в 1656 году»", "target_he": "שפינוזה הוחרם מקהילת אמסטרדם בשנת 1656", "transliteration": "шпинОза хохрАм микхилАт амстердАм бишнАт 1656"}', '{"accept": ["שפינוזה הוחרם מקהילת אמסטרדם בשנת 1656"], "correct": "שפינוזה הוחרם מקהילת אמסטרדם בשנת 1656"}', '{"text": "שפינוזה הוחרם מקהילת אמסטרדם בשנת 1656 — шпинОза хохрАм микхилАт амстердАм бишнАт 1656"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4036, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Право на достоинство является абсолютным и неотчуждаемым»", "target_he": "הזכות לכבוד היא מוחלטת ובלתי ניתנת לוויתור", "transliteration": "хазхУт лекавОд хи мухлЕтет увильтИ нитЕнет левитУр"}', '{"accept": ["הזכות לכבוד היא מוחלטת ובלתי ניתנת לוויתור"], "correct": "הזכות לכבוד היא מוחלטת ובלתי ניתנת לוויתור"}', '{"text": "הזכות לכבוד היא מוחלטת ובלתי ניתנת לוויתור — хазхУт лекавОд хи мухлЕтет увильтИ нитЕнет левитУр"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4037, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Песнь Песней — одно из самых поэтичных произведений Библии»", "target_he": "שיר השירים הוא אחד מהיצירות הפואטיות ביותר במקרא", "transliteration": "шир хаширИм ху эхАд мехайецирОт хапоЭтийот беЙОтер бамикрА"}', '{"accept": ["שיר השירים הוא אחד מהיצירות הפואטיות ביותר במקרא"], "correct": "שיר השירים הוא אחד מהיצירות הפואטיות ביותר במקרא"}', '{"text": "שיר השירים הוא אחד מהיצירות הפואטיות ביותר במקרא — шир хаширИм ху эхАд мехайецирОт хапоЭтийот беЙОтер бамикрА"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4038, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Маймонид систематизировал еврейский закон в «Мишне Тора»»", "target_he": "הרמב\"ם סידר את ההלכה היהודית במשנה תורה", "transliteration": "харамбАм сидЕр эт хахалахА хайехудИт бемишнЕ торА"}', '{"accept": ["הרמב\"ם סידר את ההלכה היהודית במשנה תורה"], "correct": "הרמב\"ם סידר את ההלכה היהודית במשנה תורה"}', '{"text": "הרמב\"ם סידר את ההלכה היהודית במשנה תורה — харамбАм сидЕр эт хахалахА хайехудИт бемишнЕ торА"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4039, 212, 'hebrew_typing', 6, '{"prompt": "Напишите: «Конституционный контроль защищает основные права личности»", "target_he": "הביקורת החוקתית מגינה על זכויות היסוד של הפרט", "transliteration": "хабикОрет хахукатИт мегинА аль зхуЙот хайесОд шель хапрАт"}', '{"accept": ["הביקורת החוקתית מגינה על זכויות היסוד של הפרט"], "correct": "הביקורת החוקתית מגינה על זכויות היסוד של הפרט"}', '{"text": "הביקורת החוקתית מגינה על זכויות היסוד של הפרט — хабикОрет хахукатИт мегинА аль зхуЙот хайесОд шель хапрАт"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4040, 212, 'translate_ru_he', 6, '{"hint": "בג\"ץ + חקיקה", "prompt_ru": "Верховный суд справедливости обладает полномочиями отменять законодательные акты", "target_he": "בג\"ץ מוסמך לבטל חקיקה של הכנסת"}', '{"accept": ["בג\"ץ מוסמך לבטל חקיקה של הכנסת"], "correct": "בג\"ץ מוסמך לבטל חקיקה של הכנסת"}', '{"text": "Верховный суд справедливости обладает полномочиями отменять законодательные акты = בג\"ץ מוסמך לבטל חקיקה של הכנסת"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4042, 212, 'translate_ru_he', 6, '{"hint": "התגלות + מפגש", "prompt_ru": "Розенцвейг утверждал, что откровение — это встреча между Богом и человеком", "target_he": "רוזנצוויג טען שההתגלות היא מפגש בין האל לאדם"}', '{"accept": ["רוזנצוויג טען שההתגלות היא מפגש בין האל לאדם"], "correct": "רוזנצוויג טען שההתגלות היא מפגש בין האל לאדם"}', '{"text": "Розенцвейг утверждал, что откровение — это встреча между Богом и человеком = רוזנצוויג טען שההתגלות היא מפגש בין האל לאדם"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4043, 212, 'translate_ru_he', 6, '{"hint": "הפר + לפצות", "prompt_ru": "Сторона нарушившая условия договора обязана возместить ущерб", "target_he": "הצד שהפר את תנאי החוזה מחויב לפצות על הנזק"}', '{"accept": ["הצד שהפר את תנאי החוזה מחויב לפצות על הנזק"], "correct": "הצד שהפר את תנאי החוזה מחויב לפצות על הנזק"}', '{"text": "Сторона нарушившая условия договора обязана возместить ущерб = הצד שהפר את תנאי החוזה מחויב לפצות על הנזק"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4044, 212, 'translate_ru_he', 6, '{"hint": "הבל הבלים", "prompt_ru": "Книга Экклезиаста утверждает: суета сует — всё суета", "target_he": "קהלת אומר: הבל הבלים הכל הבל"}', '{"accept": ["קהלת אומר: הבל הבלים הכל הבל", "קהלת אומר הבל הבלים הכל הבל"], "correct": "קהלת אומר: הבל הבלים הכל הבל"}', '{"text": "Книга Экклезиаста утверждает: суета сует — всё суета = קהלת אומר: הבל הבלים הכל הבל"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4045, 212, 'translate_ru_he', 6, '{"hint": "ציונות רוחנית", "prompt_ru": "Ахад ха-Ам стремился к духовному, а не политическому сионизму", "target_he": "אחד העם שאף לציונות רוחנית ולא מדינית"}', '{"accept": ["אחד העם שאף לציונות רוחנית ולא מדינית"], "correct": "אחד העם שאף לציונות רוחנית ולא מדינית"}', '{"text": "Ахад ха-Ам стремился к духовному, а не политическому сионизму = אחד העם שאף לציונות רוחנית ולא מדינית"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4046, 212, 'translate_ru_he', 6, '{"hint": "מידתיות + התערבות", "prompt_ru": "Принцип соразмерности ограничивает вмешательство государства в права человека", "target_he": "עקרון המידתיות מגביל את התערבות המדינה בזכויות האדם"}', '{"accept": ["עקרון המידתיות מגביל את התערבות המדינה בזכויות האדם"], "correct": "עקרון המידתיות מגביל את התערבות המדינה בזכויות האדם"}', '{"text": "Принцип соразмерности ограничивает вмешательство государства в права человека = עקרון המידתיות מגביל את התערבות המדינה בזכויות האדם"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4047, 212, 'translate_ru_he', 6, '{"hint": "צדקת הדין + צדיק", "prompt_ru": "Книга Иова ставит вопрос о теодицее — почему страдает праведник", "target_he": "ספר איוב מעלה את שאלת הצדקת הדין — מדוע סובל הצדיק"}', '{"accept": ["ספר איוב מעלה את שאלת הצדקת הדין — מדוע סובל הצדיק"], "correct": "ספר איוב מעלה את שאלת הצדקת הדין — מדוע סובל הצדיק"}', '{"text": "Книга Иова ставит вопрос о теодицее — почему страдает праведник = ספר איוב מעלה את שאלת הצדקת הדין — מדוע סובל הצדיק"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4048, 212, 'translate_ru_he', 6, '{"hint": "זרמים מיסטיים", "prompt_ru": "Гершом Шолем исследовал мистические течения в иудаизме", "target_he": "גרשם שלום חקר את הזרמים המיסטיים ביהדות"}', '{"accept": ["גרשם שלום חקר את הזרמים המיסטיים ביהדות"], "correct": "גרשם שלום חקר את הזרמים המיסטיים ביהדות"}', '{"text": "Гершом Шолем исследовал мистические течения в иудаизме = גרשם שלום חקר את הזרמים המיסטיים ביהדות"}', 30);
