INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4057, 212, 'translate_ru_he', 6, '{"hint": "ששת הימים + גיאופוליטיקה", "prompt_ru": "Шестидневная война кардинально изменила геополитику Ближнего Востока", "target_he": "מלחמת ששת הימים שינתה מן היסוד את הגיאופוליטיקה של המזרח התיכון"}', '{"accept": ["מלחמת ששת הימים שינתה מן היסוד את הגיאופוליטיקה של המזרח התיכון"], "correct": "מלחמת ששת הימים שינתה מן היסוד את הגיאופוליטיקה של המזרח התיכון"}', '{"text": "Шестидневная война кардинально изменила геополитику Ближнего Востока = מלחמת ששת הימים שינתה מן היסוד את הגיאופוליטיקה של המזרח התיכון"}', 30);
