INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (242, 12, 'match_pairs', 2, '{"pairs_left": ["פעל", "נפעל", "פיעל", "הפעיל"], "pairs_right": ["простое действие", "пассив / возвратность", "усиление", "каузатив"]}', '{"matches": {"פעל": "простое действие", "נפעל": "пассив / возвратность", "פיעל": "усиление", "הפעיל": "каузатив"}}', '{"text": "Пааль — базовый, Нифъаль — пассив, Пиэль — усиление, Хифъиль — каузатив"}', 10);
