INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (288, 36, 'match_pairs', 3, '{"pairs_left": ["ללמוד", "לקרוא", "לעבוד", "לשמוע"], "pairs_right": ["למידה", "קריאה", "עבודה", "שמיעה"]}', '{"matches": {"ללמוד": "למידה", "לעבוד": "עבודה", "לקרוא": "קריאה", "לשמוע": "שמיעה"}}', '{"text": "Мишкаль «ктилА» (קטילה) — самая продуктивная модель для отглагольных сущ."}', 10);
