INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (309, 42, 'match_pairs', 4, '{"pairs_left": ["לשבור את הראש", "לשים לב", "לעשות חיים", "לצאת מהכלים"], "pairs_right": ["ломать голову", "обратить внимание", "веселиться", "выйти из себя"]}', '{"matches": {"לשים לב": "обратить внимание", "לעשות חיים": "веселиться", "לצאת מהכלים": "выйти из себя", "לשבור את הראש": "ломать голову"}}', '{"text": "Распространённые идиомы иврита"}', 10);
