INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (996, 100, 'match_pairs', 2, '{"pairs_left": ["חדר שנה", "כוס קפה", "שולחן עבודה"], "pairs_right": ["חדר של שנה", "כוס של קפה", "שולחן של עבודה"]}', '{"matches": {"חדר שנה": "חדר של שנה", "כוס קפה": "כוס של קפה", "שולחן עבודה": "שולחן של עבודה"}}', '{"text": "Смихут — компактная форма, של — развёрнутая."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (322, 64, 'match_pairs', 4, '{"pairs_left": ["אין חדש תחת השמש", "עין תחת עין", "ארץ זבת חלב ודבש"], "pairs_right": ["ничего не меняется", "справедливое возмездие", "земля обетованная"]}', '{"matches": {"עין תחת עין": "справедливое возмездие", "אין חדש תחת השמש": "ничего не меняется", "ארץ זבת חלב ודבש": "земля обетованная"}}', '{"text": "Библейские выражения, ставшие фразеологизмами"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (330, 66, 'match_pairs', 5, '{"pairs_left": ["пассив", "стативное", "взаимное"], "pairs_right": ["נכתב — был написан", "נראה — кажется", "נפגש — встретился"]}', '{"matches": {"пассив": "נכתב — был написан", "взаимное": "נפגש — встретился", "стативное": "נראה — кажется"}}', '{"text": "Нифъаль имеет три основных значения: пассив, стативность, взаимность"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (338, 45, 'match_pairs', 5, '{"pairs_left": ["משל", "דימוי", "מטפורה", "אנפורה"], "pairs_right": ["притча/аллегория", "сравнение", "метафора", "повтор в начале строк"]}', '{"matches": {"משל": "притча/аллегория", "דימוי": "сравнение", "אנפורה": "повтор в начале строк", "מטפורה": "метафора"}}', '{"text": "Основные поэтические приёмы в ивритской поэзии"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (353, 72, 'match_pairs', 5, '{"pairs_left": ["אחלה", "יאללה", "סבבה", "חבל על הזמן"], "pairs_right": ["מצוין — отлично", "בוא/הלאה — давай", "בסדר — ок", "מדהים — потрясающе"]}', '{"matches": {"אחלה": "מצוין — отлично", "סבבה": "בסדר — ок", "יאללה": "בוא/הלאה — давай", "חבל על הזמן": "מדהים — потрясающе"}}', '{"text": "Израильский сленг — часть арабских и английских заимствований"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (360, 74, 'match_pairs', 5, '{"pairs_left": ["אני מבקש להגיש ערעור", "מה קורה אחי?", "אכן, ניתן להסיק כי"], "pairs_right": ["юридический", "разговорный", "академический"]}', '{"matches": {"מה קורה אחי?": "разговорный", "אכן, ניתן להסיק כי": "академический", "אני מבקש להגיש ערעור": "юридический"}}', '{"text": "Три основных регистра: формальный/академический, нейтральный, разговорный/сленг"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (372, 19, 'match_pairs', 1, '{"pairs_left": ["דָּג (даг — рыба)", "בַּת (бат — дочь)", "סוּס (сус — лошадь)", "כַּף (каф — ложка)"], "pairs_right": ["דָּק (дак — тонкий)", "בַּד (бад — ткань)", "שׁוּשׁ (шуш — тише)", "גַּף (гаф — крыло)"]}', '{"matches": {"בַּת (бат — дочь)": "בַּד (бад — ткань)", "דָּג (даг — рыба)": "דָּק (дак — тонкий)", "כַּף (каф — ложка)": "גַּף (гаф — крыло)", "סוּס (сус — лошадь)": "שׁוּשׁ (шуш — тише)"}}', '{"text": "Минимальные пары — слова, различающиеся только одним звуком. Различие в согласных: г/к, т/д, с/ш, к/г. Тренировка минимальных пар помогает улучшить произношение и слуховое восприятие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (379, 56, 'match_pairs', 4, '{"pairs_left": ["שֶׁלִּי (шелИ)", "אֵלֶיךָ (элЕйха)", "אִתָּנוּ (итАну)", "בִּשְׁבִילָהּ (бишвилА)", "מִמֶּנּוּ (мимЕну)"], "pairs_right": ["мой / моя / моё", "к тебе (м.р.)", "с нами", "ради неё", "от него"]}', '{"matches": {"שֶׁלִּי (шелИ)": "мой / моя / моё", "אִתָּנוּ (итАну)": "с нами", "אֵלֶיךָ (элЕйха)": "к тебе (м.р.)", "מִמֶּנּוּ (мимЕну)": "от него", "בִּשְׁבִילָהּ (бишвилА)": "ради неё"}}', '{"text": "Предлоги с суффиксами — одна из ключевых тем иврита. של → שלי, שלך...; אל → אליי, אליך...; את (с) → איתי, איתך...; בשביל → בשבילי, בשבילך...; מן → ממני, ממך..."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (827, 18, 'match_pairs', 1, '{"pairs_left": ["פָּעַל", "נִפְעַל", "פִּעֵל", "הִפְעִיל"], "pairs_right": ["простое действие", "пассив / возвратность", "усиление действия", "побудительность (каузатив)"]}', '{"matches": {"פִּעֵל": "усиление действия", "פָּעַל": "простое действие", "נִפְעַל": "пассив / возвратность", "הִפְעִיל": "побудительность (каузатив)"}}', '{"text": "Четыре основных биньяна: Пааль — базовый, Нифъаль — пассив, Пиэль — интенсив, Хифъиль — каузатив."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (828, 18, 'match_pairs', 2, '{"pairs_left": ["פִּעֵל", "הִפְעִיל", "פָּעַל"], "pairs_right": ["פּוּעַל", "הוּפְעַל", "נִפְעַל"]}', '{"matches": {"פִּעֵל": "פּוּעַל", "פָּעַל": "נִפְעַל", "הִפְעִיל": "הוּפְעַל"}}', '{"text": "Три пассивные пары: Пиэль↔Пуаль, Хифъиль↔Хуфъаль, Пааль↔Нифъаль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (838, 19, 'match_pairs', 1, '{"pairs_left": ["כָּתַבְתִּי", "כָּתַבְתָּ", "כָּתְבָה", "כָּתְבוּ"], "pairs_right": ["я", "ты (м.)", "она", "они"]}', '{"matches": {"כָּתְבָה": "она", "כָּתְבוּ": "они", "כָּתַבְתָּ": "ты (м.)", "כָּתַבְתִּי": "я"}}', '{"text": "Суффиксы прошедшего: -תי (я), -תָּ (ты м.), -ָה (она), -וּ (они)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (848, 20, 'match_pairs', 1, '{"pairs_left": ["אֶ-", "תִּ-", "יִ-", "נִ-"], "pairs_right": ["я (אני)", "ты м. / она", "он (הוא)", "мы (אנחנו)"]}', '{"matches": {"אֶ-": "я (אני)", "יִ-": "он (הוא)", "נִ-": "мы (אנחנו)", "תִּ-": "ты м. / она"}}', '{"text": "Приставки будущего: א (я), ת (ты/она), י (он/они), נ (мы)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1010, 101, 'match_pairs', 1, '{"pairs_left": ["3 (м.)", "5 (ж.)", "10 (м.)", "7 (ж.)"], "pairs_right": ["שלושה", "חמש", "עשרה", "שבע"]}', '{"matches": {"3 (м.)": "שלושה", "5 (ж.)": "חמש", "7 (ж.)": "שבע", "10 (м.)": "עשרה"}}', '{"text": "Числительные 1-10 имеют мужскую и женскую формы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (858, 21, 'match_pairs', 1, '{"pairs_left": ["כמה זה?", "יש הנחה?", "אפשר למדוד?", "יקר מדי!"], "pairs_right": ["Сколько это?", "Есть скидка?", "Можно примерить?", "Слишком дорого!"]}', '{"matches": {"כמה זה?": "Сколько это?", "יקר מדי!": "Слишком дорого!", "יש הנחה?": "Есть скидка?", "אפשר למדוד?": "Можно примерить?"}}', '{"text": "Основные фразы для покупок в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (868, 22, 'match_pairs', 2, '{"pairs_left": ["אח", "אחות", "דוד", "דודה", "בן דוד"], "pairs_right": ["брат", "сестра", "дядя", "тётя", "двоюродный брат"]}', '{"matches": {"אח": "брат", "דוד": "дядя", "אחות": "сестра", "דודה": "тётя", "בן דוד": "двоюродный брат"}}', '{"text": "Расширенная семейная лексика: דוד (дод) — дядя, דודה (додА) — тётя, בן דוד — кузен."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (887, 24, 'match_pairs', 1, '{"pairs_left": ["סוּס (лошадь)", "סֵפֶר (книга)", "שָׁלוֹם (мир)", "בִּית (дом)"], "pairs_right": ["у (шурук)", "э (цере)", "о (холам)", "и (хирик)"]}', '{"matches": {"בִּית (дом)": "и (хирик)", "סֵפֶר (книга)": "э (цере)", "סוּס (лошадь)": "у (шурук)", "שָׁלוֹם (мир)": "о (холам)"}}', '{"text": "Огласовки определяют значение слова: смена одного гласного меняет смысл."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (908, 26, 'match_pairs', 1, '{"pairs_left": ["כי", "אבל", "לכן", "גם", "או"], "pairs_right": ["причина", "противопоставление", "следствие", "добавление", "альтернатива"]}', '{"matches": {"או": "альтернатива", "גם": "добавление", "כי": "причина", "אבל": "противопоставление", "לכן": "следствие"}}', '{"text": "Основные союзы и связки для построения текста: כי, אבל, לכן, גם, או."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (920, 95, 'match_pairs', 1, '{"pairs_left": ["-תִּי", "-תָּ", "-תְּ", "-נוּ", "-וּ"], "pairs_right": ["אני (я)", "אתה (ты м.)", "את (ты ж.)", "אנחנו (мы)", "הם (они)"]}', '{"matches": {"-וּ": "הם (они)", "-נוּ": "אנחנו (мы)", "-תְּ": "את (ты ж.)", "-תָּ": "אתה (ты м.)", "-תִּי": "אני (я)"}}', '{"text": "Суффиксы прошедшего времени в Пааль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (921, 95, 'match_pairs', 1, '{"pairs_left": ["כָּתַב", "לָמַד", "שָׁמַר", "פָּתַח"], "pairs_right": ["написал", "учил", "хранил", "открыл"]}', '{"matches": {"לָמַד": "учил", "כָּתַב": "написал", "פָּתַח": "открыл", "שָׁמַר": "хранил"}}', '{"text": "Правильные глаголы Пааль в 3 л. м.р. ед.ч. (базовая форма прошедшего)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (935, 96, 'match_pairs', 2, '{"pairs_left": ["לתת", "לראות", "לבוא", "לקנות", "ללכת"], "pairs_right": ["נתן", "ראה", "בא", "קנה", "הלך"]}', '{"matches": {"לתת": "נתן", "לבוא": "בא", "ללכת": "הלך", "לקנות": "קנה", "לראות": "ראה"}}', '{"text": "Неправильные глаголы: корень меняется, но суффиксы те же."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (936, 96, 'match_pairs', 1, '{"pairs_left": ["פ\"נ — нун в начале", "ל\"ה — hей в конце", "ע\"ו — вав в середине"], "pairs_right": ["נתן (давать)", "ראה (видеть)", "בא (приходить)"]}', '{"matches": {"ל\"ה — hей в конце": "ראה (видеть)", "פ\"נ — нун в начале": "נתן (давать)", "ע\"ו — вав в середине": "בא (приходить)"}}', '{"text": "Три основные группы неправильных глаголов Пааль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (950, 97, 'match_pairs', 1, '{"pairs_left": ["אֶ-", "תִּ-", "יִ-", "נִ-"], "pairs_right": ["אני", "אתה / היא", "הוא", "אנחנו"]}', '{"matches": {"אֶ-": "אני", "יִ-": "הוא", "נִ-": "אנחנו", "תִּ-": "אתה / היא"}}', '{"text": "Приставки будущего: א (я), ת (ты/она), י (он), נ (мы)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (951, 97, 'match_pairs', 1, '{"pairs_left": ["מחר", "בשבוע הבא", "בעוד שעה", "בשנה הבאה"], "pairs_right": ["завтра", "на следующей неделе", "через час", "в следующем году"]}', '{"matches": {"מחר": "завтра", "בעוד שעה": "через час", "בשבוע הבא": "на следующей неделе", "בשנה הבאה": "в следующем году"}}', '{"text": "Слова-маркеры будущего времени в иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (965, 98, 'match_pairs', 2, '{"pairs_left": ["אלך", "אבוא", "אתן", "אקח", "אשב"], "pairs_right": ["я пойду", "я приду", "я дам", "я возьму", "я сяду"]}', '{"matches": {"אלך": "я пойду", "אקח": "я возьму", "אשב": "я сяду", "אתן": "я дам", "אבוא": "я приду"}}', '{"text": "Неправильные глаголы в будущем 1 л.: корень меняется."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (966, 98, 'match_pairs', 1, '{"pairs_left": ["будущее", "собираюсь (going to)", "отрицание"], "pairs_right": ["אכתוב מחר", "אני הולך לכתוב", "לא אכתוב"]}', '{"matches": {"будущее": "אכתוב מחר", "отрицание": "לא אכתוב", "собираюсь (going to)": "אני הולך לכתוב"}}', '{"text": "Три способа выразить будущее и его отрицание."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (980, 99, 'match_pairs', 1, '{"pairs_left": ["לי", "לך", "לו", "לה", "לנו"], "pairs_right": ["мне", "тебе (м.)", "ему", "ей", "нам"]}', '{"matches": {"לה": "ей", "לו": "ему", "לי": "мне", "לך": "тебе (м.)", "לנו": "нам"}}', '{"text": "Склонение предлога ל: ли, лехА, ло, лаh, лАну."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (981, 99, 'match_pairs', 2, '{"pairs_left": ["שלי", "שלך", "שלו", "שלה", "שלנו"], "pairs_right": ["мой", "твой (м.)", "его", "её", "наш"]}', '{"matches": {"שלה": "её", "שלו": "его", "שלי": "мой", "שלך": "твой (м.)", "שלנו": "наш"}}', '{"text": "Склонение предлога של (принадлежность)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4082, 213, 'multiple_choice', 1, '{"options": ["קיץ", "סתיו", "חורף", "אביב"], "question": "Как будет «зима» на иврите?"}', '{"correct": "חורף", "correct_index": 2}', '{"text": "חורף = зима"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1011, 101, 'match_pairs', 1, '{"pairs_left": ["ראשון", "שני", "שלישי", "רביעי", "חמישי"], "pairs_right": ["воскресенье", "понедельник", "вторник", "среда", "четверг"]}', '{"matches": {"שני": "понедельник", "חמישי": "четверг", "ראשון": "воскресенье", "רביעי": "среда", "שלישי": "вторник"}}', '{"text": "Дни недели образованы от порядковых числительных."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1025, 102, 'match_pairs', 1, '{"pairs_left": ["רופא", "עורך דין", "מורה", "נהג", "שף"], "pairs_right": ["врач", "адвокат", "учитель", "водитель", "шеф-повар"]}', '{"matches": {"שף": "шеф-повар", "נהג": "водитель", "מורה": "учитель", "רופא": "врач", "עורך דין": "адвокат"}}', '{"text": "Основные профессии на иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1026, 102, 'match_pairs', 2, '{"pairs_left": ["ספר על עצמך", "מה הניסיון שלך?", "מתי אתה יכול להתחיל?"], "pairs_right": ["расскажи о себе", "какой у тебя опыт?", "когда можешь начать?"]}', '{"matches": {"ספר על עצמך": "расскажи о себе", "מה הניסיון שלך?": "какой у тебя опыт?", "מתי אתה יכול להתחיל?": "когда можешь начать?"}}', '{"text": "Типичные вопросы на собеседовании."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1040, 103, 'match_pairs', 1, '{"pairs_left": ["ראש", "גרון", "בטן", "גב", "לב"], "pairs_right": ["голова", "горло", "живот", "спина", "сердце"]}', '{"matches": {"גב": "спина", "לב": "сердце", "בטן": "живот", "ראש": "голова", "גרון": "горло"}}', '{"text": "Основные части тела для разговора с врачом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1041, 103, 'match_pairs', 2, '{"pairs_left": ["חום", "שיעול", "סחרחורת", "חולשה"], "pairs_right": ["температура", "кашель", "головокружение", "слабость"]}', '{"matches": {"חום": "температура", "חולשה": "слабость", "שיעול": "кашель", "סחרחורת": "головокружение"}}', '{"text": "Описание симптомов у врача."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1055, 104, 'match_pairs', 1, '{"pairs_left": ["поезд", "автобус", "такси", "маршрутка"], "pairs_right": ["רכבת", "אוטובוס", "מונית", "שירות"]}', '{"matches": {"поезд": "רכבת", "такси": "מונית", "автобус": "אוטובוס", "маршрутка": "שירות"}}', '{"text": "Основные виды транспорта в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1056, 104, 'match_pairs', 2, '{"pairs_left": ["ירושלים", "תל אביב", "חיפה", "אילת"], "pairs_right": ["הכותל", "שוק הכרמל", "הגנים הבהאיים", "שונית אלמוגים"]}', '{"matches": {"אילת": "שונית אלמוגים", "חיפה": "הגנים הבהאיים", "תל אביב": "שוק הכרמל", "ירושלים": "הכותל"}}', '{"text": "Главные достопримечательности городов Израиля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1070, 105, 'match_pairs', 1, '{"pairs_left": ["אדום", "כחול", "ירוק", "לבן", "שחור"], "pairs_right": ["красный", "синий", "зелёный", "белый", "чёрный"]}', '{"matches": {"לבן": "белый", "אדום": "красный", "ירוק": "зелёный", "כחול": "синий", "שחור": "чёрный"}}', '{"text": "Основные цвета на иврите (мужской род)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1071, 105, 'match_pairs', 1, '{"pairs_left": ["קטן", "בינוני", "גדול"], "pairs_right": ["маленький (S)", "средний (M)", "большой (L)"]}', '{"matches": {"קטן": "маленький (S)", "גדול": "большой (L)", "בינוני": "средний (M)"}}', '{"text": "Размеры одежды: קטן, בינוני, גדול."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1085, 106, 'match_pairs', 1, '{"pairs_left": ["שמח", "עצוב", "כועס", "עייף", "מופתע"], "pairs_right": ["радостный", "грустный", "злой", "усталый", "удивлённый"]}', '{"matches": {"שמח": "радостный", "כועס": "злой", "עייף": "усталый", "עצוב": "грустный", "מופתע": "удивлённый"}}', '{"text": "Основные эмоции на иврите (мужской род)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1086, 106, 'match_pairs', 2, '{"pairs_left": ["בא לי", "נמאס לי", "איכפת לי", "חבל לי"], "pairs_right": ["хочется", "надоело", "не всё равно", "жаль"]}', '{"matches": {"בא לי": "хочется", "חבל לי": "жаль", "נמאס לי": "надоело", "איכפת לי": "не всё равно"}}', '{"text": "Безличные конструкции для выражения чувств."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1100, 107, 'match_pairs', 1, '{"pairs_left": ["библиотека", "спортзал", "бассейн", "стадион"], "pairs_right": ["ספריה", "חדר כושר", "בריכה", "אצטדיון"]}', '{"matches": {"бассейн": "בריכה", "стадион": "אצטדיון", "спортзал": "חדר כושר", "библиотека": "ספריה"}}', '{"text": "Общественные места для досуга и спорта."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1101, 107, 'match_pairs', 2, '{"pairs_left": ["שחייה", "ריצה", "יוגה", "כדורגל"], "pairs_right": ["плавание", "бег", "йога", "футбол"]}', '{"matches": {"יוגה": "йога", "ריצה": "бег", "שחייה": "плавание", "כדורגל": "футбол"}}', '{"text": "Виды спорта на иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1115, 108, 'match_pairs', 1, '{"pairs_left": ["מטבח", "סלון", "חדר שינה", "חדר אמבטיה", "מרפסת"], "pairs_right": ["кухня", "гостиная", "спальня", "ванная", "балкон"]}', '{"matches": {"מטבח": "кухня", "סלון": "гостиная", "מרפסת": "балкон", "חדר שינה": "спальня", "חדר אמבטיה": "ванная"}}', '{"text": "Комнаты квартиры на иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1116, 108, 'match_pairs', 2, '{"pairs_left": ["שרברב", "חשמלאי", "נגר", "צבעי"], "pairs_right": ["водопроводчик", "электрик", "плотник", "маляр"]}', '{"matches": {"נגר": "плотник", "צבעי": "маляр", "שרברב": "водопроводчик", "חשמלאי": "электрик"}}', '{"text": "Специалисты по ремонту."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4083, 213, 'multiple_choice', 1, '{"options": ["холодно", "жарко", "тепло", "прохладно"], "question": "Что означает «חם»?"}', '{"correct": "жарко", "correct_index": 1}', '{"text": "חם = жарко/горячий"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1130, 109, 'match_pairs', 1, '{"pairs_left": ["ראש השנה", "יום כיפור", "פסח", "חנוכה", "פורים"], "pairs_right": ["яблоко с мёдом", "пост", "маца", "ханукия", "костюмы"]}', '{"matches": {"פסח": "маца", "חנוכה": "ханукия", "פורים": "костюмы", "ראש השנה": "яблоко с мёдом", "יום כיפור": "пост"}}', '{"text": "Традиции основных еврейских праздников."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1131, 109, 'match_pairs', 2, '{"pairs_left": ["שנה טובה", "חג שמח", "צום קל"], "pairs_right": ["Рош ха-Шана", "общее поздравление", "Йом Кипур"]}', '{"matches": {"חג שמח": "общее поздравление", "צום קל": "Йом Кипур", "שנה טובה": "Рош ха-Шана"}}', '{"text": "Поздравления: שנה טובה — хорошего года, צום קל — лёгкого поста."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1145, 110, 'match_pairs', 1, '{"pairs_left": ["לחתוך", "לערבב", "לטגן", "להוסיף", "לבשל"], "pairs_right": ["нарезать", "перемешать", "жарить", "добавить", "варить"]}', '{"matches": {"לבשל": "варить", "לטגן": "жарить", "לחתוך": "нарезать", "לערבב": "перемешать", "להוסיף": "добавить"}}', '{"text": "Кулинарные глаголы на иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1146, 110, 'match_pairs', 2, '{"pairs_left": ["שקשוקה", "חומוס", "פלאפל", "שווארמה"], "pairs_right": ["яйца в томатном соусе", "паста из нута", "шарики из нута", "мясо на вертеле"]}', '{"matches": {"חומוס": "паста из нута", "פלאפל": "шарики из нута", "שקשוקה": "яйца в томатном соусе", "שווארמה": "мясо на вертеле"}}', '{"text": "Знаковые блюда израильской кухни."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1160, 111, 'match_pairs', 1, '{"pairs_left": ["בניין", "קומה", "מעלית", "מדרגות", "חניה"], "pairs_right": ["здание", "этаж", "лифт", "лестница", "парковка"]}', '{"matches": {"חניה": "парковка", "קומה": "этаж", "בניין": "здание", "מעלית": "лифт", "מדרגות": "лестница"}}', '{"text": "Лексика жилого здания."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1161, 111, 'match_pairs', 2, '{"pairs_left": ["סליחה על הרעש", "המעלית לא עובדת", "מתי אסיפת הדיירים?"], "pairs_right": ["извинение за шум", "проблема с лифтом", "вопрос о собрании"]}', '{"matches": {"סליחה על הרעש": "извинение за шум", "המעלית לא עובדת": "проблема с лифтом", "מתי אסיפת הדיירים?": "вопрос о собрании"}}', '{"text": "Фразы для общения с соседями."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1175, 112, 'match_pairs', 1, '{"pairs_left": ["сравнительная", "превосходная", "менее"], "pairs_right": ["יותר גדול מ-", "הכי גדול", "פחות גדול מ-"]}', '{"matches": {"менее": "פחות גדול מ-", "превосходная": "הכי גדול", "сравнительная": "יותר גדול מ-"}}', '{"text": "Три степени сравнения в иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1176, 112, 'match_pairs', 2, '{"pairs_left": ["יותר טוב", "יותר גרוע", "אותו דבר", "שונה מ-"], "pairs_right": ["лучше", "хуже", "то же самое", "отличается от"]}', '{"matches": {"שונה מ-": "отличается от", "אותו דבר": "то же самое", "יותר טוב": "лучше", "יותר גרוע": "хуже"}}', '{"text": "Полезные сравнительные выражения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1190, 113, 'match_pairs', 1, '{"pairs_left": ["אפשר", "צריך", "חייב", "אסור", "יכול"], "pairs_right": ["можно", "нужно", "должен/обязан", "запрещено", "может"]}', '{"matches": {"אסור": "запрещено", "אפשר": "можно", "חייב": "должен/обязан", "יכול": "может", "צריך": "нужно"}}', '{"text": "Пять основных модальных слов иврита."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1191, 113, 'match_pairs', 2, '{"pairs_left": ["אפשר", "מותר", "יכול"], "pairs_right": ["אי אפשר", "אסור", "לא יכול"]}', '{"matches": {"אפשר": "אי אפשר", "יכול": "לא יכול", "מותר": "אסור"}}', '{"text": "Модальные пары: можно↔нельзя, разрешено↔запрещено."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1209, 114, 'match_pairs', 1, '{"pairs_left": ["מה תרצה לשתות?", "כמה זה?", "זה רחוק?", "תודה רבה"], "pairs_right": ["Что будешь пить?", "Сколько это?", "Это далеко?", "Большое спасибо"]}', '{"matches": {"כמה זה?": "Сколько это?", "זה רחוק?": "Это далеко?", "תודה רבה": "Большое спасибо", "מה תרצה לשתות?": "Что будешь пить?"}}', '{"text": "Основные фразы из бытовых диалогов."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1224, 115, 'match_pairs', 1, '{"pairs_left": ["прошедшее", "будущее", "предлоги", "смихут", "сравнение"], "pairs_right": ["כתבתי", "אכתוב", "שלי, לי", "בית ספר", "יותר גדול"]}', '{"matches": {"смихут": "בית ספר", "будущее": "אכתוב", "предлоги": "שלי, לי", "прошедшее": "כתבתי", "сравнение": "יותר גדול"}}', '{"text": "Обзор основных тем уровня Бет."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1236, 27, 'match_pairs', 2, '{"pairs_left": ["реальное условие", "нереальное (настоящее)", "нереальное (прошлое)", "пожелание"], "pairs_right": ["אם + будущее время", "אם היה + причастие", "אילו + прошедшее", "הלוואי ש"]}', '{"matches": {"пожелание": "הלוואי ש", "реальное условие": "אם + будущее время", "нереальное (прошлое)": "אילו + прошедшее", "нереальное (настоящее)": "אם היה + причастие"}}', '{"text": "Реальное: אם + будущее. Нереальное настоящее: אם היה + причастие. Нереальное прошлое: אילו + прошедшее."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1342, 52, 'match_pairs', 2, '{"pairs_left": ["בית חולים", "מרפאה", "בית מרקחת", "מרשם", "תרופה"], "pairs_right": ["больница", "поликлиника", "аптека", "рецепт", "лекарство"]}', '{"matches": {"מרשם": "рецепт", "מרפאה": "поликлиника", "תרופה": "лекарство", "בית חולים": "больница", "בית מרקחת": "аптека"}}', '{"text": "Медицинская лексика: בית חולים (больница), מרפאה (поликлиника), בית מרקחת (аптека)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1718, 38, 'match_pairs', 2, '{"pairs_left": ["תקציב", "מיסים", "יצוא", "יבוא", "אבטלה"], "pairs_right": ["бюджет", "налоги", "экспорт", "импорт", "безработица"]}', '{"matches": {"יבוא": "импорт", "יצוא": "экспорт", "אבטלה": "безработица", "מיסים": "налоги", "תקציב": "бюджет"}}', '{"text": "Базовая экономическая терминология иврита."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1241, 28, 'match_pairs', 2, '{"pairs_left": ["שבר (сломал)", "הזמין (пригласил)", "סיפר (рассказал)", "בנה (построил)"], "pairs_right": ["נשבר (сломался)", "הוזמן (был приглашён)", "סופר (был рассказан)", "נבנה (был построен)"]}', '{"matches": {"שבר (сломал)": "נשבר (сломался)", "בנה (построил)": "נבנה (был построен)", "סיפר (рассказал)": "סופר (был рассказан)", "הזמין (пригласил)": "הוזמן (был приглашён)"}}', '{"text": "Пааль→Нифъаль: שבר→נשבר, בנה→נבנה. Хифъиль→Хуфъаль: הזמין→הוזמן. Пиэль→Пуаль: סיפר→סופר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1253, 29, 'match_pairs', 2, '{"pairs_left": ["כש / כאשר", "בגלל ש", "כדי ש", "למרות ש", "לפני ש"], "pairs_right": ["когда", "потому что", "чтобы", "несмотря на то что", "до того как"]}', '{"matches": {"כדי ש": "чтобы", "בגלל ש": "потому что", "לפני ש": "до того как", "למרות ש": "несмотря на то что", "כש / כאשר": "когда"}}', '{"text": "Составные союзы с ש: כש (когда), בגלל ש (потому что), כדי ש (чтобы), למרות ש (несмотря на), לפני ש (до того как)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1262, 30, 'match_pairs', 2, '{"pairs_left": ["יכול", "צריך", "חייב", "מותר", "אסור"], "pairs_right": ["может", "должен", "обязан", "разрешено", "запрещено"]}', '{"matches": {"אסור": "запрещено", "חייב": "обязан", "יכול": "может", "מותר": "разрешено", "צריך": "должен"}}', '{"text": "Модальные слова: יכול (может), צריך (должен), חייב (обязан), מותר (разрешено), אסור (запрещено)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1272, 31, 'match_pairs', 2, '{"pairs_left": ["ירושלים", "תל אביב", "חיפה", "אילת", "צפת"], "pairs_right": ["столица и святой город", "деловой и культурный центр", "портовый город с Бахайскими садами", "курортный город на Красном море", "город каббалы и искусства"]}', '{"matches": {"צפת": "город каббалы и искусства", "אילת": "курортный город на Красном море", "חיפה": "портовый город с Бахайскими садами", "תל אביב": "деловой и культурный центр", "ירושלים": "столица и святой город"}}', '{"text": "Основные города Израиля: Иерусалим, Тель-Авив, Хайфа, Эйлат, Цфат."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1282, 32, 'match_pairs', 2, '{"pairs_left": ["הרצאה", "סמסטר", "מלגה", "ציון", "מעונות"], "pairs_right": ["лекция", "семестр", "стипендия", "оценка", "общежитие"]}', '{"matches": {"מלגה": "стипендия", "ציון": "оценка", "הרצאה": "лекция", "סמסטר": "семестр", "מעונות": "общежитие"}}', '{"text": "Академическая лексика: הרצאה (лекция), סמסטר (семестр), מלגה (стипендия), ציון (оценка), מעונות (общежитие)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1297, 33, 'match_pairs', 2, '{"pairs_left": ["אם ירד גשם,", "כשהגעתי הביתה,", "למרות הקשיים,", "בגלל הפקק,"], "pairs_right": ["ניקח מטריה", "הילדים כבר ישנו", "הם הצליחו", "איחרנו לעבודה"]}', '{"matches": {"בגלל הפקק,": "איחרנו לעבודה", "אם ירד גשם,": "ניקח מטריה", "למרות הקשיים,": "הם הצליחו", "כשהגעתי הביתה,": "הילדים כבר ישנו"}}', '{"text": "Условие, время, уступка и причина — четыре основных типа придаточных."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1306, 34, 'match_pairs', 2, '{"pairs_left": ["Он сказал, что придёт", "Дверь была открыта", "Мне нужно учиться", "Если хочешь, приходи"], "pairs_right": ["הוא אמר שיבוא", "הדלת נפתחה", "אני צריך ללמוד", "אם אתה רוצה, בוא"]}', '{"matches": {"Мне нужно учиться": "אני צריך ללמוד", "Дверь была открыта": "הדלת נפתחה", "Если хочешь, приходи": "אם אתה רוצה, בוא", "Он сказал, что придёт": "הוא אמר שיבוא"}}', '{"text": "Ключевые конструкции Гимель: косвенная речь (ש), пассив (Нифъаль), модальность, условие."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1314, 49, 'match_pairs', 2, '{"pairs_left": ["אם תאכל ירקות", "אם ירד גשם", "אם תלמד", "אם תרצה"], "pairs_right": ["תהיה בריא", "ניקח מטריה", "תצליח במבחן", "אעזור לך"]}', '{"matches": {"אם תלמד": "תצליח במבחן", "אם תרצה": "אעזור לך", "אם ירד גשם": "ניקח מטריה", "אם תאכל ירקות": "תהיה בריא"}}', '{"text": "Реальные условия из повседневной жизни: אם + будущее → будущее."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1322, 50, 'match_pairs', 2, '{"pairs_left": ["כי", "כש", "כדי ש", "למרות ש", "עד ש"], "pairs_right": ["причина", "время", "цель", "уступка", "предел"]}', '{"matches": {"כי": "причина", "כש": "время", "עד ש": "предел", "כדי ש": "цель", "למרות ש": "уступка"}}', '{"text": "Типы придаточных: причина (כי), время (כש), цель (כדי ש), уступка (למרות ש), предел (עד ש)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1332, 51, 'match_pairs', 2, '{"pairs_left": ["условное предложение", "пассив Нифъаль", "модальность", "придаточное цели", "уступка"], "pairs_right": ["אם תלמד, תצליח", "הספר נכתב", "אני צריך ללמוד", "למדתי כדי שאצליח", "למרות שקשה, אני ממשיך"]}', '{"matches": {"уступка": "למרות שקשה, אני ממשיך", "модальность": "אני צריך ללמוד", "пассив Нифъаль": "הספר נכתב", "придаточное цели": "למדתי כדי שאצליח", "условное предложение": "אם תלמד, תצליח"}}', '{"text": "Повторение ключевых тем Гимель: условия, пассив, модальность, придаточные."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1838, 140, 'match_pairs', 2, '{"pairs_left": ["לכתוב", "להשפיע", "להתנהג", "לפתור"], "pairs_right": ["כתיבה", "השפעה", "התנהגות", "פתרון"]}', '{"matches": {"לכתוב": "כתיבה", "לפתור": "פתרון", "להשפיע": "השפעה", "להתנהג": "התנהגות"}}', '{"text": "Номинализация — ключевой процесс в академическом иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1352, 53, 'match_pairs', 2, '{"pairs_left": ["חנוכה", "פורים", "פסח", "סוכות", "שבועות"], "pairs_right": ["зажигание свечей и суфганийот", "костюмы и мишлоах манот", "седер и маца", "сукка и четыре вида", "молочные блюда"]}', '{"matches": {"פסח": "седер и маца", "חנוכה": "зажигание свечей и суфганийот", "סוכות": "сукка и четыре вида", "פורים": "костюмы и мишлоах манот", "שבועות": "молочные блюда"}}', '{"text": "Основные еврейские праздники и их главные традиции."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1364, 54, 'match_pairs', 2, '{"pairs_left": ["в ресторане", "в магазине", "по телефону", "на улице"], "pairs_right": ["הנה התפריט", "כמה זה עולה?", "מי מדבר?", "סליחה, איפה...?"]}', '{"matches": {"на улице": "סליחה, איפה...?", "в магазине": "כמה זה עולה?", "в ресторане": "הנה התפריט", "по телефону": "מי מדבר?"}}', '{"text": "Бытовые фразы: התפריט (меню), כמה עולה (сколько стоит), מי מדבר (кто говорит)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1371, 116, 'match_pairs', 2, '{"pairs_left": ["כותב", "מורה", "נוהג", "שומר", "תייר"], "pairs_right": ["писатель", "учитель", "водитель", "охранник", "турист"]}', '{"matches": {"כותב": "писатель", "מורה": "учитель", "נוהג": "водитель", "שומר": "охранник", "תייר": "турист"}}', '{"text": "Причастия часто становятся самостоятельными существительными: כותב — пишет / писатель."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1387, 117, 'match_pairs', 2, '{"pairs_left": ["אני", "אנחנו", "פה", "עכשיו", "מחר"], "pairs_right": ["הוא / היא", "הם / הן", "שם", "אז", "למחרת"]}', '{"matches": {"פה": "שם", "אני": "הוא / היא", "מחר": "למחרת", "אנחנו": "הם / הן", "עכשיו": "אז"}}', '{"text": "Правила перехода: лицо, указательные слова и время меняются."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1396, 117, 'match_pairs', 3, '{"pairs_left": ["אמר", "סיפר", "שאל", "הסביר", "הודיע"], "pairs_right": ["сказал", "рассказал", "спросил", "объяснил", "сообщил"]}', '{"matches": {"אמר": "сказал", "שאל": "спросил", "סיפר": "рассказал", "הודיע": "сообщил", "הסביר": "объяснил"}}', '{"text": "Глаголы речи: אמר (сказал), סיפר (рассказал), שאל (спросил), הסביר (объяснил), הודיע (сообщил)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1401, 118, 'match_pairs', 2, '{"pairs_left": ["נולד", "נשבר", "נכנס", "נשאר", "נפגש"], "pairs_right": ["родился", "сломался", "вошёл", "остался", "встретился"]}', '{"matches": {"נולד": "родился", "נכנס": "вошёл", "נפגש": "встретился", "נשאר": "остался", "נשבר": "сломался"}}', '{"text": "Частые глаголы Нифъаля: נולד (родился), נשבר (сломался), נכנס (вошёл), נשאר (остался), נפגש (встретился)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1410, 118, 'match_pairs', 3, '{"pairs_left": ["прошедшее 3 м.р.", "настоящее м.р.", "будущее 1 ед.", "инфинитив"], "pairs_right": ["נכתב", "נכתב", "אכתב", "להיכתב"]}', '{"matches": {"инфинитив": "להיכתב", "будущее 1 ед.": "אכתב", "настоящее м.р.": "נכתב", "прошедшее 3 м.р.": "נכתב"}}', '{"text": "Спряжение Нифъаля: прош. נכתב, наст. נכתב (одинаковые!), буд. אכתב, инф. להיכתב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1416, 119, 'match_pairs', 2, '{"pairs_left": ["בגלל", "בשביל", "במקום", "לפי", "על ידי"], "pairs_right": ["из-за", "для, ради", "вместо", "согласно", "посредством"]}', '{"matches": {"לפי": "согласно", "בגלל": "из-за", "במקום": "вместо", "בשביל": "для, ради", "על ידי": "посредством"}}', '{"text": "Составные предлоги B1: בגלל, בשביל, במקום, לפי, על ידי."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1422, 119, 'match_pairs', 3, '{"pairs_left": ["כדי ש", "למרות ש", "בתנאי ש", "מאחר ש", "בעוד ש"], "pairs_right": ["чтобы", "несмотря на", "при условии", "поскольку", "тогда как"]}', '{"matches": {"כדי ש": "чтобы", "בעוד ש": "тогда как", "מאחר ש": "поскольку", "בתנאי ש": "при условии", "למרות ש": "несмотря на"}}', '{"text": "Составные союзы с ש: כדי ש, למרות ש, בתנאי ש, מאחר ש, בעוד ש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1431, 120, 'match_pairs', 2, '{"pairs_left": ["טירון", "שחרור", "מילואים", "בסיס", "מדים"], "pairs_right": ["новобранец", "демобилизация", "резервистская служба", "военная база", "форма"]}', '{"matches": {"בסיס": "военная база", "מדים": "форма", "טירון": "новобранец", "שחרור": "демобилизация", "מילואים": "резервистская служба"}}', '{"text": "Армейский сленг: טירון, שחרור, מילואים, בסיס, מדים."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1438, 120, 'match_pairs', 3, '{"pairs_left": ["мужчины", "женщины", "друзы", "ультраортодоксы"], "pairs_right": ["~32 месяца", "~24 месяца", "обязательная", "отсрочка"]}', '{"matches": {"друзы": "обязательная", "женщины": "~24 месяца", "мужчины": "~32 месяца", "ультраортодоксы": "отсрочка"}}', '{"text": "Срок службы: мужчины ~32 мес., женщины ~24 мес., друзы — обязательная, ультраортодоксы — отсрочка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4084, 213, 'multiple_choice', 1, '{"options": ["под столом", "на столе", "рядом со столом", "за столом"], "question": "«הספר על השולחן» — где книга?"}', '{"correct": "на столе", "correct_index": 1}', '{"text": "על השולחן = на столе"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1446, 121, 'match_pairs', 2, '{"pairs_left": ["טבע", "סביבה", "מיחזור", "זיהום", "שמורת טבע"], "pairs_right": ["природа", "окружающая среда", "переработка", "загрязнение", "заповедник"]}', '{"matches": {"טבע": "природа", "זיהום": "загрязнение", "סביבה": "окружающая среда", "מיחזור": "переработка", "שמורת טבע": "заповедник"}}', '{"text": "Экологическая лексика: טבע, סביבה, מיחזור, זיהום, שמורת טבע."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1456, 121, 'match_pairs', 3, '{"pairs_left": ["ים המלח", "מדבר הנגב", "הכינרת", "הר הכרמל"], "pairs_right": ["самая низкая точка на Земле", "более половины территории", "самое большое пресное озеро", "заповедник у Хайфы"]}', '{"matches": {"הכינרת": "самое большое пресное озеро", "ים המלח": "самая низкая точка на Земле", "הר הכרמל": "заповедник у Хайфы", "מדבר הנגב": "более половины территории"}}', '{"text": "Географические объекты Израиля: Мёртвое море, Негев, Кинерет, Кармель."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1461, 122, 'match_pairs', 2, '{"pairs_left": ["ווייז", "מובילאיי", "צ''ק פוינט", "8200"], "pairs_right": ["навигация", "автономное вождение", "кибербезопасность", "военная разведка"]}', '{"matches": {"8200": "военная разведка", "ווייז": "навигация", "מובילאיי": "автономное вождение", "צ''ק פוינט": "кибербезопасность"}}', '{"text": "Израильские технологические компании: Waze, Mobileye, Check Point."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1467, 122, 'match_pairs', 3, '{"pairs_left": ["יזם", "חדשנות", "אפליקציה", "בינה מלאכותית", "מימון"], "pairs_right": ["предприниматель", "инновации", "приложение", "искусственный интеллект", "финансирование"]}', '{"matches": {"יזם": "предприниматель", "מימון": "финансирование", "חדשנות": "инновации", "אפליקציה": "приложение", "בינה מלאכותית": "искусственный интеллект"}}', '{"text": "Технологическая лексика: יזם, חדשנות, אפליקציה, בינה מלאכותית, מימון."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1476, 123, 'match_pairs', 2, '{"pairs_left": ["עיתון", "כתב", "ידיעה", "שידור חי", "ראיון"], "pairs_right": ["газета", "корреспондент", "новость", "прямой эфир", "интервью"]}', '{"matches": {"כתב": "корреспондент", "ידיעה": "новость", "עיתון": "газета", "ראיון": "интервью", "שידור חי": "прямой эфир"}}', '{"text": "Журналистская лексика: עיתון, כתב, ידיעה, שידור חי, ראיון."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1484, 123, 'match_pairs', 3, '{"pairs_left": ["ידיעות אחרונות", "הארץ", "כאן", "חדשות 12"], "pairs_right": ["крупнейшая газета", "либеральная газета", "общественное ТВ", "главный новостной канал"]}', '{"matches": {"כאן": "общественное ТВ", "הארץ": "либеральная газета", "חדשות 12": "главный новостной канал", "ידיעות אחרונות": "крупнейшая газета"}}', '{"text": "Основные СМИ: ידיעות אחרונות, הארץ, כאן, חדשות 12."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1491, 124, 'match_pairs', 2, '{"pairs_left": ["כדורגל", "כדורסל", "טניס", "שחייה", "ריצה"], "pairs_right": ["футбол", "баскетбол", "теннис", "плавание", "бег"]}', '{"matches": {"טניס": "теннис", "ריצה": "бег", "שחייה": "плавание", "כדורגל": "футбол", "כדורסל": "баскетбол"}}', '{"text": "Виды спорта: כדורגל, כדורסל, טניס, שחייה, ריצה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1497, 124, 'match_pairs', 3, '{"pairs_left": ["שער", "מגרש", "שופט", "אלוף", "אימון"], "pairs_right": ["гол / ворота", "поле / площадка", "судья", "чемпион", "тренировка"]}', '{"matches": {"שער": "гол / ворота", "אלוף": "чемпион", "מגרש": "поле / площадка", "שופט": "судья", "אימון": "тренировка"}}', '{"text": "Спортивная лексика: שער, מגרש, שופט, אלוף, אימון."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1506, 125, 'match_pairs', 2, '{"pairs_left": ["אמת", "שקר", "צדק", "שלום", "חרות"], "pairs_right": ["истина", "ложь", "справедливость", "мир", "свобода"]}', '{"matches": {"אמת": "истина", "צדק": "справедливость", "שקר": "ложь", "חרות": "свобода", "שלום": "мир"}}', '{"text": "Абстрактные понятия: אמת, שקר, צדק, שלום, חרות."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1512, 125, 'match_pairs', 3, '{"pairs_left": ["חפשי (свободный)", "חזק (сильный)", "חכם (умный)", "יפה (красивый)"], "pairs_right": ["חרות (свобода)", "חוזק (сила)", "חוכמה (мудрость)", "יופי (красота)"]}', '{"matches": {"חכם (умный)": "חוכמה (мудрость)", "חזק (сильный)": "חוזק (сила)", "יפה (красивый)": "יופי (красота)", "חפשי (свободный)": "חרות (свобода)"}}', '{"text": "Образование абстрактных существительных от прилагательных."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1524, 126, 'match_pairs', 2, '{"pairs_left": ["!מבצע מיוחד", "רק היום!", "הנחה של 50%", "במחיר השקה"], "pairs_right": ["специальная акция!", "только сегодня!", "скидка 50%", "по стартовой цене"]}', '{"matches": {"רק היום!": "только сегодня!", "הנחה של 50%": "скидка 50%", "במחיר השקה": "по стартовой цене", "!מבצע מיוחד": "специальная акция!"}}', '{"text": "Рекламные фразы: מבצע מיוחד, רק היום, הנחה, מחיר השקה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1531, 126, 'match_pairs', 3, '{"pairs_left": ["שביתה", "הנחה", "מבצע", "שידור", "פרסומת"], "pairs_right": ["забастовка", "скидка", "акция/операция", "трансляция", "реклама"]}', '{"matches": {"הנחה": "скидка", "מבצע": "акция/операция", "שביתה": "забастовка", "שידור": "трансляция", "פרסומת": "реклама"}}', '{"text": "Лексика новостей и рекламы: שביתה, הנחה, מבצע, שידור, פרסומת."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1596, 131, 'match_pairs', 2, '{"pairs_left": ["כנסת", "ממשלה", "מפלגה", "בחירות", "חוק"], "pairs_right": ["парламент", "правительство", "партия", "выборы", "закон"]}', '{"matches": {"חוק": "закон", "כנסת": "парламент", "ממשלה": "правительство", "מפלגה": "партия", "בחירות": "выборы"}}', '{"text": "Политическая лексика: כנסת, ממשלה, מפלגה, בחירות, חוק."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1537, 127, 'match_pairs', 2, '{"pairs_left": ["אם + будущее", "אם היה + причастие", "אילו + прошедшее", "חבל ש + прошедшее"], "pairs_right": ["реальное условие", "нереальное в настоящем", "нереальное в прошлом", "сожаление"]}', '{"matches": {"אם + будущее": "реальное условие", "אילו + прошедшее": "нереальное в прошлом", "חבל ש + прошедшее": "сожаление", "אם היה + причастие": "нереальное в настоящем"}}', '{"text": "Три типа условий: реальное (אם), нереальное настоящее (אם היה), нереальное прошлое (אילו)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1551, 128, 'match_pairs', 2, '{"pairs_left": ["שבר את הראש", "הרים ידיים", "פתח עיניים", "סגר פינה", "שם לב"], "pairs_right": ["долго думал", "сдался", "осознал", "уладил дело", "обратил внимание"]}', '{"matches": {"שם לב": "обратил внимание", "סגר פינה": "уладил дело", "הרים ידיים": "сдался", "פתח עיניים": "осознал", "שבר את הראש": "долго думал"}}', '{"text": "Идиомы с частями тела: שבר ראש, הרים ידיים, פתח עיניים, סגר פינה, שם לב."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1557, 128, 'match_pairs', 3, '{"pairs_left": ["עמד על", "עמד ב", "יצא נגד", "לקח חלק"], "pairs_right": ["настаивал на", "выдержал, справился", "выступил против", "принял участие"]}', '{"matches": {"עמד ב": "выдержал, справился", "עמד על": "настаивал на", "יצא נגד": "выступил против", "לקח חלק": "принял участие"}}', '{"text": "Глаголы с предлогами: עמד על (настаивал), עמד ב (справился), יצא נגד (выступил против)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1566, 129, 'match_pairs', 2, '{"pairs_left": ["גן ילדים", "בית ספר יסודי", "חטיבת ביניים", "תיכון", "אוניברסיטה"], "pairs_right": ["детский сад", "начальная школа", "средняя школа", "старшая школа", "университет"]}', '{"matches": {"תיכון": "старшая школа", "גן ילדים": "детский сад", "אוניברסיטה": "университет", "חטיבת ביניים": "средняя школа", "בית ספר יסודי": "начальная школа"}}', '{"text": "Структура образования: גן ילדים, יסודי, חטיבת ביניים, תיכון, אוניברסיטה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1572, 129, 'match_pairs', 3, '{"pairs_left": ["חינוך", "תלמיד", "ציון", "מלגה", "מקצוע"], "pairs_right": ["образование", "ученик", "оценка", "стипендия", "предмет / профессия"]}', '{"matches": {"מלגה": "стипендия", "ציון": "оценка", "חינוך": "образование", "מקצוע": "предмет / профессия", "תלמיד": "ученик"}}', '{"text": "Образовательная лексика: חינוך, תלמיד, ציון, מלגה, מקצוע."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1581, 130, 'match_pairs', 2, '{"pairs_left": ["תזונה מאוזנת", "פעילות גופנית", "שינה מספקת", "ניהול מתח"], "pairs_right": ["сбалансированное питание", "физическая активность", "достаточный сон", "управление стрессом"]}', '{"matches": {"ניהול מתח": "управление стрессом", "שינה מספקת": "достаточный сон", "תזונה מאוזנת": "сбалансированное питание", "פעילות גופנית": "физическая активность"}}', '{"text": "Четыре компонента: תזונה, פעילות גופנית, שינה, ניהול מתח."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1587, 130, 'match_pairs', 3, '{"pairs_left": ["חרדה", "דיכאון", "מתח", "פסיכולוג", "דיאטה"], "pairs_right": ["тревога", "депрессия", "стресс", "психолог", "диета"]}', '{"matches": {"מתח": "стресс", "חרדה": "тревога", "דיאטה": "диета", "דיכאון": "депрессия", "פסיכולוג": "психолог"}}', '{"text": "Расширенная медицинская лексика: חרדה, דיכאון, מתח, פסיכולוג, דיאטה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1602, 131, 'match_pairs', 3, '{"pairs_left": ["הרשות המחוקקת", "הרשות המבצעת", "הרשות השופטת"], "pairs_right": ["законодательная — Кнессет", "исполнительная — правительство", "судебная — Верховный суд"]}', '{"matches": {"הרשות המבצעת": "исполнительная — правительство", "הרשות השופטת": "судебная — Верховный суд", "הרשות המחוקקת": "законодательная — Кнессет"}}', '{"text": "Три ветви власти: מחוקקת (законодательная), מבצעת (исполнительная), שופטת (судебная)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1611, 132, 'match_pairs', 2, '{"pairs_left": ["סרט", "סדרה", "במאי", "שחקן", "הצגה"], "pairs_right": ["фильм", "сериал", "режиссёр", "актёр", "спектакль"]}', '{"matches": {"סרט": "фильм", "במאי": "режиссёр", "הצגה": "спектакль", "סדרה": "сериал", "שחקן": "актёр"}}', '{"text": "Культурная лексика: סרט, סדרה, במאי, שחקן, הצגה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4121, 213, 'fill_blank', 1, '{"hint": "Вопросительное слово «что»", "sentence": "_____ אתה רוצה?"}', '{"accept": ["מה"], "correct": "מה"}', '{"text": "מה = что"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1617, 132, 'match_pairs', 3, '{"pairs_left": ["דרמה", "קומדיה", "מותחן", "תיעודי", "אנימציה"], "pairs_right": ["драма", "комедия", "триллер", "документальный", "анимация"]}', '{"matches": {"דרמה": "драма", "מותחן": "триллер", "קומדיה": "комедия", "תיעודי": "документальный", "אנימציה": "анимация"}}', '{"text": "Жанры: דרמה, קומדיה, מותחן, תיעודי, אנימציה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1626, 133, 'match_pairs', 2, '{"pairs_left": ["משכורת", "מס", "ביטוח", "הלוואה", "משכנתא"], "pairs_right": ["зарплата", "налог", "страховка", "ссуда", "ипотека"]}', '{"matches": {"מס": "налог", "ביטוח": "страховка", "הלוואה": "ссуда", "משכורת": "зарплата", "משכנתא": "ипотека"}}', '{"text": "Финансовая лексика: משכורת, מס, ביטוח, הלוואה, משכנתא."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1632, 133, 'match_pairs', 3, '{"pairs_left": ["שכר ברוטו", "שכר נטו", "ביטוח לאומי", "מס בריאות", "קרן פנסיה"], "pairs_right": ["зарплата брутто", "зарплата нетто", "нац. страхование", "налог на здравоохранение", "пенсионный фонд"]}', '{"matches": {"שכר נטו": "зарплата нетто", "מס בריאות": "налог на здравоохранение", "קרן פנסיה": "пенсионный фонд", "שכר ברוטו": "зарплата брутто", "ביטוח לאומי": "нац. страхование"}}', '{"text": "Зарплатный листок: ברוטו, נטו, ביטוח לאומי, מס בריאות, קרן פנסיה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1641, 134, 'match_pairs', 2, '{"pairs_left": ["לכבוד", "הנדון", "שלום רב", "בכבוד רב", "תודה מראש"], "pairs_right": ["обращение", "тема письма", "приветствие", "подпись", "благодарность заранее"]}', '{"matches": {"הנדון": "тема письма", "לכבוד": "обращение", "שלום רב": "приветствие", "בכבוד רב": "подпись", "תודה מראש": "благодарность заранее"}}', '{"text": "Структура формального письма: לכבוד, הנדון, שלום רב, בכבוד רב, תודה מראש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1647, 134, 'match_pairs', 3, '{"pairs_left": ["אני פונה אליכם בנוגע ל", "אבקש ב", "אשמח לתשובה", "בברכה"], "pairs_right": ["обращаюсь по поводу", "прошу...", "буду рад/а ответу", "с наилучшими пожеланиями"]}', '{"matches": {"בברכה": "с наилучшими пожеланиями", "אבקש ב": "прошу...", "אשמח לתשובה": "буду рад/а ответу", "אני פונה אליכם בנוגע ל": "обращаюсь по поводу"}}', '{"text": "Клише формальных писем: פונה בנוגע ל, אבקש, אשמח לתשובה, בברכה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1656, 135, 'match_pairs', 2, '{"pairs_left": ["לדעתי", "אני מסכים", "אני לא מסכים", "בנוסף", "לסיכום"], "pairs_right": ["выражение мнения", "согласие", "несогласие", "добавление", "заключение"]}', '{"matches": {"בנוסף": "добавление", "לדעתי": "выражение мнения", "לסיכום": "заключение", "אני מסכים": "согласие", "אני לא מסכים": "несогласие"}}', '{"text": "Дискуссионная лексика: לדעתי, מסכים, לא מסכים, בנוסף, לסיכום."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1662, 135, 'match_pairs', 3, '{"pairs_left": ["ראשית", "שנית", "בנוסף", "לעומת זאת", "לכן"], "pairs_right": ["во-первых", "во-вторых", "кроме того", "с другой стороны", "поэтому"]}', '{"matches": {"לכן": "поэтому", "שנית": "во-вторых", "בנוסף": "кроме того", "ראשית": "во-первых", "לעומת זאת": "с другой стороны"}}', '{"text": "Связующие слова: ראשית, שנית, בנוסף, לעומת זאת, לכן."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1672, 136, 'match_pairs', 2, '{"pairs_left": ["условное", "пассив Нифъаль", "модальность", "придаточное", "косвенная речь"], "pairs_right": ["אם תלמד, תצליח", "הספר נכתב", "אני צריך ללמוד", "כשהגעתי, הוא ישן", "הוא אמר שהוא בא"]}', '{"matches": {"условное": "אם תלמד, תצליח", "модальность": "אני צריך ללמוד", "придаточное": "כשהגעתי, הוא ישן", "косвенная речь": "הוא אמר שהוא בא", "пассив Нифъаль": "הספר נכתב"}}', '{"text": "Повторение ключевых тем уровня Гимель."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1678, 136, 'match_pairs', 3, '{"pairs_left": ["армия", "экология", "технологии", "политика"], "pairs_right": ["צבא, חייל, גיוס", "טבע, סביבה, מיחזור", "סטארט-אפ, הייטק, חדשנות", "כנסת, ממשלה, בחירות"]}', '{"matches": {"армия": "צבא, חייל, גיוס", "политика": "כנסת, ממשלה, בחירות", "экология": "טבע, סביבה, מיחזור", "технологии": "סטארט-אפ, הייטק, חדשנות"}}', '{"text": "Тематические поля уровня Гимель: армия, экология, технологии, политика."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1688, 35, 'match_pairs', 2, '{"pairs_left": ["כי", "כדי", "למרות", "כאשר", "אם כי"], "pairs_right": ["потому что", "чтобы", "несмотря на", "когда", "хотя"]}', '{"matches": {"כי": "потому что", "כדי": "чтобы", "כאשר": "когда", "אם כי": "хотя", "למרות": "несмотря на"}}', '{"text": "Союзы сложных предложений: כי — причина, כדי — цель, למרות — уступка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1698, 36, 'match_pairs', 2, '{"pairs_left": ["ללמוד", "להתפתח", "לכתוב", "להשפיע"], "pairs_right": ["למידה", "התפתחות", "כתיבה", "השפעה"]}', '{"matches": {"לכתוב": "כתיבה", "ללמוד": "למידה", "להשפיע": "השפעה", "להתפתח": "התפתחות"}}', '{"text": "Мишкали: קְטִילָה (Пааль), הִתְקַטְּלוּת (Хитпаэль), הַקְטָלָה (Хифъиль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1848, 141, 'match_pairs', 2, '{"pairs_left": ["עדות", "ערעור", "גזר דין", "זכות", "חוקה"], "pairs_right": ["показания", "апелляция", "приговор", "право", "конституция"]}', '{"matches": {"זכות": "право", "חוקה": "конституция", "עדות": "показания", "ערעור": "апелляция", "גזר דין": "приговор"}}', '{"text": "Юридическая терминология иврита."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1708, 37, 'match_pairs', 2, '{"pairs_left": ["פעל", "נפעל", "פיעל", "הפעיל", "התפעל"], "pairs_right": ["базовое действие", "пассив / рефлексив", "интенсив / каузатив", "каузатив", "рефлексив / взаимность"]}', '{"matches": {"פעל": "базовое действие", "נפעל": "пассив / рефлексив", "פיעל": "интенсив / каузатив", "הפעיל": "каузатив", "התפעל": "рефлексив / взаимность"}}', '{"text": "Семь биньянов создают систему значений от одного корня."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4088, 213, 'multiple_choice', 1, '{"options": ["школа", "больница", "библиотека", "магазин"], "question": "Что такое «בית חולים»?"}', '{"correct": "больница", "correct_index": 1}', '{"text": "בית חולים = больница (букв. дом больных)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1728, 39, 'match_pairs', 2, '{"pairs_left": ["שופט", "עורך דין", "תובע", "נאשם", "עד"], "pairs_right": ["судья", "адвокат", "обвинитель", "обвиняемый", "свидетель"]}', '{"matches": {"עד": "свидетель", "נאשם": "обвиняемый", "שופט": "судья", "תובע": "обвинитель", "עורך דין": "адвокат"}}', '{"text": "Участники судебного процесса в Израиле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1738, 40, 'match_pairs', 2, '{"pairs_left": [".", ",", "?", "!"], "pairs_right": ["נקודה", "פסיק", "סימן שאלה", "סימן קריאה"]}', '{"matches": {"!": "סימן קריאה", ",": "פסיק", ".": "נקודה", "?": "סימן שאלה"}}', '{"text": "Знаки препинания в иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1748, 55, 'match_pairs', 2, '{"pairs_left": ["כתב — פעל", "כתב — נפעל", "כתב — הפעיל", "כתב — התפעל"], "pairs_right": ["написал", "был написан", "продиктовал", "переписывался"]}', '{"matches": {"כתב — פעל": "написал", "כתב — נפעל": "был написан", "כתב — הפעיל": "продиктовал", "כתב — התפעל": "переписывался"}}', '{"text": "Один корень כ.ת.ב — четыре разных значения через биньяны."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1758, 56, 'match_pairs', 2, '{"pairs_left": ["שלי", "אצלך", "עליו", "ממנה", "איתנו"], "pairs_right": ["мой", "у тебя", "на нём", "от неё", "с нами"]}', '{"matches": {"שלי": "мой", "אצלך": "у тебя", "ממנה": "от неё", "עליו": "на нём", "איתנו": "с нами"}}', '{"text": "Предлоги с местоимёнными суффиксами — важнейшая тема B2."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1768, 57, 'match_pairs', 2, '{"pairs_left": ["קְטִילָה", "קִטּוּל", "הַקְטָלָה", "הִתְקַטְּלוּת"], "pairs_right": ["Пааль", "Пиэль", "Хифъиль", "Хитпаэль"]}', '{"matches": {"קִטּוּל": "Пиэль", "קְטִילָה": "Пааль", "הַקְטָלָה": "Хифъиль", "הִתְקַטְּלוּת": "Хитпаэль"}}', '{"text": "Каждый биньян имеет свой характерный мишкаль для отглагольных существительных."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1778, 58, 'match_pairs', 2, '{"pairs_left": ["כתבה", "ראיון", "מודעה", "כותרת", "מהדורה"], "pairs_right": ["репортаж", "интервью", "объявление", "заголовок", "выпуск новостей"]}', '{"matches": {"כתבה": "репортаж", "כותרת": "заголовок", "מודעה": "объявление", "ראיון": "интервью", "מהדורה": "выпуск новостей"}}', '{"text": "Терминология израильских СМИ."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1788, 59, 'match_pairs', 2, '{"pairs_left": ["זיהום", "מיחזור", "אנרגיה סולארית", "מדבר", "השקיה"], "pairs_right": ["загрязнение", "рециклинг", "солнечная энергия", "пустыня", "орошение"]}', '{"matches": {"מדבר": "пустыня", "השקיה": "орошение", "זיהום": "загрязнение", "מיחזור": "рециклинг", "אנרגיה סולארית": "солнечная энергия"}}', '{"text": "Экологическая лексика — актуальная тема для Израиля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1798, 60, 'match_pairs', 2, '{"pairs_left": ["למרות הקשיים", "בגלל הגשם", "כדי להצליח", "על אף ההתנגדות"], "pairs_right": ["הם המשיכו לנסות", "הביטלו את המשחק", "צריך להתאמץ", "החוק אושר"]}', '{"matches": {"בגלל הגשם": "הביטלו את המשחק", "כדי להצליח": "צריך להתאמץ", "למרות הקשיים": "הם המשיכו לנסות", "על אף ההתנגדות": "החוק אושר"}}', '{"text": "Сложные предложения с разными типами связи."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1808, 137, 'match_pairs', 2, '{"pairs_left": ["לימד", "דיבר", "סיפר", "כיבד"], "pairs_right": ["הלמיד", "הדביר", "הספיר", "הכביד"]}', '{"matches": {"דיבר": "הדביר", "כיבד": "הכביד", "לימד": "הלמיד", "סיפר": "הספיר"}}', '{"text": "Пиэль — интенсив, Хифъиль — каузатив. Разные значения от одного корня."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1818, 138, 'match_pairs', 2, '{"pairs_left": ["התרחץ", "התכתבו", "התקשר", "התלבש"], "pairs_right": ["мылся (рефлексив)", "переписывались (взаимность)", "позвонил (идиоматическое)", "оделся (рефлексив)"]}', '{"matches": {"התלבש": "оделся (рефлексив)", "התקשר": "позвонил (идиоматическое)", "התרחץ": "мылся (рефлексив)", "התכתבו": "переписывались (взаимность)"}}', '{"text": "Хитпаэль — рефлексив, взаимность и идиоматические значения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1828, 139, 'match_pairs', 2, '{"pairs_left": ["אל + אני", "על + הוא", "מן + היא", "בין + אנחנו"], "pairs_right": ["אליי", "עליו", "ממנה", "בינינו"]}', '{"matches": {"אל + אני": "אליי", "מן + היא": "ממנה", "על + הוא": "עליו", "בין + אנחנו": "בינינו"}}', '{"text": "Склонение предлогов с местоимёнными суффиксами."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4075, 213, 'multiple_choice', 1, '{"options": ["Я вижу собаку", "У меня есть собака", "Я люблю собаку", "Я ищу собаку"], "question": "«יש לי כלב» — что это значит?"}', '{"correct": "У меня есть собака", "correct_index": 1}', '{"text": "יש לי = у меня есть"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1858, 142, 'match_pairs', 2, '{"pairs_left": ["כתב", "עורך", "טור דעה", "מהדורה"], "pairs_right": ["корреспондент", "редактор", "колонка мнений", "выпуск новостей"]}', '{"matches": {"כתב": "корреспондент", "עורך": "редактор", "מהדורה": "выпуск новостей", "טור דעה": "колонка мнений"}}', '{"text": "Терминология израильских СМИ."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1868, 143, 'match_pairs', 2, '{"pairs_left": ["שמחה", "עצב", "כעס", "פחד", "קנאה"], "pairs_right": ["радость", "грусть", "злость", "страх", "зависть"]}', '{"matches": {"כעס": "злость", "עצב": "грусть", "פחד": "страх", "קנאה": "зависть", "שמחה": "радость"}}', '{"text": "Базовые эмоции на иврите."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4100, 213, 'fill_blank', 1, '{"hint": "Глагол «петь» (ж.р.)", "sentence": "היא _____ שיר יפה"}', '{"accept": ["שרה"], "correct": "שרה"}', '{"text": "שרה = поёт (ж.р.)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1878, 144, 'match_pairs', 2, '{"pairs_left": ["הקמת המדינה", "מלחמת ששת הימים", "מלחמת יום הכיפורים", "הסכם אוסלו"], "pairs_right": ["1948", "1967", "1973", "1993"]}', '{"matches": {"הסכם אוסלו": "1993", "הקמת המדינה": "1948", "מלחמת ששת הימים": "1967", "מלחמת יום הכיפורים": "1973"}}', '{"text": "Ключевые даты в истории Израиля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1888, 145, 'match_pairs', 2, '{"pairs_left": ["מחקר", "השערה", "ממצאים", "מסקנות", "ביבליוגרפיה"], "pairs_right": ["исследование", "гипотеза", "результаты", "выводы", "библиография"]}', '{"matches": {"מחקר": "исследование", "השערה": "гипотеза", "ממצאים": "результаты", "מסקנות": "выводы", "ביבליוגרפיה": "библиография"}}', '{"text": "Структура научной статьи."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1898, 146, 'match_pairs', 2, '{"pairs_left": ["חשבונית", "הצעת מחיר", "רווח", "הפסד"], "pairs_right": ["счёт-фактура", "ценовое предложение", "прибыль", "убыток"]}', '{"matches": {"הפסד": "убыток", "רווח": "прибыль", "חשבונית": "счёт-фактура", "הצעת מחיר": "ценовое предложение"}}', '{"text": "Деловая терминология иврита."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4060, 213, 'multiple_choice', 1, '{"options": ["солнце", "дождь", "ветер", "снег"], "question": "Что означает слово «שמש»?"}', '{"correct": "солнце", "correct_index": 0}', '{"text": "שמש = солнце"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4061, 213, 'multiple_choice', 1, '{"options": ["מים", "חלב", "לחם", "גבינה"], "question": "Какое слово означает «молоко»?"}', '{"correct": "חלב", "correct_index": 1}', '{"text": "חלב = молоко"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4062, 213, 'multiple_choice', 1, '{"options": ["девочка", "мальчик", "мама", "папа"], "question": "Что значит «ילד»?"}', '{"correct": "мальчик", "correct_index": 1}', '{"text": "ילד = мальчик"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4063, 213, 'multiple_choice', 1, '{"options": ["אבא", "אמא", "אח", "כלב"], "question": "Какое слово НЕ относится к семье?"}', '{"correct": "כלב", "correct_index": 3}', '{"text": "כלב = собака, не член семьи"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4064, 213, 'multiple_choice', 1, '{"options": ["לחם", "גבינה", "תפוח", "שולחן"], "question": "Какое слово НЕ из группы «еда»?"}', '{"correct": "שולחן", "correct_index": 3}', '{"text": "שולחן = стол, а не еда"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4065, 213, 'multiple_choice', 1, '{"options": ["אדום", "כחול", "ירוק", "גדול"], "question": "Какое слово НЕ цвет?"}', '{"correct": "גדול", "correct_index": 3}', '{"text": "גדול = большой, а не цвет"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4066, 213, 'multiple_choice', 1, '{"options": ["סוכר", "מלח", "פלפל", "ספר"], "question": "Какое слово лишнее? סוכר, מלח, פלפל, ספר"}', '{"correct": "ספר", "correct_index": 3}', '{"text": "ספר = книга, остальные — приправы"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4067, 213, 'multiple_choice', 1, '{"options": ["спокойной ночи", "добрый вечер", "доброе утро", "до свидания"], "question": "Что означает «בוקר טוב»?"}', '{"correct": "доброе утро", "correct_index": 2}', '{"text": "בוקר טוב = доброе утро"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4068, 213, 'multiple_choice', 1, '{"options": ["Как тебя зовут?", "Как дела?", "Откуда ты?", "Сколько тебе лет?"], "question": "Что значит «מה שלומך»?"}', '{"correct": "Как дела?", "correct_index": 1}', '{"text": "מה שלומך = Как дела?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4069, 213, 'multiple_choice', 1, '{"options": ["שלום", "בבקשה", "סליחה", "כן"], "question": "Как ответить на «תודה»?"}', '{"correct": "בבקשה", "correct_index": 1}', '{"text": "בבקשה = пожалуйста (в ответ на спасибо)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4070, 213, 'multiple_choice', 1, '{"options": ["שותה", "כותב", "קורא", "ישן"], "question": "Какое слово подходит? «אני _____ מים»"}', '{"correct": "שותה", "correct_index": 0}', '{"text": "שותה = пью → Я пью воду"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4071, 213, 'multiple_choice', 1, '{"options": ["קוראת", "שותה", "אוכלת", "ישנה"], "question": "Какое слово подходит? «היא _____ ספר»"}', '{"correct": "קוראת", "correct_index": 0}', '{"text": "קוראת = читает (ж.р.)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4072, 213, 'multiple_choice', 1, '{"options": ["משחקים", "ישנים", "כותבים", "שותים"], "question": "Какое слово подходит? «הילדים _____ בחצר»"}', '{"correct": "משחקים", "correct_index": 0}', '{"text": "משחקים = играют"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4073, 213, 'multiple_choice', 1, '{"options": ["גרים", "כותבים", "שרים", "רצים"], "question": "Какое слово подходит? «אנחנו _____ בבית»"}', '{"correct": "גרים", "correct_index": 0}', '{"text": "גרים = живём"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4074, 213, 'multiple_choice', 1, '{"options": ["Я работаю в Тель-Авиве", "Я живу в Тель-Авиве", "Я учусь в Тель-Авиве", "Я родился в Тель-Авиве"], "question": "«אני גר בתל אביב» — что это значит?"}', '{"correct": "Я живу в Тель-Авиве", "correct_index": 1}', '{"text": "גר = живу"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4113, 213, 'fill_blank', 1, '{"hint": "Прилагательное «большой»", "sentence": "הבית _____ שלי"}', '{"accept": ["גדול", "הגדול"], "correct": "גדול"}', '{"text": "גדול = большой"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4085, 213, 'multiple_choice', 1, '{"options": ["в доме", "на доме", "рядом с домом", "за домом"], "question": "«הכלב ליד הבית» — где собака?"}', '{"correct": "рядом с домом", "correct_index": 2}', '{"text": "ליד הבית = рядом с домом"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4086, 213, 'multiple_choice', 1, '{"options": ["לבית הספר", "בבית הספר", "מבית הספר", "על בית הספר"], "question": "Как сказать «в школе»?"}', '{"correct": "בבית הספר", "correct_index": 1}', '{"text": "בבית הספר = в школе (ב + בית הספר)"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4087, 213, 'multiple_choice', 1, '{"options": ["ב", "ל", "מ", "על"], "question": "Какой предлог означает «из»?"}', '{"correct": "מ", "correct_index": 2}', '{"text": "מ = из"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4127, 213, 'match_pairs', 1, '{"pairs_left": ["שלום", "תודה", "סליחה", "בבקשה"], "pairs_right": ["привет", "спасибо", "извините", "пожалуйста"]}', '{"matches": {"שלום": "привет", "תודה": "спасибо", "בבקשה": "пожалуйста", "סליחה": "извините"}}', '{"text": "Основные вежливые слова"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4128, 213, 'match_pairs', 1, '{"pairs_left": ["אבא", "אמא", "אח", "אחות"], "pairs_right": ["папа", "мама", "брат", "сестра"]}', '{"matches": {"אח": "брат", "אבא": "папа", "אמא": "мама", "אחות": "сестра"}}', '{"text": "Члены семьи"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4129, 213, 'match_pairs', 1, '{"pairs_left": ["כלב", "חתול", "ציפור", "דג"], "pairs_right": ["собака", "кот", "птица", "рыба"]}', '{"matches": {"דג": "рыба", "כלב": "собака", "חתול": "кот", "ציפור": "птица"}}', '{"text": "Животные"}', 10);
