INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4168, 214, 'multiple_choice', 2, '{"options": ["вчера", "сегодня", "завтра", "послезавтра"], "question": "Что значит «מחר»?"}', '{"correct": "завтра", "correct_index": 2}', '{"text": "מחר = завтра"}', 10);
