INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4237, 214, 'match_pairs', 2, '{"pairs_left": ["ראש", "בטן", "גרון", "גב"], "pairs_right": ["голова", "живот", "горло", "спина"]}', '{"matches": {"גב": "спина", "בטן": "живот", "ראש": "голова", "גרון": "горло"}}', '{"text": "Здоровье: части тела"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4238, 214, 'match_pairs', 2, '{"pairs_left": ["כאב", "חום", "שיעול", "הצטננות"], "pairs_right": ["боль", "температура", "кашель", "простуда"]}', '{"matches": {"חום": "температура", "כאב": "боль", "שיעול": "кашель", "הצטננות": "простуда"}}', '{"text": "Здоровье: симптомы"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4239, 214, 'match_pairs', 2, '{"pairs_left": ["ארוחת בוקר", "ארוחת צהריים", "ארוחת ערב", "חטיף"], "pairs_right": ["завтрак", "обед", "ужин", "перекус"]}', '{"matches": {"חטיף": "перекус", "ארוחת ערב": "ужин", "ארוחת בוקר": "завтрак", "ארוחת צהריים": "обед"}}', '{"text": "Приёмы пищи"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4240, 214, 'match_pairs', 2, '{"pairs_left": ["כתב", "כתיבה", "מכתב", "כתבה"], "pairs_right": ["написал", "письмо (процесс)", "письмо", "статья/заметка"]}', '{"matches": {"כתב": "написал", "כתבה": "статья/заметка", "מכתב": "письмо", "כתיבה": "письмо (процесс)"}}', '{"text": "Корень כ.ת.ב — семья слов"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4242, 214, 'match_pairs', 2, '{"pairs_left": ["ספר", "ספרייה", "סופר", "סיפור"], "pairs_right": ["книга", "библиотека", "автор", "рассказ"]}', '{"matches": {"ספר": "книга", "סופר": "автор", "סיפור": "рассказ", "ספרייה": "библиотека"}}', '{"text": "Корень ס.פ.ר — семья слов"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4243, 214, 'match_pairs', 2, '{"pairs_left": ["עבד", "עבודה", "עובד", "מעביד"], "pairs_right": ["работал", "работа", "работник", "работодатель"]}', '{"matches": {"עבד": "работал", "עובד": "работник", "מעביד": "работодатель", "עבודה": "работа"}}', '{"text": "Корень ע.ב.ד — семья слов"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4244, 214, 'word_order', 2, '{"translation": "Вчера мы ходили в кино", "words_shuffled": ["לקולנוע", "אתמול", "הלכנו"], "correct_sentence": "אתמול הלכנו לקולנוע"}', '{"correct_order": ["אתמול", "הלכנו", "לקולנוע"]}', '{"text": "Время + подлежащее + глагол + место"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4264, 215, 'multiple_choice', 3, '{"options": ["болит голова", "ломать стену", "думать усердно", "злиться"], "question": "Что означает идиома «לשבור את הראש»?"}', '{"correct": "думать усердно", "correct_index": 2}', '{"text": "לשבור את הראש = ломать голову = усердно думать"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4246, 214, 'word_order', 2, '{"translation": "Завтра мы пойдём на море", "words_shuffled": ["מחר", "נלך", "לים", "אנחנו"], "correct_sentence": "מחר אנחנו נלך לים"}', '{"correct_order": ["מחר", "אנחנו", "נלך", "לים"]}', '{"text": "Время + подлежащее + глагол + место"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4247, 214, 'word_order', 2, '{"translation": "Мне нужно купить молоко", "words_shuffled": ["צריך", "אני", "חלב", "לקנות"], "correct_sentence": "אני צריך לקנות חלב"}', '{"correct_order": ["אני", "צריך", "לקנות", "חלב"]}', '{"text": "Подлежащее + צריך + инфинитив + дополнение"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4250, 214, 'word_order', 2, '{"translation": "Мой сосед очень приятный", "words_shuffled": ["שלי", "השכן", "נחמד", "מאוד"], "correct_sentence": "השכן שלי מאוד נחמד"}', '{"correct_order": ["השכן", "שלי", "מאוד", "נחמד"]}', '{"text": "Подлежащее + שלי + מאוד + прилагательное"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4252, 214, 'word_order', 2, '{"translation": "Он разговаривает по телефону с мамой", "words_shuffled": ["מדבר", "הוא", "בטלפון", "עם", "אמא"], "correct_sentence": "הוא מדבר בטלפון עם אמא"}', '{"correct_order": ["הוא", "מדבר", "בטלפון", "עם", "אמא"]}', '{"text": "Подлежащее + глагол + בטלפון + עם + дополнение"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4253, 214, 'word_order', 2, '{"translation": "Фильм был очень скучным", "words_shuffled": ["הסרט", "משעמם", "היה", "מאוד"], "correct_sentence": "הסרט היה משעמם מאוד"}', '{"correct_order": ["הסרט", "היה", "משעמם", "מאוד"]}', '{"text": "Подлежащее + היה + прилагательное + מאוד"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4254, 214, 'word_order', 2, '{"translation": "Я купила новую рубашку", "words_shuffled": ["קניתי", "חולצה", "חדשה", "אני"], "correct_sentence": "אני קניתי חולצה חדשה"}', '{"correct_order": ["אני", "קניתי", "חולצה", "חדשה"]}', '{"text": "Подлежащее + глагол + дополнение + прилагательное"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4255, 214, 'word_order', 2, '{"translation": "Я хочу приготовить еду", "words_shuffled": ["להכין", "ארוחה", "אני", "רוצה"], "correct_sentence": "אני רוצה להכין ארוחה"}', '{"correct_order": ["אני", "רוצה", "להכין", "ארוחה"]}', '{"text": "Подлежащее + רוצה + инфинитив + дополнение"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4256, 214, 'word_order', 2, '{"translation": "Сколько стоит эта квартира?", "words_shuffled": ["כמה", "הדירה", "עולה", "הזאת"], "correct_sentence": "כמה עולה הדירה הזאת"}', '{"correct_order": ["כמה", "עולה", "הדירה", "הזאת"]}', '{"text": "כמה + глагол + подлежащее + указательное"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4257, 214, 'word_order', 2, '{"translation": "Почему ты не пришёл вчера?", "words_shuffled": ["למה", "לא", "באת", "אתמול"], "correct_sentence": "למה לא באת אתמול"}', '{"correct_order": ["למה", "לא", "באת", "אתמול"]}', '{"text": "למה + отрицание + глагол + время"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4258, 214, 'word_order', 2, '{"translation": "Я встретил старого друга на улице", "words_shuffled": ["פגשתי", "ישן", "חבר", "ברחוב"], "correct_sentence": "פגשתי חבר ישן ברחוב"}', '{"correct_order": ["פגשתי", "חבר", "ישן", "ברחוב"]}', '{"text": "Глагол + дополнение + прилагательное + место"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4259, 214, 'word_order', 2, '{"translation": "Еда здесь вкуснее", "words_shuffled": ["טעים", "יותר", "האוכל", "פה"], "correct_sentence": "האוכל פה טעים יותר"}', '{"correct_order": ["האוכל", "פה", "טעים", "יותר"]}', '{"text": "Подлежащее + место + прилагательное + יותר"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4260, 215, 'multiple_choice', 3, '{"options": ["Пааль", "Пиэль", "Хифъиль", "Хитпаэль"], "question": "Какой биньян у глагола «להתלבש» (одеваться)?"}', '{"correct": "Хитпаэль", "correct_index": 3}', '{"text": "התלבש — Хитпаэль (возвратное действие)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4261, 215, 'multiple_choice', 3, '{"options": ["Пааль", "Нифъаль", "Пиэль", "Хифъиль"], "question": "Какой биньян у «נכתב» (был написан)?"}', '{"correct": "Нифъаль", "correct_index": 1}', '{"text": "נכתב — Нифъаль (пассив)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4262, 215, 'multiple_choice', 3, '{"options": ["Пааль", "Пиэль", "Хифъиль", "Нифъаль"], "question": "Какой биньян у «הסביר» (объяснил)?"}', '{"correct": "Хифъиль", "correct_index": 2}', '{"text": "הסביר — Хифъиль (каузатив)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4263, 215, 'multiple_choice', 3, '{"options": ["Пааль", "Пиэль", "Хифъиль", "Хитпаэль"], "question": "Какой биньян у «לימד» (преподавал)?"}', '{"correct": "Пиэль", "correct_index": 1}', '{"text": "לימד — Пиэль (интенсив/каузатив)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4265, 215, 'multiple_choice', 3, '{"options": ["ставить сердце", "обратить внимание", "влюбиться", "сердиться"], "question": "Что означает «לשים לב»?"}', '{"correct": "обратить внимание", "correct_index": 1}', '{"text": "לשים לב = обратить внимание (букв. положить сердце)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4266, 215, 'multiple_choice', 3, '{"options": ["жаль времени", "потрясающе", "скучно", "поздно"], "question": "Что означает «חבל על הזמן»?"}', '{"correct": "потрясающе", "correct_index": 1}', '{"text": "חבל על הזמן = потрясающе (разг.) или жаль времени"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4267, 215, 'multiple_choice', 3, '{"options": ["зарабатывать", "веселиться", "жить", "работать"], "question": "Что означает «לעשות חיים»?"}', '{"correct": "веселиться", "correct_index": 1}', '{"text": "לעשות חיים = веселиться, хорошо проводить время"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4268, 215, 'multiple_choice', 3, '{"options": ["חפץ", "מעוניין", "בא לי", "מתחשק"], "question": "Какое слово лучше подходит в формальном письме вместо «רוצה»?"}', '{"correct": "מעוניין", "correct_index": 1}', '{"text": "מעוניין — формальный аналог רוצה"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4269, 215, 'multiple_choice', 3, '{"options": ["מצוין", "נהדר", "אחלה", "מעולה"], "question": "Какое слово разговорное (сленг) для «отлично»?"}', '{"correct": "אחלה", "correct_index": 2}', '{"text": "אחלה — разговорное (из арабского)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4270, 215, 'multiple_choice', 3, '{"options": ["наконец", "тем временем", "вместо", "поэтому"], "question": "Что означает «בינתיים»?"}', '{"correct": "тем временем", "correct_index": 1}', '{"text": "בינתיים = тем временем / пока"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4271, 215, 'multiple_choice', 3, '{"options": ["потому что", "несмотря на", "поэтому", "если"], "question": "Что означает «למרות»?"}', '{"correct": "несмотря на", "correct_index": 1}', '{"text": "למרות = несмотря на"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4272, 215, 'multiple_choice', 3, '{"options": ["обязательно", "именно / как раз наоборот", "абсолютно", "конечно"], "question": "Что означает «דווקא»?"}', '{"correct": "именно / как раз наоборот", "correct_index": 1}', '{"text": "דווקא = именно, как раз (часто с оттенком противоречия)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4273, 215, 'multiple_choice', 3, '{"options": ["פתח", "סגר", "החזיק", "שבר"], "question": "Какое слово подходит? «הוא _____ את הדלת בפני הזקנה»"}', '{"correct": "החזיק", "correct_index": 2}', '{"text": "החזיק = придержал (дверь) — вежливый жест"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4274, 215, 'multiple_choice', 3, '{"options": ["להתלונן", "להתפלל", "להתרגז", "להתעמל"], "question": "Какой глагол значит «жаловаться»?"}', '{"correct": "להתלונן", "correct_index": 0}', '{"text": "להתלונן = жаловаться (Хитпаэль)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4275, 215, 'multiple_choice', 3, '{"options": ["ругаться", "добровольствовать", "соревноваться", "жаловаться"], "question": "Что означает «להתנדב»?"}', '{"correct": "добровольствовать", "correct_index": 1}', '{"text": "להתנדב = быть волонтёром"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4276, 215, 'multiple_choice', 3, '{"options": ["ישיבה", "ישיבת", "שיבה", "ישובה"], "question": "Какое слово означает «собрание/заседание»?"}', '{"correct": "ישיבה", "correct_index": 0}', '{"text": "ישיבה = заседание/собрание (а также ешива)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4277, 215, 'multiple_choice', 3, '{"options": ["переезд", "переговоры", "перевод", "пересмотр"], "question": "Что означает «משא ומתן»?"}', '{"correct": "переговоры", "correct_index": 1}', '{"text": "משא ומתן = переговоры (букв. груз и дар)"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4278, 215, 'multiple_choice', 3, '{"options": ["расписание", "бюджет", "налог", "скидка"], "question": "Что означает «תקציב»?"}', '{"correct": "бюджет", "correct_index": 1}', '{"text": "תקציב = бюджет"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4279, 215, 'multiple_choice', 3, '{"options": ["כבר אני הולך", "אני כבר סיימתי", "כבר בוקר טוב", "שלום כבר"], "question": "В каком предложении «כבר» используется правильно?"}', '{"correct": "אני כבר סיימתי", "correct_index": 1}', '{"text": "כבר = уже → «Я уже закончил»"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4280, 215, 'multiple_choice', 3, '{"options": ["עדיין אתמול", "הוא עדיין לא הגיע", "עדיין שלום", "תודה עדיין"], "question": "В каком предложении «עדיין» используется правильно?"}', '{"correct": "הוא עדיין לא הגיע", "correct_index": 1}', '{"text": "עדיין = ещё / до сих пор"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4281, 215, 'multiple_choice', 3, '{"options": ["כי", "אם", "לכן", "אבל"], "question": "Какой союз означает «поэтому»?"}', '{"correct": "לכן", "correct_index": 2}', '{"text": "לכן = поэтому"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4282, 215, 'multiple_choice', 3, '{"options": ["למרות ש", "בגלל ש", "כדי ש", "עד ש"], "question": "Какой союз означает «хотя»?"}', '{"correct": "למרות ש", "correct_index": 0}', '{"text": "למרות ש = хотя / несмотря на то что"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4283, 215, 'multiple_choice', 3, '{"options": ["провал", "успех", "предложение", "решение"], "question": "Что означает «הצלחה»?"}', '{"correct": "успех", "correct_index": 1}', '{"text": "הצלחה = успех"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4284, 215, 'multiple_choice', 3, '{"options": ["победа", "успех", "провал", "попытка"], "question": "Что означает «כישלון»?"}', '{"correct": "провал", "correct_index": 2}', '{"text": "כישלון = провал/неудача"}', 15);
