INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4360, 216, 'multiple_choice', 4, '{"options": ["рассказ", "исследование", "эксперимент", "гипотеза"], "question": "Что означает «מחקר»?"}', '{"correct": "исследование", "correct_index": 1}', '{"text": "מחקר = исследование"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4344, 215, 'word_order', 3, '{"translation": "Он преуспел несмотря на трудности", "words_shuffled": ["הצליח", "למרות", "הקשיים", "הוא"], "correct_sentence": "הוא הצליח למרות הקשיים"}', '{"correct_order": ["הוא", "הצליח", "למרות", "הקשיים"]}', '{"text": "Подлежащее + глагол + למרות + дополнение"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4346, 215, 'word_order', 3, '{"translation": "Новый закон был утверждён в Кнессете", "words_shuffled": ["החוק", "החדש", "אושר", "בכנסת"], "correct_sentence": "החוק החדש אושר בכנסת"}', '{"correct_order": ["החוק", "החדש", "אושר", "בכנסת"]}', '{"text": "Подлежащее + прилагательное + глагол (пассив) + место"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4347, 215, 'word_order', 3, '{"translation": "Несмотря на дождь, мы вышли на прогулку", "words_shuffled": ["שירד", "גשם", "למרות", "יצאנו", "לטיול"], "correct_sentence": "למרות שירד גשם יצאנו לטיול"}', '{"correct_order": ["למרות", "שירד", "גשם", "יצאנו", "לטיול"]}', '{"text": "למרות ש + условие + действие"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4348, 215, 'word_order', 3, '{"translation": "Лекция была особенно интересной", "words_shuffled": ["ההרצאה", "הייתה", "מעניינת", "במיוחד"], "correct_sentence": "ההרצאה הייתה מעניינת במיוחד"}', '{"correct_order": ["ההרצאה", "הייתה", "מעניינת", "במיוחד"]}', '{"text": "Подлежащее + הייתה + прилагательное + наречие"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4349, 215, 'word_order', 3, '{"translation": "Директор выразил возражение против предложения", "words_shuffled": ["הביע", "המנהל", "התנגדות", "להצעה"], "correct_sentence": "המנהל הביע התנגדות להצעה"}', '{"correct_order": ["המנהל", "הביע", "התנגדות", "להצעה"]}', '{"text": "Подлежащее + глагол + дополнение + ל + предмет"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4350, 215, 'word_order', 3, '{"translation": "Многие жители возражали против плана", "words_shuffled": ["תושבים", "רבים", "התנגדו", "לתוכנית"], "correct_sentence": "תושבים רבים התנגדו לתוכנית"}', '{"correct_order": ["תושבים", "רבים", "התנגדו", "לתוכנית"]}', '{"text": "Подлежащее + прилагательное + глагол + ל + предмет"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4351, 215, 'word_order', 3, '{"translation": "Из-за экономической ситуации закрылись магазины", "words_shuffled": ["בגלל", "המצב", "הכלכלי", "נסגרו", "חנויות"], "correct_sentence": "בגלל המצב הכלכלי נסגרו חנויות"}', '{"correct_order": ["בגלל", "המצב", "הכלכלי", "נסגרו", "חנויות"]}', '{"text": "בגלל + причина + результат"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4352, 215, 'word_order', 3, '{"translation": "Каждый год в городе проходит фестиваль", "words_shuffled": ["כל", "שנה", "מתקיים", "פסטיבל", "בעיר"], "correct_sentence": "כל שנה מתקיים פסטיבל בעיר"}', '{"correct_order": ["כל", "שנה", "מתקיים", "פסטיבל", "בעיר"]}', '{"text": "Время + глагол + подлежащее + место"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4354, 215, 'word_order', 3, '{"translation": "Чем больше проходит времени, тем лучше ситуация", "words_shuffled": ["ככל", "שעובר", "הזמן", "המצב", "משתפר"], "correct_sentence": "ככל שעובר הזמן המצב משתפר"}', '{"correct_order": ["ככל", "שעובר", "הזמן", "המצב", "משתפר"]}', '{"text": "ככל ש + условие + результат"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4355, 215, 'word_order', 3, '{"translation": "По-моему, нужно изменить закон", "words_shuffled": ["לדעתי", "צריך", "לשנות", "את", "החוק"], "correct_sentence": "לדעתי צריך לשנות את החוק"}', '{"correct_order": ["לדעתי", "צריך", "לשנות", "את", "החוק"]}', '{"text": "לדעתי + צריך + инфинитив + дополнение"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4356, 215, 'word_order', 3, '{"translation": "Я бы предпочёл остаться дома сегодня", "words_shuffled": ["הייתי", "מעדיף", "להישאר", "בבית", "היום"], "correct_sentence": "הייתי מעדיף להישאר בבית היום"}', '{"correct_order": ["הייתי", "מעדיף", "להישאר", "בבית", "היום"]}', '{"text": "Условное + инфинитив + место + время"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4357, 215, 'word_order', 3, '{"translation": "Он предложил творческое решение проблемы", "words_shuffled": ["הציע", "הוא", "פתרון", "יצירתי", "לבעיה"], "correct_sentence": "הוא הציע פתרון יצירתי לבעיה"}', '{"correct_order": ["הוא", "הציע", "פתרון", "יצירתי", "לבעיה"]}', '{"text": "Подлежащее + глагол + дополнение + прилагательное + ל"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4358, 215, 'word_order', 3, '{"translation": "Мне кажется, что он прав", "words_shuffled": ["נראה", "לי", "שהוא", "צודק"], "correct_sentence": "נראה לי שהוא צודק"}', '{"correct_order": ["נראה", "לי", "שהוא", "צודק"]}', '{"text": "נראה לי + ש + придаточное"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4361, 216, 'multiple_choice', 4, '{"options": ["вывод", "находка/результат", "гипотеза", "метод"], "question": "Что означает «ממצא»?"}', '{"correct": "находка/результат", "correct_index": 1}', '{"text": "ממצא = находка/результат (исследования)"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4362, 216, 'multiple_choice', 4, '{"options": ["заключение", "доказательство", "гипотеза/предположение", "факт"], "question": "Что означает «השערה»?"}', '{"correct": "гипотеза/предположение", "correct_index": 2}', '{"text": "השערה = гипотеза/предположение"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4363, 216, 'multiple_choice', 4, '{"options": ["теория", "явление", "причина", "следствие"], "question": "Что означает «תופעה»?"}', '{"correct": "явление", "correct_index": 1}', '{"text": "תופעה = явление"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4364, 216, 'multiple_choice', 4, '{"options": ["опрос", "лекция", "статья", "библиография"], "question": "Что означает «סקר»?"}', '{"correct": "опрос", "correct_index": 0}', '{"text": "סקר = опрос/обзор"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4365, 216, 'multiple_choice', 4, '{"options": ["описывать", "анализировать", "обобщать", "сравнивать"], "question": "Что означает глагол «לנתח»?"}', '{"correct": "анализировать", "correct_index": 1}', '{"text": "לנתח = анализировать (а также оперировать)"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4367, 216, 'multiple_choice', 4, '{"options": ["הוא עלול להצליח", "הוא עלול להיכשל", "הוא עלול לאכול", "הוא עלול לישון"], "question": "В каком предложении «עלול» используется правильно?"}', '{"correct": "הוא עלול להיכשל", "correct_index": 1}', '{"text": "עלול = может (с негативным оттенком) → опасность провала"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4368, 216, 'multiple_choice', 4, '{"options": ["синонимы", "עשוי — нейтральный, עלול — негативный", "עלול — нейтральный, עשוי — негативный", "нет различия"], "question": "Чем «עשוי» отличается от «עלול»?"}', '{"correct": "עשוי — нейтральный, עלול — негативный", "correct_index": 1}', '{"text": "עשוי = может (нейтрально), עלול = может (опасность)"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4369, 216, 'multiple_choice', 4, '{"options": ["לטעון", "לשאול", "לחשוב", "להאמין"], "question": "Какой глагол означает «утверждать/заявлять»?"}', '{"correct": "לטעון", "correct_index": 0}', '{"text": "לטעון = утверждать/заявлять (формально)"}', 20);
