INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4371, 216, 'multiple_choice', 4, '{"options": ["אולם", "יתרה מזאת", "מאידך", "לפיכך"], "question": "Какое слово означает «более того»?"}', '{"correct": "יתרה מזאת", "correct_index": 1}', '{"text": "יתרה מזאת = более того"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4372, 216, 'multiple_choice', 4, '{"options": ["מאידך", "לפיכך", "כמו כן", "בנוסף"], "question": "Какое слово означает «с другой стороны»?"}', '{"correct": "מאידך", "correct_index": 0}', '{"text": "מאידך = с другой стороны"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4373, 216, 'multiple_choice', 4, '{"options": ["однако", "поэтому/следовательно", "кроме того", "напротив"], "question": "Что означает «לפיכך»?"}', '{"correct": "поэтому/следовательно", "correct_index": 1}', '{"text": "לפיכך = поэтому/следовательно (формальное)"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4374, 216, 'multiple_choice', 4, '{"options": ["запрещено", "нужно", "можно/возможно", "следует"], "question": "Что означает «ניתן»?"}', '{"correct": "можно/возможно", "correct_index": 2}', '{"text": "ניתן = можно, возможно (безличная форма)"}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4375, 216, 'multiple_choice', 4, '{"options": ["רוצה", "יש", "יש צורך", "בא לי"], "question": "Какой формальный синоним слова «צריך»?"}', '{"correct": "יש צורך", "correct_index": 2}', '{"text": "יש צורך = необходимо (формальнее צריך)"}', 20);
