INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4378, 216, 'multiple_choice', 4, '{"options": ["кстати", "например", "то есть", "в итоге"], "question": "В каком контексте используется «אגב»?"}', '{"correct": "кстати", "correct_index": 0}', '{"text": "אגב = кстати / между прочим"}', 20);
