INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4558, 217, 'word_order', 5, '{"translation": "Историк оспаривает общепринятые предположения", "words_shuffled": ["ההיסטוריון", "מאתגר", "המקובלות", "את", "ההנחות"], "correct_sentence": "ההיסטוריון מאתגר את ההנחות המקובלות"}', '{"correct_order": ["ההיסטוריון", "מאתגר", "את", "ההנחות", "המקובלות"]}', '{"text": "Подлежащее + глагол + את + дополнение + прилагательное"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4559, 217, 'word_order', 5, '{"translation": "Статья выносит вопрос идентичности на повестку дня", "words_shuffled": ["היום", "סדר", "על", "הזהות", "שאלת", "את", "המאמר", "מעלה"], "correct_sentence": "המאמר מעלה את שאלת הזהות על סדר היום"}', '{"correct_order": ["המאמר", "מעלה", "את", "שאלת", "הזהות", "על", "סדר", "היום"]}', '{"text": "Подлежащее + глагол + את + дополнение + על סדר היום"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4560, 218, 'multiple_choice', 6, '{"options": ["закон", "тематический отрывок Талмуда", "молитва", "комментарий"], "question": "Что означает талмудический термин «סוגיא»?"}', '{"correct": "тематический отрывок Талмуда", "correct_index": 1}', '{"text": "סוגיא = сугья — тематический отрывок/дискуссия в Талмуде"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4561, 218, 'multiple_choice', 6, '{"options": ["согласие", "диспут/разногласие мудрецов", "запрет", "обычай"], "question": "Что означает «מחלוקת» в контексте Талмуда?"}', '{"correct": "диспут/разногласие мудрецов", "correct_index": 1}', '{"text": "מחלוקת = диспут/разногласие между мудрецами"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4562, 218, 'multiple_choice', 6, '{"options": ["мудрец Мишны", "мудрец Талмуда", "пророк", "священник"], "question": "Что означает арамейское выражение «תנא»?"}', '{"correct": "мудрец Мишны", "correct_index": 0}', '{"text": "תנא = тана — мудрец эпохи Мишны"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4563, 218, 'multiple_choice', 6, '{"options": ["мудрец Мишны", "мудрец Гемары/Талмуда", "комментатор", "законодатель"], "question": "Что означает «אמורא»?"}', '{"correct": "мудрец Гемары/Талмуда", "correct_index": 1}', '{"text": "אמורא = амора — мудрец эпохи Гемары"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4564, 218, 'multiple_choice', 6, '{"options": ["притча", "религиозный закон", "молитва", "мидраш"], "question": "Что означает «הלכה»?"}', '{"correct": "религиозный закон", "correct_index": 1}', '{"text": "הלכה = галаха — еврейский религиозный закон"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4565, 218, 'multiple_choice', 6, '{"options": ["закон", "нарративная/гомилетическая часть", "комментарий", "философия"], "question": "Что означает «אגדה» в раввинистической литературе?"}', '{"correct": "нарративная/гомилетическая часть", "correct_index": 1}', '{"text": "אגדה = агада — нарративная часть (притчи, проповеди)"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4566, 218, 'multiple_choice', 6, '{"options": ["вот/вдруг", "здесь", "ибо", "ещё"], "question": "Что означает библейское «הנה»?"}', '{"correct": "вот/вдруг", "correct_index": 0}', '{"text": "הנה = вот, се (библейская частица)"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4567, 218, 'multiple_choice', 6, '{"options": ["только «потому что»", "потому что / что / когда / хотя", "только «что»", "только «когда»"], "question": "Что означает библейское «כי»?"}', '{"correct": "потому что / что / когда / хотя", "correct_index": 1}', '{"text": "כי — многозначная частица: потому что, что, когда, хотя, ведь"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4605, 218, 'fill_blank', 6, '{"hint": "Глагол «предлагать (толкование)»", "sentence": "הפרשן _____ משמעות אלטרנטיבית לפסוק"}', '{"accept": ["מציע"], "correct": "מציע"}', '{"text": "מציע = предлагает"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4569, 218, 'multiple_choice', 6, '{"options": ["будущее + вав", "прошедшее + вав (вав-перевертыш)", "повелительное", "причастие"], "question": "Какая форма у библейского «ותאמר»?"}', '{"correct": "прошедшее + вав (вав-перевертыш)", "correct_index": 1}', '{"text": "ותאמר = вав-хиппух + имперфект = прошедшее (и сказала)"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4570, 218, 'multiple_choice', 6, '{"options": ["и будет", "и было", "будет", "бывает"], "question": "Что означает библейское «ויהי»?"}', '{"correct": "и было", "correct_index": 1}', '{"text": "ויהי = и было (вав-хиппух + имперфект от היה)"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4571, 218, 'multiple_choice', 6, '{"options": ["который/что", "если", "когда", "где"], "question": "Что означает архаичное «אשר»?"}', '{"correct": "который/что", "correct_index": 0}', '{"text": "אשר = который, что (относительная частица, арх.)"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4613, 218, 'fill_blank', 6, '{"hint": "Глагол «передаваться»", "sentence": "המסורת _____ מדור לדור"}', '{"accept": ["נמסרת", "עוברת"], "correct": "נמסרת"}', '{"text": "נמסרת = передаётся"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4572, 218, 'multiple_choice', 6, '{"options": ["потому что / из-за того что", "после того как", "перед тем как", "для того чтобы"], "question": "Как звучит библейская конструкция причины с «יען»?"}', '{"correct": "потому что / из-за того что", "correct_index": 0}', '{"text": "יען = потому что (библейский союз)"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4573, 218, 'multiple_choice', 6, '{"options": ["лингвистика", "философия языка", "грамматика", "риторика"], "question": "Что означает «פילוסופיה של הלשון»?"}', '{"correct": "философия языка", "correct_index": 1}', '{"text": "פילוסופיה של הלשון = философия языка"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4574, 218, 'multiple_choice', 6, '{"options": ["феноменология", "герменевтика", "семиотика", "прагматика"], "question": "Что означает «פנומנולוגיה»?"}', '{"correct": "феноменология", "correct_index": 0}', '{"text": "פנומנולוגיה = феноменология (учение о явлениях сознания)"}', 30);
