INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4601, 218, 'fill_blank', 6, '{"hint": "Талмудическое «что это значит?»", "sentence": "מאי _____? אמר רב"}', '{"accept": ["טעמא"], "correct": "טעמא"}', '{"text": "מאי טעמא = какова причина? (арамейское)"}', 30);
