INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4603, 218, 'fill_blank', 6, '{"hint": "Талмудическая формула «это... а это...»", "sentence": "הא _____ הא — противопоставление в Талмуде"}', '{"accept": ["לא קשיא"], "correct": "לא קשיא"}', '{"text": "לא קשיא הא... הא... = нет противоречия: это... а это..."}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4604, 218, 'fill_blank', 6, '{"hint": "Глагол «формулировать» (юрид.)", "sentence": "המשנה _____ את הדין בצמצום"}', '{"accept": ["מנסחת"], "correct": "מנסחת"}', '{"text": "מנסחת = формулирует"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4607, 218, 'fill_blank', 6, '{"hint": "Глагол «отличаться/характеризоваться»", "sentence": "הסוגיה _____ מורכבות רבה"}', '{"accept": ["מאופיינת", "רוויה"], "correct": "מאופיינת"}', '{"text": "מאופיינת ב = характеризуется"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4608, 218, 'fill_blank', 6, '{"hint": "«Этот вопрос» (формально)", "sentence": "_____ נדון בהרחבה בספרות המחקר"}', '{"accept": ["נושא זה", "הנושא"], "correct": "נושא זה"}', '{"text": "נושא זה = этот вопрос/тема"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4609, 218, 'fill_blank', 6, '{"hint": "Глагол «раздвигать/оспаривать»", "sentence": "היצירה _____ את גבולות הז''אנר"}', '{"accept": ["מערערת על", "מרחיבה"], "correct": "מערערת על"}', '{"text": "מערערת על = оспаривает, подрывает"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4610, 218, 'fill_blank', 6, '{"hint": "«В основе» (формальное)", "sentence": "_____ מונחת ההנחה כי השפה מעצבת מציאות"}', '{"accept": ["ביסוד", "בבסיס"], "correct": "ביסוד"}', '{"text": "ביסוד = в основе"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4614, 218, 'fill_blank', 6, '{"hint": "«Дискурс» — определение", "sentence": "_____ הוא מערכת הביטויים הלשוניים של תרבות"}', '{"accept": ["דיסקורס"], "correct": "דיסקורס"}', '{"text": "דיסקורס = дискурс"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4615, 218, 'fill_blank', 6, '{"hint": "Глагол «покоиться/основываться»", "sentence": "הטיעון _____ על אדני ההיגיון הפורמלי"}', '{"accept": ["עומד", "נשען"], "correct": "עומד"}', '{"text": "עומד על = покоится на/основывается на"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4616, 218, 'fill_blank', 6, '{"hint": "«Суть/корень»", "sentence": "ה_____ של המחלוקת הוא מהותי ולא טכני"}', '{"accept": ["שורש", "ליבה"], "correct": "שורש"}', '{"text": "שורש = корень/суть"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4617, 218, 'fill_blank', 6, '{"hint": "Глагол «определять/характеризовать»", "sentence": "הפילוסוף _____ את מושג הזמן כחוויה סובייקטיבית"}', '{"accept": ["מגדיר"], "correct": "מגדיר"}', '{"text": "מגדיר = определяет"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4618, 218, 'fill_blank', 6, '{"hint": "Глагол «обрушивать/направлять» (критику)", "sentence": "המאמר _____ ביקורת על המודל הפוזיטיביסטי"}', '{"accept": ["מותח"], "correct": "מותח"}', '{"text": "מותח ביקורת = направляет критику"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4619, 218, 'fill_blank', 6, '{"hint": "Талмудическая формула «спорили»", "sentence": "_____ בית שמאי ובית הלל"}', '{"accept": ["נחלקו"], "correct": "נחלקו"}', '{"text": "נחלקו = спорили/разделились во мнениях"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4620, 218, 'fill_blank', 6, '{"hint": "«Различие/разрыв»", "sentence": "ה_____ בין הגישות מצביע על פלורליזם מתודולוגי"}', '{"accept": ["פער", "שוני"], "correct": "פער"}', '{"text": "פער = разрыв/различие"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4621, 218, 'fill_blank', 6, '{"hint": "«Обочина/на полях» (примечание)", "sentence": "הערת _____ חשובה לדיון: לא כל טקסט ניתן לפרשנות אחידה"}', '{"accept": ["שוליים"], "correct": "שוליים"}', '{"text": "הערת שוליים = примечание на полях, сноска"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4622, 218, 'fill_blank', 6, '{"hint": "«На основании»", "sentence": "_____ הדברים האמורים, ניתן להסיק מסקנה כללית"}', '{"accept": ["לאור", "על סמך", "נוכח"], "correct": "לאור"}', '{"text": "לאור = на основании/в свете"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4623, 218, 'fill_blank', 6, '{"hint": "«Согласно» (высокий стиль)", "sentence": "_____ המקרא, האדם נברא בצלם אלוהים"}', '{"accept": ["על פי", "לפי"], "correct": "על פי"}', '{"text": "על פי = согласно"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4624, 218, 'fill_blank', 6, '{"hint": "Формула «как написано (в Писании)»", "sentence": "_____ הכתוב: לא תרצח"}', '{"accept": ["כאמור", "ככתוב"], "correct": "כאמור"}', '{"text": "כאמור/ככתוב = как написано/сказано"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4625, 218, 'fill_blank', 6, '{"hint": "Глагол «черпать/питаться»", "sentence": "הטיעון _____ ממקורות קלאסיים וממחקרים עכשוויים"}', '{"accept": ["ניזון", "שואב"], "correct": "ניזון"}', '{"text": "ניזון מ = питается из/черпает"}', 30);
