INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4627, 218, 'match_pairs', 6, '{"pairs_left": ["תנא", "אמורא", "סבורא", "גאון"], "pairs_right": ["мудрец Мишны", "мудрец Гемары", "мудрец эпохи Саворим", "глава академии"]}', '{"matches": {"תנא": "мудрец Мишны", "גאון": "глава академии", "אמורא": "мудрец Гемары", "סבורא": "мудрец эпохи Саворим"}}', '{"text": "Эпохи раввинистической мудрости"}', 30);
