INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4639, 218, 'match_pairs', 6, '{"pairs_left": ["דאמר", "תנן", "אמר רב", "איבעיא להו"], "pairs_right": ["который сказал", "мы учили (в Мишне)", "сказал рав", "спрашивали они"]}', '{"matches": {"תנן": "мы учили (в Мишне)", "דאמר": "который сказал", "אמר רב": "сказал рав", "איבעיא להו": "спрашивали они"}}', '{"text": "Формулы цитирования в Талмуде"}', 30);
