INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4641, 218, 'match_pairs', 6, '{"pairs_left": ["ריבונות", "פלורליזם", "סובלנות", "הגמוניה"], "pairs_right": ["суверенитет", "плюрализм", "толерантность", "гегемония"]}', '{"matches": {"הגמוניה": "гегемония", "סובלנות": "толерантность", "ריבונות": "суверенитет", "פלורליזם": "плюрализм"}}', '{"text": "Политическая философия C2"}', 30);
