INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4644, 218, 'word_order', 6, '{"translation": "В начале сотворил Бог небеса", "words_shuffled": ["ברא", "בראשית", "אלוהים", "את", "השמים"], "correct_sentence": "בראשית ברא אלוהים את השמים"}', '{"correct_order": ["בראשית", "ברא", "אלוהים", "את", "השמים"]}', '{"text": "Библейский порядок: обстоятельство + глагол + подлежащее + дополнение"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4645, 218, 'word_order', 6, '{"translation": "И сказал Бог: да будет свет. И стал свет", "words_shuffled": ["ויאמר", "יהי", "אור", "אלוהים", "ויהי", "אור"], "correct_sentence": "ויאמר אלוהים יהי אור ויהי אור"}', '{"correct_order": ["ויאמר", "אלוהים", "יהי", "אור", "ויהי", "אור"]}', '{"text": "Библейская конструкция: ויאמר + подлежащее + повеление + исполнение"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4646, 218, 'word_order', 6, '{"translation": "И возлюби ближнего своего как себя", "words_shuffled": ["כמוך", "לרעך", "ואהבת"], "correct_sentence": "ואהבת לרעך כמוך"}', '{"correct_order": ["ואהבת", "לרעך", "כמוך"]}', '{"text": "Библейская заповедь: глагол + дополнение + сравнение"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4648, 218, 'word_order', 6, '{"translation": "Школа Шаммая говорит, а школа Гиллеля говорит", "words_shuffled": ["בית", "שמאי", "אומרים", "ובית", "הלל", "אומרים"], "correct_sentence": "בית שמאי אומרים ובית הלל אומרים"}', '{"correct_order": ["בית", "שמאי", "אומרים", "ובית", "הלל", "אומרים"]}', '{"text": "Формула мишнаитского спора"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4649, 218, 'word_order', 6, '{"translation": "Аргумент покоится на основах формальной логики", "words_shuffled": ["עומד", "הטיעון", "על", "ההיגיון", "אדני", "הפורמלי"], "correct_sentence": "הטיעון עומד על אדני ההיגיון הפורמלי"}', '{"correct_order": ["הטיעון", "עומד", "על", "אדני", "ההיגיון", "הפורמלי"]}', '{"text": "Подлежащее + глагол + על אדני + дополнение"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4650, 218, 'word_order', 6, '{"translation": "Экзегетическое предприятие обновляется в каждом поколении", "words_shuffled": ["מתחדש", "בכל", "הפרשני", "המפעל", "דור"], "correct_sentence": "המפעל הפרשני מתחדש בכל דור"}', '{"correct_order": ["המפעל", "הפרשני", "מתחדש", "בכל", "דור"]}', '{"text": "Подлежащее + глагол + בכל + время"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4651, 218, 'word_order', 6, '{"translation": "Возникает противоречие между галахой и этикой", "words_shuffled": ["סתירה", "בין", "נוצרת", "והאתיקה", "ההלכה"], "correct_sentence": "נוצרת סתירה בין ההלכה והאתיקה"}', '{"correct_order": ["נוצרת", "סתירה", "בין", "ההלכה", "והאתיקה"]}', '{"text": "Глагол + подлежащее + בין + А + ו + Б"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4653, 218, 'word_order', 6, '{"translation": "Разрыв между подходами указывает на методологический плюрализм", "words_shuffled": ["הגישות", "בין", "מצביע", "הפער", "פלורליזם", "על", "מתודולוגי"], "correct_sentence": "הפער בין הגישות מצביע על פלורליזם מתודולוגי"}', '{"correct_order": ["הפער", "בין", "הגישות", "מצביע", "על", "פלורליזם", "מתודולוגי"]}', '{"text": "Подлежащее + בין + А + глагол + על + дополнение"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4654, 218, 'word_order', 6, '{"translation": "Статья направляет критику на позитивистскую модель", "words_shuffled": ["ביקורת", "המאמר", "מותח", "הפוזיטיביסטי", "על", "המודל"], "correct_sentence": "המאמר מותח ביקורת על המודל הפוזיטיביסטי"}', '{"correct_order": ["המאמר", "מותח", "ביקורת", "על", "המודל", "הפוזיטיביסטי"]}', '{"text": "Подлежащее + глагол + дополнение + על + предмет"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4655, 218, 'word_order', 6, '{"translation": "Философия языка формирует сознание", "words_shuffled": ["פילוסופיה", "מעצבת", "של", "השפה", "את", "התודעה"], "correct_sentence": "פילוסופיה של השפה מעצבת את התודעה"}', '{"correct_order": ["פילוסופיה", "של", "השפה", "מעצבת", "את", "התודעה"]}', '{"text": "Подлежащее + של + определение + глагол + дополнение"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4656, 218, 'word_order', 6, '{"translation": "Академическая дискуссия ведётся на нескольких уровнях", "words_shuffled": ["הדיון", "האקדמי", "מתנהל", "רבדים", "במספר"], "correct_sentence": "הדיון האקדמי מתנהל במספר רבדים"}', '{"correct_order": ["הדיון", "האקדמי", "מתנהל", "במספר", "רבדים"]}', '{"text": "Подлежащее + прилагательное + глагол + ב + дополнение"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4659, 218, 'word_order', 6, '{"translation": "Текст открыт для множественных прочтений", "words_shuffled": ["לקריאות", "פתוח", "הטקסט", "מרובות"], "correct_sentence": "הטקסט פתוח לקריאות מרובות"}', '{"correct_order": ["הטקסט", "פתוח", "לקריאות", "מרובות"]}', '{"text": "Подлежащее + прилагательное + ל + дополнение"}', 30);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4660, 116, 'match_pairs', 2, '{"pairs_left": ["מחקר", "ניסוי", "תוצאה", "מסקנה"], "pairs_right": ["исследование", "эксперимент", "результат", "вывод"]}', '{"matches": {"מחקר": "исследование", "מסקנה": "вывод", "ניסוי": "эксперимент", "תוצאה": "результат"}}', '{"text": "Соедините слова с их переводами."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4661, 127, 'match_pairs', 2, '{"pairs_left": ["שיעור", "מבחן", "ציון", "תעודה"], "pairs_right": ["урок", "экзамен", "оценка", "аттестат"]}', '{"matches": {"מבחן": "экзамен", "ציון": "оценка", "שיעור": "урок", "תעודה": "аттестат"}}', '{"text": "Соедините слова с их переводами."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4662, 214, 'match_pairs', 2, '{"pairs_left": ["תהליך", "מערכת", "חומר", "אנרגיה"], "pairs_right": ["процесс", "система", "вещество", "энергия"]}', '{"matches": {"חומר": "вещество", "מערכת": "система", "תהליך": "процесс", "אנרגיה": "энергия"}}', '{"text": "Соедините слова с их переводами."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3847, 207, 'translate_ru_he', 1, '{"hint": "ספר", "prompt_ru": "Это книга", "target_he": "זה ספר"}', '{"accept": ["זה ספר"], "correct": "זה ספר"}', '{"text": "Это книга = זה ספר"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (457, 8, 'match_pairs', 1, '{"pairs_left": ["ילד", "ילדה", "ספר", "מורה"], "pairs_right": ["מורות", "ספרים", "ילדות", "ילדים"]}', '{"matches": {"ילד": "ילדים", "ספר": "ספרים", "ילדה": "ילדות", "מורה": "מורות"}}', '{"text": "ילד→ילדים, ילדה→ילדות, ספר→ספרים, מורה→מורות."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (467, 9, 'match_pairs', 1, '{"pairs_left": ["אני", "אתה", "היא", "אנחנו", "הם"], "pairs_right": ["они (м)", "мы", "она", "ты (м)", "я"]}', '{"matches": {"הם": "они (м)", "אני": "я", "אתה": "ты (м)", "היא": "она", "אנחנו": "мы"}}', '{"text": "אני — я, אתה — ты (м), היא — она, אנחנו — мы, הם — они."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (417, 4, 'match_pairs', 1, '{"pairs_left": ["ע", "פ", "צ", "ק", "ר", "ש"], "pairs_right": ["Шин", "Реш", "Куф", "Цади", "Пей", "Айин"]}', '{"matches": {"ע": "Айин", "פ": "Пей", "צ": "Цади", "ק": "Куф", "ר": "Реш", "ש": "Шин"}}', '{"text": "ע — Айин, פ — Пей, צ — Цади, ק — Куф, ר — Реш, ש — Шин."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (437, 6, 'match_pairs', 1, '{"pairs_left": ["патАх", "хирИк", "холАм", "кубУц", "цЕре"], "pairs_right": ["э", "у", "о", "и", "а"]}', '{"matches": {"цЕре": "э", "кубУц": "у", "патАх": "а", "хирИк": "и", "холАм": "о"}}', '{"text": "Патах — а, хирик — и, холам — о, кубуц — у, цере — э."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (487, 11, 'match_pairs', 1, '{"pairs_left": ["כותב", "כותבת", "כותבים", "כותבות"], "pairs_right": ["пишут (ж)", "пишут (м)", "пишет (ж)", "пишет (м)"]}', '{"matches": {"כותב": "пишет (м)", "כותבת": "пишет (ж)", "כותבות": "пишут (ж)", "כותבים": "пишут (м)"}}', '{"text": "כותב — м.ед., כותבת — ж.ед., כותבים — м.мн., כותבות — ж.мн."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (447, 7, 'match_pairs', 1, '{"pairs_left": ["ילד", "ספר", "בית", "מורה"], "pairs_right": ["המורה", "הבית", "הספר", "הילד"]}', '{"matches": {"בית": "הבית", "ילד": "הילד", "ספר": "הספר", "מורה": "המורה"}}', '{"text": "Артикль הַ ставится перед существительным: ילד→הילד, ספר→הספר, бית→הבית, морэ→המורה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (387, 1, 'match_pairs', 1, '{"pairs_left": ["א", "ב", "ג", "ד", "ה"], "pairs_right": ["Хей", "Далет", "Гимель", "Бет", "Алеф"]}', '{"matches": {"א": "Алеф", "ב": "Бет", "ג": "Гимель", "ד": "Далет", "ה": "Хей"}}', '{"text": "א — Алеф, ב — Бет, ג — Гимель, ד — Далет, ה — Хей."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (477, 10, 'match_pairs', 1, '{"pairs_left": ["ב", "ל", "מ", "על", "עם"], "pairs_right": ["с (вместе)", "на/над", "из/от", "к/для", "в/внутри"]}', '{"matches": {"ב": "в/внутри", "ל": "к/для", "מ": "из/от", "על": "на/над", "עם": "с (вместе)"}}', '{"text": "ב — в, ל — к, מ — из, על — на, עם — с."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (497, 12, 'match_pairs', 1, '{"pairs_left": ["פעל", "נפעל", "פיעל", "הפעיל"], "pairs_right": ["каузатив", "усиление", "пассив/возвратность", "простое действие"]}', '{"matches": {"פעל": "простое действие", "נפעל": "пассив/возвратность", "פיעל": "усиление", "הפעיל": "каузатив"}}', '{"text": "Пааль — простой, Нифъаль — пассив, Пиэль — усиление, Хифъиль — каузатив."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (507, 13, 'match_pairs', 1, '{"pairs_left": ["כתבתי", "כתבת", "כתב", "כתבנו"], "pairs_right": ["мы написали", "он написал", "ты (м) написал", "я написал(а)"]}', '{"matches": {"כתב": "он написал", "כתבת": "ты (м) написал", "כתבנו": "мы написали", "כתבתי": "я написал(а)"}}', '{"text": "כתבתי — я, כתבת — ты (м), כתב — он, כתבנו — мы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (517, 14, 'match_pairs', 1, '{"pairs_left": ["אכתוב", "תכתוב", "יכתוב", "נכתוב"], "pairs_right": ["мы напишем", "он напишет", "ты (м) напишешь", "я напишу"]}', '{"matches": {"אכתוב": "я напишу", "יכתוב": "он напишет", "נכתוב": "мы напишем", "תכתוב": "ты (м) напишешь"}}', '{"text": "אכתוב — я, תכתוב — ты (м), יכתוב — он, נכתוב — мы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (527, 15, 'match_pairs', 1, '{"pairs_left": ["שלום", "מה שלומך?", "תודה", "סליחה"], "pairs_right": ["извините", "спасибо", "как дела?", "привет"]}', '{"matches": {"שלום": "привет", "תודה": "спасибо", "סליחה": "извините", "מה שלומך?": "как дела?"}}', '{"text": "שלום — привет, מה שלומך — как дела, תודה — спасибо, סליחה — извините."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (537, 16, 'match_pairs', 1, '{"pairs_left": ["חלב", "לחם", "מים", "גבינה"], "pairs_right": ["сыр", "вода", "хлеб", "молоко"]}', '{"matches": {"חלב": "молоко", "לחם": "хлеб", "מים": "вода", "גבינה": "сыр"}}', '{"text": "חלב — молоко, לחם — хлеб, מים — вода, גבינה — сыр."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (478, 10, 'word_order', 1, '{"words": ["בבית", "הספר", "הילד"], "instruction": "Составьте «Мальчик в школе»", "translation": "Мальчик в школе", "words_shuffled": ["בבית", "הילד", "הספר"]}', '{"correct_order": ["הילד", "הספר", "בבית"]}', '{"text": "הילד בבית הספר — мальчик в школе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (547, 17, 'match_pairs', 1, '{"pairs_left": ["אבא", "אמא", "אח", "אחות", "סבא"], "pairs_right": ["дедушка", "сестра", "брат", "мама", "папа"]}', '{"matches": {"אח": "брат", "אבא": "папа", "אמא": "мама", "סבא": "дедушка", "אחות": "сестра"}}', '{"text": "אבא — папа, אמא — мама, אח — брат, אחות — сестра, סבא — дедушка."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (557, 77, 'match_pairs', 1, '{"pairs_left": ["אחד", "שניים", "שלושה", "ארבעה", "חמישה"], "pairs_right": ["5", "4", "3", "2", "1"]}', '{"matches": {"אחד": "1", "ארבעה": "4", "חמישה": "5", "שלושה": "3", "שניים": "2"}}', '{"text": "Числа 1-5 м.р.: אחד, שניים, שלושה, ארבעה, חמישה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (563, 77, 'match_pairs', 2, '{"pairs_left": ["שש", "שבע", "שמונה", "תשע", "עשר"], "pairs_right": ["10", "9", "8", "7", "6"]}', '{"matches": {"שש": "6", "עשר": "10", "שבע": "7", "תשע": "9", "שמונה": "8"}}', '{"text": "Числа 6-10 ж.р.: שש, שבע, שמונה, תשע, עשר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (572, 78, 'match_pairs', 1, '{"pairs_left": ["ראש", "יד", "רגל", "עין", "אוזן"], "pairs_right": ["ухо", "глаз", "нога", "рука", "голова"]}', '{"matches": {"יד": "рука", "עין": "глаз", "ראש": "голова", "רגל": "нога", "אוזן": "ухо"}}', '{"text": "ראש — голова, יד — рука, רגל — нога, עין — глаз, אוזן — ухо."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (578, 78, 'match_pairs', 2, '{"pairs_left": ["רופא", "רופא שיניים", "בית חולים", "בית מרקחת", "תרופה"], "pairs_right": ["лекарство", "аптека", "больница", "стоматолог", "врач"]}', '{"matches": {"רופא": "врач", "תרופה": "лекарство", "בית חולים": "больница", "בית מרקחת": "аптека", "רופא שיניים": "стоматолог"}}', '{"text": "רופא — врач, רופא שיניים — стоматолог, בית חולים — больница, בית מרקחת — аптека."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (587, 79, 'match_pairs', 1, '{"pairs_left": ["מכתב", "חבילה", "בול", "מעטפה", "דואר"], "pairs_right": ["почта", "конверт", "марка", "посылка", "письмо"]}', '{"matches": {"בול": "марка", "דואר": "почта", "מכתב": "письмо", "חבילה": "посылка", "מעטפה": "конверт"}}', '{"text": "מכתב — письмо, חבילה — посылка, בול — марка, מעטפה — конверт, דואר — почта."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (593, 79, 'match_pairs', 2, '{"pairs_left": ["לשלוח", "לקבל", "כתובת", "שולח", "נמען"], "pairs_right": ["получатель", "отправитель", "адрес", "получить", "отправить"]}', '{"matches": {"לקבל": "получить", "נמען": "получатель", "שולח": "отправитель", "כתובת": "адрес", "לשלוח": "отправить"}}', '{"text": "לשלוח — отправить, לקבל — получить, כתובת — адрес, שולח — отправитель, נמען — получатель."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (602, 80, 'match_pairs', 1, '{"pairs_left": ["תפריט", "מנה ראשונה", "מנה עיקרית", "קינוח", "חשבון"], "pairs_right": ["счёт", "десерт", "основное блюдо", "первое блюдо", "меню"]}', '{"matches": {"חשבון": "счёт", "קינוח": "десерт", "תפריט": "меню", "מנה עיקרית": "основное блюдо", "מנה ראשונה": "первое блюдо"}}', '{"text": "תפריט — меню, מנה ראשונה — первое, מנה עיקרית — основное, קינוח — десерт, חשבון — счёт."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (608, 80, 'match_pairs', 1, '{"pairs_left": ["קפה", "תה", "מיץ", "מים", "יין"], "pairs_right": ["вино", "вода", "сок", "чай", "кофе"]}', '{"matches": {"תה": "чай", "יין": "вино", "מים": "вода", "מיץ": "сок", "קפה": "кофе"}}', '{"text": "קפה — кофе, תה — чай, מיץ — сок, מים — вода, יין — вино."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (617, 81, 'match_pairs', 1, '{"pairs_left": ["תפוח", "בננה", "תפוז", "ענבים", "אבטיח"], "pairs_right": ["арбуз", "виноград", "апельсин", "банан", "яблоко"]}', '{"matches": {"בננה": "банан", "תפוז": "апельсин", "תפוח": "яблоко", "אבטיח": "арбуз", "ענבים": "виноград"}}', '{"text": "תפוח — яблоко, בננה — банан, תפוז — апельсин, ענבים — виноград, אבטיח — арбуз."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (623, 81, 'match_pairs', 2, '{"pairs_left": ["עגבנייה", "מלפפון", "גזר", "בצל", "חסה"], "pairs_right": ["салат (латук)", "лук", "морковь", "огурец", "помидор"]}', '{"matches": {"בצל": "лук", "גזר": "морковь", "חסה": "салат (латук)", "מלפפון": "огурец", "עגבנייה": "помидор"}}', '{"text": "עגבנייה — помидор, מלפפון — огурец, גזר — морковь, בצל — лук, חסה — салат."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (632, 82, 'match_pairs', 1, '{"pairs_left": ["סלון", "מטבח", "חדר שינה", "חדר אמבטיה", "מרפסת"], "pairs_right": ["балкон", "ванная", "спальня", "кухня", "гостиная"]}', '{"matches": {"מטבח": "кухня", "סלון": "гостиная", "מרפסת": "балкон", "חדר שינה": "спальня", "חדר אמבטיה": "ванная"}}', '{"text": "סלון — гостиная, מטבח — кухня, חדר שינה — спальня, חדר אמבטיה — ванная, מרפסת — балкон."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (638, 82, 'match_pairs', 2, '{"pairs_left": ["כיסא", "שולחן", "מיטה", "ארון", "ספה"], "pairs_right": ["диван", "шкаф", "кровать", "стол", "стул"]}', '{"matches": {"ספה": "диван", "ארון": "шкаф", "כיסא": "стул", "מיטה": "кровать", "שולחן": "стол"}}', '{"text": "כיסא — стул, שולחן — стол, מיטה — кровать, ארון — шкаф, ספה — диван."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (647, 83, 'match_pairs', 1, '{"pairs_left": ["אוטובוס", "רכבת", "מונית", "מטוס", "אופניים"], "pairs_right": ["велосипед", "самолёт", "такси", "поезд", "автобус"]}', '{"matches": {"מטוס": "самолёт", "רכבת": "поезд", "מונית": "такси", "אוטובוס": "автобус", "אופניים": "велосипед"}}', '{"text": "אוטובוס — автобус, רכבת — поезд, מונית — такси, מטוס — самолёт, אופניים — велосипед."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (653, 83, 'match_pairs', 2, '{"pairs_left": ["כרטיס", "תחנה", "קו", "נוסע", "נהג"], "pairs_right": ["водитель", "пассажир", "маршрут", "остановка", "билет"]}', '{"matches": {"קו": "маршрут", "נהג": "водитель", "נוסע": "пассажир", "תחנה": "остановка", "כרטיס": "билет"}}', '{"text": "כרטיס — билет, תחנה — остановка, קו — маршрут, נוסע — пассажир, נהג — водитель."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (662, 84, 'match_pairs', 1, '{"pairs_left": ["חורף", "אביב", "קיץ", "סתיו"], "pairs_right": ["осень", "лето", "весна", "зима"]}', '{"matches": {"קיץ": "лето", "אביב": "весна", "חורף": "зима", "סתיו": "осень"}}', '{"text": "חורף — зима, אביב — весна, קיץ — лето, סתיו — осень."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (668, 84, 'match_pairs', 2, '{"pairs_left": ["חם", "קר", "גשם", "רוח", "ענן"], "pairs_right": ["облако", "ветер", "дождь", "холодно", "жарко"]}', '{"matches": {"חם": "жарко", "קר": "холодно", "גשם": "дождь", "ענן": "облако", "רוח": "ветер"}}', '{"text": "חם — жарко, קר — холодно, גשם — дождь, רוח — ветер, ענן — облако."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (677, 85, 'match_pairs', 1, '{"pairs_left": ["קריאה", "שחייה", "ריצה", "בישול", "ציור"], "pairs_right": ["рисование", "готовка", "бег", "плавание", "чтение"]}', '{"matches": {"ציור": "рисование", "ריצה": "бег", "בישול": "готовка", "קריאה": "чтение", "שחייה": "плавание"}}', '{"text": "קריאה — чтение, שחייה — плавание, ריצה — бег, בישול — готовка, ציור — рисование."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (683, 85, 'match_pairs', 2, '{"pairs_left": ["כדורגל", "כדורסל", "טניס", "כדורעף", "שחמט"], "pairs_right": ["шахматы", "волейбол", "теннис", "баскетбол", "футбол"]}', '{"matches": {"טניס": "теннис", "שחמט": "шахматы", "כדורגל": "футбол", "כדורסל": "баскетбол", "כדורעף": "волейбол"}}', '{"text": "כדורגל — футбол, כדורסל — баскетбол, טניס — теннис, כדורעף — волейбол, שחמט — шахматы."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (692, 86, 'match_pairs', 1, '{"pairs_left": ["ילד", "ילדה", "כלב", "חתול", "מורה"], "pairs_right": ["מורות", "חתולים", "כלבים", "ילדות", "ילדים"]}', '{"matches": {"ילד": "ילדים", "כלב": "כלבים", "חתול": "חתולים", "ילדה": "ילדות", "מורה": "מורות"}}', '{"text": "ילד→ילדים, ילדה→ילדות, כלב→כלבים, חתול→חתולים, מורה→מורות."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (698, 86, 'match_pairs', 2, '{"pairs_left": ["שנה", "עיר", "אישה", "איש", "יום"], "pairs_right": ["ימים", "אנשים", "נשים", "ערים", "שנים"]}', '{"matches": {"איש": "אנשים", "יום": "ימים", "עיר": "ערים", "שנה": "שנים", "אישה": "נשים"}}', '{"text": "Исключения: שנה→שנים, עיר→ערים, אישה→נשים, איש→אנשים, יום→ימים."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (707, 87, 'match_pairs', 1, '{"pairs_left": ["ספר", "בית", "ילדה", "מורה", "כלב"], "pairs_right": ["הכלב", "המורה", "הילדה", "הבית", "הספר"]}', '{"matches": {"בית": "הבית", "כלב": "הכלב", "ספר": "הספר", "ילדה": "הילדה", "מורה": "המורה"}}', '{"text": "Добавляем הַ: ספר→הספר, בית→הבית, ילדה→הילדה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (713, 87, 'match_pairs', 2, '{"pairs_left": ["בית ספר", "בית חולים", "בית כנסת", "בית קפה"], "pairs_right": ["кафе", "синагога", "больница", "школа"]}', '{"matches": {"בית ספר": "школа", "בית קפה": "кафе", "בית כנסת": "синагога", "בית חולים": "больница"}}', '{"text": "Составные слова с בית: школа, больница, синагога, кафе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (722, 88, 'match_pairs', 1, '{"pairs_left": ["ב", "על", "ליד", "מתחת ל", "בין"], "pairs_right": ["между", "под", "рядом", "на", "в"]}', '{"matches": {"ב": "в", "על": "на", "בין": "между", "ליד": "рядом", "מתחת ל": "под"}}', '{"text": "ב — в, על — на, ליד — рядом, מתחת ל — под, בין — между."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (728, 88, 'match_pairs', 2, '{"pairs_left": ["מול", "אחרי", "לפני", "מעל", "מאחורי"], "pairs_right": ["сзади", "над", "перед", "после", "напротив"]}', '{"matches": {"מול": "напротив", "מעל": "над", "אחרי": "после", "לפני": "перед", "מאחורי": "сзади"}}', '{"text": "מול — напротив, אחרי — после, לפני — перед, מעל — над, מאחורי — сзади."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (737, 89, 'match_pairs', 1, '{"pairs_left": ["ל", "מ", "אל", "עד", "דרך"], "pairs_right": ["через", "до", "к (формально)", "из/от", "к/для"]}', '{"matches": {"ל": "к/для", "מ": "из/от", "אל": "к (формально)", "עד": "до", "דרך": "через"}}', '{"text": "ל — к/для, מ — из, אל — к (формальный), עד — до, דרך — через."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (743, 89, 'match_pairs', 2, '{"pairs_left": ["הלך ל", "בא מ", "נסע דרך", "הגיע עד", "חזר מ"], "pairs_right": ["вернулся из", "добрался до", "проехал через", "пришёл из", "пошёл к"]}', '{"matches": {"בא מ": "пришёл из", "הלך ל": "пошёл к", "חזר מ": "вернулся из", "הגיע עד": "добрался до", "נסע דרך": "проехал через"}}', '{"text": "הלך ל — пошёл к, בא מ — пришёл из, נסע דרך — проехал через, הגיע עד — добрался до."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (752, 90, 'match_pairs', 1, '{"pairs_left": ["אחת", "שתיים", "שלוש", "ארבע", "חמש"], "pairs_right": ["5:00", "4:00", "3:00", "2:00", "1:00"]}', '{"matches": {"אחת": "1:00", "חמש": "5:00", "ארבע": "4:00", "שלוש": "3:00", "שתיים": "2:00"}}', '{"text": "אחת — час, שתיים — два, שלוש — три, ארבע — четыре, חמש — пять."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (458, 8, 'word_order', 1, '{"words": ["גדולים", "הילדים"], "instruction": "Составьте «Дети большие»", "translation": "Дети большие", "words_shuffled": ["הילדים", "גדולים"]}', '{"correct_order": ["הילדים", "גדולים"]}', '{"text": "הילדים גדולים — дети большие. Прилагательное согласуется в роде и числе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (758, 90, 'match_pairs', 1, '{"pairs_left": ["בוקר", "צהריים", "אחר הצהריים", "ערב", "לילה"], "pairs_right": ["ночь", "вечер", "после обеда", "полдень", "утро"]}', '{"matches": {"ערב": "вечер", "בוקר": "утро", "לילה": "ночь", "צהריים": "полдень", "אחר הצהריים": "после обеда"}}', '{"text": "בוקר — утро, צהריים — полдень, אחר הצהריים — после обеда, ערב — вечер, לילה — ночь."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (767, 91, 'match_pairs', 1, '{"pairs_left": ["ראשון", "שני", "שלישי", "רביעי", "חמישי"], "pairs_right": ["четверг", "среда", "вторник", "понедельник", "воскресенье"]}', '{"matches": {"שני": "понедельник", "חמישי": "четверг", "ראשון": "воскресенье", "רביעי": "среда", "שלישי": "вторник"}}', '{"text": "Дни недели: ראשון — вс, שני — пн, שלישי — вт, רביעי — ср, חמישי — чт."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (773, 91, 'match_pairs', 2, '{"pairs_left": ["היום", "מחר", "אתמול", "בשבוע הבא", "בשבוע שעבר"], "pairs_right": ["на прошлой неделе", "на следующей неделе", "вчера", "завтра", "сегодня"]}', '{"matches": {"מחר": "завтра", "היום": "сегодня", "אתמול": "вчера", "בשבוע הבא": "на следующей неделе", "בשבוע שעבר": "на прошлой неделе"}}', '{"text": "היום — сегодня, מחר — завтра, אתמול — вчера."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (782, 92, 'match_pairs', 1, '{"pairs_left": ["שם", "גיל", "עיר", "מקצוע", "משפחה"], "pairs_right": ["семья", "профессия", "город", "возраст", "имя"]}', '{"matches": {"שם": "имя", "גיל": "возраст", "עיר": "город", "מקצוע": "профессия", "משפחה": "семья"}}', '{"text": "שם — имя, גיל — возраст, עיר — город, מקצוע — профессия, משפחה — семья."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (788, 92, 'match_pairs', 2, '{"pairs_left": ["מהנדס", "רופא", "מורה", "עורך דין", "תוכניתן"], "pairs_right": ["программист", "адвокат", "учитель", "врач", "инженер"]}', '{"matches": {"מורה": "учитель", "רופא": "врач", "מהנדס": "инженер", "תוכניתן": "программист", "עורך דין": "адвокат"}}', '{"text": "מהנדס — инженер, רופא — врач, מורה — учитель, עורך דין — адвокат, תוכניתן — программист."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (797, 93, 'match_pairs', 1, '{"pairs_left": ["דרכון", "מזוודה", "כרטיס טיסה", "שער", "טיסה"], "pairs_right": ["рейс", "выход (гейт)", "билет на самолёт", "чемодан", "паспорт"]}', '{"matches": {"שער": "выход (гейт)", "טיסה": "рейс", "דרכון": "паспорт", "מזוודה": "чемодан", "כרטיס טיסה": "билет на самолёт"}}', '{"text": "דרכון — паспорт, מזוודה — чемодан, כרטיס טיסה — билет, שער — гейт, טיסה — рейс."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (803, 93, 'match_pairs', 2, '{"pairs_left": ["המראה", "נחיתה", "עלייה למטוס", "ביקורת דרכונים", "מכס"], "pairs_right": ["таможня", "паспортный контроль", "посадка", "приземление", "взлёт"]}', '{"matches": {"מכס": "таможня", "המראה": "взлёт", "נחיתה": "приземление", "עלייה למטוס": "посадка", "ביקורת דרכונים": "паспортный контроль"}}', '{"text": "המראה — взлёт, נחיתה — приземление, עלייה למטוס — посадка, ביקורת דרכונים — контроль."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (812, 94, 'match_pairs', 1, '{"pairs_left": ["שלום", "תודה", "בבקשה", "סליחה", "כן"], "pairs_right": ["да", "извините", "пожалуйста", "спасибо", "привет"]}', '{"matches": {"כן": "да", "שלום": "привет", "תודה": "спасибо", "בבקשה": "пожалуйста", "סליחה": "извините"}}', '{"text": "Базовые слова: שלום, תודה, בבקשה, סליחה, כן."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (818, 94, 'match_pairs', 1, '{"pairs_left": ["אני", "אתה", "הוא", "אנחנו", "הם"], "pairs_right": ["они", "мы", "он", "ты (м)", "я"]}', '{"matches": {"הם": "они", "אני": "я", "אתה": "ты (м)", "הוא": "он", "אנחנו": "мы"}}', '{"text": "Местоимения: אני — я, אתה — ты, הוא — он, אנחנו — мы, הם — они."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (94, 60, 'word_order', 4, '{"translation": "Несмотря на все трудности, он преуспел", "words_shuffled": ["הצליח", "למרות", "הקשיים", "כל", "הוא"], "correct_sentence": "למרות כל הקשיים הוא הצליח"}', '{"correct_order": ["למרות", "כל", "הקשיים", "הוא", "הצליח"]}', '{"text": "למרות + существительное (без ש-!) = несмотря на. למרות ש- + предложение = несмотря на то что. Здесь למרות כל הקשיים — без ש-, потому что дальше не придаточное."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (256, 29, 'word_order', 3, '{"words": ["ש", "היא", "אמרה", "תבוא", "מחר"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Она сказала, что придёт завтра", "words_shuffled": ["ש", "תבוא", "מחר", "אמרה", "היא"]}', '{"correct_order": ["אמרה", "ש", "תבוא", "מחר", "היא"]}', '{"text": "אמרה שהיא תבוא מחר — порядок: сказуемое + ש + подлежащее придаточного"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (188, 31, 'word_order', 3, '{"translation": "Это путешествие было замечательным опытом", "words_shuffled": ["נהדרת", "הזה", "היה", "חוויה", "הטיול"], "correct_sentence": "הטיול הזה היה חוויה נהדרת"}', '{"correct_order": ["הטיול", "הזה", "היה", "חוויה", "נהדרת"]}', '{"text": "הטיול הזה היה חוויה נהדרת — подлежащее (הטיול הזה) + сказуемое (היה) + именная часть (חוויה נהדרת)."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (468, 9, 'word_order', 1, '{"words": ["עברית", "לומדת", "היא"], "instruction": "Составьте «Она учит иврит»", "translation": "Она учит иврит", "words_shuffled": ["לומדת", "עברית", "היא"]}', '{"correct_order": ["היא", "לומדת", "עברית"]}', '{"text": "היא לומדת עברית — она учит иврит."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (192, 32, 'word_order', 3, '{"translation": "После учёбы я хочу работать в хайтек-компании", "words_shuffled": ["לעבוד", "הלימודים", "רוצה", "אני", "אחרי", "בחברת", "הייטק"], "correct_sentence": "אחרי הלימודים אני רוצה לעבוד בחברת הייטק"}', '{"correct_order": ["אחרי", "הלימודים", "אני", "רוצה", "לעבוד", "בחברת", "הייטק"]}', '{"text": "אחרי הלימודים אני רוצה לעבוד בחברת הייטק — обстоятельство времени (אחרי הלימודים) + подлежащее + глагол + инфинитив + дополнение."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (198, 38, 'word_order', 3, '{"translation": "Правительство много инвестирует в исследования и разработки", "words_shuffled": ["רבות", "הממשלה", "ופיתוח", "במחקר", "משקיעה"], "correct_sentence": "הממשלה משקיעה רבות במחקר ופיתוח"}', '{"correct_order": ["הממשלה", "משקיעה", "רבות", "במחקר", "ופיתוח"]}', '{"text": "הממשלה משקיעה רבות במחקר ופיתוח — подлежащее + сказуемое + наречие + предложное дополнение. Глагол משקיעה (машкиА) — биньян хифъиль."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (203, 39, 'word_order', 3, '{"translation": "Судьи Верховного суда назначаются специальной комиссией", "words_shuffled": ["על", "ממונים", "ידי", "העליון", "שופטי", "המשפט", "בית", "ועדה", "מיוחדת"], "correct_sentence": "שופטי בית המשפט העליון ממונים על ידי ועדה מיוחדת"}', '{"correct_order": ["שופטי", "בית", "המשפט", "העליון", "ממונים", "על", "ידי", "ועדה", "מיוחדת"]}', '{"text": "שופטי בית המשפט העליון ממונים על ידי ועדה מיוחדת — пассивная конструкция: ממונים (назначаются) + על ידי (посредством). Биньян пуаль."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (218, 47, 'word_order', 6, '{"translation": "Правительство объявило, что утвердило новый экономический план", "words_shuffled": ["הממשלה", "הודיעה", "כי", "תוכנית", "אישרה", "חדשה", "כלכלית"], "correct_sentence": "הממשלה הודיעה כי אישרה תוכנית כלכלית חדשה"}', '{"correct_order": ["הממשלה", "הודיעה", "כי", "אישרה", "תוכנית", "כלכלית", "חדשה"]}', '{"text": "Газетный синтаксис: подлежащее (הממשלה) + глагол (הודיעה) + כי (что) + придаточное предложение. Обратите внимание на порядок прилагательных: תוכנית כלכלית חדשה — существительное + прилагательное-определение + прилагательное-качество."}', 20);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (268, 49, 'word_order', 3, '{"words": ["נלך", "אם", "הגשם", "ייפסק", "לטייל"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Если дождь прекратится, пойдём гулять", "words_shuffled": ["לטייל", "אם", "נלך", "הגשם", "ייפסק"]}', '{"correct_order": ["אם", "ייפסק", "הגשם", "נלך", "לטייל"]}', '{"text": "אם הגשם ייפסק נלך לטייל"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (307, 41, 'word_order', 4, '{"words": ["גדולה", "היא", "השפעתו", "של", "המורה", "על", "התלמידים"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Велико влияние учителя на учеников", "words_shuffled": ["השפעתו", "של", "על", "המורה", "התלמידים", "גדולה"]}', '{"correct_order": ["גדולה", "השפעתו", "של", "המורה", "על", "התלמידים"]}', '{"text": "Инверсия: предикатив גדולה вынесен в начало предложения"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (382, 60, 'word_order', 4, '{"words": ["את", "הנושאים", "שלמדנו", "ברמה", "הזאת", "כל", "לסכם", "אפשר"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Можно подытожить все темы, которые мы изучили на этом уровне", "words_shuffled": ["ברמה", "לסכם", "כל", "את", "הנושאים", "שלמדנו", "אפשר", "הזאת"]}', '{"correct_order": ["אפשר", "לסכם", "כל", "הנושאים", "שלמדנו", "ברמה", "הזאת", "את"]}', '{"text": "אפשר לסכם את כל הנושאים שלמדנו ברמה הזאת — можно + инфинитив, את перед определённое прямое дополнение, שלמדנו — придаточное определительное с ש."}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (388, 1, 'word_order', 1, '{"words": ["ה", "ד", "ג", "ב", "א"], "instruction": "Расставьте буквы в алфавитном порядке", "translation": "Алеф, Бет, Гимель, Далет, Хей", "words_shuffled": ["ה", "ג", "א", "ד", "ב"]}', '{"correct_order": ["א", "ב", "ג", "ד", "ה"]}', '{"text": "Правильный порядок: א ב ג ד ה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (398, 2, 'word_order', 1, '{"words": ["י", "ט", "ח", "ז", "ו"], "instruction": "Расставьте буквы в алфавитном порядке", "translation": "Вав, Зайин, Хет, Тет, Йуд", "words_shuffled": ["ז", "ח", "ט", "י", "ו"]}', '{"correct_order": ["ו", "ז", "ח", "ט", "י"]}', '{"text": "Правильный порядок: ו ז ח ט י."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (408, 3, 'word_order', 1, '{"words": ["ס", "נ", "מ", "ל", "כ"], "instruction": "Расставьте буквы в алфавитном порядке", "translation": "Каф, Ламед, Мем, Нун, Самех", "words_shuffled": ["מ", "נ", "ס", "ל", "כ"]}', '{"correct_order": ["כ", "ל", "מ", "נ", "ס"]}', '{"text": "Правильный порядок: כ ל מ נ ס."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (418, 4, 'word_order', 1, '{"words": ["ש", "ר", "ק", "צ", "פ", "ע"], "instruction": "Расставьте буквы в алфавитном порядке", "translation": "Айин, Пей, Цади, Куф, Реш, Шин", "words_shuffled": ["פ", "ש", "ע", "ר", "ק", "צ"]}', '{"correct_order": ["ע", "פ", "צ", "ק", "ר", "ש"]}', '{"text": "Правильный порядок: ע פ צ ק ר ש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (428, 5, 'word_order', 1, '{"words": ["ת", "ש", "ר", "ק", "צ"], "instruction": "Расставьте последние 5 букв алфавита в порядке", "translation": "Цади, Куф, Реш, Шин, Тав", "words_shuffled": ["ש", "ת", "צ", "ק", "ר"]}', '{"correct_order": ["צ", "ק", "ר", "ש", "ת"]}', '{"text": "Последние 5 букв: צ ק ר ש ת."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (488, 11, 'word_order', 1, '{"words": ["ספר", "קוראת", "היא"], "instruction": "Составьте «Она читает книгу»", "translation": "Она читает книгу", "words_shuffled": ["קוראת", "היא", "ספר"]}', '{"correct_order": ["היא", "קוראת", "ספר"]}', '{"text": "היא קוראת ספר — она читает книгу. קוראת — ж.р. ед.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (498, 12, 'word_order', 1, '{"words": ["התפעל", "הפעיל", "פיעל", "נפעל", "פעל"], "instruction": "Расставьте биньяны по порядку (от простого к сложному)", "translation": "Пааль, Нифъаль, Пиэль, Хифъиль, Хитпаэль", "words_shuffled": ["הפעיל", "נפעל", "פעל", "פיעל", "התפעל"]}', '{"correct_order": ["פעל", "נפעל", "פיעל", "הפעיל", "התפעל"]}', '{"text": "Традиционный порядок: פעל, נפעל, פיעל, הפעיל, התפעל."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (508, 13, 'word_order', 1, '{"words": ["עברית", "למדתי", "בביה\"ס"], "instruction": "Составьте «Я учил иврит в школе»", "translation": "Я учил иврит в школе", "words_shuffled": ["למדתי", "עברית", "בביה\"ס"]}', '{"correct_order": ["למדתי", "עברית", "בביה\"ס"]}', '{"text": "למדתי עברית בביה\"ס — я учил иврит в школе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (518, 14, 'word_order', 1, '{"words": ["עברית", "ילמד", "הוא", "מחר"], "instruction": "Составьте «Он будет учить иврит завтра»", "translation": "Он будет учить иврит завтра", "words_shuffled": ["עברית", "מחר", "ילמד", "הוא"]}', '{"correct_order": ["הוא", "ילמד", "עברית", "מחר"]}', '{"text": "הוא ילמד עברית מחר — он будет учить иврит завтра."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (528, 15, 'word_order', 1, '{"words": ["בביה\"ס", "עברית", "אני", "לומד"], "instruction": "Составьте «Я учу иврит в школе»", "translation": "Я учу иврит в школе", "words_shuffled": ["בביה\"ס", "לומד", "אני", "עברית"]}', '{"correct_order": ["אני", "לומד", "עברית", "בביה\"ס"]}', '{"text": "אני לומד עברית בביה\"ס — я учу иврит в школе."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (538, 16, 'word_order', 1, '{"words": ["בבקשה", "חלב", "אחד"], "instruction": "Составьте «Одно молоко, пожалуйста»", "translation": "Одно молоко, пожалуйста", "words_shuffled": ["חלב", "אחד", "בבקשה"]}', '{"correct_order": ["חלב", "אחד", "בבקשה"]}', '{"text": "חלב אחד, בבקשה — одно молоко, пожалуйста."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (548, 17, 'word_order', 1, '{"words": ["גדולה", "המשפחה", "שלי"], "instruction": "Составьте «Моя семья большая»", "translation": "Моя семья большая", "words_shuffled": ["שלי", "המשפחה", "גדולה"]}', '{"correct_order": ["המשפחה", "שלי", "גדולה"]}', '{"text": "המשפחה שלי גדולה — моя семья большая."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (558, 77, 'word_order', 1, '{"words": ["בבקשה", "תפוחים", "קילו", "שני"], "instruction": "Составьте «Два кило яблок, пожалуйста»", "translation": "Два кило яблок, пожалуйста", "words_shuffled": ["תפוחים", "קילו", "שני", "בבקשה"]}', '{"correct_order": ["שני", "קילו", "תפוחים", "בבקשה"]}', '{"text": "שני קילו תפוחים, בבקשה — два кило яблок, пожалуйста."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (564, 77, 'word_order', 2, '{"words": ["?", "בסך הכל", "כמה", "זה"], "instruction": "Составьте «Сколько это всего?»", "translation": "Сколько это всего?", "words_shuffled": ["בסך הכל", "זה", "?", "כמה"]}', '{"correct_order": ["כמה", "זה", "בסך הכל", "?"]}', '{"text": "כמה זה בסך הכל? — сколько это всего?"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (573, 78, 'word_order', 1, '{"words": ["הראש", "כואב", "לי"], "instruction": "Составьте «У меня болит голова»", "translation": "У меня болит голова", "words_shuffled": ["הראש", "לי", "כואב"]}', '{"correct_order": ["כואב", "הראש", "לי"]}', '{"text": "כואב לי הראש — у меня болит голова."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (580, 78, 'word_order', 2, '{"words": ["תרופה", "צריך", "אני", "לקחת"], "instruction": "Составьте «Мне нужно принять лекарство»", "translation": "Мне нужно принять лекарство", "words_shuffled": ["צריך", "אני", "תרופה", "לקחת"]}', '{"correct_order": ["אני", "צריך", "לקחת", "תרופה"]}', '{"text": "אני צריך לקחת תרופה — мне нужно принять лекарство."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (588, 79, 'word_order', 1, '{"words": ["חבילה", "לשלוח", "רוצה", "אני"], "instruction": "Составьте «Я хочу отправить посылку»", "translation": "Я хочу отправить посылку", "words_shuffled": ["חבילה", "רוצה", "לשלוח", "אני"]}', '{"correct_order": ["אני", "רוצה", "לשלוח", "חבילה"]}', '{"text": "אני רוצה לשלוח חבילה — я хочу отправить посылку."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (595, 79, 'word_order', 2, '{"words": ["?", "מגיעה", "מתי", "החבילה"], "instruction": "Составьте «Когда придёт посылка?»", "translation": "Когда придёт посылка?", "words_shuffled": ["החבילה", "מתי", "?", "מגיעה"]}', '{"correct_order": ["מתי", "החבילה", "מגיעה", "?"]}', '{"text": "מתי החבילה מגיעה? — когда придёт посылка?"}', 10);
