INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1232, 27, 'word_order', 2, '{"words": ["תצליח", "תלמד", "אם", "במבחן"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Если будешь учиться, сдашь экзамен", "words_shuffled": ["תלמד", "תצליח", "במבחן", "אם"]}', '{"correct_order": ["אם", "תלמד", "תצליח", "במבחן"]}', '{"text": "אם תלמד, תצליח במבחן — реальное условие: אם + будущее → будущее."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1238, 27, 'word_order', 3, '{"words": ["הייתי", "אילו", "קונה", "בית", "עשיר", "הייתי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Если бы я был богатым, я бы купил дом", "words_shuffled": ["עשיר", "הייתי", "קונה", "בית", "אילו", "הייתי"]}', '{"correct_order": ["אילו", "הייתי", "עשיר", "הייתי", "קונה", "בית"]}', '{"text": "אילו הייתי עשיר, הייתי קונה בית. Два הייתי: первое — «был бы», второе — вспомогательное для причастия."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1242, 28, 'word_order', 3, '{"words": ["על", "ידי", "נבנה", "הבית", "מהנדס", "ישראלי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Дом был построен израильским инженером", "words_shuffled": ["הבית", "ידי", "ישראלי", "נבנה", "מהנדס", "על"]}', '{"correct_order": ["הבית", "נבנה", "על", "ידי", "מהנדס", "ישראלי"]}', '{"text": "הבית נבנה על ידי מהנדס ישראלי. Пассив Нифъаль + על ידי для указания деятеля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1248, 28, 'word_order', 2, '{"words": ["נרשם", "הוא", "חדש", "לקורס"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Он записался на новый курс", "words_shuffled": ["הוא", "לקורס", "חדש", "נרשם"]}', '{"correct_order": ["הוא", "נרשם", "לקורס", "חדש"]}', '{"text": "הוא נרשם לקורס חדש. Нифъаль נרשם (нирשАм) — записался (возвратное значение)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1252, 29, 'word_order', 2, '{"words": ["שיצליח", "כדי", "עזרתי", "לו"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я помог ему, чтобы он преуспел", "words_shuffled": ["עזרתי", "כדי", "שיצליח", "לו"]}', '{"correct_order": ["עזרתי", "לו", "כדי", "שיצליח"]}', '{"text": "עזרתי לו כדי שיצליח. Целевое придаточное: כדי ש + будущее время (при разных субъектах)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1258, 29, 'word_order', 3, '{"words": ["הביתה", "שסיימנו", "אחרי", "את", "העבודה", "הלכנו"], "instruction": "Расставьте слова в правильном порядке:", "translation": "После того как мы закончили работу, мы пошли домой", "words_shuffled": ["הביתה", "שסיימנו", "הלכנו", "העבודה", "את", "אחרי"]}', '{"correct_order": ["אחרי", "שסיימנו", "את", "העבודה", "הלכנו", "הביתה"]}', '{"text": "אחרי שסיימנו את העבודה, הלכנו הביתה. Временное придаточное с אחרי ש."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1263, 30, 'word_order', 2, '{"words": ["לעשן", "פה", "אסור"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Здесь запрещено курить", "words_shuffled": ["לעשן", "אסור", "פה"]}', '{"correct_order": ["אסור", "לעשן", "פה"]}', '{"text": "אסור לעשן פה. Безличная модальная конструкция: אסור + инфинитив + обстоятельство."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1268, 30, 'word_order', 3, '{"words": ["לעזור", "אני", "לך", "יכול"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я могу тебе помочь", "words_shuffled": ["יכול", "לך", "אני", "לעזור"]}', '{"correct_order": ["אני", "יכול", "לעזור", "לך"]}', '{"text": "אני יכול לעזור לך. Порядок: подлежащее + модальное + инфинитив + дополнение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1273, 31, 'word_order', 2, '{"words": ["לכותל", "מגיעים", "סליחה", "איך"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Извините, как добраться до Стены плача?", "words_shuffled": ["מגיעים", "לכותל", "סליחה", "איך"]}', '{"correct_order": ["סליחה", "איך", "מגיעים", "לכותל"]}', '{"text": "סליחה, איך מגיעים לכותל? Типичный вопрос туриста. מגיעים — безличная форма «добираются»."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1278, 31, 'word_order', 3, '{"words": ["עתיקה", "צפת", "עיר", "על", "גבוה", "הר"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Цфат — древний город на высокой горе", "words_shuffled": ["צפת", "גבוה", "עיר", "עתיקה", "על", "הר"]}', '{"correct_order": ["צפת", "עיר", "עתיקה", "על", "הר", "גבוה"]}', '{"text": "צפת עיר עתיקה על הר גבוה. Именное предложение без глагола «быть» в настоящем."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1283, 32, 'word_order', 2, '{"words": ["אני", "באוניברסיטה", "מדעי", "לומדת", "המחשב"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я (ж.р.) изучаю компьютерные науки в университете", "words_shuffled": ["מדעי", "אני", "לומדת", "באוניברסיטה", "המחשב"]}', '{"correct_order": ["אני", "לומדת", "מדעי", "המחשב", "באוניברסיטה"]}', '{"text": "אני לומדת מדעי המחשב באוניברסיטה. Порядок: субъект + глагол + объект + обстоятельство."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1288, 32, 'word_order', 3, '{"words": ["התלמידים", "הפרויקט", "הגישו", "את", "בזמן"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Студенты сдали проект вовремя", "words_shuffled": ["בזמן", "הפרויקט", "התלמידים", "הגישו", "את"]}', '{"correct_order": ["התלמידים", "הגישו", "את", "הפרויקט", "בזמן"]}', '{"text": "התלמידים הגישו את הפרויקט בזמן. הגישו — Хифъиль, прош. время мн.ч."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1296, 33, 'word_order', 3, '{"words": ["את", "הצליחו", "לעבור", "רוב", "התלמידים", "המבחן"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Большинство студентов смогли сдать экзамен", "words_shuffled": ["הצליחו", "את", "התלמידים", "המבחן", "לעבור", "רוב"]}', '{"correct_order": ["רוב", "התלמידים", "הצליחו", "לעבור", "את", "המבחן"]}', '{"text": "רוב התלמידים הצליחו לעבור את המבחן. Хифъиль הצליחו + инфинитив לעבור."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1304, 34, 'word_order', 3, '{"words": ["שלו", "הסופר", "תורגם", "לעשרים", "שנכתב", "הספר", "ידי", "על", "שפות"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Книга, написанная писателем, переведена на двадцать языков", "words_shuffled": ["על", "תורגם", "שנכתב", "הסופר", "ידי", "שפות", "לעשרים", "הספר"]}', '{"correct_order": ["הספר", "שנכתב", "על", "ידי", "הסופר", "תורגם", "לעשרים", "שפות"]}', '{"text": "הספר שנכתב על ידי הסופר תורגם לעשרים שפות. Два пассива: נכתב (Нифъаль), תורגם (Пуаль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1312, 49, 'word_order', 3, '{"words": ["הייתי", "לא", "באתי", "בא", "אם", "ידעתי", "שהישיבה", "בוטלה", "הייתי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Если бы я знал, что совещание отменили, не пришёл бы", "words_shuffled": ["באתי", "שהישיבה", "ידעתי", "אם", "לא", "הייתי", "הייתי", "בוטלה"]}', '{"correct_order": ["אם", "הייתי", "ידעתי", "שהישיבה", "בוטלה", "לא", "הייתי", "באתי"]}', '{"text": "אם הייתי יודע שהישיבה בוטלה, לא הייתי בא. Нереальное условие + косвенная речь."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1318, 49, 'word_order', 2, '{"words": ["ביחד", "נבשל", "בוא", "זמן", "לך", "יש", "אם"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Если у тебя есть время, давай готовить вместе", "words_shuffled": ["ביחד", "זמן", "אם", "נבשל", "יש", "בוא", "לך"]}', '{"correct_order": ["אם", "יש", "לך", "זמן", "בוא", "נבשל", "ביחד"]}', '{"text": "אם יש לך זמן, בוא נבשל ביחד. Реальное условие + приглашение (בוא + будущее)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1323, 50, 'word_order', 3, '{"words": ["שהוא", "כי", "לא", "באתי", "חולה", "היה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я не пришёл, потому что он был болен", "words_shuffled": ["חולה", "כי", "באתי", "שהוא", "היה"]}', '{"correct_order": ["באתי", "כי", "שהוא", "היה", "חולה"]}', '{"text": "Примечание: это «לא באתי כי שהוא היה חולה» — но правильный ответ: לא באתי כי הוא היה חולה. כי вводит причину, ש не нужен после כי."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1328, 50, 'word_order', 2, '{"words": ["הביתה", "הלכנו", "שסיימנו", "אחרי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "После того как закончили, пошли домой", "words_shuffled": ["שסיימנו", "אחרי", "הלכנו", "הביתה"]}', '{"correct_order": ["אחרי", "שסיימנו", "הלכנו", "הביתה"]}', '{"text": "אחרי שסיימנו, הלכנו הביתה. Временное придаточное: אחרי ש + прошедшее."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1333, 51, 'word_order', 3, '{"words": ["שנכתב", "ידי", "הספר", "תורגם", "על", "לעשרים", "הסופר", "שפות"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Книга, написанная писателем, переведена на двадцать языков", "words_shuffled": ["שפות", "הסופר", "על", "תורגם", "הספר", "לעשרים", "שנכתב", "ידי"]}', '{"correct_order": ["הספר", "שנכתב", "על", "ידי", "הסופר", "תורגם", "לעשרים", "שפות"]}', '{"text": "הספר שנכתב על ידי הסופר תורגם לעשרים שפות. Нифъаль + Пуаль + על ידי."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1338, 51, 'word_order', 3, '{"words": ["ממשיכה", "קשה", "היא", "ללמוד", "למרות", "שזה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Она продолжает учиться, несмотря на то что это трудно", "words_shuffled": ["שזה", "קשה", "היא", "ללמוד", "ממשיכה", "למרות"]}', '{"correct_order": ["למרות", "שזה", "קשה", "היא", "ממשיכה", "ללמוד"]}', '{"text": "למרות שזה קשה, היא ממשיכה ללמוד. Уступка + Хифъиль המשיכה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1343, 52, 'word_order', 2, '{"words": ["דם", "בדיקת", "לעשות", "צריך", "אני"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Мне нужно сдать анализ крови", "words_shuffled": ["דם", "בדיקת", "לעשות", "אני", "צריך"]}', '{"correct_order": ["אני", "צריך", "לעשות", "בדיקת", "דם"]}', '{"text": "אני צריך לעשות בדיקת דם. בדיקת דם (бдикАт дам) — анализ крови. Смихут (сопряжённая конструкция)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1353, 53, 'word_order', 3, '{"words": ["שמח", "חג", "חנוכה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Весёлой Хануки!", "words_shuffled": ["חג", "שמח", "חנוכה"]}', '{"correct_order": ["חנוכה", "שמח", "חג"]}', '{"text": "Порядок поздравления: название праздника + שמח или חג + שמח. חנוכה שמח!"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1358, 53, 'word_order', 2, '{"words": ["ומתוקה", "שנה", "טובה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Хорошего и сладкого года!", "words_shuffled": ["טובה", "ומתוקה", "שנה"]}', '{"correct_order": ["שנה", "טובה", "ומתוקה"]}', '{"text": "שנה טובה ומתוקה! Традиционное поздравление на Рош ха-Шана."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1366, 54, 'word_order', 2, '{"words": ["בבקשה", "לשניים", "שולחן"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Столик на двоих, пожалуйста", "words_shuffled": ["שולחן", "לשניים", "בבקשה"]}', '{"correct_order": ["שולחן", "לשניים", "בבקשה"]}', '{"text": "שולחן לשניים, בבקשה. Простая просьба в ресторане."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1373, 116, 'word_order', 2, '{"words": ["סבלנות", "דורשת", "הלמידה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Учёба требует терпения", "words_shuffled": ["סבלנות", "הלמידה", "דורשת"]}', '{"correct_order": ["הלמידה", "דורשת", "סבלנות"]}', '{"text": "הלמידה דורשת סבלנות. למידה (лемидА) — учёба, герундий. דורשת — требует (ж.р.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1379, 116, 'word_order', 3, '{"words": ["הטכנולוגית", "מהירה", "מאוד", "ההתפתחות"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Технологическое развитие очень быстрое", "words_shuffled": ["מאוד", "ההתפתחות", "מהירה", "הטכנולוגית"]}', '{"correct_order": ["ההתפתחות", "הטכנולוגית", "מהירה", "מאוד"]}', '{"text": "ההתפתחות הטכנולוגית מהירה מאוד. Именное предложение: подлежащее + прилагательное."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1388, 117, 'word_order', 2, '{"words": ["שהוא", "אמר", "ללמוד", "דני", "רוצה", "שם"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Дани сказал, что он хочет учиться там", "words_shuffled": ["ללמוד", "שהוא", "רוצה", "דני", "אמר", "שם"]}', '{"correct_order": ["דני", "אמר", "שהוא", "רוצה", "ללמוד", "שם"]}', '{"text": "דני אמר שהוא רוצה ללמוד שם. Косвенная речь: אני→הוא, פה→שם."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1393, 117, 'word_order', 3, '{"words": ["שהיא", "הבטיחה", "היא", "תגיע", "בזמן"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Она пообещала, что приедет вовремя", "words_shuffled": ["שהיא", "היא", "בזמן", "הבטיחה", "תגיע"]}', '{"correct_order": ["היא", "הבטיחה", "שהיא", "תגיע", "בזמן"]}', '{"text": "היא הבטיחה שהיא תגיע בזמן. Хифъиль הבטיחה — пообещала."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1403, 118, 'word_order', 2, '{"words": ["מהר", "נרדם", "התינוק"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Малыш быстро заснул", "words_shuffled": ["התינוק", "מהר", "נרדם"]}', '{"correct_order": ["התינוק", "נרדם", "מהר"]}', '{"text": "התינוק נרדם מהר. נרדם (нирдАм) — заснул. Нифъаль, начинательное значение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1408, 118, 'word_order', 3, '{"words": ["ידי", "על", "נכתב", "ישראלי", "הספר", "סופר"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Книга была написана израильским писателем", "words_shuffled": ["הספר", "סופר", "על", "ידי", "ישראלי", "נכתב"]}', '{"correct_order": ["הספר", "נכתב", "על", "ידי", "סופר", "ישראלי"]}', '{"text": "הספר נכתב על ידי סופר ישראלי. Пассив Нифъаль + על ידי для деятеля."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1418, 119, 'word_order', 2, '{"words": ["ש", "בתנאי", "שם", "שתהיה", "אבוא"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я приду при условии, что ты будешь там", "words_shuffled": ["ש", "אבוא", "שם", "שתהיה", "בתנאי"]}', '{"correct_order": ["אבוא", "בתנאי", "ש", "שתהיה", "שם"]}', '{"text": "אבוא בתנאי שתהיה שם. בתנאי ש (битнАй ше) — при условии, что."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1424, 119, 'word_order', 3, '{"words": ["ש", "אני", "בעוד", "לומד", "הוא", "ישן"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я учусь, тогда как он спит", "words_shuffled": ["בעוד", "ש", "אני", "לומד", "הוא", "ישן"]}', '{"correct_order": ["ש", "בעוד", "הוא", "ישן", "אני", "לומד"]}', '{"text": "Ожидаемый ответ: בעוד שהוא ישן, אני לומד или אני לומד בעוד שהוא ישן."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1433, 120, 'word_order', 2, '{"words": ["שנקרא", "בסיסי", "עוברים", "אימון", "חיילים", "טירונות"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Солдаты проходят базовый курс, называемый тиронут", "words_shuffled": ["שנקרא", "טירונות", "בסיסי", "אימון", "עוברים", "חיילים"]}', '{"correct_order": ["חיילים", "עוברים", "בסיסי", "אימון", "שנקרא", "טירונות"]}', '{"text": "חיילים עוברים אימון בסיסי שנקרא טירונות. טירונות (тиронУт) — курс молодого бойца."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1439, 120, 'word_order', 3, '{"words": ["היוקרתיות", "היא", "8200", "ביותר", "אחת", "היחידות", "יחידת"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Подразделение 8200 — одно из самых престижных", "words_shuffled": ["8200", "היא", "יחידת", "היחידות", "אחת", "היוקרתיות", "ביותר"]}', '{"correct_order": ["יחידת", "אחת", "היא", "היוקרתיות", "היחידות", "8200", "ביותר"]}', '{"text": "יחידת 8200 היא אחת היחידות היוקרתיות ביותר. Превосходная степень: ה...ביותר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1448, 121, 'word_order', 2, '{"words": ["אקולוגית", "זו", "חמורה", "בעיה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Это серьёзная экологическая проблема", "words_shuffled": ["חמורה", "אקולוגית", "בעיה", "זו"]}', '{"correct_order": ["זו", "בעיה", "אקולוגית", "חמורה"]}', '{"text": "זו בעיה אקולוגית חמורה. חמורה (хамурА) — серьёзная, тяжёлая."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1453, 121, 'word_order', 3, '{"words": ["הנגב", "ממחצית", "תופס", "המדינה", "שטח", "יותר", "מדבר"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Пустыня Негев занимает более половины территории страны", "words_shuffled": ["יותר", "מדבר", "המדינה", "ממחצית", "שטח", "הנגב", "תופס"]}', '{"correct_order": ["מדבר", "הנגב", "תופס", "יותר", "ממחצית", "שטח", "המדינה"]}', '{"text": "מדבר הנגב תופס יותר ממחצית שטח המדינה. תופס — занимает. מחצית — половина."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1463, 122, 'word_order', 2, '{"words": ["בעולם", "מכל", "מדינה", "סטארט-אפים", "יותר", "בישראל", "יש", "אחרת"], "instruction": "Расставьте слова в правильном порядке:", "translation": "В Израиле больше стартапов, чем в любой другой стране мира", "words_shuffled": ["יש", "מכל", "בעולם", "אחרת", "יותר", "סטארט-אפים", "בישראל"]}', '{"correct_order": ["בישראל", "יש", "יותר", "סטארט-אפים", "מכל", "אחרת", "בעולם"]}', '{"text": "בישראל יש יותר סטארט-אפים מכל מדינה אחרת בעולם."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1469, 122, 'word_order', 3, '{"words": ["מצוינים", "8200", "מכשירות", "בתחומי", "יחידות", "כמו", "צעירים", "הסייבר"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Подразделения вроде 8200 готовят отличных молодых специалистов в области кибербезопасности", "words_shuffled": ["צעירים", "בתחומי", "8200", "מצוינים", "יחידות", "מכשירות", "הסייבר", "כמו"]}', '{"correct_order": ["יחידות", "כמו", "8200", "מכשירות", "צעירים", "מצוינים", "בתחומי", "הסייבר"]}', '{"text": "יחידות כמו 8200 מכשירות צעירים מצוינים בתחומי הסייבר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1478, 123, 'word_order', 2, '{"words": ["כבד", "השבוע", "חום", "גל", "צפוי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "На этой неделе ожидается сильная жара", "words_shuffled": ["צפוי", "כבד", "גל", "חום", "השבוע"]}', '{"correct_order": ["גל", "חום", "כבד", "צפוי", "השבוע"]}', '{"text": "גל חום כבד צפוי השבוע. צפוי (цафУй) — ожидается. גל חום — волна жары."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1483, 123, 'word_order', 3, '{"words": ["חדשות", "מהדורת", "של", "שמונה", "ה", "ערב"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Вечерний выпуск новостей в восемь", "words_shuffled": ["חדשות", "ה", "של", "מהדורת", "ערב", "שמונה"]}', '{"correct_order": ["ה", "מהדורת", "חדשות", "של", "שמונה", "ערב"]}', '{"text": "מהדורת החדשות של שמונה בערב. מהדורה (маhадурА) — выпуск. Смихут: מהדורת חדשות."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1493, 124, 'word_order', 2, '{"words": ["למכבי", "אפס", "שתיים"], "instruction": "Расставьте слова в правильном порядке:", "translation": "2:0 в пользу Маккаби", "words_shuffled": ["למכבי", "אפס", "שתיים"]}', '{"correct_order": ["שתיים", "למכבי", "אפס"]}', '{"text": "!שתיים אפס למכבי Результат матча: שתיים (два) — אפס (ноль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1499, 124, 'word_order', 3, '{"words": ["תחרות", "בין", "הקבוצות", "הגדולה", "השנה", "היא"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Большие соревнования между командами в этом году", "words_shuffled": ["השנה", "הגדולה", "בין", "תחרות", "היא", "הקבוצות"]}', '{"correct_order": ["הגדולה", "תחרות", "בין", "הקבוצות", "השנה", "היא"]}', '{"text": "התחרות הגדולה בין הקבוצות היא השנה. תחרות (тахарУт) — соревнование."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1508, 125, 'word_order', 2, '{"words": ["ריקים", "החיים", "אהבה", "בלי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Без любви жизнь пуста", "words_shuffled": ["ריקים", "בלי", "אהבה", "החיים"]}', '{"correct_order": ["בלי", "אהבה", "החיים", "ריקים"]}', '{"text": "בלי אהבה החיים ריקים. Абстрактное существительное אהבה — любовь."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1514, 125, 'word_order', 3, '{"words": ["ינצח", "הצדק", "בסוף"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Справедливость победит в конце", "words_shuffled": ["ינצח", "הצדק", "בסוף"]}', '{"correct_order": ["הצדק", "ינצח", "בסוף"]}', '{"text": "הצדק ינצח בסוף. Абстрактное подлежащее + глагол будущего времени."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1526, 126, 'word_order', 2, '{"words": ["חינם", "אחד", "קנה", "קבל", "אחד"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Купи один, получи один бесплатно", "words_shuffled": ["חינם", "קבל", "קנה", "אחד", "אחד"]}', '{"correct_order": ["קנה", "אחד", "קבל", "אחד", "חינם"]}', '{"text": "קנה אחד, קבל אחד חינם. Классическая рекламная формула."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1532, 126, 'word_order', 3, '{"words": ["מצומצמת", "תפעל", "הציבורית", "במתכונת", "התחבורה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Общественный транспорт будет работать в сокращённом режиме", "words_shuffled": ["במתכונת", "תפעל", "התחבורה", "מצומצמת", "הציבורית"]}', '{"correct_order": ["התחבורה", "הציבורית", "תפעל", "במתכונת", "מצומצמת"]}', '{"text": "התחבורה הציבורית תפעל במתכונת מצומצמת. Новостной синтаксис."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1538, 127, 'word_order', 3, '{"words": ["הייתי", "אילו", "הגענו", "בזמן", "ההופעה", "את", "רואים"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Если бы мы пришли вовремя, увидели бы шоу", "words_shuffled": ["אילו", "הייתי", "בזמן", "הגענו", "ההופעה", "את", "רואים"]}', '{"correct_order": ["אילו", "הגענו", "בזמן", "הייתי", "רואים", "את", "ההופעה"]}', '{"text": "אילו הגענו בזמן, היינו רואים את ההופעה. Нереальное условие III типа."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1543, 127, 'word_order', 3, '{"words": ["רפואה", "אילו", "הייתי", "רופא", "למדתי", "היום"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Если бы я учился медицине, был бы сегодня врачом", "words_shuffled": ["היום", "אילו", "רופא", "למדתי", "הייתי", "רפואה"]}', '{"correct_order": ["אילו", "למדתי", "רפואה", "הייתי", "רופא", "היום"]}', '{"text": "אילו למדתי רפואה, הייתי רופא היום. Смешанное условие: прошлое → настоящее."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1553, 128, 'word_order', 2, '{"words": ["הראש", "על", "את", "שברה", "היא", "הבעיה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Она ломала голову над проблемой", "words_shuffled": ["הבעיה", "היא", "שברה", "את", "על", "הראש"]}', '{"correct_order": ["היא", "שברה", "את", "הראש", "על", "הבעיה"]}', '{"text": "היא שברה את הראש על הבעיה. Идиома שבר ראש — долго думал."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1559, 128, 'word_order', 3, '{"words": ["ולא", "עמד", "ויתר", "שלו", "הוא", "על"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Он настоял на своём и не уступил", "words_shuffled": ["שלו", "ולא", "הוא", "ויתר", "על", "עמד"]}', '{"correct_order": ["הוא", "עמד", "על", "שלו", "ולא", "ויתר"]}', '{"text": "הוא עמד על שלו ולא ויתר. Идиома + ויתר (ватЕр) — уступил, сдался."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1568, 129, 'word_order', 2, '{"words": ["עברית", "חובה", "הבגרות", "מקצועות", "כוללת", "ומתמטיקה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Багрут включает обязательные предметы: иврит и математику", "words_shuffled": ["חובה", "ומתמטיקה", "כוללת", "מקצועות", "עברית", "הבגרות"]}', '{"correct_order": ["הבגרות", "כוללת", "מקצועות", "חובה", "עברית", "ומתמטיקה"]}', '{"text": "הבגרות כוללת מקצועות חובה: עברית ומתמטיקה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1574, 129, 'word_order', 3, '{"words": ["חובה", "כוללת", "אנגלית", "הבגרות", "תנ\"ך", "עברית", "מקצועות"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Багрут включает обязательные предметы: иврит, английский, ТАНАХ", "words_shuffled": ["הבגרות", "תנ\"ך", "מקצועות", "אנגלית", "עברית", "כוללת", "חובה"]}', '{"correct_order": ["הבגרות", "כוללת", "מקצועות", "חובה", "עברית", "אנגלית", "תנ\"ך"]}', '{"text": "הבגרות כוללת מקצועות חובה: עברית, אנגלית, תנ\"ך."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1583, 130, 'word_order', 2, '{"words": ["גופנית", "פעילות", "עושה", "בשבוע", "אני", "פעמים", "שלוש"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я занимаюсь спортом три раза в неделю", "words_shuffled": ["פעילות", "אני", "גופנית", "עושה", "שלוש", "פעמים", "בשבוע"]}', '{"correct_order": ["אני", "עושה", "פעילות", "גופנית", "שלוש", "פעמים", "בשבוע"]}', '{"text": "אני עושה פעילות גופנית שלוש פעמים בשבוע."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1589, 130, 'word_order', 3, '{"words": ["הנפשית", "פה", "יותר", "הבריאות", "היום", "מטאבו", "אינה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Психическое здоровье сегодня больше не табу", "words_shuffled": ["הבריאות", "הנפשית", "מטאבו", "אינה", "היום"]}', '{"correct_order": ["הבריאות", "הנפשית", "היום", "אינה", "מטאבו"]}', '{"text": "הבריאות הנפשית היום אינה מטאבו. Обратный порядок от ожидаемого."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1598, 131, 'word_order', 2, '{"words": ["הממשלה", "ראש", "עומד", "המבצעת", "בראש", "הרשות"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Премьер-министр стоит во главе исполнительной власти", "words_shuffled": ["בראש", "המבצעת", "הרשות", "הממשלה", "עומד", "ראש"]}', '{"correct_order": ["הממשלה", "ראש", "עומד", "בראש", "הרשות", "המבצעת"]}', '{"text": "ראש הממשלה עומד בראש הרשות המבצעת. ראש הממשלה — премьер-министр."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1604, 131, 'word_order', 3, '{"words": ["חסימה", "לעבור", "את", "צריכה", "מפלגה", "אחוז", "ה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Партия должна преодолеть электоральный барьер", "words_shuffled": ["אחוז", "מפלגה", "את", "חסימה", "צריכה", "לעבור", "ה"]}', '{"correct_order": ["מפלגה", "צריכה", "לעבור", "את", "ה", "אחוז", "חסימה"]}', '{"text": "מפלגה צריכה לעבור את אחוז החסימה. לעבור — преодолеть, пройти."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1613, 132, 'word_order', 2, '{"words": ["הסרט", "בינלאומיים", "בפרסים", "הישראלי", "זכה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Израильский фильм получил международные призы", "words_shuffled": ["הישראלי", "הסרט", "זכה", "בפרסים", "בינלאומיים"]}', '{"correct_order": ["הסרט", "הישראלי", "זכה", "בינלאומיים", "בפרסים"]}', '{"text": "הסרט הישראלי זכה בפרסים בינלאומיים. זכה ב — выиграл, получил."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1619, 132, 'word_order', 3, '{"words": ["ב-1917", "שנוסד", "הלאומי", "הוא", "התיאטרון", "הבימה", "במוסקבה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Габима — национальный театр, основанный в 1917 г. в Москве", "words_shuffled": ["במוסקבה", "הבימה", "ב-1917", "הלאומי", "הוא", "שנוסד", "התיאטרון"]}', '{"correct_order": ["הבימה", "הוא", "התיאטרון", "הלאומי", "שנוסד", "ב-1917", "במוסקבה"]}', '{"text": "הבימה הוא התיאטרון הלאומי שנוסד ב-1917 במוסקבה. נוסד — был основан (Нифъаль)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1628, 133, 'word_order', 2, '{"words": ["חיים", "שלחתי", "קורות"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я отправил резюме", "words_shuffled": ["קורות", "חיים", "שלחתי"]}', '{"correct_order": ["שלחתי", "קורות", "חיים"]}', '{"text": "שלחתי קורות חיים. שלחתי — я отправил (Пиэль от שלח)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1634, 133, 'word_order', 3, '{"words": ["עבודה", "מחר", "יש", "לי", "ראיון"], "instruction": "Расставьте слова в правильном порядке:", "translation": "У меня завтра собеседование", "words_shuffled": ["עבודה", "מחר", "יש", "לי", "ראיון"]}', '{"correct_order": ["יש", "לי", "ראיון", "עבודה", "מחר"]}', '{"text": "יש לי ראיון עבודה מחר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1643, 134, 'word_order', 2, '{"words": ["רב", "בכבוד"], "instruction": "Расставьте слова в правильном порядке:", "translation": "С уважением", "words_shuffled": ["בכבוד", "רב"]}', '{"correct_order": ["בכבוד", "רב"]}', '{"text": "בכבוד רב — стандартная подпись формального письма."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1649, 134, 'word_order', 3, '{"words": ["בבקשה", "הנדון", "רופא", "משפחה", "להחלפת"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Тема: просьба о замене семейного врача", "words_shuffled": ["משפחה", "הנדון", "רופא", "להחלפת"]}', '{"correct_order": ["הנדון", "להחלפת", "רופא", "משפחה"]}', '{"text": "הנדון: להחלפת רופא משפחה. Формальная запись темы письма."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1658, 135, 'word_order', 2, '{"words": ["שני", "מצד"], "instruction": "Расставьте слова в правильном порядке:", "translation": "С другой стороны", "words_shuffled": ["שני", "מצד"]}', '{"correct_order": ["מצד", "שני"]}', '{"text": "מצד שני — с другой стороны. Связующее выражение для контраргумента."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1664, 135, 'word_order', 3, '{"words": ["לכן", "בלימוד", "להשקיע", "חשוב", "שפות"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Поэтому важно инвестировать в изучение языков", "words_shuffled": ["להשקיע", "בלימוד", "שפות", "חשוב", "לכן"]}', '{"correct_order": ["לכן", "חשוב", "להשקיע", "בלימוד", "שפות"]}', '{"text": "לכן חשוב להשקיע בלימוד שפות. לכן — поэтому. Вывод аргумента."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1673, 136, 'word_order', 3, '{"words": ["שהוא", "בהייטק", "אמר", "חדש", "עובד", "הוא", "ומחפש", "סטארט-אפ"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Он сказал, что работает в хай-теке и ищет новый стартап", "words_shuffled": ["עובד", "ומחפש", "חדש", "סטארט-אפ", "אמר", "בהייטק", "הוא", "שהוא"]}', '{"correct_order": ["הוא", "אמר", "שהוא", "עובד", "בהייטק", "ומחפש", "סטארט-אפ", "חדש"]}', '{"text": "הוא אמר שהוא עובד בהייטק ומחפש סטארט-אפ חדש. Косвенная речь + сложное предложение."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1679, 136, 'word_order', 3, '{"words": ["להתפתח", "ממשיכה", "הקשיים", "הישראלית", "למרות", "הכלכלה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Несмотря на трудности, израильская экономика продолжает развиваться", "words_shuffled": ["הישראלית", "למרות", "ממשיכה", "להתפתח", "הכלכלה", "הקשיים"]}', '{"correct_order": ["למרות", "הקשיים", "הכלכלה", "הישראלית", "ממשיכה", "להתפתח"]}', '{"text": "למרות הקשיים, הכלכלה הישראלית ממשיכה להתפתח. Итоговое предложение B1."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1689, 35, 'word_order', 2, '{"words": ["ללמוד", "באתי", "כדי", "עברית", "לאוניברסיטה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я пришёл в университет, чтобы учить иврит", "words_shuffled": ["ללמוד", "לאוניברסיטה", "כדי", "עברית", "באתי"]}', '{"correct_order": ["באתי", "לאוניברסיטה", "כדי", "ללמוד", "עברית"]}', '{"text": "כדי + инфинитив: באתי לאוניברסיטה כדי ללמוד עברית."}', 10);
