INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (2992, 198, 'word_order', 2, '{"translation": "Результаты указывают на значимую связь", "words_shuffled": ["מצביעים", "על", "קשר", "מובהק", "הממצאים"], "correct_sentence": "הממצאים מצביעים על קשר מובהק"}', '{"correct_order": ["הממצאים", "מצביעים", "על", "קשר", "מובהק"]}', '{"text": "Правильный порядок: הממצאים מצביעים על קשר מובהק"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (2997, 199, 'word_order', 2, '{"translation": "Стиль меняет опыт читателя", "words_shuffled": ["הסגנון", "את", "משנה", "חוויית", "הקורא"], "correct_sentence": "הסגנון משנה את חוויית הקורא"}', '{"correct_order": ["הסגנון", "משנה", "את", "חוויית", "הקורא"]}', '{"text": "Правильный порядок: הסגנון משנה את חוויית הקורא"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (3002, 200, 'word_order', 2, '{"translation": "Иврит — один из древнейших языков мира", "words_shuffled": ["העברית", "היא", "מהשפות", "העתיקות", "אחת", "בעולם"], "correct_sentence": "העברית היא אחת מהשפות העתיקות בעולם"}', '{"correct_order": ["העברית", "היא", "אחת", "מהשפות", "העתיקות", "בעולם"]}', '{"text": "Правильный порядок: העברית היא אחת מהשפות העתיקות בעולם"}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (285, 35, 'word_order', 3, '{"words": ["הצלחנו", "הקשיים", "ש", "להתגבר", "למרות", "עליהם"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Несмотря на трудности, мы их преодолели", "words_shuffled": ["למרות", "ש", "להתגבר", "הצלחנו", "עליהם", "הקשיים"]}', '{"correct_order": ["למרות", "הקשיים", "ש", "הצלחנו", "להתגבר", "עליהם"]}', '{"text": "למרות + существительное, ש + сказуемое придаточного"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1073, 105, 'word_order', 1, '{"words": ["הזאת", "החולצה", "עולה", "כמה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Сколько стоит эта рубашка?", "words_shuffled": ["עולה", "החולצה", "הזאת", "כמה"]}', '{"correct_order": ["כמה", "עולה", "החולצה", "הזאת"]}', '{"text": "הזאת — эта (ж.р.). כמה עולה — сколько стоит."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (319, 63, 'word_order', 5, '{"words": ["התרבות", "של", "רבה", "ניכרת", "על", "השפה", "השפעה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Заметно большое влияние культуры на язык", "words_shuffled": ["רבה", "על", "של", "השפעה", "השפה", "ניכרת", "התרבות"]}', '{"correct_order": ["ניכרת", "השפעה", "רבה", "של", "התרבות", "על", "השפה"]}', '{"text": "Инверсия: предикатив ניכרת вынесен в начало"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (438, 6, 'word_order', 2, '{"words": ["ָ", "י", "בּ", "ִ", "ת"], "instruction": "Какой порядок букв и огласовок в слове בַּיִת (дом)?", "translation": "байит — дом", "words_shuffled": ["בּ", "ת", "ָ", "ִ", "י"]}', '{"correct_order": ["בּ", "ָ", "י", "ִ", "ת"]}', '{"text": "בַּיִת (бАйит) — дом. Бет-патах, Йуд-хирик, Тав."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (448, 7, 'word_order', 1, '{"words": ["על", "השולחן", "הספר"], "instruction": "Составьте предложение «Книга на столе»", "translation": "Книга на столе", "words_shuffled": ["השולחן", "הספר", "על"]}', '{"correct_order": ["הספר", "על", "השולחן"]}', '{"text": "הספר על השולחן — книга на столе. Оба существительных с артиклем."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (730, 88, 'word_order', 1, '{"words": ["לפני", "הבית", "הילדים"], "instruction": "Составьте «Дети перед домом»", "translation": "Дети перед домом", "words_shuffled": ["הבית", "לפני", "הילדים"]}', '{"correct_order": ["הילדים", "לפני", "הבית"]}', '{"text": "הילדים לפני הבית — дети перед домом."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (831, 18, 'word_order', 1, '{"words": ["הוא", "עברית", "אותנו", "לימד"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Он обучал нас ивриту", "words_shuffled": ["עברית", "הוא", "אותנו", "לימד"]}', '{"correct_order": ["הוא", "לימד", "אותנו", "עברית"]}', '{"text": "לימד (лимЭд) — обучал, Пиэль от корня ל.מ.ד. Пиэль придаёт каузативный / усиленный оттенок."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (839, 19, 'word_order', 1, '{"words": ["למדתי", "באולפן", "שנתיים", "עברית"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я учил иврит в ульпане два года", "words_shuffled": ["עברית", "באולפן", "שנתיים", "למדתי"]}', '{"correct_order": ["למדתי", "עברית", "באולפן", "שנתיים"]}', '{"text": "למדתי (ламАдти) — я учил. Порядок: глагол + объект + место + время."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (859, 21, 'word_order', 1, '{"words": ["וחלב", "לחם", "לקנות", "רוצה", "אני"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я хочу купить хлеб и молоко", "words_shuffled": ["לחם", "אני", "רוצה", "לקנות", "וחלב"]}', '{"correct_order": ["אני", "רוצה", "לקנות", "לחם", "וחלב"]}', '{"text": "Порядок: подлежащее + хочу + инфинитив + объекты."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (869, 22, 'word_order', 1, '{"words": ["בתל אביב", "המשפחה", "שלי", "גרה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Моя семья живёт в Тель-Авиве", "words_shuffled": ["בתל אביב", "שלי", "גרה", "המשפחה"]}', '{"correct_order": ["המשפחה", "שלי", "גרה", "בתל אביב"]}', '{"text": "המשפחה שלי (hа-мишпахА шелИ) — моя семья. גרה (гарА) — живёт (ж.р., т.к. משפחה — ж.р.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (882, 23, 'word_order', 2, '{"words": ["בבוקר", "הוא", "מוקדם", "קם"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Он встаёт утром рано", "words_shuffled": ["בבוקר", "הוא", "מוקדם", "קם"]}', '{"correct_order": ["הוא", "קם", "בבוקר", "מוקדם"]}', '{"text": "קם (кам) — встаёт. בבוקר (бабОкер) — утром. מוקדם (мукдАм) — рано."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (892, 24, 'word_order', 2, '{"words": ["מהר", "בשדה", "רץ", "הסוס"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Лошадь бежит быстро в поле", "words_shuffled": ["רץ", "מהר", "הסוס", "בשדה"]}', '{"correct_order": ["הסוס", "רץ", "מהר", "בשדה"]}', '{"text": "סוס (сус) — лошадь, רץ (рац) — бежит, שדה (садЭ) — поле."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (900, 25, 'word_order', 1, '{"words": ["הספר", "הולך", "הילד", "כל", "יום", "לבית"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Мальчик ходит в школу каждый день", "words_shuffled": ["הולך", "לבית", "יום", "הילד", "כל", "הספר"]}', '{"correct_order": ["הילד", "הולך", "לבית", "הספר", "כל", "יום"]}', '{"text": "בית הספר — школа (определённый смихут). כל יום — каждый день."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (909, 26, 'word_order', 2, '{"words": ["שלי", "רוצה", "לספר", "החופשה", "לכם", "אני", "על"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я хочу рассказать вам о моём отпуске", "words_shuffled": ["החופשה", "רוצה", "לכם", "לספר", "על", "אני", "שלי"]}', '{"correct_order": ["אני", "רוצה", "לספר", "לכם", "על", "החופשה", "שלי"]}', '{"text": "לספר (лесапЭр) — рассказать. על (аль) — о. החופשה שלי — мой отпуск."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (923, 95, 'word_order', 1, '{"words": ["למד", "הוא", "באולפן", "עברית"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Он учил иврит в ульпане", "words_shuffled": ["למד", "הוא", "באולפן", "עברית"]}', '{"correct_order": ["הוא", "למד", "עברית", "באולפן"]}', '{"text": "למד (ламАд) — учил, 3 л. м.р. Базовая форма без суффикса."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (937, 96, 'word_order', 1, '{"words": ["לשוק", "וקניתי", "פירות", "הלכתי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я ходил на рынок и купил фрукты", "words_shuffled": ["לשוק", "פירות", "הלכתי", "וקניתי"]}', '{"correct_order": ["הלכתי", "לשוק", "וקניתי", "פירות"]}', '{"text": "הלכתי — я ходил (ה.ל.כ, неправильный). קניתי — я купил (ק.נ.ה, группа ל\"ה)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (938, 96, 'word_order', 2, '{"words": ["הראשונה", "הים", "בפעם", "ראתה", "היא", "את"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Она увидела море в первый раз", "words_shuffled": ["הראשונה", "בפעם", "ראתה", "הים", "את", "היא"]}', '{"correct_order": ["היא", "ראתה", "את", "הים", "בפעם", "הראשונה"]}', '{"text": "ראתה (раатА) — она увидела. בפעם הראשונה — в первый раз."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (952, 97, 'word_order', 1, '{"words": ["מחר", "לסבתא", "אכתוב", "מכתב"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Завтра я напишу письмо бабушке", "words_shuffled": ["לסבתא", "אכתוב", "מכתב", "מחר"]}', '{"correct_order": ["מחר", "אכתוב", "מכתב", "לסבתא"]}', '{"text": "אכתוב (эхтОв) — я напишу. Маркер времени מחר в начале."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (953, 97, 'word_order', 2, '{"words": ["בשנה", "הם", "הבאה", "עברית", "ילמדו"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Они будут учить иврит в следующем году", "words_shuffled": ["בשנה", "ילמדו", "עברית", "הם", "הבאה"]}', '{"correct_order": ["הם", "ילמדו", "עברית", "בשנה", "הבאה"]}', '{"text": "ילמדו (йилмедУ) — они будут учить. בשנה הבאה — в следующем году."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (968, 98, 'word_order', 2, '{"words": ["הולכים", "בחוץ", "הערב", "אנחנו", "לאכול"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Сегодня вечером мы собираемся поесть вне дома", "words_shuffled": ["אנחנו", "בחוץ", "הולכים", "לאכול", "הערב"]}', '{"correct_order": ["אנחנו", "הולכים", "לאכול", "בחוץ", "הערב"]}', '{"text": "הולכים לאכול — собираемся поесть. בחוץ — вне дома/на улице."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (982, 99, 'word_order', 1, '{"words": ["זמן", "היום", "יש", "לי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "У меня сегодня есть время", "words_shuffled": ["זמן", "היום", "לי", "יש"]}', '{"correct_order": ["יש", "לי", "זמן", "היום"]}', '{"text": "יש לי — у меня есть. Безличная конструкция владения."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (983, 99, 'word_order', 2, '{"words": ["אותי", "הוא", "ראה", "ברחוב"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Он увидел меня на улице", "words_shuffled": ["הוא", "ברחוב", "ראה", "אותי"]}', '{"correct_order": ["הוא", "ראה", "אותי", "ברחוב"]}', '{"text": "אותי (отИ) — меня. Маркер прямого дополнения את + суффикс."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (997, 100, 'word_order', 1, '{"words": ["הולכים", "כל", "הספר", "הילדים", "לבית", "בוקר"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Дети ходят в школу каждое утро", "words_shuffled": ["כל", "הספר", "הילדים", "הולכים", "לבית", "בוקר"]}', '{"correct_order": ["הילדים", "הולכים", "לבית", "הספר", "כל", "בוקר"]}', '{"text": "בית הספר — определённый смихут (школа). Артикль ה перед ספר."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (998, 100, 'word_order', 2, '{"words": ["הים", "נכנסנו", "לבית", "ליד", "קפה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Мы зашли в кафе рядом с морем", "words_shuffled": ["נכנסנו", "קפה", "ליד", "לבית", "הים"]}', '{"correct_order": ["נכנסנו", "לבית", "קפה", "ליד", "הים"]}', '{"text": "בית קפה — неопределённый смихут (кафе). ליד הים — рядом с морем."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1012, 101, 'word_order', 2, '{"words": ["ילדים", "בנות", "יש", "שלושה", "ושתי", "לי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "У меня три сына и две дочери", "words_shuffled": ["יש", "ושתי", "לי", "שלושה", "בנות", "ילדים"]}', '{"correct_order": ["יש", "לי", "שלושה", "ילדים", "ושתי", "בנות"]}', '{"text": "שלושה ילדים — три сына (м.). שתי בנות — две дочери (ж.)."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1013, 101, 'word_order', 1, '{"words": ["הראשון", "היום", "זה", "בעבודה", "שלי"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Это мой первый день на работе", "words_shuffled": ["הראשון", "זה", "בעבודה", "שלי", "היום"]}', '{"correct_order": ["זה", "היום", "הראשון", "שלי", "בעבודה"]}', '{"text": "הראשון — первый. Порядковое с артиклем ה."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1027, 102, 'word_order', 1, '{"words": ["אני", "חמש", "כבר", "כמהנדס", "שנים", "עובד"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Я работаю инженером уже пять лет", "words_shuffled": ["חמש", "אני", "כבר", "שנים", "כמהנדס", "עובד"]}', '{"correct_order": ["אני", "עובד", "כמהנדס", "כבר", "חמש", "שנים"]}', '{"text": "כ + профессия — в качестве. כבר חמש שנים — уже пять лет."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1028, 102, 'word_order', 2, '{"words": ["לי", "שנים", "יש", "ניסיון", "של", "שלוש"], "instruction": "Расставьте слова в правильном порядке:", "translation": "У меня опыт три года", "words_shuffled": ["ניסיון", "שלוש", "לי", "של", "שנים", "יש"]}', '{"correct_order": ["יש", "לי", "ניסיון", "של", "שלוש", "שנים"]}', '{"text": "ניסיון של שלוש שנים — опыт три года."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1042, 103, 'word_order', 1, '{"words": ["לי", "הבטן", "ימים", "כואב", "כבר", "שלושה"], "instruction": "Расставьте слова в правильном порядке:", "translation": "У меня болит живот уже три дня", "words_shuffled": ["הבטן", "ימים", "כואב", "לי", "שלושה", "כבר"]}', '{"correct_order": ["כואב", "לי", "הבטן", "כבר", "שלושה", "ימים"]}', '{"text": "כואב לי הבטן — болит живот. כבר שלושה ימים — уже три дня."}', 10);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1043, 103, 'word_order', 2, '{"words": ["אני", "לבית", "ללכת", "מרקחת", "צריך"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Мне нужно пойти в аптеку", "words_shuffled": ["אני", "ללכת", "מרקחת", "לבית", "צריך"]}', '{"correct_order": ["אני", "צריך", "ללכת", "לבית", "מרקחת"]}', '{"text": "בית מרקחת — аптека (смихут). צריך ללכת — нужно пойти."}', 10);
