INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (1088, 106, 'word_order', 2, '{"words": ["בתור", "לי", "לחכות", "נמאס"], "instruction": "Расставьте слова в правильном порядке:", "translation": "Мне надоело ждать в очереди", "words_shuffled": ["לי", "לחכות", "נמאס", "בתור"]}', '{"correct_order": ["נמאס", "לי", "לחכות", "בתור"]}', '{"text": "נמאס לי — мне надоело. לחכות בתור — ждать в очереди."}', 10);
