INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4353, 215, 'word_order', 3, '{"translation": "После того как я закончил учёбу, я нашёл работу", "words_shuffled": ["אחרי", "שסיימתי", "מצאתי", "עבודה", "את", "הלימודים"], "correct_sentence": "אחרי שסיימתי את הלימודים מצאתי עבודה"}', '{"correct_order": ["אחרי", "שסיימתי", "את", "הלימודים", "מצאתי", "עבודה"]}', '{"text": "אחרי ש + придаточное + главное"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4359, 215, 'word_order', 3, '{"translation": "Как только я получил сообщение, я ему позвонил", "words_shuffled": ["ברגע", "שקיבלתי", "התקשרתי", "אליו", "את", "ההודעה"], "correct_sentence": "ברגע שקיבלתי את ההודעה התקשרתי אליו"}', '{"correct_order": ["ברגע", "שקיבלתי", "את", "ההודעה", "התקשרתי", "אליו"]}', '{"text": "ברגע ש + придаточное + главное"}', 15);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4452, 216, 'word_order', 4, '{"translation": "Суд постановил, что закон конституционен", "words_shuffled": ["קבע", "כי", "החוק", "חוקתי", "בית", "המשפט"], "correct_sentence": "בית המשפט קבע כי החוק חוקתי"}', '{"correct_order": ["בית", "המשפט", "קבע", "כי", "החוק", "חוקתי"]}', '{"text": "Подлежащее + глагол + כי + придаточное"}', 20);
