INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4549, 217, 'word_order', 5, '{"translation": "Судебное решение создало важный прецедент", "words_shuffled": ["הפסיקה", "חשוב", "תקדים", "יצרה"], "correct_sentence": "הפסיקה יצרה תקדים חשוב"}', '{"correct_order": ["הפסיקה", "יצרה", "תקדים", "חשוב"]}', '{"text": "Подлежащее + глагол + дополнение + прилагательное"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4553, 217, 'word_order', 5, '{"translation": "Без исторического контекста невозможно понять текст", "words_shuffled": ["ההקשר", "ללא", "את", "להבין", "הטקסט", "אפשר", "אי", "ההיסטורי"], "correct_sentence": "ללא ההקשר ההיסטורי אי אפשר להבין את הטקסט"}', '{"correct_order": ["ללא", "ההקשר", "ההיסטורי", "אי", "אפשר", "להבין", "את", "הטקסט"]}', '{"text": "ללא + контекст + אי אפשר + инфинитив + дополнение"}', 25);
INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4647, 218, 'word_order', 6, '{"translation": "Если лёгкое таково, тем более тяжёлое", "words_shuffled": ["אם", "הקל", "כך", "החמור", "קל", "וחומר", "על", "אחת", "כמה", "וכמה"], "correct_sentence": "אם הקל כך קל וחומר החמור על אחת כמה וכמה"}', '{"correct_order": ["אם", "הקל", "כך", "קל", "וחומר", "החמור", "על", "אחת", "כמה", "וכמה"]}', '{"text": "Аргумент каль вахомер: если А, то тем более Б"}', 30);
