INSERT INTO public.exercises (id, lesson_id, type, difficulty, prompt_json, answer_json, explanation_json, points) VALUES (4658, 218, 'word_order', 6, '{"translation": "В основе лежит предположение, что язык формирует реальность", "words_shuffled": ["כי", "מונחת", "ביסוד", "ההנחה", "השפה", "מציאות", "מעצבת"], "correct_sentence": "ביסוד מונחת ההנחה כי השפה מעצבת מציאות"}', '{"correct_order": ["ביסוד", "מונחת", "ההנחה", "כי", "השפה", "מעצבת", "מציאות"]}', '{"text": "ביסוד + глагол + подлежащее + כי + придаточное"}', 30);
